  "main.rs": "/// Splits a shell command string into tokens in a quote-aware fashion,
/// matching bash's behavior for single quotes.
///
/// The approach uses a simple state machine that walks through the input
/// character by character, tracking whether we're inside single quotes
/// and whether we're currently building a token.
fn tokenize(input: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current = String::new();
    let mut in_single_quote = false;
    let mut in_token = false;

    for ch in input.chars() {
        match ch {
            '\'' => {
                // Toggle quoting. Opening or closing a quote always means
                // we are inside a token (even if the quoted portion is empty).
                in_single_quote = !in_single_quote;
                in_token = true;
            }
            ' ' if !in_single_quote => {
                // Unquoted space: if we were building a token, finish it.
                if in_token {
                    tokens.push(std::mem::take(&mut current));
                    in_token = false;
                }
            }
            _ => {
                // Any other character (or a space inside quotes) is part
                // of the current token.
                current.push(ch);
                in_token = true;
            }
        }
    }

    // Don't forget the last token if the string didn't end with unquoted whitespace.
    if in_token {
        tokens.push(current);
    }

    tokens
}

fn main() {
    let input = " one  ' two  'three    four";
    let tokens = tokenize(input);
    println!("{} args:", tokens.len());
    for token in &tokens {
        println!("<{}>", token);
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_basic() {
        assert_eq!(
            tokenize(" one  ' two  'three    four"),
            vec!["one", " two  three", "four"]
        );
    }

    #[test]
    fn test_empty() {
        assert_eq!(tokenize(""), Vec::<String>::new());
    }

    #[test]
    fn test_only_spaces() {
        assert_eq!(tokenize("    "), Vec::<String>::new());
    }

    #[test]
    fn test_single_token() {
        assert_eq!(tokenize("hello"), vec!["hello"]);
    }

    #[test]
    fn test_empty_quotes_produce_empty_token() {
        // bash: foo '' bar  => 3 args: <foo> <> <bar>
        assert_eq!(tokenize("foo '' bar"), vec!["foo", "", "bar"]);
    }

    #[test]
    fn test_quoted_spaces_only() {
        assert_eq!(tokenize("'   '"), vec!["   "]);
    }

    #[test]
    fn test_adjacent_quoted_and_unquoted() {
        // bash: 'ab'cd'ef' => <abcdef>
        assert_eq!(tokenize("'ab'cd'ef'"), vec!["abcdef"]);
