#[derive(Deserialize, Debug)]
struct CharacterRaw {
    name: String,
    ac: u8,
    hp: u16,
}

#[derive(Debug)]
struct Character {
    name: String,
    ac: u8,
    current: u16,
    max: u16,
    temp: u16,
}

impl From<CharacterRaw> for Character {
    fn from(raw: CharacterRaw) -> Self {
        Character {
            name: raw.name,
            ac: raw.ac,
            current: raw.hp,
            max: raw.hp,
            temp: 0,
        }
    }
}

// If you really want to avoid the helper struct, you can use a custom
// Deserialize impl. Here's one approach using deserialize_with on an
// intermediate wrapper so you keep derive for everything else:

mod single_field_approach {
    use serde::de::{self, Deserializer, MapAccess, Visitor};
    use serde::Deserialize;
    use std::fmt;

    #[derive(Debug)]
    pub struct Character {
        pub name: String,
        pub ac: u8,
        pub current: u16,
        pub max: u16,
        pub temp: u16,
    }

    impl<'de> Deserialize<'de> for Character {
        fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
        where
            D: Deserializer<'de>,
        {
            #[derive(Deserialize)]
            #[serde(field_identifier, rename_all = "lowercase")]
            enum Field {
                Name,
                Ac,
                Hp,
            }

            struct CharacterVisitor;

            impl<'de> Visitor<'de> for CharacterVisitor {
                type Value = Character;

                fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                    formatter.write_str("struct Character")
                }

                fn visit_map<V>(self, mut map: V) -> Result<Character, V::Error>
                where
                    V: MapAccess<'de>,
                {
                    let mut name = None;
                    let mut ac = None;
                    let mut hp = None;

                    while let Some(key) = map.next_key()? {
                        match key {
                            Field::Name => {
                                if name.is_some() {
                                    return Err(de::Error::duplicate_field("name"));
                                }
                                name = Some(map.next_value()?);
                            }
                            Field::Ac => {
                                if ac.is_some() {
                                    return Err(de::Error::duplicate_field("ac"));
                                }
                                ac = Some(map.next_value()?);
                            }
                            Field::Hp => {
                                if hp.is_some() {
                                    return Err(de::Error::duplicate_field("hp"));
                                }
                                hp = Some(map.next_value()?);
                            }
                        }
                    }

                    let name = name.ok_or_else(|| de::Error::missing_field("name"))?;
                    let ac = ac.ok_or_else(|| de::Error::missing_field("ac"))?;
                    let hp: u16 = hp.ok_or_else(|| de::Error::missing_field("hp"))?;

                    Ok(Character {
                        name,
                        ac,
                        current: hp,
                        max: hp,
                        temp: 0,
                    })
                }
            }

            const FIELDS: &[&str] = &["name", "ac", "hp"];
            deserializer.deserialize_struct("Character", FIELDS, CharacterVisitor)
        }
    }
}

fn main() {
    let json = r#"{
        "name": "Henry",
        "ac": 16,
        "hp": 54
    }"#;

    // Approach 1: Using a helper struct (simplest, recommended)
    println!("=== Approach 1: Helper struct + From ===");
    let raw: CharacterRaw = serde_json::from_str(json).unwrap();
    let character: Character = raw.into();
    println!("{:#?}", character);

    // Approach 2: Custom Deserialize impl (no helper struct at call site)
    println!("\n=== Approach 2: Custom Deserialize impl ===");
    let character: single_field_approach::Character = serde_json::from_str(json).unwrap();
    println!("{:#?}", character);
}
"
}
