  "main.rs": "use std::io::Write;
use std::process::Command;

fn main() {
    // The Python script is embedded into the binary at compile time.
    let script_contents = include_str!("../src/python/script.py");

    // Write the embedded script to a temporary file so we can invoke the
    // Python interpreter on it.  This avoids the need to know an install-
    // time filesystem path – the script travels *inside* the binary.
    let mut tmp = tempfile().expect("failed to create temporary file");
    tmp.write_all(script_contents.as_bytes())
        .expect("failed to write script to temporary file");
    let tmp_path = tmp.path.clone();
    // Flush & keep the file alive (we still hold `tmp`) so Python can read it.
    tmp.file.sync_all().expect("failed to sync temporary file");

    let status = Command::new("python3")
        .arg(&tmp_path)
        .status();

    // Clean up the temporary file (best-effort).
    let _ = std::fs::remove_file(&tmp_path);

    match status {
        Ok(s) => {
            if !s.success() {
                std::process::exit(s.code().unwrap_or(1));
            }
        }
        Err(e) => {
            // Fall back to `python` if `python3` is not found.
            if e.kind() == std::io::ErrorKind::NotFound {
                // Re-create the temp file for the fallback attempt.
                let mut tmp2 = tempfile().expect("failed to create temporary file");
                tmp2.write_all(script_contents.as_bytes())
                    .expect("failed to write script to temporary file");
                let tmp2_path = tmp2.path.clone();
                tmp2.file.sync_all().expect("failed to sync temporary file");

                let status2 = Command::new("python")
                    .arg(&tmp2_path)
                    .status();

                let _ = std::fs::remove_file(&tmp2_path);

                match status2 {
                    Ok(s) => {
                        if !s.success() {
                            std::process::exit(s.code().unwrap_or(1));
                        }
                    }
                    Err(e2) => {
                        eprintln!("Error: could not find a Python interpreter: {e2}");
                        std::process::exit(1);
                    }
                }
            } else {
                eprintln!("Error running python3: {e}");
                std::process::exit(1);
            }
        }
    }
}

// ---------------- Minimal temp-file helper (no external crate) ----------------

struct TempFile {
    path: std::path::PathBuf,
    file: std::fs::File,
}

impl Write for TempFile {
    fn write(&mut self, buf: &[u8]) -> std::io::Result<usize> {
        self.file.write(buf)
    }
    fn flush(&mut self) -> std::io::Result<()> {
        self.file.flush()
    }
}

fn tempfile() -> std::io::Result<TempFile> {
    let mut dir = std::env::temp_dir();
    let unique_name = format!(
        "rust_program_{}.py",
        std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap_or_default()
            .as_nanos()
    );
    dir.push(unique_name);
    let file = std::fs::File::create(&dir)?;
    Ok(TempFile {
        path: dir,
        file,
    })
}
"
}
```

### How it works

1. **Embedding the script** – `include_str!("../src/python/script.py")` bakes the contents of `src/python/script.py` into the compiled binary at compile time. After `cargo install`, the binary is completely self-contained; no separate `.py` file needs to be distributed.

2. **Running the script** – At runtime the program writes the embedded source to a temporary `.py` file and invokes `python3` (falling back to `python`) on it via `std::process::Command`. The temp file is cleaned up afterwards.

3. **User experience** – The user simply runs `cargo install rust-program` and then `rust-program`. They never see or need to know about `script.py`; they only need a Python interpreter on their `PATH`.

### To test

Create the following layout and run `cargo run`:

```
rust-program/
├── Cargo.toml
└── src/
    ├── main.rs
    └── python/
        └── script.py   ← put any Python code here
```

