/// This lets LLVM emit optimal code for every target (including SIMD on x86-64
/// and aarch64) without any manual `unsafe` pointer work.
///
/// The approach is valid because:
/// * We only need the bytes of each pixel to stay in their original relative
///   order inside the pixel – and a `u32` reverse does exactly that.
/// * Alignment: `align_to_mut` handles the (unlikely) unaligned prefix/suffix
///   for us, but in practice a pixel buffer handed out by any allocator or
///   image library will already be 4-byte aligned.
fn flip_line(line_bytes: &mut [u8]) {
    assert_eq!(
        line_bytes.len() % BYTES_PER_PIXEL,
        0,
        "line length must be a multiple of BYTES_PER_PIXEL"
    );

    // SAFETY: we are reinterpreting groups of 4 u8 as u32.
    // `align_to_mut` returns (prefix, middle, suffix).  For a 4-byte-aligned
    // buffer the prefix and suffix will be empty and `middle` covers everything.
    // If the buffer happens to be unaligned we fall back to the byte-swap path
    // for the prefix/suffix bytes (which will be empty in any realistic case).
    let (prefix, middle, suffix) = unsafe { line_bytes.align_to_mut::<u32>() };

    // Fast path – the whole slice is nicely aligned (expected case).
    if prefix.is_empty() && suffix.is_empty() {
