            vec![x]
        })
        .collect();

    let answers: Vec<f32> = inputs
        .iter()
        .map(|input| {
            let x = input[0];
            x.abs().sqrt() + 1.0 + x * x  // target function
        })
        .collect();

    // Create the genetic programming codex (defines how trees are created and evolved)
    let codex = TreeCodex::regression(1, store)
        .set_depth(5);

