#[derive(Props, Clone, PartialEq, Debug)]
struct PointProps {
    x: f64,
    y: f64,
    #[props(default = 8.0)]
    r: f64,
    #[props(default = true)]
    draggable: bool,
    #[props(default = "blue".to_string())]
    color: String,
