/// A draggable SVG circle.
///
/// When the user presses the mouse button on this circle, it enters a
/// "dragged" local state. While dragged it reads the shared `DragState`
/// context (mouse position updated by `DragProvider`) and moves itself
/// accordingly. Because `DragProvider` captures mousemove on the whole
/// wrapper, the drag continues even when the cursor leaves the small
/// circle – solving the "naive implementation" problem described in the
/// task.
#[component]
fn Point(props: PointProps) -> Element {
    let mut coords = use_signal(|| ElementPoint::new(props.x, props.y));
    let mut local_dragged = use_signal(|| false);
    let drag_state = use_context::<DragState>();
    let mouse_coords = drag_state.mouse_position;
    let mouse_dragged = drag_state.is_dragged;

    // Reactive: whenever the signals we read here change, this component
    // re-runs – but only *this* component, not the entire tree.
    if *local_dragged.read() {
        // If the global mouse button was released, stop dragging.
        if !*mouse_dragged.read() {
            local_dragged.set(false);
        } else {
            let mp = *mouse_coords.read();
            let current = *coords.read();
            if mp.x != current.x || mp.y != current.y {
                coords.set(mp);
            }
        }
    }

    let color = props.color.clone();

    rsx! {
