    state: u64,
}

impl ConstRng {
    const fn new(seed: u64) -> Self {
        // Ensure state is never zero (xorshift requirement)
        let state = if seed == 0 { 0xDEADBEEFCAFEBABE } else { seed };
        Self { state }
