use nix::sys::mman::{mmap_anonymous, shm_open, shm_unlink, MapFlags, ProtFlags};
use nix::sys::stat::Mode;
use nix::unistd::{close, ftruncate};
use std::io::{self, Write};
use std::num::NonZeroUsize;
use std::os::unix::io::AsRawFd;
use std::time::{Duration, Instant};

/// Query the terminal's pixel dimensions via the TIOCGWINSZ ioctl.
fn terminal_size_pixels() -> (u32, u32) {
    use std::mem::MaybeUninit;

    #[repr(C)]
    struct Winsize {
        ws_row: u16,
        ws_col: u16,
        ws_xpixel: u16,
        ws_ypixel: u16,
    }

    unsafe {
        let mut ws = MaybeUninit::<Winsize>::uninit();
        // TIOCGWINSZ = 0x5413 on Linux
        let ret = libc::ioctl(libc::STDOUT_FILENO, 0x5413, ws.as_mut_ptr());
        if ret == 0 {
            let ws = ws.assume_init();
            if ws.ws_xpixel > 0 && ws.ws_ypixel > 0 {
                return (ws.ws_xpixel as u32, ws.ws_ypixel as u32);
            }
        }
    }
    // Fallback
    (640, 480)
}

fn main() {
    let stdout = io::stdout();
    let mut handle = stdout.lock();

    let (width, height) = terminal_size_pixels();
    let width = width as usize;
    let height = height as usize;
    let num_pixels = width * height;
    let data_size = num_pixels * 3; // RGB, f=24

    // ── Create a POSIX shared-memory object ──────────────────────────────
    let shm_name = "/kitty_shm_animation";

    // Clean up any previous leftover
    let _ = shm_unlink(shm_name);

    let shm_fd = shm_open(
        shm_name,
        OFlag::O_CREAT | OFlag::O_RDWR,
        Mode::S_IRUSR | Mode::S_IWUSR,
    )
    .expect("shm_open failed");

    ftruncate(&shm_fd, data_size as i64).expect("ftruncate failed");

    // mmap the shared memory so we can write pixels into it directly
    let shm_ptr = unsafe {
        mmap_anonymous(
            None,
            NonZeroUsize::new(1).unwrap(), // placeholder, we won't use this
            ProtFlags::PROT_READ | ProtFlags::PROT_WRITE,
            MapFlags::MAP_SHARED,
        )
        .ok(); // we actually need the fd-backed version, see below

        libc::mmap(
            std::ptr::null_mut(),
            data_size,
            libc::PROT_READ | libc::PROT_WRITE,
            libc::MAP_SHARED,
            shm_fd.as_raw_fd(),
            0,
        )
    };

    if shm_ptr == libc::MAP_FAILED {
        panic!("mmap failed");
    }

    let buf: &mut [u8] =
        unsafe { std::slice::from_raw_parts_mut(shm_ptr as *mut u8, data_size) };

    // We will reuse the same image id so Kitty replaces the previous frame.
    let image_id: u32 = 42;

    // Hide the cursor and clear the screen once
    write!(handle, "\x1b[?25l\x1b[2J").unwrap();

    let target_frame_time = Duration::from_secs_f64(1.0 / 60.0);
    let mut time: f32 = 0.0;
    let mut first_frame = true;

    // ── Main loop ────────────────────────────────────────────────────────
    loop {
        let frame_start = Instant::now();

        // Generate animated RGB gradient directly into the shared memory buffer
        let inv_w = std::f32::consts::PI / width as f32;
        let inv_h = std::f32::consts::PI / height as f32;
        let time_r = time;
        let time_g = time * 1.3;
        let time_b = time * 0.7;

        let mut offset = 0usize;
        for y in 0..height {
            let fy = y as f32 * inv_h;
            let sin_g_base = (fy + time_g).sin() * 0.5 + 0.5;
            let g_val = (sin_g_base * 255.0) as u8;
            for x in 0..width {
                let fx = x as f32 * inv_w;
                let r = ((fx + time_r).sin() * 0.5 + 0.5) * 255.0;
                let b = ((fx + fy + time_b).sin() * 0.5 + 0.5) * 255.0;
                buf[offset] = r as u8;
                buf[offset + 1] = g_val;
                buf[offset + 2] = b as u8;
                offset += 3;
            }
        }

        // Move cursor home
        write!(handle, "\x1b[H").unwrap();

        // Transmit the frame via the shared memory path.
        // t=s  → shared memory transmission
        // The payload is the name of the shm object (without leading slash per spec,
        // but Kitty actually expects the full path that shm_open would resolve to).
        // Kitty expects the shm name exactly as passed to shm_open (with the slash).
        //
        // On first frame we use a=T (transmit and display). On subsequent frames
