            .unwrap();
            first_frame = false;
        } else {
            // For subsequent frames, we re-transmit with the same image id.
            // Using a=T,t=s tells Kitty to re-read the shm.
            write!(
                handle,
                "\x1b_Ga=T,t=s,f=24,s={},v={},i={},q=2;{}\x1b\\",
                width, height, image_id, shm_name
            )
            .unwrap();
        }

        handle.flush().unwrap();

        time += 0.05;

        // Frame rate limiting
        let elapsed = frame_start.elapsed();
        if elapsed < target_frame_time {
            std::thread::sleep(target_frame_time - elapsed);
        }
    }

    // Cleanup (unreachable in this loop, but good practice)
    #[allow(unreachable_code)]
    {
        unsafe {
            libc::munmap(shm_ptr, data_size);
        }
        let _ = close(shm_fd.as_raw_fd());
        let _ = shm_unlink(shm_name);
    }
