async fn get_oauth_token(
    http: &Client,
    tenant_id: &str,
    client_id: &str,
    client_secret: &str,
) -> Result<String, Box<dyn std::error::Error>> {
    let token_url = format!(
        "https://login.microsoftonline.com/{}/oauth2/v2.0/token",
        tenant_id
    );
    let params = TokenRequest {
        grant_type: "client_credentials",
        client_id,
        client_secret,
        scope: "https://storage.azure.com/.default",
    };
    let response = http.post(&token_url).form(&params).send().await?;

    let status = response.status();
    if !status.is_success() {
        let body_text = response
            .text()
            .await
            .unwrap_or_else(|e| format!("Failed to read error body: {e}"));
        return Err(
            format!("token endpoint returned non-success status: {status}, body: {body_text}")
                .into(),
        );
    }

    let body_text = response.text().await?;
    match serde_json::from_str::<TokenResponse>(&body_text) {
        Ok(tr) => Ok(tr.access_token),
        Err(e) => Err(format!(
            "Failed to decode token response. Error: {e}. Raw body: {body_text}"
        )
        .into()),
    }
}

// ---------------------------------------------------------------------------
// Core download logic
// ---------------------------------------------------------------------------

/// List ALL blob names under `prefix` first, then download them all at once
/// with high concurrency using `futures::stream::buffer_unordered`.
///
/// Key differences from the original Rust code:
///
/// 1. We collect **all** blob names across all listing pages **before**
///    starting any downloads. The original code downloaded per-page which
///    serialised listing → download → listing → download.
///
/// 2. We use `buffer_unordered(concurrency)` with a high concurrency limit
///    (matching `Environment.ProcessorCount` from C# or higher). The C#
///    `Parallel.ForEachAsync` with `MaxDegreeOfParallelism = ProcessorCount`
///    still ends up with many in-flight IO tasks because of async/await;
///    the Rust equivalent needs the same.
///
/// 3. The `ContainerClient` / `BlobClient` from the Azure SDK internally
///    creates a new `reqwest::Client` per service client, which already
///    pools connections. So connection reuse is handled.
async fn list_and_download(
    container_client: &ContainerClient,
    prefix: &str,
    concurrency: usize,
) -> Vec<TradeData> {
    // ---- Step 1: List all blob names ----
    let mut blob_names: Vec<String> = Vec::new();
    let mut stream = container_client
        .list_blobs()
        .prefix(prefix.to_string())
        .into_stream();

    while let Some(response) = stream.next().await {
        match response {
            Ok(resp) => {
                for blob in resp.blobs.blobs() {
                    if blob.name.ends_with(".json") {
                        blob_names.push(blob.name.clone());
                    }
                }
            }
            Err(e) => {
                eprintln!("[WARN] Error listing blobs with prefix {prefix}: {e}");
            }
        }
    }

    println!(
        "[LOG] Listed {} blobs under prefix '{}'",
        blob_names.len(),
        prefix
    );

    // ---- Step 2: Download all blobs concurrently ----
    let container_client = container_client.clone();
    let trades: Vec<TradeData> = futures::stream::iter(blob_names.into_iter().map(move |name| {
        let cc = container_client.clone();
        async move {
            let blob_client = cc.blob_client(&name);
            match blob_client.get_content().await {
                Ok(data) => match serde_json::from_slice::<TradeData>(&data) {
                    Ok(trade) => Some(trade),
                    Err(e) => {
                        eprintln!("[WARN] JSON parse error for {name}: {e}");
                        None
                    }
                },
                Err(e) => {
                    eprintln!("[WARN] Download error for {name}: {e}");
                    None
                }
            }
        }
    }))
    .buffer_unordered(concurrency)
    .filter_map(|x| async { x })
    .collect()
    .await;

    trades
}

// ---------------------------------------------------------------------------
// Public entry point
// ---------------------------------------------------------------------------
pub async fn fetch_trades_from_azure() -> Result<Vec<TradeData>, String> {
    let total_start = Instant::now();

    // Load .env if present (silently ignore if missing)
    let _ = dotenvy::dotenv();

    let tenant_id = env::var("AZURE_TENANT_ID").map_err(|e| format!("AZURE_TENANT_ID: {e}"))?;
    let client_id = env::var("AZURE_CLIENT_ID").map_err(|e| format!("AZURE_CLIENT_ID: {e}"))?;
    let client_secret =
        env::var("AZURE_CLIENT_SECRET").map_err(|e| format!("AZURE_CLIENT_SECRET: {e}"))?;
    let storage_account =
        env::var("AZURE_ACCOUNT_NAME").map_err(|e| format!("AZURE_ACCOUNT_NAME: {e}"))?;
    let container_name =
        env::var("AZURE_CONTAINER_NAME").map_err(|e| format!("AZURE_CONTAINER_NAME: {e}"))?;

    // Prefixes – comma-separated list in a single env var, or individual vars.
    // Supports both AZURE_PREFIXES="pfx1,pfx2" and individual AZURE_PREFIX_OPT / AZURE_PREFIX_FUT.
    let prefixes: Vec<String> = if let Ok(raw) = env::var("AZURE_PREFIXES") {
        raw.split(',')
            .map(|s| s.trim().to_string())
            .filter(|s| !s.is_empty())
            .collect()
    } else {
        let mut v = Vec::new();
        if let Ok(p) = env::var("AZURE_PREFIX_OPT") {
            v.push(p);
        }
        if let Ok(p) = env::var("AZURE_PREFIX_FUT") {
            v.push(p);
        }
        v
    };

    if prefixes.is_empty() {
        return Err("No prefixes configured (set AZURE_PREFIXES or AZURE_PREFIX_OPT / AZURE_PREFIX_FUT)".into());
    }

    // --- Auth ---
    let auth_start = Instant::now();
    println!("[LOG] Authenticating...");
    // Build a shared reqwest client for the token request
    let http = Client::builder()
        .build()
        .map_err(|e| format!("reqwest client build: {e}"))?;
    let token = get_oauth_token(&http, &tenant_id, &client_id, &client_secret)
        .await
        .map_err(|e| e.to_string())?;
    println!(
        "[LOG] Auth took {:.2}s",
        auth_start.elapsed().as_secs_f64()
    );

    // --- Build Azure SDK client ---
    let credentials = StorageCredentials::bearer_token(token);
    let blob_service = BlobServiceClient::new(&storage_account, credentials);
    let container_client = Arc::new(blob_service.container_client(&container_name));

    // High concurrency: at least num_cpus * 4, or 64, whichever is larger.
    // The C# code uses `Environment.ProcessorCount` but because these are IO
    // tasks (not CPU), going higher is fine and matches what the .NET thread
    // pool actually does under the covers.
    let concurrency = std::thread::available_parallelism()
        .map(|n| n.get())
        .unwrap_or(8)
        .max(8)
        * 8;
    let concurrency = concurrency.max(64); // at least 64 in-flight downloads
    println!("[LOG] Download concurrency: {concurrency}");

    // --- List & download all prefixes concurrently ---
    let download_start = Instant::now();
    let mut handles = Vec::new();
    for prefix in prefixes {
        let cc = Arc::clone(&container_client);
        handles.push(tokio::spawn(async move {
            list_and_download(&cc, &prefix, concurrency).await
        }));
    }

    let mut all_trades: Vec<TradeData> = Vec::new();
    for handle in handles {
        match handle.await {
            Ok(trades) => all_trades.extend(trades),
            Err(e) => eprintln!("[WARN] Task join error: {e}"),
        }
    }
    println!(
        "[LOG] Download phase took {:.2}s",
        download_start.elapsed().as_secs_f64()
    );

    println!(
        "[LOG] Total: {} trades in {:.2}s",
        all_trades.len(),
        total_start.elapsed().as_secs_f64()
    );

    Ok(all_trades)
}

// ---------------------------------------------------------------------------
// main
// ---------------------------------------------------------------------------
#[tokio::main]
async fn main() {
    match fetch_trades_from_azure().await {
        Ok(trades) => {
            println!("Successfully fetched {} trades.", trades.len());
        }
        Err(e) => {
            eprintln!("Error: {e}");
            std::process::exit(1);
        }
    }
}
"
}
