    // We can construct an n x k matrix where every row is `mean`.
    let ones_column = DMatrix::from_element(n, 1, 1.0); // n x 1 column of ones
    let mean_matrix = &ones_column * &mean; // (n x 1) * (1 x k) = n x k
    let centered = &matrix - &mean_matrix;

    println!("Centered matrix (approach 1 - outer product broadcast):");
    println!("{}", centered);

    // --- Approach 2: Subtract mean from each row using an iterator ---
