use std::sync::Arc;
use tokio::time::{sleep, Duration};

/// Simulates a queue handler that runs alongside the HTTP server.
/// It checks `running` to know when to stop gracefully.
async fn queue_handler_loop(running: Arc<AtomicBool>) {
    info!("Queue handler started.");
    let mut iteration = 0u64;
    while running.load(Ordering::SeqCst) {
        iteration += 1;
        // Simulate processing a message from a queue
        if iteration % 5 == 0 {
            info!("Queue handler: processed batch (iteration {})", iteration);
        }
        // Sleep a bit to simulate waiting for new messages
        sleep(Duration::from_millis(500)).await;
    }
    // Graceful shutdown: finish any pending work here
    info!("Queue handler: finishing pending work before shutdown...");
    sleep(Duration::from_millis(200)).await;
    info!("Queue handler stopped gracefully.");
}

async fn health() -> HttpResponse {
    HttpResponse::Ok().json(serde_json::json!({"status": "ok"}))
}

async fn index() -> HttpResponse {
    HttpResponse::Ok().body("Hello! Try GET /health or press Ctrl+C to test graceful shutdown.")
}

#[actix_web::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Initialize logger
    env_logger::Builder::from_env(env_logger::Env::default().default_filter_or("info")).init();

    info!("Starting the application.");

    // Shared flag so we can signal the queue handler to stop
    let running = Arc::new(AtomicBool::new(true));

    // Create the Actix Web server and obtain its handle for programmatic shutdown
    let server = HttpServer::new(move || {
        App::new()
            .wrap(middleware::Logger::default())
            .route("/", web::get().to(index))
            .route("/health", web::get().to(health))
    })
    .bind("127.0.0.1:8080")?
    .disable_signals()   // We handle signals ourselves
    .shutdown_timeout(10) // seconds to wait for in-flight requests
    .run();

    let server_handle = server.handle();

    // Spawn the HTTP server as a task
    let server_task = tokio::spawn(server);

    // Spawn the queue handler as a task
    let queue_running = running.clone();
    let queue_task = tokio::spawn(queue_handler_loop(queue_running));

    info!("Application is running. Press Ctrl+C to initiate graceful shutdown.");

    // Wait for Ctrl+C
    tokio::signal::ctrl_c().await.expect("Failed to listen for Ctrl+C");
    warn!("Ctrl+C received! Initiating graceful shutdown...");

    // 1. Signal the queue handler to stop
    running.store(false, Ordering::SeqCst);

    // 2. Tell the Actix server to stop gracefully (true = graceful)
    server_handle.stop(true).await;
    info!("HTTP server has stopped.");

    // 3. Wait for the queue handler task to finish
    if let Err(e) = queue_task.await {
        log::error!("Queue handler task panicked: {:?}", e);
    }
    info!("Queue handler task has finished.");

    // 4. Wait for the server task to finish (should already be done)
    if let Err(e) = server_task.await {
        log::error!("Server task error: {:?}", e);
    }

    info!("Application shut down gracefully. No background processes left.");
    Ok(())
}
"
}
