// ---------- Minimal request / response types ----------

pub struct Request {
    pub path: String,
}

#[derive(Debug)]
pub struct Response {
    pub body: String,
}

// ---------- Unified handler storage ----------

type HandlerFn =
    dyn for<'a> Fn(&'a Request) -> BoxFuture<'a, Response> + Send + Sync + 'static;

pub struct Handler(Arc<HandlerFn>);

// ---------- Helper trait that abstracts over sync *and* async fns ----------
//
// The key insight: we do NOT use two blanket `impl From<F> for Handler` blocks
// (which would overlap and also hit the HRTB + opaque-future mismatch).
// Instead we introduce a small helper trait with a GAT-like associated
// future, and provide two marker-guided implementations via a helper
// wrapper so the user never has to name them.

/// Trait implemented for every function that can serve as a handler.
///
/// `F: IntoHandler` means either
///   • `F: Fn(&Request) -> Response`            (sync), or
///   • `F: Fn(&Request) -> impl Future<…>`      (async).
pub trait IntoHandler: Send + Sync + 'static {
    fn into_handler(self) -> Handler;
}

// ---- Async path ----
// We cannot write a single blanket impl that covers both because of
// the HRTB-opaque-future issue. The trick is to require the user's
// async fn to satisfy a *named* trait (`AsyncHandlerFn`) whose sole
// method returns a BoxFuture – and then provide a blanket impl of
// *that* trait for every matching async fn by going through an
// explicit helper function that does the boxing.

/// Object-safe version of an async handler.
pub trait AsyncHandlerFn: Send + Sync + 'static {
    fn call<'a>(&self, req: &'a Request) -> BoxFuture<'a, Response>;
}

/// Blanket: every `Fn(&Request) -> Fut` where `Fut: Future<Output=Response>`
/// implements `AsyncHandlerFn` – the boxing happens here, inside a
/// non-higher-ranked context, which sidesteps the HRTB problem.
impl<F, Fut> AsyncHandlerFn for F
where
    F: Fn(&Request) -> Fut + Send + Sync + 'static,
    Fut: Future<Output = Response> + Send + 'static,
{
    fn call<'a>(&self, req: &'a Request) -> BoxFuture<'a, Response> {
        // We own the future; it is 'static, so promoting to 'a is fine.
        let fut = (self)(req);
        Box::pin(fut)
    }
}

/// Newtype so we can have two non-overlapping `IntoHandler` impls.
pub struct Async<F>(pub F);

impl<F: AsyncHandlerFn> IntoHandler for Async<F> {
    fn into_handler(self) -> Handler {
        Handler(Arc::new(move |req| self.0.call(req)))
    }
}

// ---- Sync path ----

pub struct Sync_<F>(pub F);

impl<F> IntoHandler for Sync_<F>
where
    F: Fn(&Request) -> Response + Send + Sync + 'static,
{
    fn into_handler(self) -> Handler {
        Handler(Arc::new(move |req| {
            let resp = (self.0)(req);
            Box::pin(async move { resp })
        }))
    }
}

