}

// Async impl: F: Fn(&Request) -> Fut
impl<F, Fut> IntoHandler2<AsyncTag> for F
where
    F: Fn(&Request) -> Fut + Send + Sync + 'static,
    Fut: Future<Output = Response> + Send + 'static,
{
    fn into_handler2(self) -> Handler {
        Handler(Arc::new(move |req| {
            let fut = (self)(req);
            Box::pin(fut)
        }))
