name = "async-fn-once-send"
version = "0.1.0"
edition = "2024"

[dependencies]
tokio = { version = "1", features = ["full"] }
",
  "main.rs": "use std::future::Future;
use std::pin::Pin;
use tokio::sync::mpsc;

pub struct Context(i32);

pub enum InnerAsyncEvent {
    DoWithContext {
        block: Box<
            dyn for<'a> FnOnce(
                    &'a mut Context,
                ) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
                + Send,
        >,
    },
}

/// Wraps an async closure that takes `&mut Context` into the boxed
/// FnOnce form required by `InnerAsyncEvent`.
///
/// The key trick: we cannot directly require `AsyncFnOnce` whose
/// `CallOnceFuture` is `Send` on stable Rust, because there is no
/// syntax for that yet. Instead we accept a *regular* generic `F`
/// that already has the right shape:
///
///   for<'a> FnOnce(&'a mut Context) -> Fut<'a>
///
/// where `Fut<'a>: Future<Output = ()> + Send + 'a`.
///
/// At the call-site you simply write an `async move |ctx| { … }`
/// closure – the compiler will unify it with this signature provided
/// the returned future is `Send`.
///
/// Because `F` is `FnOnce`, we need one extra wrapper layer (`Option`
/// + `FnOnce` → `Fn` is the classic trick) so that it fits inside
/// a `Box<dyn FnOnce(…)>`.
pub fn with_context_async<F, Fut>(sender: &mpsc::UnboundedSender<InnerAsyncEvent>, block: F)
where
    F: for<'a> AsyncFnOnce(&'a mut Context) + Send + 'static,
    // We don't actually use `Fut` as a type parameter; see the
    // helper-based approach below.
{
    // Use the helper to convert.
    let _ = sender.send(InnerAsyncEvent::DoWithContext {
        block: into_boxed_fn_once(block),
    });
}

/// The real conversion helper.
///
/// We want to accept any `F` such that calling `f(ctx)` for any
/// lifetime `'a` gives a `Future<Output=()> + Send + 'a`.
///
/// On edition 2024 / Rust 1.85+ `AsyncFnOnce` is stable, but
/// bounding its `CallOnceFuture` as `Send` is not directly
/// expressible with a simple trait bound.  The classic work-around
/// is to introduce a helper trait that encodes the HRTB + Send
/// requirement.
trait AsyncFnOnceSend<'a> {
    type Fut: Future<Output = ()> + Send + 'a;
    fn call(self, ctx: &'a mut Context) -> Self::Fut;
}

impl<'a, F, Fut> AsyncFnOnceSend<'a> for F
where
    F: FnOnce(&'a mut Context) -> Fut,
    Fut: Future<Output = ()> + Send + 'a,
{
    type Fut = Fut;
    fn call(self, ctx: &'a mut Context) -> Fut {
        self(ctx)
    }
}

fn into_boxed_fn_once<F>(
    f: F,
) -> Box<
    dyn for<'a> FnOnce(
            &'a mut Context,
        ) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
        + Send,
>
where
    F: for<'a> AsyncFnOnceSend<'a> + Send + 'static,
{
    Box::new(move |ctx| Box::pin(AsyncFnOnceSend::call(f, ctx)))
}

// ---------------------------------------------------------------------------
// Demo
// ---------------------------------------------------------------------------

#[tokio::main]
async fn main() {
    let (tx, mut rx) = mpsc::unbounded_channel::<InnerAsyncEvent>();

    // ---- Nice ergonomic call-site ----
    with_context_async(&tx, async |ctx: &mut Context| {
        ctx.0 += 1;
        println!("Inside async closure: ctx.0 = {}", ctx.0);
    });

    // You can also construct the event manually with the helper:
    let event = InnerAsyncEvent::DoWithContext {
        block: into_boxed_fn_once(async |ctx: &mut Context| {
            ctx.0 += 100;
            println!("Second closure: ctx.0 = {}", ctx.0);
        }),
    };
    let _ = tx.send(event);

    drop(tx); // close the channel so the receiver loop ends

    // ---- Consumer side (another task / thread) ----
    let handle = tokio::spawn(async move {
        let mut ctx = Context(0);
        while let Some(event) = rx.recv().await {
            match event {
                InnerAsyncEvent::DoWithContext { block } => {
                    block(&mut ctx).await;
                }
            }
        }
        println!("Final ctx.0 = {}", ctx.0);
    });

    handle.await.unwrap();
}
"
}
