    ast::{self, HasName},
    ted,
};

fn main() {
    let examples = vec![
        r#"use vexide::{devices::smart::*, prelude::*};"#,
        r#"use vexide::devices::*;"#,
        r#"use vexide::devices::smart::Motor;"#,
        r#"use vexide::{devices, fs};"#,
        r#"use vexide::devices;"#,
        r#"use vexide::devices::{smart, adi};"#,
        r#"use {vexide::{devices, fs}, core::borrow};"#,
        r#"use vexide::devices::smart::{Motor, Sensor};"#,
        r#"use vexide::{devices::smart::{Motor, Sensor}, prelude::*};"#,
        r#"use vexide::{devices::{smart, adi}, fs};"#,
        r#"use vexide::devices::adi::AdiPort;"#,
        r#"use vexide::{devices::adi::AdiPort, devices::smart::Motor};"#,
    ];

    for example in &examples {
        println!("Input:  {}", example);
        let result = rewrite_source(example);
        println!("Output: {}", result.trim());
        println!();
    }
}

fn rewrite_source(source: &str) -> String {
    let parse = SourceFile::parse(source, ra_ap_syntax::Edition::Edition2021);
    let file = parse.tree();
    // Clone the tree so we can mutate it
    let file = file.clone_for_update();

    let use_items: Vec<ast::Use> = file.syntax().descendants().filter_map(ast::Use::cast).collect();

    for use_item in use_items {
        if let Some(tree) = use_item.use_tree() {
            rewrite_use_item(&use_item, &tree);
        }
    }

    file.syntax().to_string()
}

/// Collect all "leaf" imports from a use tree as (full_path_segments, has_star) tuples.
fn collect_leaves(tree: &ast::UseTree, prefix: &[String]) -> Vec<(Vec<String>, bool)> {
    let mut current_prefix = prefix.to_vec();

    if let Some(path) = tree.path() {
        for segment in path_segments(&path) {
            current_prefix.push(segment);
        }
    }

    if let Some(list) = tree.use_tree_list() {
        let mut results = Vec::new();
        for child in list.use_trees() {
            results.extend(collect_leaves(&child, &current_prefix));
        }
        results
    } else if tree.star_token().is_some() {
        vec![(current_prefix, true)]
    } else {
        vec![(current_prefix, false)]
    }
}

fn path_segments(path: &ast::Path) -> Vec<String> {
    let mut segments = Vec::new();
    let mut current = Some(path.clone());
    // ast::Path is a linked list via .qualifier()
    let mut chain = Vec::new();
    while let Some(p) = current {
        if let Some(seg) = p.segment() {
            chain.push(seg.to_string());
        }
        current = p.qualifier();
    }
    chain.reverse();
    segments.extend(chain);
    segments
}

/// Rewrite a single use item. We collect all leaf imports, rewrite their paths
/// (removing `devices` after `vexide`), then reconstruct the use statement.
fn rewrite_use_item(use_item: &ast::Use, tree: &ast::UseTree) {
    let leaves = collect_leaves(tree, &[]);

    // Rewrite each leaf path: if it starts with vexide::devices, remove "devices"
    let rewritten: Vec<(Vec<String>, bool)> = leaves
        .into_iter()
        .map(|(segs, star)| {
            let new_segs = rewrite_path_segments(segs);
            (new_segs, star)
        })
        .collect();

    // Deduplicate
    let mut deduped = Vec::new();
    for item in &rewritten {
        if !deduped.contains(item) {
            deduped.push(item.clone());
        }
    }

    // Reconstruct the use statement text
    let use_text = build_use_statement(&deduped, has_leading_brace(tree));

    // Parse the new use statement and replace
    let new_parse = SourceFile::parse(&use_text, ra_ap_syntax::Edition::Edition2021);
    let new_file = new_parse.tree();
    let new_use_items: Vec<ast::Use> = new_file
        .syntax()
        .descendants()
        .filter_map(ast::Use::cast)
        .collect();

    if let Some(new_use) = new_use_items.first() {
        // Replace the old use item's syntax node with the new one
        let new_node = new_use.syntax().clone_for_update();
        ted::replace(use_item.syntax(), new_node);
    }
}

/// Check if the top-level use tree starts with a brace (e.g., `use {vexide::..., core::...};`)
fn has_leading_brace(tree: &ast::UseTree) -> bool {
    tree.path().is_none() && tree.use_tree_list().is_some()
}

fn rewrite_path_segments(segs: Vec<String>) -> Vec<String> {
    if segs.len() >= 2 && segs[0] == "vexide" && segs[1] == "devices" {
        // Remove "devices" — flatten vexide::devices::X to vexide::X
        // But if it's just vexide::devices with nothing after, we drop it entirely
        // (importing the module itself — after flattening, the items are directly under vexide)
        let mut new_segs = vec!["vexide".to_string()];
        new_segs.extend(segs.into_iter().skip(2));
        if new_segs.len() == 1 {
            // "vexide::devices" alone becomes just "vexide"
            // We keep it as just ["vexide"]
        }
        new_segs
    } else {
        segs
    }
}

/// Build a `use` statement string from a list of (path_segments, is_star) leaves.
/// If `leading_brace` is true, the original had a top-level brace grouping disparate crates.
fn build_use_statement(leaves: &[(Vec<String>, bool)], leading_brace: bool) -> String {
    // Group leaves into a tree structure for nice output
    let tree = build_tree(leaves);

    if leading_brace && tree.len() > 1 {
        // Multiple top-level entries: use {a::b, c::d};
        let parts: Vec<String> = tree.iter().map(|t| render_tree_node(t)).collect();
        format!("use {{{}}};\n", parts.join(", "))
    } else if tree.len() == 1 {
        format!("use {};\n", render_tree_node(&tree[0]))
    } else {
        // Multiple top-level but no leading brace — shouldn't normally happen from a single use,
        // but handle gracefully
        let parts: Vec<String> = tree.iter().map(|t| render_tree_node(t)).collect();
        format!("use {{{}}};\n", parts.join(", "))
    }
}

#[derive(Debug, Clone)]
enum UseTreeNode {
    Leaf {
        star: bool,
    },
    Branch {
        children: Vec<(String, UseTreeNode)>,
    },
}

/// Build a hierarchical tree from flat leaf paths, merging common prefixes.
fn build_tree(leaves: &[(Vec<String>, bool)]) -> Vec<(String, UseTreeNode)> {
    // Group by first segment
    let mut groups: Vec<(String, Vec<(Vec<String>, bool)>)> = Vec::new();

    for (segs, star) in leaves {
        if segs.is_empty() {
            continue;
        }
        let first = &segs[0];
        let rest: Vec<String> = segs[1..].to_vec();
        if let Some(group) = groups.iter_mut().find(|(k, _)| k == first) {
            group.1.push((rest, *star));
        } else {
            groups.push((first.clone(), vec![(rest, *star)]));
        }
    }

    let mut result = Vec::new();
    for (key, sub_leaves) in groups {
        let node = build_subtree(&sub_leaves);
        result.push((key, node));
    }
    result
}

fn build_subtree(leaves: &[(Vec<String>, bool)]) -> UseTreeNode {
    // Check if any leaf is empty (meaning this node is a direct import)
    let has_direct: Vec<_> = leaves.iter().filter(|(s, _)| s.is_empty()).collect();
    let sub_leaves: Vec<_> = leaves.iter().filter(|(s, _)| !s.is_empty()).cloned().collect();

    if sub_leaves.is_empty() {
        // All leaves terminate here
        let star = has_direct.iter().any(|(_, s)| *s);
        UseTreeNode::Leaf { star }
    } else {
        let mut children = build_tree(&sub_leaves);
        // If there's also a direct import of this node, add a "self" entry
        if !has_direct.is_empty() {
            let star = has_direct.iter().any(|(_, s)| *s);
            // Insert self at beginning
            children.insert(0, ("self".to_string(), UseTreeNode::Leaf { star }));
        }
        UseTreeNode::Branch { children }
    }
}

fn render_tree_node(node: &(String, UseTreeNode)) -> String {
    let (name, tree) = node;
    match tree {
        UseTreeNode::Leaf { star: true } => format!("{}::*", name),
        UseTreeNode::Leaf { star: false } => name.clone(),
        UseTreeNode::Branch { children } => {
            if children.len() == 1 {
                // Collapse single-child branches: a::{b} -> a::b
                let child_rendered = render_tree_node(&children[0]);
                format!("{}::{}", name, child_rendered)
            } else {
                let parts: Vec<String> = children.iter().map(|c| render_tree_node(c)).collect();
                format!("{}::{{{}}}", name, parts.join(", "))
            }
        }
    }
}
"
}
```

This solution works by:

1. **Collecting all leaf imports** from the use tree into flat `(path_segments, has_star)` tuples via depth-first traversal
2. **Rewriting paths** — any path starting with `vexide::devices` has the `devices` segment removed, flattening it to `vexide::...`
3. **Rebuilding a tree structure** from the rewritten flat paths, merging common prefixes back into nested `use` groups
4. **Rendering** the tree back into a `use` statement string
5. **Replacing** the original syntax node using `ted::replace`

This approach avoids the edge-case nightmare of trying to do in-place tree surgery. Instead, it normalizes to flat paths, transforms them, and reconstructs. The reconstruction handles:
- Single imports (`use vexide::smart::Motor;`)
- Glob imports (`use vexide::*;`)
- Nested groups (`use vexide::{smart::*, prelude::*};`)
- Leading-brace multi-crate imports (`use {vexide::..., core::...};`)
- Deduplication when flattening causes collisions

