  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll, RawWaker, RawWakerVTable, Waker};

/// Result of trying to poll a future exactly once.
enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// Create a no-op waker.  We only need it to call `poll` once; we don't
/// actually need wake-up notifications because we will either use the
/// value immediately or hand the future off to the Tokio runtime.
fn noop_waker() -> Waker {
    fn noop(_: *const ()) {}
    fn clone(p: *const ()) -> RawWaker {
        RawWaker::new(p, &VTABLE)
    }
    static VTABLE: RawWakerVTable =
        RawWakerVTable::new(clone, noop, noop, noop);
    unsafe { Waker::from_raw(RawWaker::new(std::ptr::null(), &VTABLE)) }
}

/// Try to poll a pinned future exactly once using a no-op waker.
///
/// * `Ready(x)` – the future completed synchronously.
/// * `Pending`  – the future is not yet ready; the caller still owns it
///   and can, for example, spawn it on the Tokio runtime.
fn try_poll<X>(future: Pin<&mut dyn Future<Output = X>>) -> TryPollResult<X> {
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);
    match future.poll(&mut cx) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

// ---------------------------------------------------------------------------
// Demo helpers
// ---------------------------------------------------------------------------

/// A future that completes immediately (never yields).
async fn instant_future() -> &'static str {
    "hello from instant future"
}

/// A future that must yield (uses tokio::time::sleep).
async fn slow_future() -> &'static str {
    tokio::time::sleep(std::time::Duration::from_millis(50)).await;
    "hello from slow future"
}

// ---------------------------------------------------------------------------
// Demonstration
// ---------------------------------------------------------------------------

/// This function is *not* async, but it is called from an async context
/// (i.e. inside a Tokio runtime so `tokio::spawn` is available).
fn handle_future(mut fut: Pin<Box<dyn Future<Output = &'static str> + Send>>) {
    // Poll once – if it completes synchronously we use the value right away.
    // We need to re-pin after moving into try_poll, but because we already
    // have a Pin<Box<…>> we can just use Pin::as_mut().
    match try_poll(fut.as_mut()) {
        TryPollResult::Ready(value) => {
            println!("[sync path]  Future was ready immediately: {value}");
        }
        TryPollResult::Pending => {
            println!("[sync path]  Future is pending – spawning a task …");
            // Hand the future to the Tokio runtime.
            tokio::spawn(async move {
                let value = fut.await;
                println!("[async task] Future completed: {value}");
            });
        }
    }
}

#[tokio::main]
async fn main() {
    println!("=== Demo 1: future that completes without yielding ===");
    let fut = Box::pin(instant_future());
    handle_future(fut);

    println!();
    println!("=== Demo 2: future that must yield ===");
    let fut = Box::pin(slow_future());
    handle_future(fut);

    // Give the spawned task time to finish.
    tokio::time::sleep(std::time::Duration::from_millis(200)).await;
    println!("\nDone.");
}
