  "main.rs": "use axum::{
    Router,
    extract::{FromRequest, FromRequestParts, Request, State},
    http::{StatusCode, header::HeaderName, request::Parts},
    response::{IntoResponse, Json as AxumJson},
    routing::post,
};
use serde::{Deserialize, Serialize, de::DeserializeOwned};
use std::sync::Arc;
use validator::Validate;

// ---------------------------------------------------------------------------
// Shared state
// ---------------------------------------------------------------------------
type SharedState = Arc<AppState>;

#[derive(Debug)]
struct AppState {
    // put real fields here
}

// ---------------------------------------------------------------------------
// API error
// ---------------------------------------------------------------------------
#[derive(Debug, Serialize)]
struct APIError {
    status: u16,
    message: String,
}

impl APIError {
    fn invalid_input(msg: &str) -> Self {
        Self {
            status: 400,
            message: msg.to_string(),
        }
    }

    fn bad_request(msg: &str) -> Self {
        Self {
            status: 400,
            message: msg.to_string(),
        }
    }

    fn unauthorized(msg: &str) -> Self {
        Self {
            status: 401,
            message: msg.to_string(),
        }
    }

    fn forbidden(msg: &str) -> Self {
        Self {
            status: 403,
            message: msg.to_string(),
        }
    }
}

impl IntoResponse for APIError {
    fn into_response(self) -> axum::response::Response {
        let status = StatusCode::from_u16(self.status).unwrap_or(StatusCode::INTERNAL_SERVER_ERROR);
        let body = serde_json::json!({ "error": self.message });
        (status, AxumJson(body)).into_response()
    }
}

// ---------------------------------------------------------------------------
// API version extractor (FromRequestParts)
// ---------------------------------------------------------------------------
#[derive(Debug, Clone)]
enum APIVersion {
    V1,
    V2,
}

impl std::fmt::Display for APIVersion {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            APIVersion::V1 => write!(f, "v1"),
            APIVersion::V2 => write!(f, "v2"),
        }
    }
}

impl std::str::FromStr for APIVersion {
    type Err = String;
    fn from_str(s: &str) -> Result<Self, Self::Err> {
        match s.to_lowercase().as_str() {
            "v1" | "1" => Ok(APIVersion::V1),
            "v2" | "2" => Ok(APIVersion::V2),
            other => Err(format!("unknown API version: {other}")),
        }
    }
}

struct ApiVersionHeader(pub APIVersion);

impl<S> FromRequestParts<S> for ApiVersionHeader
where
    S: Send + Sync,
{
    type Rejection = APIError;

    async fn from_request_parts(parts: &mut Parts, _state: &S) -> Result<Self, Self::Rejection> {
        let name = HeaderName::from_static("x-api-version");
        let value = parts
            .headers
            .get(&name)
            .ok_or_else(|| APIError::bad_request("missing X-Api-Version header"))?;

        let s = value
            .to_str()
            .map_err(|_| APIError::bad_request("invalid X-Api-Version header"))?;

        let version: APIVersion = s
            .parse()
            .map_err(|err: String| APIError::bad_request(&err))?;

        Ok(ApiVersionHeader(version))
    }
}

// ---------------------------------------------------------------------------
// AccessClaims extractor (FromRequestParts) – simplified for demo
// ---------------------------------------------------------------------------
#[derive(Debug, Clone)]
struct AccessClaims {
    sub: String,
    role: String,
}

impl AccessClaims {
    fn validate_role_admin(&self) -> Result<(), APIError> {
        if self.role == "admin" {
            Ok(())
        } else {
            Err(APIError::forbidden("admin role required"))
        }
    }
}

impl<S> FromRequestParts<S> for AccessClaims
where
    S: Send + Sync,
{
    type Rejection = APIError;

    async fn from_request_parts(parts: &mut Parts, _state: &S) -> Result<Self, Self::Rejection> {
        // In a real app you would decode a JWT from the Authorization header.
        // For this demo we just read two custom headers.
        let sub = parts
            .headers
            .get("x-user-id")
            .and_then(|v| v.to_str().ok())
            .unwrap_or("anonymous")
            .to_string();

        let role = parts
            .headers
            .get("x-user-role")
            .and_then(|v| v.to_str().ok())
            .unwrap_or("user")
            .to_string();

        if sub == "anonymous" {
            return Err(APIError::unauthorized("missing authentication"));
        }

        Ok(AccessClaims { sub, role })
    }
}

// ---------------------------------------------------------------------------
// ValidatedJson extractor (FromRequest – consumes body)
//
// KEY INSIGHT: To be usable as an Axum handler argument the extractor must
// implement `FromRequest` (not just have a helper `new` method).  Axum
// supports up to **16** extractors in a handler signature, but **at most one
// of them may implement `FromRequest`** (i.e. consume the body).  All the
// others must implement `FromRequestParts`.
//
// The original code only had a `new()` helper but never implemented
// `FromRequest` for `ValidatedJson<T>`, so Axum could not call the
// extractor and the trait bound `Handler<_, _>` was not satisfied.
// ---------------------------------------------------------------------------
struct ValidatedJson<T>(pub T);

impl<T, S> FromRequest<S> for ValidatedJson<T>
where
    T: DeserializeOwned + Validate,
    S: Send + Sync,
{
    type Rejection = APIError;

    async fn from_request(req: Request, state: &S) -> Result<Self, Self::Rejection> {
        // First extract the raw Json<T> using Axum's built-in extractor.
        let axum::extract::Json(payload) =
            axum::extract::Json::<T>::from_request(req, state)
                .await
                .map_err(|e| APIError::invalid_input(&e.to_string()))?;

        // Then run the validator crate validations.
        payload
            .validate()
            .map_err(|e| APIError::invalid_input(&e.to_string()))?;

        Ok(ValidatedJson(payload))
    }
}

// ---------------------------------------------------------------------------
// DTO
// ---------------------------------------------------------------------------
#[derive(Debug, Serialize, Deserialize, Validate)]
struct RevokeUser {
    #[validate(length(min = 6, message = "user_id must be at least 6 characters"))]
    pub user_id: String,
}

// ---------------------------------------------------------------------------
// Handler – now compiles with 4 extractors because:
//   • ApiVersionHeader  -> FromRequestParts
//   • State<SharedState> -> FromRequestParts
//   • AccessClaims      -> FromRequestParts
//   • ValidatedJson     -> FromRequest   (must be LAST)
// ---------------------------------------------------------------------------
async fn revoke_user_handler(
    ApiVersionHeader(api_version): ApiVersionHeader,
    State(state): State<SharedState>,
    access_claims: AccessClaims,
    ValidatedJson(revoke_user): ValidatedJson<RevokeUser>,
) -> Result<impl IntoResponse, APIError> {
    tracing::info!("api version: {}", api_version);

    if access_claims.sub != revoke_user.user_id {
        // only admin can revoke tokens of other users
        access_claims.validate_role_admin()?;
    }

    tracing::info!("revoke_user: {:?}", revoke_user);

    // In a real app: caching::revoke_user_tokens(&revoke_user.user_id, &state).await?;
    let _ = state; // silence unused warning

    Ok((
        StatusCode::OK,
        AxumJson(serde_json::json!({ "revoked": revoke_user.user_id })),
    ))
}

// ---------------------------------------------------------------------------
// Fallback 404
// ---------------------------------------------------------------------------
async fn error_404_handler() -> impl IntoResponse {
    (StatusCode::NOT_FOUND, "not found")
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------
#[tokio::main]
async fn main() {
    tracing_subscriber::fmt::init();

    let state = Arc::new(AppState {});

    let auth_routes = Router::new().route("/revoke-user", post(revoke_user_handler));

    let app = Router::new()
        .nest("/v1/auth", auth_routes.clone())
        .nest("/v2/auth", auth_routes)
        .fallback(error_404_handler)
        .with_state(state);

    let listener = tokio::net::TcpListener::bind("0.0.0.0:3000").await.unwrap();
    tracing::info!("listening on {}", listener.local_addr().unwrap());

    println!("Server running on http://0.0.0.0:3000");
    println!();
    println!("Test with:");
    println!(r#"  curl -X POST http://localhost:3000/v1/auth/revoke-user \"#);
    println!(r#"    -H 'Content-Type: application/json' \"#);
    println!(r#"    -H 'X-Api-Version: v1' \"#);
    println!(r#"    -H 'X-User-Id: user123456' \"#);
    println!(r#"    -H 'X-User-Role: admin' \"#);
    println!(r#"    -d '{"user_id": "user123456"}'"#);
    println!();
    println!("Validation failure (user_id too short):");
    println!(r#"  curl -X POST http://localhost:3000/v1/auth/revoke-user \"#);
    println!(r#"    -H 'Content-Type: application/json' \"#);
    println!(r#"    -H 'X-Api-Version: v1' \"#);
    println!(r#"    -H 'X-User-Id: user123456' \"#);
    println!(r#"    -H 'X-User-Role: admin' \"#);
    println!(r#"    -d '{"user_id": "ab"}'"#);

    axum::serve(listener, app).await.unwrap();
}
"
}
