        let timeout = tick_rate
            .checked_sub(last_tick.elapsed())
            .unwrap_or(Duration::ZERO);

        // `poll` will block for *at most* `timeout` duration.
        // It returns `true` if an event is available, `false` if the timeout expired.
        if event::poll(timeout)? {
            // An event is available — read it (this will NOT block because poll said it's ready).
            let ev = event::read()?;

            match ev {
                Event::Key(key) => {
