                    stdout.flush()?;
                }
                Event::Resize(w, h) => {
                    print!("  Terminal resized to {}x{}\r\n", w, h);
                    stdout.flush()?;
                }
                _ => {}
            }
        }

        // After poll returns (either because an event arrived or the timeout expired),
        // check whether it's time for a tick.
        if last_tick.elapsed() >= tick_rate {
            tick_count += 1;
            print!("Tick #{} (elapsed since start: {}s)\r\n", tick_count, tick_count);
            stdout.flush()?;
            last_tick = Instant::now();
        }
    }

