use std::fmt;

// The borrowed struct we want to deserialize into.
#[derive(Deserialize, Debug)]
struct MyData<'a> {
    data: &'a str,
    more_data: &'a str,
}

/// A self-referential container that owns the JSON `String` and holds
/// the deserialized `MyData` borrowing from it.
///
/// # Safety
///
/// * `source` is pinned (boxed) so its heap allocation never moves.
/// * `parsed` borrows from `source` – we erase the lifetime to `'static`
///   but guarantee that `source` is never mutated and always outlives
///   `parsed` because both live inside the same struct and `source` is
///   listed (and therefore dropped) *after* `parsed` — Rust drops fields
///   in declaration order, so we put `parsed` before `source`.
/// * The struct is `Send` so it can cross a `tokio::spawn` boundary.
struct OwnedMyData {
    // dropped first (borrows from `source`)
    parsed: MyData<'static>,
    // dropped second – the backing allocation
    _source: Box<str>,
}

// SAFETY: The inner `&str` references point into the heap-allocated
// `_source` which is owned and never mutated. This is safe to send
// across threads.
unsafe impl Send for OwnedMyData {}
unsafe impl Sync for OwnedMyData {}

impl fmt::Debug for OwnedMyData {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("OwnedMyData")
            .field("data", &self.parsed.data)
            .field("more_data", &self.parsed.more_data)
            .finish()
    }
}

impl OwnedMyData {
    /// Deserialise the JSON `String` **once**, keeping zero-copy borrows
    /// into the original buffer.
    fn new(json: String) -> Result<Self, serde_json::Error> {
        // Pin the string on the heap so the address is stable.
        let source: Box<str> = json.into_boxed_str();

        // Obtain a reference with the true lifetime of `source`.
        let source_ref: &str = &source;

        // SAFETY: We extend the lifetime to 'static.  This is sound because
        // `source` is heap-pinned inside `Box<str>`, is never mutated, and
        // will not be dropped before `parsed` (field drop order).
        let static_ref: &'static str = unsafe { std::mem::transmute(source_ref) };

        let parsed: MyData<'static> = serde_json::from_str(static_ref)?;

        Ok(OwnedMyData {
            parsed,
            _source: source,
        })
    }

    /// Access the parsed data.
    fn get(&self) -> &MyData<'_> {
        &self.parsed
    }
}

#[tokio::main]
async fn main() {
    // Simulate receiving a JSON payload (e.g. from TCP).
    let incoming: String =
        r#"{"data": "hello world", "more_data": "foo bar baz"}"#.to_owned();

    // Deserialise once – zero copy, no clone.
    let owned = OwnedMyData::new(incoming).expect("valid JSON");

    println!("[main thread] Deserialized: {:?}", owned.get());

    // Move across a tokio::spawn boundary – no Clone, no DeserializeOwned.
    let handle = tokio::spawn(async move {
        println!("[spawned task] data      = {}", owned.get().data);
        println!("[spawned task] more_data = {}", owned.get().more_data);
        println!("[spawned task] full      = {:?}", owned.get());
    });

