    use serde::de::{self, Deserializer, MapAccess, Visitor};
    use std::fmt;

    #[derive(Debug)]
    pub struct Character {
        pub name: String,
        pub ac: u8,
        pub current: u16,
        pub max: u16,
        pub temp: u16,
    }

