                    let ac = ac.ok_or_else(|| de::Error::missing_field("ac"))?;
                    let hp: u16 = hp.ok_or_else(|| de::Error::missing_field("hp"))?;

                    Ok(Character {
                        name,
                        ac,
                        current: hp,
                        max: hp,
                        temp: 0,
                    })
                }
            }

