                            Some(struct_chunked.into_series())
                        })
                        .collect();

                    // Now build a ListChunked from these optional Series
                    let list_chunked = Series::new(
                        PlSmallStr::from("foo"),
                        &list_series
                            .iter()
                            .map(|s| s.as_ref().cloned())
                            .collect::<Vec<Option<Series>>>(),
                    );

                    Ok(list_chunked.into_column())
                },
                GetOutput::from_type(DataType::List(Box::new(DataType::Struct(
                    vec![
                        Field::new(PlSmallStr::from("c1"), DataType::String),
                        Field::new(PlSmallStr::from("c2"), DataType::String),
                    ],
                )))),
            )
            .alias("foo"),
    );

    let result = lf.collect()?;
    println!("{}", result);

    Ok(())
}
"
}
```

**Key insight**: You cannot `.collect()` an iterator of `Option<StructChunked>` into a `StructChunked` because `FromIterator<Option<StructChunked>>` is not implemented for struct types. Instead, the approach is:

1. For each row, build a `StructChunked` (from component `Series`) and convert it to a `Series`.
2. Collect all rows as `Vec<Option<Series>>` and construct a `Series` from that, which Polars will interpret as a `List` column.
3. Use `GetOutput::from_type(...)` to declare the output schema as `List(Struct(...))`.

This produces the expected output where each row contains a list of structs with fields `c1` and `c2`.

