/// Listens for SIGINT / SIGTERM and forwards them as Messages.
/// Checks `running` flag periodically so we can break out.
fn yield_signals(sender: Sender<Message>, running: Arc<AtomicBool>) {
    let mut signals = Signals::new(&[SIGINT, SIGTERM]).unwrap();
    // Use the non-blocking / timeout based API so we can check `running`
    loop {
        if !running.load(Ordering::SeqCst) {
