        vec![100, 200, 300, 400],
        vec![5],
    ];

    // Approach 1: Parallel over outer, sequential over inner
    // Each inner vec is processed on a separate thread, inner elements are sequential.
    let result_outer_par: Vec<Vec<String>> = a
        .par_iter()
        .map(|inner| inner.iter().map(|&x| format!("val={}", x * 2)).collect())
        .collect();

    println!("Approach 1 (par outer, seq inner):");
    for row in &result_outer_par {
        println!("  {:?}", row);
    }

    // Approach 2: Parallel over both outer AND inner
    // Both levels use par_iter for maximum parallelism.
    let result_both_par: Vec<Vec<String>> = a
        .par_iter()
        .map(|inner| {
            inner
                .par_iter()
                .map(|&x| format!("val={}", x * 2))
                .collect()
        })
        .collect();

    println!("\nApproach 2 (par outer, par inner):");
    for row in &result_both_par {
        println!("  {:?}", row);
    }

    // Approach 3: Flatten, process in parallel, then reshape back.
    // Useful when you want a single flat parallel pass over all elements.
    let lengths: Vec<usize> = a.iter().map(|inner| inner.len()).collect();

    let flat: Vec<usize> = a.iter().flatten().copied().collect();

    let processed: Vec<String> = flat
        .par_iter()
        .map(|&x| format!("val={}", x * 2))
        .collect();

    // Reshape back using the recorded lengths
    let mut iter = processed.into_iter();
    let result_reshape: Vec<Vec<String>> = lengths
        .iter()
        .map(|&len| iter.by_ref().take(len).collect())
        .collect();

    println!("\nApproach 3 (flatten, par process, reshape):");
    for row in &result_reshape {
