use futures_util::StreamExt;
use tokio::sync::broadcast::{self, Sender};
use tokio::sync::Notify;
use tokio_stream::wrappers::BroadcastStream;
use tokio_stream::Stream;

/// A custom error type for receive errors.
#[derive(Debug)]
pub struct RecvError;

/// Represents an event sent through the channel.
#[derive(Debug, Clone)]
pub struct Event {
    pub message: String,
}

/// A shared shutdown signal that all components can observe.
#[derive(Clone)]
pub struct ShutdownSignal {
    notify: Arc<Notify>,
}

impl ShutdownSignal {
    pub fn new() -> Self {
        Self {
            notify: Arc::new(Notify::new()),
        }
    }

    /// Trigger shutdown — all waiters will be notified.
    pub fn shutdown(&self) {
        self.notify.notify_waiters();
    }

    /// Wait until shutdown is signaled.
    pub async fn wait(&self) {
        self.notify.notified().await;
    }
}

/// Creates the channel primitives plus a shared shutdown signal.
pub fn events_channel() -> (EventSender, EventStreamFactory, ShutdownSignal) {
    let (tx, _) = broadcast::channel(20);
    let shutdown = ShutdownSignal::new();
    (
        EventSender {
            tx: tx.clone(),
            shutdown: shutdown.clone(),
        },
        EventStreamFactory {
            tx,
            shutdown: shutdown.clone(),
        },
        shutdown,
    )
}

/// Cloneable sender — you can clone this as many times as you like.
#[derive(Debug, Clone)]
pub struct EventSender {
    tx: Sender<Event>,
    shutdown: ShutdownSignal,
}

impl EventSender {
    pub fn send(&self, event: Event) {
        // Ignore send errors (e.g., no active receivers).
        let _ = self.tx.send(event);
    }
}

/// Factory that produces new subscriber streams.
#[derive(Clone)]
pub struct EventStreamFactory {
    tx: Sender<Event>,
    shutdown: ShutdownSignal,
}

impl EventStreamFactory {
    /// Returns a stream that yields events until the shutdown signal fires.
    /// When shutdown is signaled the stream ends (returns `None`), which will
    /// cleanly terminate an SSE response.
    pub fn all_events(&self) -> impl Stream<Item = Result<Event, RecvError>> + Send + '_ {
        let inner = BroadcastStream::new(self.tx.subscribe()).filter_map(|event| async move {
            match event {
                Ok(event) => Some(Ok(event)),
                Err(_) => Some(Err(RecvError)),
            }
        });

        // Wrap the stream so it terminates when shutdown is signaled.
        let shutdown = self.shutdown.clone();
        async_stream(inner, shutdown)
    }
}

/// Helper: wraps an inner stream so that it terminates when the shutdown signal
/// fires.  Uses `tokio::select!` internally.
fn async_stream<S>(
    inner: S,
    shutdown: ShutdownSignal,
) -> impl Stream<Item = Result<Event, RecvError>> + Send
where
    S: Stream<Item = Result<Event, RecvError>> + Send + Unpin,
{
    futures_util::stream::unfold(
        (inner, shutdown, false),
        |(mut inner, shutdown, done)| async move {
            if done {
                return None;
            }
            tokio::select! {
                item = inner.next() => {
                    match item {
                        Some(val) => Some((val, (inner, shutdown, false))),
                        None => None, // inner stream ended naturally
                    }
                }
                _ = shutdown.wait() => {
                    // Shutdown signaled — end the stream.
                    println!("[stream] shutdown signal received, ending stream");
                    None
                }
            }
        },
    )
}

#[tokio::main]
async fn main() {
    let (sender, factory, shutdown) = events_channel();

    // Clone sender and factory to demonstrate that cloning is fine.
    let sender2 = sender.clone();
    let factory2 = factory.clone();

    // Spawn a consumer task using the first factory.
    let consumer1 = tokio::spawn(async move {
        let mut stream = std::pin::pin!(factory.all_events());
        println!("[consumer-1] listening for events...");
        while let Some(result) = stream.next().await {
            match result {
                Ok(event) => println!("[consumer-1] received: {:?}", event.message),
                Err(_) => println!("[consumer-1] receive error (lagged)"),
            }
        }
        println!("[consumer-1] stream ended");
    });

    // Spawn a second consumer task using the cloned factory.
    let consumer2 = tokio::spawn(async move {
        let mut stream = std::pin::pin!(factory2.all_events());
        println!("[consumer-2] listening for events...");
        while let Some(result) = stream.next().await {
            match result {
                Ok(event) => println!("[consumer-2] received: {:?}", event.message),
                Err(_) => println!("[consumer-2] receive error (lagged)"),
            }
        }
        println!("[consumer-2] stream ended");
    });

    // Spawn a producer that sends a few events then triggers shutdown.
    let producer = tokio::spawn(async move {
        for i in 1..=5 {
            let msg = format!("event-{}", i);
            println!("[producer] sending: {}", msg);
            sender.send(Event {
