            sender2.send(Event {
                message: format!("{}-from-clone", msg),
            });
            tokio::time::sleep(std::time::Duration::from_millis(300)).await;
        }

        println!("[producer] done sending. Triggering shutdown...");
        shutdown.shutdown();
    });

    // Wait for all tasks to finish.
    let _ = tokio::join!(producer, consumer1, consumer2);
    println!("[main] all tasks completed, process exiting cleanly");
}
