    ///
    /// ```ignore
    /// let index = self.channel_index.fetch_add(1, Ordering::Relaxed);
    /// ```
    ///
    /// Replacement using critical_section:
    ///
    /// The correct ordering here is `Ordering::Relaxed` — and here is why:
    ///
    /// 1. Inside a critical-section, interrupts are disabled (and on multi-core
    ///    rp2040 the other core is also locked out via the hardware spinlock that
    ///    the critical-section implementation uses). This means no other code can
    ///    observe or mutate `channel_index` between our `load` and `store`.
    ///    The critical section itself provides the necessary synchronization
    ///    barrier — it is the mutual-exclusion mechanism, not the atomic
    ///    ordering.
    ///
    /// 2. `Ordering::Relaxed` is sufficient because:
    ///    - On thumbv6m (Cortex-M0+), there is no out-of-order execution, so
    ///      loads and stores to the same location are naturally ordered.
    ///    - The critical section already acts as a full memory barrier on entry
    ///      and exit (compiler fences / barriers are inserted by the
    ///      critical-section implementation). No reordering of the load/store
    ///      pair across the critical section boundary can happen.
    ///    - The original `fetch_add` also used `Ordering::Relaxed`, so we are
    ///      preserving exactly the same semantics: the only guarantee we need
    ///      is atomicity of the read-modify-write, which the critical section
    ///      provides.
    ///
    /// 3. Using a stronger ordering (e.g., `SeqCst`) would add unnecessary
    ///    overhead (DMB instructions on ARMv7+, though on ARMv6-M they are
    ///    NOPs). It would not provide any additional correctness because the
    ///    critical section already prevents concurrent access.
    ///
    /// Therefore `Ordering::Relaxed` is correct and optimal.
    fn fetch_add_index(&self) -> usize {
        critical_section::with(|_cs| {
            let old_val = self.channel_index.load(Ordering::Relaxed);
            self.channel_index.store(old_val + 1, Ordering::Relaxed);
            old_val
        })
    }
}

fn main() {
