use std::path::PathBuf;

use serde::Deserialize;
use serde_json::Value;

#[derive(Deserialize, Debug)]
struct A {
    path_list: Vec<PathBuf>,
}

/// Recursively resolve any `{"$ref": "<file>#/<json_pointer>"}` nodes
/// found inside a `serde_json::Value` tree.
///
/// Supported `$ref` format:  `./relative/path.json#/pointer/parts`
/// The part before `#` is a file path (relative to cwd).
/// The part after `#` is a JSON Pointer (RFC 6901).
fn resolve_refs(value: &mut Value) {
    match value {
        Value::Object(map) => {
            // Check whether this object is a `$ref` reference
            if map.len() == 1 {
                if let Some(ref_val) = map.get("$ref") {
                    if let Some(ref_str) = ref_val.as_str() {
                        if let Some(resolved) = resolve_ref_string(ref_str) {
                            *value = resolved;
                            // The resolved value itself may contain refs,
                            // so recurse into it.
                            resolve_refs(value);
                            return;
                        }
                    }
                }
            }
            // Not a $ref – recurse into every value
            for v in map.values_mut() {
                resolve_refs(v);
            }
        }
        Value::Array(arr) => {
            for v in arr.iter_mut() {
                resolve_refs(v);
            }
        }
        _ => {}
    }
}

/// Given a ref string like `./a.json#/p_list`, read the file, parse it,
/// and extract the sub-value at the given JSON pointer.
fn resolve_ref_string(ref_str: &str) -> Option<Value> {
    // Split on the first '#'
    let (file_path, pointer) = if let Some(idx) = ref_str.find('#') {
        let (fp, ptr) = ref_str.split_at(idx);
        // ptr starts with '#', JSON pointer is the rest
        (fp, &ptr[1..])
    } else {
        (ref_str, "/")
    };

    let content = fs::read_to_string(file_path)
        .unwrap_or_else(|e| panic!("failed to read referenced file '{}': {}", file_path, e));

    let mut root: Value = serde_json::from_str(&content)
        .unwrap_or_else(|e| panic!("failed to parse referenced file '{}': {}", file_path, e));

    // Recursively resolve any refs inside the referenced file as well
    resolve_refs(&mut root);

    if pointer.is_empty() || pointer == "/" {
        Some(root)
    } else {
        root.pointer(pointer).cloned()
    }
}

fn main() {
    // Read the top-level JSON file
    let json_data = fs::read_to_string("b.json").expect("failed to read from b.json");

    // Parse into a generic Value so we can resolve $ref nodes
    let mut raw: Value = serde_json::from_str(&json_data).expect("failed to parse b.json");

    // Resolve all $ref references recursively
    resolve_refs(&mut raw);

    // Now deserialize into the strongly-typed struct
    let a_obj: A = serde_json::from_value(raw).expect("deserialization failed");

    for p in &a_obj.path_list {
        println!("{}", p.display());
