  "main.rs": "/// Splits a shell command string into tokens in a quote-aware fashion,
/// mimicking how bash handles single quotes and whitespace.
///
/// Rules:
/// - Unquoted whitespace separates tokens.
/// - Single-quoted regions preserve their content literally (including spaces).
/// - A quoted region glues to adjacent non-whitespace (e.g. `' two  'three` → ` two  three`).
fn tokenize(input: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current = String::new();
    let mut in_single_quote = false;
    let mut chars = input.chars();

    while let Some(ch) = chars.next() {
        match ch {
            '\'' if !in_single_quote => {
                // Opening a single-quoted section. We start/continue a token.
                in_single_quote = true;
            }
            '\'' if in_single_quote => {
                // Closing a single-quoted section.
                in_single_quote = false;
            }
            ' ' if !in_single_quote => {
                // Unquoted space: delimiter
                if !current.is_empty() {
                    tokens.push(std::mem::take(&mut current));
                }
            }
            _ => {
                current.push(ch);
            }
        }
    }

    if !current.is_empty() {
        tokens.push(current);
    }

    tokens
}

fn main() {
    let input = " one  ' two  'three    four";
    let tokens = tokenize(input);
    println!("{} args:", tokens.len());
    for token in &tokens {
        println!("<{}>", token);
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_basic_example() {
        let result = tokenize(" one  ' two  'three    four");
        assert_eq!(result, vec!["one", " two  three", "four"]);
    }

    #[test]
    fn test_no_quotes() {
        let result = tokenize("hello   world");
        assert_eq!(result, vec!["hello", "world"]);
    }

    #[test]
    fn test_empty_quotes() {
        let result = tokenize("a''b");
        assert_eq!(result, vec!["ab"]);
    }

    #[test]
    fn test_only_quoted() {
        let result = tokenize("'hello world'");
        assert_eq!(result, vec!["hello world"]);
    }

    #[test]
    fn test_empty_string() {
        let result = tokenize("");
        assert_eq!(result, Vec::<String>::new());
