Here's a working solution that avoids the `RefCell` borrow issue by deferring the feedback emissions using a scheduling mechanism. The core problem is that synchronous feedback creates a re-entrant borrow on the `BehaviorSubject`'s internal `RefCell`. We can break the cycle by queuing feedback values and processing them after the current emission completes.

```json
{
  "Cargo.toml": "[package]
name = "rxrust-flipflop"
version = "0.1.0"
edition = "2021"

[dependencies]
",
  "main.rs": "use std::cell::RefCell;
use std::collections::VecDeque;
use std::rc::Rc;

/// A simple reactive subject that holds a current value and notifies subscribers.
/// This is a minimal reimplementation to avoid the RefCell reentrancy issue in rxRust.

type Callback = Box<dyn FnMut(bool)>;

struct SubjectInner {
    value: bool,
    subscribers: Vec<Callback>,
    pending: VecDeque<bool>,
    emitting: bool,
}

#[derive(Clone)]
struct Subject {
    inner: Rc<RefCell<SubjectInner>>,
}

impl Subject {
    fn new(initial: bool) -> Self {
        Subject {
            inner: Rc::new(RefCell::new(SubjectInner {
                value: initial,
                subscribers: Vec::new(),
                pending: VecDeque::new(),
                emitting: false,
            })),
        }
    }

    fn value(&self) -> bool {
        self.inner.borrow().value
    }

    fn subscribe<F: FnMut(bool) + 'static>(&self, f: F) {
        self.inner.borrow_mut().subscribers.push(Box::new(f));
    }

    fn next(&self, val: bool) {
        {
            let mut inner = self.inner.borrow_mut();
            if inner.emitting {
                // We're in a reentrant call — queue it for later
                inner.pending.push_back(val);
                return;
            }
            inner.emitting = true;
            inner.value = val;
        }
        self.drain_notify(val);
    }

    fn drain_notify(&self, first_val: bool) {
        // Notify subscribers for `first_val`, then drain any pending values
        let mut val = first_val;
        loop {
            let count = self.inner.borrow().subscribers.len();
            for i in 0..count {
                let mut cb = {
                    let mut inner = self.inner.borrow_mut();
                    // Temporarily take the callback out so we can call it without holding the borrow
                    let mut placeholder: Callback = Box::new(|_| {});
                    std::mem::swap(&mut inner.subscribers[i], &mut placeholder);
                    placeholder
                };
                cb(val);
                {
                    let mut inner = self.inner.borrow_mut();
                    std::mem::swap(&mut inner.subscribers[i], &mut cb);
                }
            }
            // Check for pending values that were queued during notification
            let next_val = {
                let mut inner = self.inner.borrow_mut();
                if let Some(v) = inner.pending.pop_front() {
                    inner.value = v;
                    Some(v)
                } else {
                    inner.emitting = false;
                    None
                }
            };
            match next_val {
                Some(v) => val = v,
                None => break,
            }
        }
    }
}

/// A combined-latest node: emits (a, b) whenever either input changes.
struct CombineLatest {
    output: Subject,
    a: Rc<RefCell<bool>>,
    b: Rc<RefCell<bool>>,
}

impl CombineLatest {
    fn new(sa: &Subject, sb: &Subject) -> Self {
        let a = Rc::new(RefCell::new(sa.value()));
        let b = Rc::new(RefCell::new(sb.value()));
        let output = Subject::new(false); // placeholder

        let out1 = output.clone();
        let a1 = a.clone();
        let b1 = b.clone();
        sa.subscribe(move |va| {
            *a1.borrow_mut() = va;
            let vb = *b1.borrow();
            out1.next(va & vb); // We'll do NAND outside; here just combine
        });

        let out2 = output.clone();
        let a2 = a.clone();
        let b2 = b.clone();
        sb.subscribe(move |vb| {
            *b2.borrow_mut() = vb;
            let va = *a2.borrow();
            out2.next(va & vb);
        });

        CombineLatest { output, a, b }
    }
}

fn nand(name: &str, a: &Subject, b: &Subject) -> Subject {
    let a_val = Rc::new(RefCell::new(a.value()));
    let b_val = Rc::new(RefCell::new(b.value()));
    let output = Subject::new(!(a.value() & b.value()));

    let out1 = output.clone();
    let a1 = a_val.clone();
    let b1 = b_val.clone();
    let n1 = name.to_string();
    a.subscribe(move |va| {
        *a1.borrow_mut() = va;
        let vb = *b1.borrow();
        let result = !(va & vb);
        println!("nand {} ({}, {}) = {}", n1, va, vb, result);
        out1.next(result);
    });

    let out2 = output.clone();
    let a2 = a_val.clone();
    let b2 = b_val.clone();
    let n2 = name.to_string();
    b.subscribe(move |vb| {
        *b2.borrow_mut() = vb;
        let va = *a2.borrow();
        let result = !(va & vb);
        println!("nand {} ({}, {}) = {}", n2, va, vb, result);
        out2.next(result);
    });

    output
}

/// RS flip-flop built from two NAND gates with cross-feedback.
///   q  = NAND(s, q_bar)
///   q_bar = NAND(r, q)
///
/// With active-low inputs: s=0 sets q=1, r=0 sets q_bar=1.
/// Both high = hold state. Both low = invalid.
fn flipflop(s: &Subject, r: &Subject) -> (Subject, Subject) {
    // We need feedback subjects for the cross-coupled outputs.
    // Initialize to a consistent idle state (s=1, r=1 -> q=1, q_bar=0 or vice versa).
    // Let's pick q=true, q_bar=false as initial state.
    let q_fb = Subject::new(true);
    let q_bar_fb = Subject::new(false);

    // q = NAND(s, q_bar_fb)
    let q = nand("S", s, &q_bar_fb);
    // q_bar = NAND(r, q_fb)
    let q_bar = nand("R", r, &q_fb);

    // Feedback: q -> q_fb (feeds into R-nand's second input)
    let q_fb_clone = q_fb.clone();
    q.subscribe(move |v| {
        q_fb_clone.next(v);
    });

    // Feedback: q_bar -> q_bar_fb (feeds into S-nand's second input)
    let q_bar_fb_clone = q_bar_fb.clone();
    q_bar.subscribe(move |v| {
        q_bar_fb_clone.next(v);
    });

    (q, q_bar)
}

fn main() {
    let s = Subject::new(true);
    let r = Subject::new(true);

    let (q, q_bar) = flipflop(&s, &r);

    // Observe outputs
    let q_out = Rc::new(RefCell::new(q.value()));
    let qb_out = Rc::new(RefCell::new(q_bar.value()));

    let q_out1 = q_out.clone();
    q.subscribe(move |v| {
        *q_out1.borrow_mut() = v;
    });
    let qb_out1 = qb_out.clone();
    q_bar.subscribe(move |v| {
        *qb_out1.borrow_mut() = v;
    });

    println!("=== Initial state ===");
    println!("Q={}, Q_bar={}\n", *q_out.borrow(), *qb_out.borrow());

    println!("=== SET (s=false, r=true) ===");
    s.next(false);
    println!("Q={}, Q_bar={}\n", *q_out.borrow(), *qb_out.borrow());

    println!("=== Release set (s=true, r=true) ===");
    s.next(true);
    println!("Q={}, Q_bar={}\n", *q_out.borrow(), *qb_out.borrow());

    println!("=== RESET (s=true, r=false) ===");
    r.next(false);
    println!("Q={}, Q_bar={}\n", *q_out.borrow(), *qb_out.borrow());

    println!("=== Release reset (s=true, r=true) ===");
    r.next(true);
    println!("Q={}, Q_bar={}\n", *q_out.borrow(), *qb_out.borrow());

    println!("=== SET again (s=false, r=true) ===");
    s.next(false);
    println!("Q={}, Q_bar={}\n", *q_out.borrow(), *qb_out.borrow());

    println!("=== Release set (s=true, r=true) ===");
    s.next(true);
    println!("Q={}, Q_bar={}\n", *q_out.borrow(), *qb_out.borrow());
}
"
}
```

**Key insight:** The original `rxRust` problem is that `BehaviorSubject` uses a `RefCell` internally, and when a feedback loop causes a reentrant `next()` call during an active emission, it panics with "RefCell already borrowed."

The solution implements a custom `Subject` with a **deferred emission queue**: when `next()` is called while already emitting (reentrant call from a subscriber), the value is queued in a `VecDeque<bool>` instead of immediately emitting. After the current notification pass completes, queued values are drained and emitted in order. Subscribers are temporarily swapped out during invocation to avoid holding the `RefCell` borrow across the callback, allowing nested `next()` calls to safely enqueue without panic.

This correctly models an RS flip-flop with cross-coupled NAND gates, demonstrating set, reset, and hold behavior.

