Here's a solution that demonstrates how to work around the `enum_dispatch` same-crate limitation by using a procedural-macro-free approach with a custom macro that generates the enum dispatch boilerplate. This keeps the three logical layers separate (as modules here, but the pattern applies to separate crates too) without any circular dependencies.

```json
{
  "Cargo.toml": "[package]
name = "enum_dispatch_design"
version = "0.1.0"
edition = "2021"

[dependencies]
",
  "main.rs": "/// ---------------------------------------------------------------------------
/// This example demonstrates how to solve the enum_dispatch cross-crate
/// limitation by using a declarative macro that generates both the enum and
/// the trait-forwarding impl.  The three logical layers are:
///
///   al  – abstract layer   (trait definitions)
///   il  – implementation layer (concrete types that impl the traits)
///   bl  – business layer   (enum that wraps concrete types + dispatch)
///
/// With real crates the layout would be:
///   al  -> standalone crate
///   il  -> depends on al
///   bl  -> depends on al + il
///
/// No circular dependency, and no need for `enum_dispatch` crate at all.
/// ---------------------------------------------------------------------------

// ============================================================
// Abstract Layer (al) – traits and a helper macro
// ============================================================
mod al {
    use std::fmt;

    /// The big trait with many methods (shortened for demo, but the pattern
    /// scales to 20+ methods trivially – just add lines to the macro).
    pub trait Rest: fmt::Debug {
        fn get(&self, url: &str) -> String;
        fn post(&self, url: &str, body: &str) -> String;
        fn put(&self, url: &str, body: &str) -> String;
        fn delete(&self, url: &str) -> String;
        fn patch(&self, url: &str, body: &str) -> String;
        fn head(&self, url: &str) -> String;
        fn options(&self, url: &str) -> String;
        fn connect(&self, url: &str) -> String;
        fn trace_req(&self, url: &str) -> String;
        fn health_check(&self) -> bool;
        fn base_url(&self) -> &str;
        fn timeout_ms(&self) -> u64;
        fn retries(&self) -> u32;
        fn set_retries(&mut self, n: u32);
        fn set_timeout_ms(&mut self, ms: u64);
        fn authenticate(&mut self, token: &str) -> bool;
        fn refresh_token(&mut self) -> Option<String>;
        fn upload(&self, url: &str, data: &[u8]) -> String;
        fn download(&self, url: &str) -> Vec<u8>;
        fn status(&self) -> String;
    }

    /// Macro that generates an enum plus a `Rest` impl that forwards every
    /// method to the inner variant.  This is the key piece that replaces
    /// `enum_dispatch` without requiring the trait and enum to live in the
    /// same crate.
    ///
    /// Usage (in the business layer):
    ///
    /// ```ignore
    /// rest_dispatch! {
    ///     pub enum Item {
    ///         Foo(il::Foo),
    ///         Boo(il::Boo),
    ///     }
    /// }
    /// ```
    #[macro_export]
    macro_rules! rest_dispatch {
        (
            $(#[$meta:meta])*
            $vis:vis enum $Enum:ident {
                $( $Variant:ident($Ty:ty) ),* $(,)?
            }
        ) => {
            $(#[$meta])*
            $vis enum $Enum {
                $( $Variant($Ty), )*
            }

            // Forward every `Rest` method via match.
            // The macro simply enumerates all methods once.  When you add a
            // method to the trait you add one forwarding arm here – but you
            // never have to write N (variant) × M (method) boilerplate.
            impl $crate::al::Rest for $Enum {
                fn get(&self, url: &str) -> String {
                    match self { $( $Enum::$Variant(inner) => inner.get(url), )* }
                }
                fn post(&self, url: &str, body: &str) -> String {
                    match self { $( $Enum::$Variant(inner) => inner.post(url, body), )* }
                }
                fn put(&self, url: &str, body: &str) -> String {
                    match self { $( $Enum::$Variant(inner) => inner.put(url, body), )* }
                }
                fn delete(&self, url: &str) -> String {
                    match self { $( $Enum::$Variant(inner) => inner.delete(url), )* }
                }
                fn patch(&self, url: &str, body: &str) -> String {
                    match self { $( $Enum::$Variant(inner) => inner.patch(url, body), )* }
                }
                fn head(&self, url: &str) -> String {
                    match self { $( $Enum::$Variant(inner) => inner.head(url), )* }
                }
                fn options(&self, url: &str) -> String {
                    match self { $( $Enum::$Variant(inner) => inner.options(url), )* }
                }
                fn connect(&self, url: &str) -> String {
                    match self { $( $Enum::$Variant(inner) => inner.connect(url), )* }
                }
                fn trace_req(&self, url: &str) -> String {
                    match self { $( $Enum::$Variant(inner) => inner.trace_req(url), )* }
                }
                fn health_check(&self) -> bool {
                    match self { $( $Enum::$Variant(inner) => inner.health_check(), )* }
                }
                fn base_url(&self) -> &str {
                    match self { $( $Enum::$Variant(inner) => inner.base_url(), )* }
                }
                fn timeout_ms(&self) -> u64 {
                    match self { $( $Enum::$Variant(inner) => inner.timeout_ms(), )* }
                }
                fn retries(&self) -> u32 {
                    match self { $( $Enum::$Variant(inner) => inner.retries(), )* }
                }
                fn set_retries(&mut self, n: u32) {
                    match self { $( $Enum::$Variant(inner) => inner.set_retries(n), )* }
                }
                fn set_timeout_ms(&mut self, ms: u64) {
                    match self { $( $Enum::$Variant(inner) => inner.set_timeout_ms(ms), )* }
                }
                fn authenticate(&mut self, token: &str) -> bool {
                    match self { $( $Enum::$Variant(inner) => inner.authenticate(token), )* }
                }
                fn refresh_token(&mut self) -> Option<String> {
                    match self { $( $Enum::$Variant(inner) => inner.refresh_token(), )* }
                }
                fn upload(&self, url: &str, data: &[u8]) -> String {
                    match self { $( $Enum::$Variant(inner) => inner.upload(url, data), )* }
                }
                fn download(&self, url: &str) -> Vec<u8> {
                    match self { $( $Enum::$Variant(inner) => inner.download(url), )* }
                }
                fn status(&self) -> String {
                    match self { $( $Enum::$Variant(inner) => inner.status(), )* }
                }
            }

            // Convenience `From` impls so you can write `Item::from(foo)`.
            $(
                impl From<$Ty> for $Enum {
                    fn from(v: $Ty) -> Self {
                        $Enum::$Variant(v)
                    }
                }
            )*

            // Forward Debug
            impl std::fmt::Debug for $Enum {
                fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
                    match self {
                        $( $Enum::$Variant(inner) => std::fmt::Debug::fmt(inner, f), )*
                    }
                }
            }
        };
    }
