    // Target function: f(x) = x^2 + 1
    let inputs: Vec<Vec<f32>> = (-10..=10).map(|i| vec![i as f32]).collect();
    let targets: Vec<f32> = inputs.iter().map(|v| v[0] * v[0] + 1.0).collect();

