Here's a self-contained Bevy application that demonstrates the solution. The key insight is that you need to transform the hit normal into the cube's local space, determine which local axis it corresponds to, and then compose the cube's rotation with the appropriate face rotation.

```json
{
  "Cargo.toml": "[package]
name = "block-gizmo-demo"
version = "0.1.0"
edition = "2021"

[dependencies]
bevy = "0.15"
",
  "main.rs": "use bevy::prelude::*;
use bevy::input::mouse::MouseMotion;
use bevy::window::PrimaryWindow;
use bevy::color::palettes::css;

#[derive(Component)]
struct Block;

#[derive(Component)]
struct MainCamera;

#[derive(Resource, Default)]
struct RaycastResult {
    hit_entity: Option<Entity>,
    hit_point: Vec3,
    hit_normal: Vec3,
}

fn main() {
    App::new()
        .add_plugins(DefaultPlugins)
        .init_resource::<RaycastResult>()
        .add_systems(Startup, setup)
        .add_systems(Update, (
            rotate_block,
            raycast_from_camera,
            draw_placement_gizmo,
        ).chain())
        .run();
}

fn setup(
    mut commands: Commands,
    mut meshes: ResMut<Assets<Mesh>>,
    mut materials: ResMut<Assets<StandardMaterial>>,
) {
    // Spawn a cube (block) with some initial rotation to demonstrate the problem
