        Mesh3d(meshes.add(Cuboid::new(1.0, 1.0, 1.0))),
        MeshMaterial3d(materials.add(StandardMaterial {
            base_color: Color::srgba(0.3, 0.5, 0.8, 0.7),
            alpha_mode: AlphaMode::Blend,
            ..default()
        })),
        Transform::from_translation(Vec3::ZERO)
            .with_rotation(Quat::from_euler(EulerRot::XYZ, 0.3, 0.5, 0.2)),
        Block,
    ));

    // Light
    commands.spawn((
        DirectionalLight {
            illuminance: 10000.0,
            shadows_enabled: true,
            ..default()
        },
        Transform::from_xyz(4.0, 8.0, 4.0).looking_at(Vec3::ZERO, Vec3::Y),
    ));

    // Ambient light
    commands.insert_resource(AmbientLight {
        color: Color::WHITE,
        brightness: 300.0,
    });

    // Camera
    commands.spawn((
        Camera3d::default(),
        Transform::from_xyz(3.0, 3.0, 3.0).looking_at(Vec3::ZERO, Vec3::Y),
        MainCamera,
    ));

    println!("=== Block Gizmo Demo ===");
    println!("Move mouse over the cube to see the placement indicator.");
    println!("Press A/D to rotate the cube around Y axis.");
    println!("Press W/S to rotate the cube around X axis.");
    println!("Press Q/E to rotate the cube around Z axis.");
}

fn rotate_block(
    time: Res<Time>,
    keyboard: Res<ButtonInput<KeyCode>>,
    mut query: Query<&mut Transform, With<Block>>,
) {
    let speed = 1.0;
    let dt = time.delta_secs();

    for mut transform in query.iter_mut() {
        if keyboard.pressed(KeyCode::KeyA) {
            transform.rotate(Quat::from_rotation_y(speed * dt));
        }
        if keyboard.pressed(KeyCode::KeyD) {
            transform.rotate(Quat::from_rotation_y(-speed * dt));
        }
        if keyboard.pressed(KeyCode::KeyW) {
            transform.rotate(Quat::from_rotation_x(speed * dt));
        }
        if keyboard.pressed(KeyCode::KeyS) {
            transform.rotate(Quat::from_rotation_x(-speed * dt));
        }
        if keyboard.pressed(KeyCode::KeyQ) {
            transform.rotate(Quat::from_rotation_z(speed * dt));
        }
        if keyboard.pressed(KeyCode::KeyE) {
            transform.rotate(Quat::from_rotation_z(-speed * dt));
        }
    }
}

/// Manual ray-AABB (OBB) intersection against the cube
fn raycast_from_camera(
    window_q: Query<&Window, With<PrimaryWindow>>,
    camera_q: Query<(&Camera, &GlobalTransform), With<MainCamera>>,
    block_q: Query<(Entity, &GlobalTransform), With<Block>>,
    mut raycast_result: ResMut<RaycastResult>,
) {
    raycast_result.hit_entity = None;

    let Ok(window) = window_q.get_single() else { return };
    let Some(cursor_pos) = window.cursor_position() else { return };
    let Ok((camera, cam_gt)) = camera_q.get_single() else { return };

    // Get ray from camera
    let Ok(ray) = camera.viewport_to_world(cam_gt, cursor_pos) else { return };

    let ray_origin = ray.origin;
    let ray_dir = ray.direction.as_vec3();

    // Test against each block (we only have one)
    let half_extents = Vec3::splat(0.5); // cube is 1x1x1

    let mut closest_t = f32::MAX;
    let mut closest_entity = None;
    let mut closest_normal = Vec3::ZERO;

    for (entity, gt) in block_q.iter() {
        let block_pos = gt.translation();
        let block_rot = gt.to_scale_rotation_translation().1;
        let inv_rot = block_rot.inverse();

        // Transform ray into local space of the block
        let local_origin = inv_rot * (ray_origin - block_pos);
        let local_dir = inv_rot * ray_dir;

        // AABB intersection in local space
        let mut tmin = f32::NEG_INFINITY;
        let mut tmax = f32::INFINITY;
        let mut hit_normal_local = Vec3::ZERO;

        for i in 0..3 {
            let o = match i { 0 => local_origin.x, 1 => local_origin.y, _ => local_origin.z };
            let d = match i { 0 => local_dir.x, 1 => local_dir.y, _ => local_dir.z };
            let half = match i { 0 => half_extents.x, 1 => half_extents.y, _ => half_extents.z };

            if d.abs() < 1e-8 {
                if o < -half || o > half {
                    tmin = f32::INFINITY; // no hit
                    break;
                }
            } else {
                let mut t1 = (-half - o) / d;
                let mut t2 = (half - o) / d;
                let mut normal_dir = -1.0f32;

                if t1 > t2 {
                    std::mem::swap(&mut t1, &mut t2);
                    normal_dir = 1.0;
                }

                if t1 > tmin {
                    tmin = t1;
                    let mut n = Vec3::ZERO;
                    match i {
                        0 => n.x = -normal_dir,
                        1 => n.y = -normal_dir,
                        _ => n.z = -normal_dir,
                    }
                    hit_normal_local = n;
                }
                if t2 < tmax {
                    tmax = t2;
                }

                if tmin > tmax || tmax < 0.0 {
                    tmin = f32::INFINITY;
                    break;
                }
            }
        }

        if tmin < closest_t && tmin > 0.0 && tmin <= tmax {
            closest_t = tmin;
            closest_entity = Some(entity);
            // Transform normal back to world space
            closest_normal = (block_rot * hit_normal_local).normalize();
        }
    }

    if let Some(entity) = closest_entity {
        raycast_result.hit_entity = Some(entity);
        raycast_result.hit_point = ray_origin + ray_dir * closest_t;
        raycast_result.hit_normal = closest_normal;
    }
}

fn draw_placement_gizmo(
    mut gizmos: Gizmos,
    raycast_result: Res<RaycastResult>,
    block_q: Query<&GlobalTransform, With<Block>>,
) {
    let Some(entity) = raycast_result.hit_entity else { return };
    let Ok(gt) = block_q.get(entity) else { return };

    let hit_normal = raycast_result.hit_normal;
    let block_translation = gt.translation();
    let block_rotation = gt.to_scale_rotation_translation().1;

    // ============================================================
    // THE KEY SOLUTION:
    // 
    // 1. Transform the world-space hit normal into the block's local space.
    // 2. Determine which local face axis it corresponds to (±X, ±Y, ±Z).
    // 3. Compute the local-space rotation that aligns +Z with that face normal.
    // 4. Compose: final_rotation = block_rotation * local_face_rotation
    //
    // This ensures the gizmo rectangle is both:
    //   - Pointing outward along the face normal, AND
    //   - Aligned/rotated with the cube's own orientation.
    // ============================================================

    let inv_block_rot = block_rotation.inverse();
    let local_normal = (inv_block_rot * hit_normal).normalize();

    // Snap to the closest axis in local space
    let axes = [
        Vec3::X, Vec3::NEG_X,
        Vec3::Y, Vec3::NEG_Y,
        Vec3::Z, Vec3::NEG_Z,
    ];

    let mut best_axis = Vec3::Z;
    let mut best_dot = f32::NEG_INFINITY;
    for axis in &axes {
        let d = local_normal.dot(*axis);
        if d > best_dot {
            best_dot = d;
            best_axis = *axis;
        }
    }

    // Compute the local rotation that takes +Z to the face axis.
    // `gizmos.rect` draws in the XY plane of the given transform, 
    // with the normal pointing along +Z, so we need to map +Z -> best_axis.
    //
    // We use from_rotation_arc, but we also need to be careful about
    // the 180-degree case (Vec3::Z -> Vec3::NEG_Z).
    let local_face_rotation = if (best_axis + Vec3::Z).length() < 1e-4 {
        // 180 degree rotation: Z -> -Z, rotate around Y
        Quat::from_rotation_y(std::f32::consts::PI)
    } else {
        Quat::from_rotation_arc(Vec3::Z, best_axis)
    };

    // Final world rotation: block rotation composed with local face rotation
    let final_rotation = block_rotation * local_face_rotation;

    // Face center: the center of the face in world space
    let face_center_local = best_axis * 0.5;
    let face_center_world = block_translation + block_rotation * face_center_local;

    // Offset slightly along normal to prevent z-fighting
    let gizmo_pos = face_center_world + hit_normal * 0.01;

    gizmos.rect(
        Isometry3d::new(gizmo_pos, final_rotation),
        Vec2::new(1.0, 1.0),
        Color::Srgba(css::LIME),
    );

    // Also draw a small line showing the normal direction for debugging
    gizmos.line(face_center_world, face_center_world + hit_normal * 0.5, Color::Srgba(css::YELLOW));

    // Draw a wireframe of the cube for clarity
    let corners_local = [
        Vec3::new(-0.5, -0.5, -0.5),
        Vec3::new( 0.5, -0.5, -0.5),
        Vec3::new( 0.5,  0.5, -0.5),
        Vec3::new(-0.5,  0.5, -0.5),
        Vec3::new(-0.5, -0.5,  0.5),
        Vec3::new( 0.5, -0.5,  0.5),
        Vec3::new( 0.5,  0.5,  0.5),
        Vec3::new(-0.5,  0.5,  0.5),
    ];

    let edges = [
        (0,1),(1,2),(2,3),(3,0),
        (4,5),(5,6),(6,7),(7,4),
        (0,4),(1,5),(2,6),(3,7),
    ];

    for (a, b) in &edges {
        let wa = block_translation + block_rotation * corners_local[*a];
        let wb = block_translation + block_rotation * corners_local[*b];
        gizmos.line(wa, wb, Color::Srgba(css::GRAY));
    }
}
"
}
```

## How the Solution Works

The critical fix is in `draw_placement_gizmo`. The problem was that `Quat::from_rotation_arc(Vec3::Z, hit.normal)` only aligns the gizmo's Z-axis with the face normal but doesn't respect the cube's own rotation around that axis. The solution:

1. **Transform the world-space hit normal into the cube's local space** using the inverse of the cube's rotation.
2. **Snap to the nearest local axis** (±X, ±Y, ±Z) to determine which face was hit.
3. **Compute a local-space rotation** that maps the gizmo's default +Z direction to that face's local axis using `Quat::from_rotation_arc(Vec3::Z, best_axis)`.
4. **Compose the rotations**: `final_rotation = block_rotation * local_face_rotation`. This ensures the gizmo both faces outward along the normal AND rotates with the cube.

Use **W/A/S/D/Q/E** keys to rotate the cube and hover the mouse over it to see the green placement indicator stay flush with each face.

