use std::pin::Pin;
use tokio::sync::mpsc;

pub struct Context(i32);

pub enum InnerAsyncEvent {
    DoWithContext {
        block: Box<
            dyn for<'a> FnOnce(
                    &'a mut Context,
                ) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
                + Send,
        >,
