/// Wraps an async closure so it can be sent between threads.
///
/// The key insight: we can't directly require `AsyncFnOnce` to produce a `Send` future
/// on stable Rust (the `CallOnceFuture` associated type isn't constrainable via `AsyncFnOnce` alone).
/// Instead, we use a helper trait with a blanket impl that ties the `Send` bound
/// to the future returned by the closure.
pub trait SendAsyncFnOnce<'a> {
    fn call(self: Box<Self>, ctx: &'a mut Context) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>;
}

impl<'a, F, Fut> SendAsyncFnOnce<'a> for F
where
    F: FnOnce(&'a mut Context) -> Fut + 'a,
    Fut: Future<Output = ()> + Send + 'a,
{
    fn call(self: Box<Self>, ctx: &'a mut Context) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>> {
        Box::pin((*self)(ctx))
    }
}

/// Convenience function: takes a nice async closure and wraps it into an `InnerAsyncEvent`.
///
/// The closure must:
/// - Accept `&mut Context`
/// - Return a `Send` future
/// - Be `Send + 'static` itself
///
/// Usage looks like:
/// ```
/// with_context_async(&tx, |ctx: &mut Context| async move {
///     ctx.0 += 1;
/// });
/// ```
pub fn with_context_async<F>(work_sender: &mpsc::UnboundedSender<InnerAsyncEvent>, block: F)
where
    F: for<'a> SendAsyncFnOnce<'a> + Send + 'static,
{
    let _ = work_sender.send(InnerAsyncEvent::DoWithContext {
        block: Box::new(move |ctx: &mut Context| {
            let boxed: Box<dyn SendAsyncFnOnce<'_> + '_> = Box::new(block);
            boxed.call(ctx)
        }),
    });
}

#[tokio::main]
async fn main() {
    let (tx, mut rx) = mpsc::unbounded_channel::<InnerAsyncEvent>();

    // --- The nice ergonomic API: just pass an async closure! ---
    with_context_async(&tx, |ctx: &mut Context| async move {
        ctx.0 += 10;
        println!("First closure set ctx to {}", ctx.0);
    });

    with_context_async(&tx, |ctx: &mut Context| async move {
        ctx.0 *= 3;
        println!("Second closure set ctx to {}", ctx.0);
    });

    // Drop sender so the receiver will eventually return None
    drop(tx);

    // Spawn a task on another thread to process events
    let handle = tokio::spawn(async move {
        let mut ctx = Context(0);
        while let Some(event) = rx.recv().await {
            match event {
                InnerAsyncEvent::DoWithContext { block } => {
                    let fut = block(&mut ctx);
                    fut.await;
                }
            }
        }
        println!("Final context value: {}", ctx.0);
    });

    handle.await.unwrap();
}
