impl<R: Resource> ResourceRef<R>
where
    R::DynamicType: 'static + Default + Clone + std::fmt::Debug + PartialEq + Eq + std::hash::Hash,
{
    pub fn new(resource: &R) -> Self {
        let name = resource
            .meta()
            .name
            .as_deref()
            .expect("Resource must have a name");
        Self::new_named(name)
    }

    pub fn new_named(name: &str) -> Self {
        let dynamic_type = R::DynamicType::default();
        let group: Cow<'_, str> = R::group(&dynamic_type);
        let group = if group.is_empty() {
            None
        } else {
            // Convert Cow -> owned String so we don't borrow `dynamic_type`
            Some(group.into_owned())
        };
        let kind: Cow<'_, str> = R::kind(&dynamic_type);

        Self {
            type_: PhantomData,
            dynamic_type,
            group,
            kind: kind.into_owned(),
            name: name.to_string(),
        }
    }

    pub fn group(&self) -> Option<&str> {
        self.group.as_deref()
    }

    pub fn kind(&self) -> &str {
        &self.kind
    }

    pub fn name(&self) -> &str {
        &self.name
    }
}

/// ───────────────────────────────────────────────────────────
/// Approach 2 – lazy / deferred computation (zero extra allocation)
/// ───────────────────────────────────────────────────────────
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct ResourceRefLazy<R: Resource>
where
    R::DynamicType: Default + Clone + std::fmt::Debug + PartialEq + Eq + std::hash::Hash,
{
    type_: PhantomData<R>,
    dynamic_type: R::DynamicType,
    name: String,
}

impl<R: Resource> ResourceRefLazy<R>
where
    R::DynamicType: 'static + Default + Clone + std::fmt::Debug + PartialEq + Eq + std::hash::Hash,
{
    pub fn new_named(name: &str) -> Self {
        Self {
            type_: PhantomData,
            dynamic_type: R::DynamicType::default(),
            name: name.to_string(),
        }
    }

    /// Computed on the fly – the Cow borrows from `self.dynamic_type` which
    /// lives long enough because it is behind `&self`.
    pub fn group(&self) -> Option<Cow<'_, str>> {
        let g = R::group(&self.dynamic_type);
        if g.is_empty() {
            None
        } else {
            Some(g)
        }
    }

    pub fn kind(&self) -> Cow<'_, str> {
        R::kind(&self.dynamic_type)
    }

    pub fn name(&self) -> &str {
        &self.name
    }
}

