  "Cargo.toml": "[package]
name = "derive-foo-demo"
version = "0.1.0"
edition = "2021"

[dependencies]
",
  "main.rs": "/// The trait we want to derive.
trait Foo {
    fn go(&self);
}

/// Helper trait that the "derive macro" would generate.
/// By giving it a different method name, we avoid ambiguity.
/// The concrete struct must have an inherent `go(&self)` method,
/// and this blanket-ish manual impl bridges to it.
///
/// In a real proc-macro you would generate the `ConcreteFooHelper` trait
/// and its impl automatically. Here we do it by hand to demonstrate the technique.
trait ConcreteFooHelper {
    fn __concrete_go(&self);
}

// --- Example 1: ConcreteFoo HAS the inherent method => compiles & works ---

struct ConcreteFoo;

impl ConcreteFoo {
    pub fn go(&self) {
        println!("ConcreteFoo::go() - the real inherent method");
    }
}

// What the derive macro would generate:
// 1) A helper trait impl that calls the inherent method through a module
//    where `Foo` is NOT in scope, so `self.go()` can only resolve to the
//    inherent method.
mod __derive_concrete_foo {
    use super::ConcreteFoo;
    // NOTE: `Foo` is deliberately NOT imported here.

    pub trait Helper {
        fn __concrete_go(&self);
    }

    impl Helper for ConcreteFoo {
        #[inline(always)]
        fn __concrete_go(&self) {
            // Because `Foo` is not in scope, `self.go()` can ONLY resolve
            // to the inherent `ConcreteFoo::go`. If that method doesn't
            // exist, this is a compile error — no recursion possible.
            self.go();
        }
    }
}

impl Foo for ConcreteFoo {
    fn go(&self) {
        // Call through the helper, which is guaranteed to call the inherent method.
        use __derive_concrete_foo::Helper;
        self.__concrete_go();
    }
}

// --- Example 2: A generic struct to show it works with generics ---

struct GenericFoo<T> {
    value: T,
}

impl<T: std::fmt::Debug> GenericFoo<T> {
    pub fn go(&self) {
        println!("GenericFoo::go() - value is {:?}", self.value);
    }
}

mod __derive_generic_foo {
    use super::GenericFoo;
    // `Foo` is NOT in scope.

    pub trait Helper {
        fn __concrete_go(&self);
    }

    impl<T: std::fmt::Debug> Helper for GenericFoo<T> {
        #[inline(always)]
        fn __concrete_go(&self) {
            self.go(); // resolves to inherent GenericFoo::<T>::go
        }
    }
}

impl<T: std::fmt::Debug> Foo for GenericFoo<T> {
    fn go(&self) {
        use __derive_generic_foo::Helper;
        self.__concrete_go();
    }
}

// --- Example 3 (commented out): Missing inherent method => compile error ---
// Uncomment the block below to verify that a missing inherent `go()` method
// produces a compile-time error instead of infinite recursion.
//
// struct BrokenFoo;
//
// // NOTE: no `impl BrokenFoo { fn go(&self) { ... } }`
//
// mod __derive_broken_foo {
//     use super::BrokenFoo;
//
//     pub trait Helper {
//         fn __concrete_go(&self);
//     }
//
//     impl Helper for BrokenFoo {
//         fn __concrete_go(&self) {
//             self.go(); // ERROR: no method named `go` found for `&BrokenFoo`
//         }
//     }
// }
//
// impl Foo for BrokenFoo {
//     fn go(&self) {
//         use __derive_broken_foo::Helper;
//         self.__concrete_go();
//     }
// }

fn call_foo(f: &dyn Foo) {
    f.go();
}

fn main() {
