// ---------------------------------------------------------------------------
// The unified handler storage type
// ---------------------------------------------------------------------------
type BoxFuture<'a, T> = Pin<Box<dyn Future<Output = T> + Send + 'a>>;

type HandlerFn =
    dyn for<'a> Fn(&'a Request) -> BoxFuture<'a, Response> + Send + Sync + 'static;

pub struct Handler(Arc<HandlerFn>);

// ---------------------------------------------------------------------------
// A helper trait that abstracts over both sync and async handlers.
//
// The key insight: we do NOT use a single generic `Fut` type parameter on
// the impl.  Instead we define an associated type inside the trait so that
// the future type can *depend on the lifetime* of the borrow.  This sidesteps
// the HRTB + opaque-type mismatch that the questioner hit.
// ---------------------------------------------------------------------------
pub trait IntoHandler: Send + Sync + 'static {
    fn call<'a>(&self, req: &'a Request) -> BoxFuture<'a, Response>;
}

// Blanket impl for **async** handlers:
//   F: Fn(&Request) -> Fut,  Fut: Future<Output = Response> + Send
//
// We express the bound with a *helper trait* so we can tie the future's
// lifetime to the borrow lifetime without a bare HRTB on `Fut`.
// ---------------------------------------------------------------------------

/// Marker trait: "F is an async handler"
pub trait AsyncHandlerFn: Send + Sync + 'static {
    type Fut<'a>: Future<Output = Response> + Send + 'a;
    fn call<'a>(&self, req: &'a Request) -> Self::Fut<'a>;
}

impl<F, Fut> AsyncHandlerFn for F
where
    F: for<'a> Fn(&'a Request) -> Fut + Send + Sync + 'static,
    Fut: Future<Output = Response> + Send,
{
    type Fut<'a> = Fut;
    fn call<'a>(&self, req: &'a Request) -> Self::Fut<'a> {
        (self)(req)
    }
}

