// (Response trivially is not a Future, so it won't *match*, but Rust still
// considers overlapping impls).  So we cannot write two blanket IntoHandler
// impls.  Instead we use a small **wrapper new-type** for each case and
// provide From conversions.

pub struct AsyncWrapper<F>(F);
pub struct SyncWrapper<F>(F);

impl<F: AsyncHandlerFn> IntoHandler for AsyncWrapper<F> {
    fn call<'a>(&self, req: &'a Request) -> BoxFuture<'a, Response> {
        Box::pin(self.0.call(req))
    }
}

impl<F> IntoHandler for SyncWrapper<F>
where
    F: Fn(&Request) -> Response + Send + Sync + 'static,
{
    fn call<'a>(&self, req: &'a Request) -> BoxFuture<'a, Response> {
        let resp = (self.0)(req);
        Box::pin(async move { resp })
    }
}

impl<F: IntoHandler> From<F> for Handler {
    fn from(f: F) -> Self {
        Handler(Arc::new(move |req| f.call(req)))
