}

/// Wrap an **async** handler so `add_route` accepts it.
pub fn async_fn<F>(f: F) -> AsyncWrapper<F>
where
    F: AsyncHandlerFn,
{
    AsyncWrapper(f)
}

// ---------------------------------------------------------------------------
// Alternatively – the *truly ergonomic* approach:  provide TWO `add_route`
// variants so the user never has to think about it.
// ---------------------------------------------------------------------------
pub struct Server {
    routes: Vec<(String, Handler)>,
}

impl Server {
    pub fn new() -> Self {
