    /// trait-bound level with *one* generic parameter, callers must use the
    /// `sync_fn()` / `async_fn()` wrappers when using this method.
    pub fn add_route<H: IntoHandler>(&mut self, path: &str, h: H) {
        self.routes.push((path.to_owned(), Handler::from(h)));
