/// Parses a date string as returned by LanceDB into a `DateTime<Utc>`.
///
/// LanceDB may return dates in several forms:
///   - "1970-01-01T00:00:00"          (no fractional seconds, no timezone)
///   - "2025-08-02T17:35:41.409"      (fractional seconds, no timezone)
///   - "2025-08-04T01:48:44.017Z"     (fractional seconds with Z)
///   - "2025-08-04T01:48:44Z"         (no fractional seconds with Z)
///
/// `DateTime::parse_from_str` requires a timezone offset in the string,
/// which these strings don't have. The fix is to parse as `NaiveDateTime`
/// first (which doesn't require a timezone) and then attach UTC.
fn parse_lancedb_date(d: &str) -> Result<DateTime<Utc>, String> {
    // Strip a trailing 'Z' if present so we can always parse as naive
    let trimmed = d.trim_end_matches('Z');

    // Try with fractional seconds first, then without
    let naive = NaiveDateTime::parse_from_str(trimmed, "%Y-%m-%dT%H:%M:%S%.f")
        .or_else(|_| NaiveDateTime::parse_from_str(trimmed, "%Y-%m-%dT%H:%M:%S"))
        .map_err(|e| format!("Failed to parse '{}': {}", d, e))?;

    Ok(DateTime::<Utc>::from_naive_utc_and_offset(naive, Utc))
}

/// Converts a LanceDB date string to a Unix timestamp in milliseconds.
fn date_string_to_millis(d: &str) -> Result<i64, String> {
    let dt = parse_lancedb_date(d)?;
    Ok(dt.timestamp_millis())
}

/// Converts a LanceDB date string to a Unix timestamp in seconds.
fn date_string_to_secs(d: &str) -> Result<i64, String> {
    let dt = parse_lancedb_date(d)?;
    Ok(dt.timestamp())
