use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use tokio::time::{sleep, Duration};

/// Simulates a queue handler that does periodic work.
/// It checks `shutdown_flag` to know when to stop gracefully.
async fn queue_handler_loop(shutdown_flag: Arc<AtomicBool>) {
    info!("Queue handler started.");
    let mut iteration = 0u64;
    loop {
        if shutdown_flag.load(Ordering::SeqCst) {
            info!("Queue handler received shutdown signal. Finishing pending work...");
            // Simulate finishing pending work
            sleep(Duration::from_millis(500)).await;
            info!("Queue handler shut down gracefully.");
            return;
        }
        iteration += 1;
        info!("Queue handler doing work iteration {}...", iteration);
        sleep(Duration::from_secs(2)).await;
    }
}

async fn health() -> HttpResponse {
    HttpResponse::Ok().body("OK")
}

#[actix_web::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Initialize logger
    env_logger::Builder::from_env(env_logger::Env::default().default_filter_or("info")).init();

    info!("Starting the application.");

    // Shared flag to signal the queue handler to shut down
    let shutdown_flag = Arc::new(AtomicBool::new(false));
    let shutdown_flag_clone = shutdown_flag.clone();

    // Create the Actix Web server and obtain its handle for programmatic shutdown
    let server = HttpServer::new(|| {
        App::new()
            .route("/health", web::get().to(health))
    })
    .bind("127.0.0.1:8080")?
    .disable_signals() // We manage signals ourselves
    .run();

    let server_handle = server.handle();

    // Spawn the HTTP server as a background task
    let server_task = rt::spawn(server);

    // Spawn the queue handler as a background task
    let queue_task = tokio::spawn(queue_handler_loop(shutdown_flag_clone));

    info!("Application is running. Press Ctrl+C to shut down.");

    // Wait for Ctrl+C
    tokio::signal::ctrl_c().await.expect("Failed to listen for Ctrl+C");
    info!("Ctrl+C received. Initiating graceful shutdown...");

    // 1. Signal the queue handler to stop
    shutdown_flag.store(true, Ordering::SeqCst);

    // 2. Tell Actix to do a graceful shutdown (true = graceful, waits for in-flight requests)
    server_handle.stop(true).await;
    info!("HTTP server stopped.");

    // 3. Wait for the queue handler to finish its cleanup
    let _ = queue_task.await;
    info!("Queue handler stopped.");

    // 4. Wait for the server task to fully complete
    let _ = server_task.await;

    info!("Application shut down gracefully. No background processes left.");
    Ok(())
}
