  "main.rs": "//! Lazy Asset Loader for Bevy
//!
//! Demonstrates a custom `AssetReader` that intercepts asset paths of the form
//! `"myarchive.zip#textures/foo.png"` and lazily extracts only the requested
//! entry from the zip (or any archive format you plug in).
//!
//! This avoids loading all 3200 textures up-front: each texture is extracted on
//! demand when Bevy's asset server asks for it.
//!
//! To test:
//!   1. Create a folder called `assets/` next to the binary (or next to Cargo.toml
//!      when running with `cargo run`).
//!   2. Put a zip file in it, e.g. `assets/textures.zip`, containing at least one
//!      PNG such as `hello.png` at the zip root.
//!   3. Run `cargo run` – a window will open showing the sprite.
//!
//! The magic path is: `"textures.zip#hello.png"`
//! The part before `#` is resolved relative to `assets/` via the default file
//! reader; the part after `#` is the entry path inside the archive.

use bevy::{
    asset::io::{
        AssetReader, AssetReaderError, AssetSource, AssetSourceId,
        PathStream, Reader,
    },
    prelude::*,
};
use std::{
    io::{Cursor, Read},
    path::{Path, PathBuf},
    sync::Arc,
};

// ---------------------------------------------------------------------------
// 1. A small helper: an in-memory Reader produced from a Vec<u8>
// ---------------------------------------------------------------------------

struct MemoryReader {
    cursor: futures_lite::io::Cursor<Vec<u8>>,
}

impl MemoryReader {
    fn new(data: Vec<u8>) -> Self {
        Self {
            cursor: futures_lite::io::Cursor::new(data),
        }
    }
}

impl futures_lite::io::AsyncRead for MemoryReader {
    fn poll_read(
        mut self: std::pin::Pin<&mut Self>,
        cx: &mut std::task::Context<'_>,
        buf: &mut [u8],
    ) -> std::task::Poll<std::io::Result<usize>> {
        std::pin::Pin::new(&mut self.cursor).poll_read(cx, buf)
    }
}

// ---------------------------------------------------------------------------
// 2. ZipAssetReader – wraps the default (file-system) reader and intercepts
//    paths that contain a '#' separator.
// ---------------------------------------------------------------------------

struct ZipAssetReader {
    /// The default file-based reader Bevy would normally use.
    default_reader: Box<dyn AssetReader>,
}

impl ZipAssetReader {
    fn new(default_reader: Box<dyn AssetReader>) -> Self {
        Self { default_reader }
    }
}

/// Split `"some/archive.zip#inner/path.png"` into
/// `("some/archive.zip", "inner/path.png")`.
fn split_archive_path(path: &Path) -> Option<(PathBuf, String)> {
    let s = path.to_str()?;
    let idx = s.find('#')?;
    let archive = PathBuf::from(&s[..idx]);
    let entry = s[idx + 1..].to_string();
    Some((archive, entry))
}

impl AssetReader for ZipAssetReader {
    fn read<'a>(
        &'a self,
        path: &'a Path,
    ) -> impl std::future::Future<Output = Result<Box<dyn Reader + 'a>, AssetReaderError>> + 'a
    {
        async move {
            // Check whether the path contains '#'
            if let Some((archive_path, entry_name)) = split_archive_path(path) {
                // Use the default reader to fetch the archive bytes
                let mut reader = self.default_reader.read(&archive_path).await?;

                // Read all bytes of the archive into memory
                let mut archive_bytes: Vec<u8> = Vec::new();
                futures_lite::io::AsyncReadExt::read_to_end(&mut reader, &mut archive_bytes)
                    .await
                    .map_err(|e| {
                        AssetReaderError::Io(Arc::new(e))
                    })?;

                // Open the zip and extract the requested entry
                let cursor = Cursor::new(archive_bytes);
                let mut zip = zip::ZipArchive::new(cursor).map_err(|e| {
                    AssetReaderError::Io(Arc::new(std::io::Error::new(
                        std::io::ErrorKind::InvalidData,
                        format!("Failed to open zip archive: {e}"),
                    )))
                })?;

                let mut entry = zip.by_name(&entry_name).map_err(|_| {
                    AssetReaderError::NotFound(path.to_path_buf())
                })?;

                let mut buf = Vec::with_capacity(entry.size() as usize);
                entry.read_to_end(&mut buf).map_err(|e| {
                    AssetReaderError::Io(Arc::new(e))
                })?;

                let boxed: Box<dyn Reader> = Box::new(MemoryReader::new(buf));
                Ok(boxed)
            } else {
                // Not an archive path – fall through to the default reader
                self.default_reader.read(path).await
            }
        }
    }

    fn read_meta<'a>(
        &'a self,
        path: &'a Path,
    ) -> impl std::future::Future<Output = Result<Box<dyn Reader + 'a>, AssetReaderError>> + 'a
    {
        async move {
            if split_archive_path(path).is_some() {
                // No .meta files inside archives
                Err(AssetReaderError::NotFound(path.to_path_buf()))
            } else {
                self.default_reader.read_meta(path).await
            }
        }
    }

    fn read_directory<'a>(
        &'a self,
        path: &'a Path,
    ) -> impl std::future::Future<Output = Result<Box<PathStream>, AssetReaderError>> + 'a {
        self.default_reader.read_directory(path)
    }

    fn is_directory<'a>(
        &'a self,
        path: &'a Path,
    ) -> impl std::future::Future<Output = Result<bool, AssetReaderError>> + 'a {
        self.default_reader.is_directory(path)
    }
}

// ---------------------------------------------------------------------------
// 3. Bevy plugin that replaces the default AssetSource with our zip-aware one
// ---------------------------------------------------------------------------

struct ZipAssetReaderPlugin;

impl Plugin for ZipAssetReaderPlugin {
    fn build(&self, app: &mut App) {
        // Replace the default asset source's reader with our ZipAssetReader.
        app.register_asset_source(
            AssetSourceId::Default,
            AssetSource::build().with_reader(|| {
                // Create the default filesystem reader so we can delegate to it.
                let default_reader = AssetSource::get_default_reader("assets".to_string())();
                Box::new(ZipAssetReader::new(default_reader))
            }),
        );
    }
}

// ---------------------------------------------------------------------------
// 4. Example application
// ---------------------------------------------------------------------------

/// Create a tiny zip file at `assets/textures.zip` containing a generated PNG
/// named `hello.png` so the demo is fully self-contained.
fn ensure_test_assets() {
    let dir = std::path::Path::new("assets");
    std::fs::create_dir_all(dir).ok();

    let zip_path = dir.join("textures.zip");
    if zip_path.exists() {
        return;
    }

    // Generate a simple 64x64 magenta/black checkerboard PNG in memory.
    let (w, h) = (64u32, 64u32);
    let mut img = image::RgbaImage::new(w, h);
    for y in 0..h {
        for x in 0..w {
            let checker = ((x / 8) + (y / 8)) % 2 == 0;
            let color = if checker {
                image::Rgba([255, 0, 255, 255])
            } else {
                image::Rgba([0, 0, 0, 255])
            };
            img.put_pixel(x, y, color);
        }
    }
    let mut png_bytes: Vec<u8> = Vec::new();
    {
        let cursor = Cursor::new(&mut png_bytes);
        let encoder = image::codecs::png::PngEncoder::new(cursor);
        image::ImageEncoder::write_image(
            encoder,
            &img,
            w,
            h,
            image::ExtendedColorType::Rgba8,
        )
        .expect("Failed to encode PNG");
    }

    // Write a zip containing that PNG.
    let file = std::fs::File::create(&zip_path).expect("Failed to create zip file");
    let mut zip_writer = zip::ZipWriter::new(file);
    let options = zip::write::SimpleFileOptions::default()
        .compression_method(zip::CompressionMethod::Stored);
    zip_writer
        .start_file("hello.png", options)
        .expect("zip start_file");
    std::io::Write::write_all(&mut zip_writer, &png_bytes).expect("zip write");
    zip_writer.finish().expect("zip finish");

    println!("Created test asset: {}", zip_path.display());
}

fn main() {
    // Generate a tiny test zip so the demo works out of the box.
    ensure_test_assets();

    App::new()
        // Register our custom reader BEFORE DefaultPlugins so the default
        // asset source uses it.
        .add_plugins(ZipAssetReaderPlugin)
        .add_plugins(DefaultPlugins.set(ImagePlugin::default_nearest()))
        .add_systems(Startup, setup)
        .run();
}

fn setup(mut commands: Commands, asset_server: Res<AssetServer>) {
