use std::pin::Pin;
use std::task::{Context, Poll, RawWaker, RawWakerVTable, Waker};

/// Result of trying to poll a future once without blocking.
enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// Create a no-op waker. When we just want to poll once and check,
/// we don't need a real waker — we won't be waiting for a wake-up.
fn noop_waker() -> Waker {
    fn noop(_: *const ()) {}
    fn clone(_: *const ()) -> RawWaker {
        RawWaker::new(std::ptr::null(), &VTABLE)
    }
    static VTABLE: RawWakerVTable = RawWakerVTable::new(clone, noop, noop, noop);
    unsafe { Waker::from_raw(RawWaker::new(std::ptr::null(), &VTABLE)) }
}

/// Try to poll a pinned future exactly once.
/// - If it resolves immediately (without yielding), return `Ready(value)`.
/// - Otherwise return `Pending`.
fn try_poll<X>(future: Pin<&mut dyn Future<Output = X>>) -> TryPollResult<X> {
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);
    match future.poll(&mut cx) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

// ---------------------------------------------------------------------------
// Demo helpers
// ---------------------------------------------------------------------------

/// A future that resolves immediately (never yields).
async fn instant_value() -> i32 {
    42
}

/// A future that yields at least once before completing.
async fn delayed_value() -> i32 {
    // `tokio::task::yield_now()` causes the future to return Pending once.
    tokio::task::yield_now().await;
    99
}

// ---------------------------------------------------------------------------
// Main – runs inside the tokio runtime
// ---------------------------------------------------------------------------

#[tokio::main]
async fn main() {
    // ---- Case 1: future that completes immediately ----
    println!("=== Case 1: instant future ===");
    {
        let mut fut = Box::pin(instant_value());
        match try_poll(fut.as_mut()) {
            TryPollResult::Ready(val) => {
                println!("  Polled Ready immediately with value: {val}");
            }
            TryPollResult::Pending => {
                println!("  Polled Pending — spawning task to finish it…");
                let handle = tokio::spawn(async move {
                    let val = fut.await;
                    println!("  [spawned task] got value: {val}");
                });
                handle.await.unwrap();
            }
        }
    }

    // ---- Case 2: future that yields (Pending on first poll) ----
    println!("\n=== Case 2: delayed future ===");
    {
        let mut fut = Box::pin(delayed_value());
        match try_poll(fut.as_mut()) {
            TryPollResult::Ready(val) => {
                println!("  Polled Ready immediately with value: {val}");
            }
            TryPollResult::Pending => {
                println!("  Polled Pending — spawning task to finish it…");
                let handle = tokio::spawn(async move {
                    // We already polled once; now just .await to let it finish.
                    let val = fut.await;
                    println!("  [spawned task] got value: {val}");
                });
                handle.await.unwrap();
            }
        }
    }
}
