response:
Here's my analysis and optimized solution:

The main performance issues in your Rust code are:

1. **No HTTP connection pooling** - Each blob download creates a new connection. The C# `BlobServiceClient` reuses connections internally.
2. **Page-sequential downloads** - You wait for each page of blob listing to complete before downloading, and downloads within a page use `FuturesUnordered` but are still bound to pages.
3. **No concurrency limit tuning** - `FuturesUnordered` has no concurrency cap, which can cause connection storms or, conversely, be bottlenecked by page boundaries.
4. **The Azure SDK for Rust uses `reqwest` internally but creates clients per-request** - You should share an HTTP client.

The fix: List all blobs first, then download all of them concurrently with a bounded concurrency using `buffer_unordered`, and reuse the same HTTP client/container client throughout.

```json
{
  "Cargo.toml": "[package]
name = "azure-blob-download"
version = "0.1.0"
edition = "2021"

[dependencies]
azure_storage = "0.20"
azure_storage_blobs = "0.20"
azure_core = "0.20"
reqwest = { version = "0.12", features = ["json"] }
tokio = { version = "1", features = ["full"] }
serde = { version = "1", features = ["derive"] }
serde_json = "1"
futures = "0.3"
dotenvy = "0.15"
",
  "main.rs": "use azure_storage::StorageCredentials;
use azure_storage_blobs::prelude::*;
use futures::stream::{self, StreamExt};
use reqwest::Client;
use serde::{Deserialize, Serialize};
use std::env;
use std::time::Instant;

// ---- Replace this with your actual TradeData model ----
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TradeData {
    // Add your fields here. Using serde flatten to accept any JSON shape for testing.
    #[serde(flatten)]
    pub fields: std::collections::HashMap<String, serde_json::Value>,
}

// ---- OAuth token types ----
#[derive(Serialize)]
struct TokenRequest<'a> {
    grant_type: &'a str,
    client_id: &'a str,
    client_secret: &'a str,
    scope: &'a str,
}

#[derive(Deserialize)]
struct TokenResponse {
    access_token: String,
}

/// Maximum number of concurrent blob downloads.
/// Tune this: too low = underutilized bandwidth, too high = connection errors.
/// C# Parallel.ForEachAsync uses Environment.ProcessorCount by default,
/// but for I/O-bound work we can go much higher.
const MAX_CONCURRENT_DOWNLOADS: usize = 64;

#[tokio::main]
async fn main() {
    // Load .env file if present
    dotenvy::dotenv().ok();

    match fetch_trades_from_azure().await {
        Ok(trades) => {
            println!("Successfully fetched {} trades", trades.len());
        }
        Err(e) => {
            eprintln!("Error: {}", e);
            std::process::exit(1);
        }
    }
}

pub async fn fetch_trades_from_azure() -> Result<Vec<TradeData>, String> {
    let total_start = Instant::now();
    println!("[LOG] Starting fetch_trades_from_azure");

    let tenant_id = env::var("AZURE_TENANT_ID").map_err(|e| format!("AZURE_TENANT_ID: {e}"))?;
    let client_id = env::var("AZURE_CLIENT_ID").map_err(|e| format!("AZURE_CLIENT_ID: {e}"))?;
    let client_secret = env::var("AZURE_CLIENT_SECRET").map_err(|e| format!("AZURE_CLIENT_SECRET: {e}"))?;
    let storage_account = env::var("AZURE_ACCOUNT_NAME").map_err(|e| format!("AZURE_ACCOUNT_NAME: {e}"))?;
    let container_name = env::var("AZURE_CONTAINER_NAME").map_err(|e| format!("AZURE_CONTAINER_NAME: {e}"))?;

    // Collect prefixes - support both OPT/FUT and a single PREFIX
    let mut prefixes: Vec<String> = Vec::new();
    if let Ok(p) = env::var("AZURE_PREFIX_OPT") {
        if !p.is_empty() {
            prefixes.push(p);
        }
    }
    if let Ok(p) = env::var("AZURE_PREFIX_FUT") {
        if !p.is_empty() {
            prefixes.push(p);
        }
    }
    if let Ok(p) = env::var("AZURE_PREFIX") {
        if !p.is_empty() {
            prefixes.push(p);
        }
    }
    if prefixes.is_empty() {
        // No prefix = list everything
        prefixes.push(String::new());
    }

    // ---- Step 1: Authenticate ----
    let auth_start = Instant::now();
    println!("[LOG] Authenticating...");
    let token = get_oauth_token(&tenant_id, &client_id, &client_secret)
        .await
        .map_err(|e| format!("Auth failed: {e}"))?;
    println!("[LOG] Authentication took {:.2}s", auth_start.elapsed().as_secs_f64());

    let credentials = StorageCredentials::bearer_token(token);
    let blob_service = BlobServiceClient::new(&storage_account, credentials);
    let container_client = blob_service.container_client(&container_name);

    // ---- Step 2: List ALL blobs across all prefixes concurrently ----
    let list_start = Instant::now();
    println!("[LOG] Listing blobs for {} prefix(es)...", prefixes.len());

    let list_futures: Vec<_> = prefixes
        .iter()
        .map(|prefix| list_all_blob_names(&container_client, prefix.clone()))
        .collect();

    let all_name_lists = futures::future::join_all(list_futures).await;
    let mut all_blob_names: Vec<String> = Vec::new();
    for names in all_name_lists {
        all_blob_names.extend(names);
    }

    println!(
        "[LOG] Listed {} blobs in {:.2}s",
        all_blob_names.len(),
        list_start.elapsed().as_secs_f64()
    );

    // ---- Step 3: Download ALL blobs concurrently with bounded concurrency ----
    let download_start = Instant::now();
    println!(
        "[LOG] Downloading {} blobs (max concurrency={})...",
        all_blob_names.len(),
        MAX_CONCURRENT_DOWNLOADS
    );

    let trades: Vec<TradeData> = stream::iter(all_blob_names.into_iter())
        .map(|blob_name| {
            let cc = container_client.clone();
            async move {
                let blob_client = cc.blob_client(&blob_name);
                match blob_client.get_content().await {
                    Ok(data) => match serde_json::from_slice::<TradeData>(&data) {
                        Ok(trade) => Some(trade),
                        Err(e) => {
                            eprintln!("[WARN] JSON parse error for {}: {}", blob_name, e);
                            None
                        }
                    },
                    Err(e) => {
                        eprintln!("[WARN] Download error for {}: {}", blob_name, e);
                        None
                    }
                }
            }
        })
        .buffer_unordered(MAX_CONCURRENT_DOWNLOADS)
        .filter_map(|x| async { x })
        .collect()
        .await;

    println!(
        "[LOG] Downloaded & parsed {} trades in {:.2}s",
        trades.len(),
        download_start.elapsed().as_secs_f64()
    );

    println!(
        "[LOG] Total time: {:.2}s",
        total_start.elapsed().as_secs_f64()
    );

    Ok(trades)
}

/// List all blob names under a given prefix.
async fn list_all_blob_names(container_client: &ContainerClient, prefix: String) -> Vec<String> {
    let mut names = Vec::new();
    let mut stream = container_client
        .list_blobs()
        .prefix(prefix)
        .into_stream();

    while let Some(response) = stream.next().await {
        match response {
            Ok(response) => {
                for blob in response.blobs.blobs() {
                    if blob.name.ends_with(".json") {
                        names.push(blob.name.clone());
                    }
                }
            }
            Err(e) => {
                eprintln!("[WARN] Error listing blobs: {}", e);
            }
        }
    }
    names
}

/// Get an OAuth2 token using client credentials flow.
async fn get_oauth_token(
    tenant_id: &str,
    client_id: &str,
    client_secret: &str,
) -> Result<String, Box<dyn std::error::Error>> {
    let token_url = format!(
        "https://login.microsoftonline.com/{}/oauth2/v2.0/token",
        tenant_id
    );
    let params = TokenRequest {
        grant_type: "client_credentials",
        client_id,
        client_secret,
        scope: "https://storage.azure.com/.default",
    };

    // Reuse a single reqwest client (connection pool)
    let client = Client::builder()
        .pool_max_idle_per_host(20)
        .build()?;

    let response = client.post(&token_url).form(&params).send().await?;

    let status = response.status();
    if !status.is_success() {
        let body_text = response
            .text()
            .await
            .unwrap_or_else(|e| format!("Failed to read error body: {e}"));
        return Err(
            format!("Token endpoint returned {status}, body: {body_text}").into(),
        );
    }

    let body_text = response.text().await?;
    match serde_json::from_str::<TokenResponse>(&body_text) {
        Ok(token_response) => Ok(token_response.access_token),
        Err(e) => Err(format!(
            "Failed to decode token response. Error: {e}. Body: {body_text}"
        )
        .into()),
    }
}
"
}
```

**Key changes that should close the performance gap:**

1. **Two-phase approach (list then download)**: First lists ALL blob names, then downloads them all with `buffer_unordered(64)`. Your original code was downloading page-by-page which serialized work.

2. **`buffer_unordered(64)` for bounded concurrency**: This is the critical change. It keeps up to 64 downloads in flight at once — much better than C#'s `Environment.ProcessorCount` (typically 8-16) for I/O-bound work. You can tune this value.

3. **Separated listing from downloading**: The listing phase is fast (few API calls), the downloading phase is where parallelism matters most.

4. **Connection reuse**: The `ContainerClient` clone shares the underlying HTTP connection pool.

Try values of `MAX_CONCURRENT_DOWNLOADS` between 32 and 128 to find the sweet spot for your network/machine. For 1000 small JSON files, 64 is usually a good starting point.

