fn main() -> io::Result<()> {
    // Enable raw mode so we get key-by-key input without waiting for Enter.
    crossterm::terminal::enable_raw_mode()?;

    println!("Starting event loop. Press 'q' to quit.\r");
    println!("The 'Tick!' message now appears every second, independent of key presses.\r");
    io::stdout().flush()?;

    let tick_rate = Duration::from_secs(1);
    let mut last_tick = Instant::now();

    loop {
        // Calculate how much time is left until the next tick.
        let timeout = tick_rate
            .checked_sub(last_tick.elapsed())
            .unwrap_or(Duration::ZERO);

        // `poll` will block for *at most* `timeout`, returning `true` if an
        // event is ready to be read, or `false` if the timeout expired with
        // no event.  This is the idiomatic crossterm pattern for combining
        // timed ticks with user input.
        if event::poll(timeout)? {
            // An event is available — read it (this will NOT block because
            // poll already told us an event is ready).
            let ev = event::read()?;

            // We use \r at the end of lines because raw mode does not
            // translate \n into \r\n.
            println!("- Event received: {:?}\r", ev);
