Here's a self-contained example that demonstrates how to properly serialize complex nested data with FlatBuffers in Rust, including a multithreaded approach using Rayon. The key insight is that you **cannot** share `FlatBufferBuilder` across threads — instead, you do your parallel work (collecting/preparing data) first, then serialize sequentially into the builder.

```json
{
  "Cargo.toml": "[package]
name = "flatbuffer-demo"
version = "0.1.0"
edition = "2021"

[dependencies]
flatbuffers = "24.3.25"
rayon = "1.10"
",
  "main.rs": "//! Self-contained FlatBuffers serialization demo.
//!
//! Key lesson: FlatBufferBuilder is NOT Send/Sync and cannot be shared across
//! threads. The correct pattern is:
//!   1. Do all your parallel/expensive work FIRST (string processing, data
//!      gathering, transformations, etc.) collecting results into plain Rust
//!      types (Vec<String>, Vec<SomeStruct>, etc.).
//!   2. Then, on a SINGLE thread, feed everything into the FlatBufferBuilder
//!      sequentially.
//!
//! This avoids all the borrow-checker and Send/Sync issues.

use rayon::prelude::*;

// ---------------------------------------------------------------------------
// Since we can't run `flatc` in this self-contained example, we'll build the
// FlatBuffer manually using the raw API. This is equivalent to what the
// generated code does under the hood.
// ---------------------------------------------------------------------------
use flatbuffers::{FlatBufferBuilder, WIPOffset, ForwardsUOffset, Vector};

// ---------------------------------------------------------------------------
// Domain types (the "complex data" we want to serialize)
// ---------------------------------------------------------------------------

#[derive(Debug, Clone)]
struct Citation {
    author: String,
    title: String,
    year: u16,
}

#[derive(Debug, Clone)]
struct FrontMatter {
    title: String,
    ignored_parsers: Vec<String>,
}

#[derive(Debug, Clone)]
struct MdxParsingResult {
    content: String,
    front_matter: Option<FrontMatter>,
    citations: Vec<Citation>,
    tags: Vec<String>,
}

// ---------------------------------------------------------------------------
// Serialization helpers – these write into the builder on a SINGLE thread.
// ---------------------------------------------------------------------------

/// Serialize a single Citation into the builder.
/// Table layout (manual):
///   CitationBuffer { author: string, title: string, year: uint16 }
fn serialize_citation<'a>(
    builder: &mut FlatBufferBuilder<'a>,
    citation: &Citation,
) -> WIPOffset<flatbuffers::UnionWIPOffset> {
    let author = builder.create_string(&citation.author);
    let title = builder.create_string(&citation.title);

    // Build table manually:
    let mut cit = builder.start_table();
    builder.push_slot_always(flatbuffers::FieldLoc { id: 0, pad: 0 }, author);
    // We'll use a simpler approach: nested table via finish()
    drop(cit);

    // Actually let's use a cleaner pattern with explicit field indices.
    // For clarity we'll just build a table with ordered fields.
    let start = builder.start_table();
    builder.push_slot_always::<WIPOffset<&str>>(
        flatbuffers::FieldLoc { id: 0, pad: 0 }, author);
    builder.push_slot_always::<WIPOffset<&str>>(
        flatbuffers::FieldLoc { id: 1, pad: 0 }, title);
    builder.push_slot::<u16>(
        flatbuffers::FieldLoc { id: 2, pad: 0 }, citation.year, 0);
    builder.end_table(start)
}

// ---------------------------------------------------------------------------
// The main serialization function demonstrating the correct pattern.
// ---------------------------------------------------------------------------

impl MdxParsingResult {
    /// Serialize `self` into a FlatBuffer byte vec.
    ///
    /// Pattern:
    ///   Phase 1 – parallel: prepare / transform data using Rayon.
    ///   Phase 2 – sequential: feed prepared data into FlatBufferBuilder.
    fn serialize_to_flatbuffer(&self) -> Vec<u8> {
        // ===================================================================
        // PHASE 1: Parallel data preparation
        // ===================================================================

        // Example: uppercase all tags in parallel (simulate expensive work)
        let prepared_tags: Vec<String> = self
            .tags
            .par_iter()
            .map(|tag| {
                // Simulate some expensive transformation
                let mut s = tag.to_uppercase();
                s.push_str("_processed");
                s
            })
            .collect();

        // Example: process ignored_parsers in parallel
        let prepared_ignored_parsers: Vec<String> = self
            .front_matter
            .as_ref()
            .map(|fm| {
                fm.ignored_parsers
                    .par_iter()
                    .map(|p| {
                        // Simulate expensive work
                        format!("processed::{}", p)
                    })
                    .collect()
            })
            .unwrap_or_default();

        // Example: process citations in parallel
        let prepared_citations: Vec<(String, String, u16)> = self
            .citations
            .par_iter()
            .map(|c| {
                // Simulate expensive transformation
                (
                    c.author.to_uppercase(),
                    c.title.clone(),
                    c.year,
                )
            })
            .collect();

        // ===================================================================
        // PHASE 2: Sequential serialization into FlatBufferBuilder
        //
        // NO threading here – the builder is used mutably on one thread only.
        // ===================================================================
        let mut builder = FlatBufferBuilder::with_capacity(1024);

        // --- Serialize citations ---
        let citation_offsets: Vec<WIPOffset<flatbuffers::UnionWIPOffset>> = prepared_citations
            .iter()
            .map(|(author, title, year)| {
                let a = builder.create_string(author);
                let t = builder.create_string(title);
                let start = builder.start_table();
                builder.push_slot_always::<flatbuffers::WIPOffset<&str>>(
                    flatbuffers::FieldLoc { id: 0, pad: 0 }, a);
                builder.push_slot_always::<flatbuffers::WIPOffset<&str>>(
                    flatbuffers::FieldLoc { id: 1, pad: 0 }, t);
                builder.push_slot::<u16>(
                    flatbuffers::FieldLoc { id: 2, pad: 0 }, *year, 0);
                builder.end_table(start)
            })
            .collect();
        let citations_vec = builder.create_vector(&citation_offsets);

        // --- Serialize tags ---
        let tag_offsets: Vec<WIPOffset<&str>> = prepared_tags
            .iter()
            .map(|t| builder.create_string(t))
            .collect();
        let tags_vec = builder.create_vector(&tag_offsets);

        // --- Serialize ignored parsers ---
        let parser_offsets: Vec<WIPOffset<&str>> = prepared_ignored_parsers
            .iter()
            .map(|p| builder.create_string(p))
            .collect();
        let parsers_vec = builder.create_vector(&parser_offsets);

        // --- Serialize front matter ---
        let fm_offset = self.front_matter.as_ref().map(|fm| {
            let title = builder.create_string(&fm.title);
            let start = builder.start_table();
            builder.push_slot_always::<flatbuffers::WIPOffset<&str>>(
                flatbuffers::FieldLoc { id: 0, pad: 0 }, title);
            builder.push_slot_always(
                flatbuffers::FieldLoc { id: 1, pad: 0 }, parsers_vec);
            builder.end_table(start)
        });

        // --- Serialize content ---
        let content = builder.create_string(&self.content);

        // --- Build root table: MdxParsingResultBuffer ---
        let root_start = builder.start_table();
        builder.push_slot_always::<flatbuffers::WIPOffset<&str>>(
            flatbuffers::FieldLoc { id: 0, pad: 0 }, content);
        if let Some(fm) = fm_offset {
            builder.push_slot_always(
                flatbuffers::FieldLoc { id: 1, pad: 0 }, fm);
        }
        builder.push_slot_always(
            flatbuffers::FieldLoc { id: 2, pad: 0 }, citations_vec);
        builder.push_slot_always(
            flatbuffers::FieldLoc { id: 3, pad: 0 }, tags_vec);
        let root = builder.end_table(root_start);

        builder.finish(root, None);

        builder.finished_data().to_vec()
    }
}

// ---------------------------------------------------------------------------
// Main – build sample data, serialize, and verify we get bytes back.
// ---------------------------------------------------------------------------

fn main() {
    let data = MdxParsingResult {
        content: "# Hello World\n\nThis is some **MDX** content.".to_string(),
        front_matter: Some(FrontMatter {
            title: "My Document".to_string(),
