  "main.rs": "//! Demonstration of concurrent read/write to a PTY **without** a shared mutex.
//!
//! The key insight: instead of wrapping a single `Session` in `Arc<Mutex<…>>`
//! (which makes the writer block while the reader sits in a blocking `read()`),
//! we split the PTY master file descriptor into two **independent** owned handles
//! — one for reading, one for writing — so neither side ever blocks the other.
//!
//! This example uses the `portable-pty` crate (works on macOS, Linux, Windows)
//! but the same fd-splitting technique applies to `expectrl`: under the hood
//! `expectrl::Session` wraps a master-fd; you can `try_clone()` it (or `dup(2)`
//! the raw fd) and hand the clone to a reader thread while the original stays
//! with the writer.
//!
//! Run with: cargo run
//! Then type lines into stdin — they are forwarded to the child shell.
//! Everything the shell prints is echoed back to your terminal.
//! Type "exit" (+ Enter) to quit.

use portable_pty::{native_pty_system, CommandBuilder, PtySize};
use std::io::{self, BufRead, Read, Write};
use std::sync::{
    atomic::{AtomicBool, Ordering},
    Arc,
};
use std::thread;
use std::time::Duration;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    // ---------------------------------------------------------------
    // 1. Spawn a child process inside a PTY
    // ---------------------------------------------------------------
    let pty_system = native_pty_system();

    let pair = pty_system.openpty(PtySize {
        rows: 24,
        cols: 80,
        pixel_width: 0,
        pixel_height: 0,
    })?;

    // Use the user's default shell, or fall back to /bin/sh
    let shell = std::env::var("SHELL").unwrap_or_else(|_| "/bin/sh".into());
    let mut cmd = CommandBuilder::new(&shell);
    cmd.env("TERM", "xterm-256color");

    let mut child = pair.slave.spawn_command(cmd)?;
    // We no longer need the slave side in the parent process.
    drop(pair.slave);

    // ---------------------------------------------------------------
    // 2. Obtain **two independent handles** to the master side.
    //    This is the crux of the solution: one handle for reading,
    //    one for writing. No shared mutex needed.
    // ---------------------------------------------------------------
    //  `try_clone_reader()` gives us an owned Read handle.
    //  `try_clone_writer()` gives us an owned Write handle.
    //  They operate on the same underlying PTY fd (via `dup`) so
    //  they can be used from different threads concurrently.
    let mut reader = pair.master.try_clone_reader()?;
    let mut writer = pair.master.try_clone_writer()?;

    // Keep the master alive so the fd isn't closed.
    // We move it into a variable that lives until the end of main.
    let _master = pair.master;

    let done = Arc::new(AtomicBool::new(false));

    // ---------------------------------------------------------------
    // 3. Reader thread — reads from PTY, prints to stdout.
    //    In a Tauri app you would `app_handle.emit("agent-output", …)`
    //    instead of writing to stdout.
    // ---------------------------------------------------------------
    let done_r = done.clone();
    let reader_handle = thread::spawn(move || {
        let mut buf = [0u8; 4096];
        loop {
            match reader.read(&mut buf) {
                Ok(0) => {
                    // EOF — child closed its side
                    break;
                }
                Ok(n) => {
                    let text = String::from_utf8_lossy(&buf[..n]);
                    // In Tauri: app.emit("agent-output", text.to_string());
                    print!("{}", text);
                    let _ = io::stdout().flush();
                }
                Err(e) => {
                    if done_r.load(Ordering::Relaxed) {
                        break;
                    }
                    eprintln!("[reader error] {e}");
                    break;
                }
            }
        }
        done_r.store(true, Ordering::Relaxed);
    });

    // ---------------------------------------------------------------
    // 4. Writer thread — reads lines from stdin, sends to PTY.
    //    In a Tauri app this would be your `send_to_agent` command
    //    which simply calls `writer.write_all(data.as_bytes())`.
    //    **No mutex required** because `writer` is exclusively owned.
    // ---------------------------------------------------------------
    let done_w = done.clone();
    let writer_handle = thread::spawn(move || {
        let stdin = io::stdin();
        for line in stdin.lock().lines() {
            if done_w.load(Ordering::Relaxed) {
                break;
            }
            match line {
                Ok(l) => {
                    // Send the line + carriage return (like pressing Enter in xterm)
                    let payload = format!("{}\r", l);
                    if writer.write_all(payload.as_bytes()).is_err() {
                        break;
                    }
                    let _ = writer.flush();
                }
                Err(_) => break,
            }
        }
        done_w.store(true, Ordering::Relaxed);
    });

    // ---------------------------------------------------------------
    // 5. Wait for the child to exit, then clean up threads.
    // ---------------------------------------------------------------
    let _status = child.wait();
    done.store(true, Ordering::Relaxed);

    // Give threads a moment to notice the flag / EOF, then join.
    thread::sleep(Duration::from_millis(200));
    let _ = reader_handle.join();
    // The writer thread may be blocked on stdin; that's fine for a demo.
    // In production you'd use a channel instead of stdin.
    let _ = writer_handle.join();

    println!("\n[demo finished]");
    Ok(())
}

// ===================================================================
// HOW TO APPLY THIS TO YOUR TAURI + EXPECTRL CODE
// ===================================================================
//
// The root cause of your freeze:
//   Arc<Mutex<Session>> shared between reader thread and send().
//   The reader thread calls `session.read()` while holding the lock.
//   `read()` blocks until the child produces output.
//   Meanwhile `send()` tries to `.lock()` → deadlock / freeze.
//
// The fix — split the fd so reads and writes are independent:
//
// Option A — with `portable-pty` (recommended, cross-platform):
//   Use `master.try_clone_reader()` and `master.try_clone_writer()`
