    pub preposition: bool,
    #[serde(default)]
    pub common: bool,
    pub stress: Option<Stress>,
    pub gender: Option<Gender>,
}

// ===========================================================================
//  APPROACH: Derive a parallel "partial" / "filter" type via a trait.
//
//  The core idea is:
//    1.  For every struct that participates in filtering we create a
//        *mirror* struct where **every** field is wrapped in Option
//        (even fields that are already Option or bool).
//        When the filter JSON omits a field it deserialises to None,
//        meaning "don't care".
//
//    2.  We implement a trait  `MatchesFilter<F>`  on the real type,
//        where `F` is the corresponding filter type.  The method
//        `matches_filter(&self, filter: &F) -> bool`  returns true
//        when every field that IS set in the filter equals the
//        corresponding field in self.  For nested structs the check
//        recurses.
//
//  A declarative macro generates both the filter struct and the
//  MatchesFilter impl so you only have to list the fields once.
// ===========================================================================

pub trait MatchesFilter<F> {
    fn matches_filter(&self, filter: &F) -> bool;
}

// ---- Macro that generates a "Filter" mirror struct + MatchesFilter impl ---

/// For a leaf / scalar field whose real type is `T`, the filter struct
/// stores `Option<T>`.  If the filter value is `Some(v)` we check
/// `*real_value == v`.
///
/// For a nested struct field whose real type is `T` (with filter type
/// `TFilter`), the filter struct stores `Option<TFilter>`.  If the
/// filter value is `Some(f)` we recurse: `real_value.matches_filter(&f)`.
///
/// The macro distinguishes the two cases with a `nested(...)` marker.
///
/// Syntax
/// ------
/// ```ignore
/// define_filter! {
///     /// The real struct       The generated filter struct
///     DictWordMetadata     =>  DictWordMetadataFilter {
///         // plain / leaf fields  ──  filter stores Option<RealType>
///         preposition: bool,
///         common: bool,
///         stress: Option<Stress>,
///         gender: Option<Gender>,
///
///         // nested struct fields ──  filter stores Option<NestedFilter>
///         noun: Option<NounData> => nested(NounDataFilter),
///         verb: Option<VerbData> => nested(VerbDataFilter),
///     }
/// }
/// ```
macro_rules! define_filter {
    (
        $real:ident => $filter:ident {
            $(
                $field:ident : $real_ty:ty
                $( => nested( $nested_filter:ty ) )?
            ),* $(,)?
        }
    ) => {
        // ---- Generate the filter struct ----
        #[derive(Debug, Default, Clone, Serialize, Deserialize)]
        pub struct $filter {
            $(
                pub $field: Option< define_filter!(@filter_inner_ty $real_ty $( , $nested_filter )? ) >,
            )*
        }

        // ---- Generate MatchesFilter impl ----
        impl MatchesFilter<$filter> for $real {
            fn matches_filter(&self, filter: &$filter) -> bool {
                $(
                    if let Some(ref filter_val) = filter.$field {
                        define_filter!(@check self, $field, $real_ty, filter_val $( , $nested_filter )? );
                    }
                )*
                true
            }
        }
    };

    // ---------- helper: compute the inner type stored in the filter Option ----------

    // nested case  ──  store the nested filter type
    (@filter_inner_ty $real_ty:ty , $nested_filter:ty) => { $nested_filter };
    // Option<T> leaf  ──  unwrap one layer so filter stores Option<T> not Option<Option<T>>
    // We detect Option via a tt‑muncher; for simplicity we just store T.
    // Unfortunately declarative macros can't pattern‑match on generic params,
    // so we handle Option<$inner> explicitly with a separate arm below.
    // For non‑Option leaves the filter simply stores the same type.
    (@filter_inner_ty $real_ty:ty) => { $real_ty };

    // ---------- helper: emit the check for one field ----------

    // Nested struct whose real field type is Option<SomeStruct>
    (@check $self_:ident, $field:ident, Option<$inner:ty>, $fv:ident, $nested_filter:ty) => {
        match &$self_.$field {
            Some(ref real_inner) => {
                if !real_inner.matches_filter($fv) {
                    return false;
                }
            }
            None => {
                // The real value is None but the filter demands something → no match
                return false;
            }
        }
    };

    // Leaf field whose real type is Option<T>  (filter_val is &T after unwrapping filter Option)
    (@check $self_:ident, $field:ident, Option<$inner:ty>, $fv:ident) => {
        match &$self_.$field {
            Some(ref real_inner) => {
                if real_inner != $fv {
                    return false;
                }
            }
            None => {
                return false;
            }
        }
    };

    // Leaf field whose real type is a plain value (bool, enum, …)
    (@check $self_:ident, $field:ident, $real_ty:ty, $fv:ident) => {
        if &$self_.$field != $fv {
            return false;
        }
    };
}

// ---------------------------------------------------------------------------
//  Now use the macro for each struct that needs filtering
// ---------------------------------------------------------------------------

define_filter! {
    NounData => NounDataFilter {
        countable: Option<bool>,
        proper: Option<bool>,
