    println!("Filter 1 (stress=Oxitona):  {}", word.matches_filter(&filter1)); // true

    // ---------------------------------------------------------------
    //  Filter 2 – stress doesn't match
    // ---------------------------------------------------------------
    let json2 = r#"{ "stress": "Paroxitona" }"#;
    let filter2: DictWordMetadataFilter = serde_json::from_str(json2).unwrap();
    println!("Filter 2 (stress=Paroxitona): {}", word.matches_filter(&filter2)); // false

    // ---------------------------------------------------------------
    //  Filter 3 – check a nested struct field (noun.countable)
    // ---------------------------------------------------------------
    let json3 = r#"{ "noun": { "countable": true } }"#;
    let filter3: DictWordMetadataFilter = serde_json::from_str(json3).unwrap();
    println!("Filter 3 (noun.countable=true): {}", word.matches_filter(&filter3)); // true

    // ---------------------------------------------------------------
    //  Filter 4 – nested field doesn't match
    // ---------------------------------------------------------------
    let json4 = r#"{ "noun": { "proper": true } }"#;
    let filter4: DictWordMetadataFilter = serde_json::from_str(json4).unwrap();
    println!("Filter 4 (noun.proper=true): {}", word.matches_filter(&filter4)); // false

