  "main.rs": "//! Demonstration of rehydrating a parent span across async boundaries
//! (simulating a Pingora-like proxy where stage callbacks can run on any thread).
//!
//! The key idea:
//!   1. Create a long-lived **request span** when the request arrives.
//!   2. Store a `tracing::Span` handle in a shared context object.
//!   3. In every stage callback, call `context.request_span.enter()` (sync) or
//!      `.in_scope(|| …)` or instrument a future with it so that the stage span
//!      becomes a child of the stored request span – *no matter which thread
//!      the runtime schedules us on*.
//!
//! For **async** code the safest approach is:
//!   • `my_future.instrument(context.request_span.clone())` — this re-attaches
//!     the span every time the future is polled.
//!   • Inside that future you can open a *new* child span normally; it will
//!     automatically become a child of the request span because that span is
//!     the current one while the future is being polled.
//!
//! The resulting trace looks like:
//!
//! |-- request ------------------------------------------------|
//!   |-- stage_1 --|                                            
//!                    |-- stage_2 --|                            
//!                                    |-- upstream_call --|     

use opentelemetry::trace::TracerProvider as _;
use opentelemetry_sdk::{
    trace::{SdkTracerProvider, SpanProcessor},
    Resource,
};
use opentelemetry::KeyValue;
use std::sync::Arc;
use tokio::time::{sleep, Duration};
use tracing::{info, info_span, Instrument};
use tracing_subscriber::{layer::SubscriberExt, util::SubscriberInitExt};

// ---------------------------------------------------------------------------
// Shared context that travels across stage callbacks (like Pingora's CTX).
// ---------------------------------------------------------------------------
struct RequestContext {
    /// The top-level request span.  Clone it and use `.instrument()` /
    /// `.in_scope()` in every stage to re-parent into this span.
    request_span: tracing::Span,
    // You can put other per-request data here.
    pub request_id: String,
}

// ---------------------------------------------------------------------------
// Simulated "proxy trait" – each method is an async stage callback that may
// be called on any Tokio worker thread.
// ---------------------------------------------------------------------------

/// Stage 1: e.g. request filtering
async fn stage_1(ctx: &RequestContext) {
    // Create a child span **inside** the request span.
    let span = info_span!(parent: &ctx.request_span, "stage_1", request_id = %ctx.request_id);

    async {
        info!("stage_1: doing some work");
        sleep(Duration::from_millis(50)).await;
        info!("stage_1: done");
    }
    .instrument(span)
    .await;
}

/// Stage 2: e.g. request transformation
async fn stage_2(ctx: &RequestContext) {
    let span = info_span!(parent: &ctx.request_span, "stage_2", request_id = %ctx.request_id);

    async {
        info!("stage_2: transforming request");
        sleep(Duration::from_millis(40)).await;
        info!("stage_2: done");
    }
    .instrument(span)
    .await;
}

/// Stage 3: upstream call
async fn upstream_call(ctx: &RequestContext) {
    let span = info_span!(parent: &ctx.request_span, "upstream_call", request_id = %ctx.request_id);

    async {
        info!("upstream_call: calling origin");
        sleep(Duration::from_millis(80)).await;
        info!("upstream_call: got response");
    }
    .instrument(span)
    .await;
}

// ---------------------------------------------------------------------------
// An alternative pattern: if you prefer `#[tracing::instrument]` you can
// re-enter the parent span with `.in_scope()` or by wrapping the whole
// function body in `async { … }.instrument(ctx.request_span.clone()).await`.
// ---------------------------------------------------------------------------

/// Shows the alternative `.in_scope()` style (synchronous enter, good for
/// short non-async blocks).
fn _sync_stage_example(ctx: &RequestContext) {
    ctx.request_span.in_scope(|| {
        let _child = info_span!("sync_stage").entered();
        info!("doing sync work");
    });
}

// ---------------------------------------------------------------------------
// Bootstrap
// ---------------------------------------------------------------------------

fn init_tracing() {
    // Export spans to stdout so you can see the trace without a collector.
    let exporter = opentelemetry_stdout::SpanExporter::default();

    let provider = SdkTracerProvider::builder()
        .with_span_processor(
            opentelemetry_sdk::trace::BatchSpanProcessor::builder(exporter)
                .build(),
        )
        .with_resource(Resource::builder().with_attributes([KeyValue::new("service.name", "span-rehydrate-demo")]).build())
        .build();

    let tracer = provider.tracer("demo");

    // Bridge tracing <-> OpenTelemetry
    let otel_layer = tracing_opentelemetry::layer().with_tracer(tracer);

    tracing_subscriber::registry()
        .with(otel_layer)
        .with(
            tracing_subscriber::fmt::layer()
                .with_span_events(tracing_subscriber::fmt::format::FmtSpan::CLOSE)
                .compact(),
        )
        .with(tracing_subscriber::EnvFilter::new("info"))
        .init();

    // Keep the provider alive for the lifetime of the program so spans are
    // flushed on drop.  In a real app you'd store it and call shutdown.
    // For this demo we just leak it.
    Box::leak(Box::new(provider));
}

#[tokio::main]
async fn main() {
    init_tracing();

    // Simulate two concurrent requests to prove each one keeps its own parent.
    let h1 = tokio::spawn(handle_request("req-001".into()));
    let h2 = tokio::spawn(handle_request("req-002".into()));

    let _ = tokio::join!(h1, h2);

    // Give the batch exporter a moment to flush.
    sleep(Duration::from_secs(2)).await;

    info!("all done – check the trace output above");
}

async fn handle_request(request_id: String) {
    // 1️⃣  Create the top-level request span.
    let request_span = info_span!("request", %request_id);

    // 2️⃣  Build the shared context, storing the span handle.
    let ctx = Arc::new(RequestContext {
        request_span: request_span.clone(),
        request_id,
    });

    // 3️⃣  Simulate Pingora dispatching stage callbacks on arbitrary threads.
    //     Each stage re-parents itself under `request_span` via the context.

    // We wrap the entire sequence in the request span so the span stays open
    // for the full duration.
    async {
        // --- stage 1 (may run on any worker) ---
        let c = Arc::clone(&ctx);
        let s1 = tokio::spawn(async move { stage_1(&c).await });
        s1.await.unwrap();

        // --- stage 2 ---
        let c = Arc::clone(&ctx);
        let s2 = tokio::spawn(async move { stage_2(&c).await });
        s2.await.unwrap();

        // --- upstream ---
        let c = Arc::clone(&ctx);
        let s3 = tokio::spawn(async move { upstream_call(&c).await });
        s3.await.unwrap();
    }
    .instrument(request_span)
    .await;
}
"
}
