```json
{
  "Cargo.toml": "[package]
name = "question-location-log"
version = "0.1.0"
edition = "2021"

[dependencies]
dotenvy = "0.15.7"
env_logger = "0.11.8"
log = "0.4.27"
thiserror = "2.0.14"
