  "main.rs": "// Not my real error, I use [actix_web]
#[derive(Debug, thiserror::Error)]
pub enum FrameworkError {
    #[error("400: {0}")]
    Error400(Box<dyn std::error::Error>),
}

pub mod my_library {
    pub mod extensions {
        pub mod logging {
            use crate::FrameworkError;

            /// Helper that does the actual logging with an explicit module path.
            /// This is NOT meant to be called directly by users — use the macro instead,
            /// or call via the trait method which uses the macro internally.
            pub fn log_with_module(
                level: log::Level,
                explicit_module: &str,
                file: &str,
                line: u32,
                message: std::fmt::Arguments<'_>,
            ) {
                log::logger().log(
                    &log::Record::builder()
                        .args(message)
                        .level(level)
                        .target(explicit_module)
                        .module_path(Some(explicit_module))
                        .file(Some(file))
                        .line(Some(line))
                        .build(),
                );
            }

            /// This macro captures `module_path!()` at the **call site** and forwards
            /// it so the log record shows the caller's module, not ours.
            ///
            /// Usage: `log_from_caller!(log::Level::Warn, "format {}", arg);`
            #[macro_export]
            macro_rules! log_from_caller {
                ($level:expr, $($arg:tt)+) => {
                    $crate::my_library::extensions::logging::log_with_module(
                        $level,
                        module_path!(),
                        file!(),
                        line!(),
                        format_args!($($arg)+),
                    )
                };
            }

            /// A trait to extend `Result` with logging + error-conversion helpers.
            ///
            /// Because we need `module_path!()` to resolve at the **call site**, the
            /// trait methods themselves cannot produce the correct module. Instead we
            /// provide a macro [`log_and_explain_400!`] that does everything in one
            /// shot.  However, if you still want `.method()` syntax, you can use the
            /// two-step approach below where the trait carries the caller info that
            /// was captured by a thin wrapper macro.
            pub trait LogChangeErrForRespExt {
                type R;

                fn log_and_explain_400_with_context(
                    self,
                    caller_module: &str,
                    caller_file: &str,
                    caller_line: u32,
                ) -> Self::R;

                fn log_hide_res_with_context(
                    self,
                    caller_module: &str,
                    caller_file: &str,
                    caller_line: u32,
                ) -> Self::R;
            }

            impl<T, E: std::error::Error + 'static> LogChangeErrForRespExt for Result<T, E> {
                type R = Result<T, FrameworkError>;

                fn log_and_explain_400_with_context(
                    self,
                    caller_module: &str,
                    caller_file: &str,
                    caller_line: u32,
                ) -> Self::R {
                    match self {
                        Ok(ok) => Ok(ok),
                        Err(err) => {
                            log_with_module(
                                log::Level::Warn,
                                caller_module,
                                caller_file,
                                caller_line,
                                format_args!(
                                    "{}:{}: Error: {:?}",
                                    caller_file, caller_line, err
                                ),
                            );
                            Err(FrameworkError::Error400(Box::new(err)))
                        }
                    }
                }

                fn log_hide_res_with_context(
                    self,
                    caller_module: &str,
                    caller_file: &str,
                    caller_line: u32,
                ) -> Self::R {
                    match self {
                        Ok(ok) => Ok(ok),
                        Err(err) => {
                            log_with_module(
                                log::Level::Warn,
                                caller_module,
                                caller_file,
                                caller_line,
                                format_args!(
                                    "{}:{}: Hidden error: {:?}",
                                    caller_file, caller_line, err
                                ),
                            );
                            Err(FrameworkError::Error400(
                                Box::new(std::io::Error::new(
                                    std::io::ErrorKind::Other,
                                    "Unexpected error occurred",
                                ))
                            ))
                        }
                    }
                }
            }

            /// Convenience macro that gives you `.log_and_explain_400()` **method-call
            /// style** while still capturing the caller's module.
            ///
            /// Usage:
            /// ```ignore
            /// let val = failing_function().log_and_explain_400!()?;
            /// ```
            ///
            /// This is actually parsed as:
            /// ```ignore
            /// let val = log_and_explain_400!(failing_function())?;
            /// ```
            #[macro_export]
            macro_rules! log_and_explain_400 {
                ($expr:expr) => {{
                    use $crate::my_library::extensions::logging::LogChangeErrForRespExt;
                    ($expr).log_and_explain_400_with_context(
                        module_path!(),
                        file!(),
                        line!(),
                    )
                }};
            }

            #[macro_export]
            macro_rules! log_hide_res {
                ($expr:expr) => {{
                    use $crate::my_library::extensions::logging::LogChangeErrForRespExt;
                    ($expr).log_hide_res_with_context(
                        module_path!(),
                        file!(),
                        line!(),
                    )
                }};
            }
        }
    }
}

pub mod my_application_code {
    pub mod routes_example {
        use crate::my_library::extensions::logging::LogChangeErrForRespExt;

        fn failing_function() -> Result<u32, std::num::ParseIntError> {
            "abc".parse()
        }

        pub fn some_route() -> Result<u32, crate::FrameworkError> {
            log::warn!("This log call is from the correct module");

            // ── Option A: Use the macro (captures module_path at call site) ──
            let long_chain = log_and_explain_400!(failing_function())? + 42;

            Ok(long_chain)
        }

        pub fn some_route_method_style() -> Result<u32, crate::FrameworkError> {
            log::warn!("Method-style demo (with explicit context)");

            // ── Option B: Call the trait method directly, passing context ──
            // This is slightly more verbose but gives you real `.method()` chaining.
            let long_chain = failing_function()
                .log_and_explain_400_with_context(
                    module_path!(),
                    file!(),
                    line!(),
                )? + 42;

            Ok(long_chain)
        }

        pub fn some_route_hide() -> Result<u32, crate::FrameworkError> {
            log::warn!("Hide-style demo");
            let long_chain = log_hide_res!(failing_function())? + 42;
            Ok(long_chain)
        }
    }
}

fn main() {
