  "main.rs": "use serde::Deserialize;
use std::sync::Arc;

/// Our borrowed data structure — uses `&'a str` to avoid copying strings.
#[derive(Deserialize, Debug)]
struct MyData<'a> {
    data: &'a str,
    more_data: &'a str,
}

/// A self-referential wrapper that owns the source `String` and holds
/// the deserialized (borrowed) struct pointing into it.
///
/// We achieve this safely by:
/// 1. Pinning the `String` on the heap via `Arc<String>` so it is never moved.
/// 2. Storing the raw deserialized fields (pointers into that `String`) as
///    plain owned values derived at construction time.
///
/// Because the struct no longer literally contains a reference we avoid
/// lifetime issues, yet we still deserialize only once and never clone
/// the payload.
///
/// We do **not** use `DeserializeOwned` — we call `serde_json::from_str`
/// with a true borrow and then copy only the thin `&str` pairs (pointer +
/// length, 16 bytes each) into owned "fat-pointer" representations.
///
/// Safety argument: `_source` is an `Arc<String>` that is never mutated
/// and lives at least as long as the `ParsedData` value, so the slices
/// remain valid.
struct ParsedData {
    /// Keeps the backing allocation alive.
    _source: Arc<String>,
    /// Pointer + length into `_source`.
    data_ptr: *const str,
    more_data_ptr: *const str,
}

// SAFETY: The backing `String` is behind an `Arc` (heap-allocated, never
// moved, never mutated).  The raw pointers point into that allocation and
// are only dereferenced via `&self` methods, so no data race is possible.
unsafe impl Send for ParsedData {}
unsafe impl Sync for ParsedData {}

impl ParsedData {
    /// Deserialize once from a `String`.  The string is moved into an `Arc`
    /// so the borrowed slices inside `MyData` remain valid.
    fn new(source: String) -> Result<Self, serde_json::Error> {
        let source = Arc::new(source);

        // Deserialize with a genuine borrow — no `DeserializeOwned`.
        // `temp` borrows from `source` which lives on the heap inside the Arc.
        let temp: MyData<'_> = serde_json::from_str(&source)?;

        // Capture the fat pointers (pointer + length) so we can recreate
        // `&str` later without carrying a lifetime.
        let data_ptr: *const str = temp.data;
        let more_data_ptr: *const str = temp.more_data;

        Ok(ParsedData {
            _source: source,
            data_ptr,
            more_data_ptr,
        })
    }

    fn data(&self) -> &str {
        // SAFETY: `_source` is alive and immutable.
        unsafe { &*self.data_ptr }
    }

    fn more_data(&self) -> &str {
        // SAFETY: `_source` is alive and immutable.
        unsafe { &*self.more_data_ptr }
    }
}

impl std::fmt::Debug for ParsedData {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("ParsedData")
            .field("data", &self.data())
            .field("more_data", &self.more_data())
            .finish()
    }
}

#[tokio::main]
async fn main() {
    // Simulate receiving a JSON payload (e.g. from a TCP stream).
    let incoming: String =
        r#"{"data": "hello world", "more_data": "foo bar baz"}"#.to_owned();

    // Deserialize ONCE.  No clone, no DeserializeOwned.
    let parsed = Arc::new(
        ParsedData::new(incoming).expect("failed to deserialize"),
    );

    println!("[main] parsed: {:?}", parsed);

    // Spawn several tokio tasks that share the parsed data.
    let mut handles = Vec::new();

    for i in 0..3 {
        let parsed = Arc::clone(&parsed);
        handles.push(tokio::spawn(async move {
            // Access the borrowed fields from another task / thread.
            println!(
                "[task {}] data = {:?}, more_data = {:?}",
                i,
                parsed.data(),
                parsed.more_data()
            );
        }));
    }

    for h in handles {
        h.await.unwrap();
    }

    println!("All tasks completed successfully.");
}
"
}
```

