  "repr_discriminant/src/lib.rs": "use proc_macro::TokenStream;
use proc_macro2::Span;
use quote::quote;
use syn::parse::{Parse, ParseStream};
use syn::token::Comma;
use syn::{parse_macro_input, Data, DeriveInput, Ident, Type};

const DEFAULT_DISCRIMINANT_METHOD_NAME: &str = "discriminant";

#[proc_macro_attribute]
pub fn repr_discriminant(args: TokenStream, input: TokenStream) -> TokenStream {
    let args: Args = parse_macro_input!(args);
    let typ = args.typ;
    let method_name = args
        .method_name
        .unwrap_or_else(|| Ident::new(DEFAULT_DISCRIMINANT_METHOD_NAME, Span::call_site()));
    let input: DeriveInput = parse_macro_input!(input as DeriveInput);
    let generics = &input.generics;
    let (impl_generics, ty_generics, where_clause) = generics.split_for_impl();
    let name = &input.ident;
    let body = match input.data {
        Data::Enum(_) => {
            // The fix: construct the doc string dynamically so #typ is interpolated
            let safety_doc = format!(
                " This method is safe, because the macro guarantees that the enum is repr({}).",
                quote!(#typ)
            );
            quote! {
                /// Returns the discriminant value of the enum.
                ///
                /// # Safety
                ///
                #[doc = #safety_doc]
                pub const fn #method_name(&self) -> #typ {
                    #[allow(unsafe_code)]
                    unsafe {
                        *::core::ptr::from_ref(self)
                            .cast::<#typ>()
                    }
                }
            }
        }
        _ => unimplemented!(),
    };

    TokenStream::from(quote! {
        #[repr(#typ)]
        #input

        impl #impl_generics #name #ty_generics #where_clause {
            #body
        }
    })
}

struct Args {
    typ: Type,
    method_name: Option<Ident>,
}

impl Parse for Args {
    fn parse(input: ParseStream<'_>) -> syn::Result<Self> {
        let typ: Type = input.parse()?;

        if input.is_empty() {
            return Ok(Self {
                typ,
                method_name: None,
            });
        };

        let _: Comma = input.parse()?;
        let method_name = input.parse()?;

        if !input.is_empty() {
            return Err(input.error("Unexpected tokens after method name"));
        }

        Ok(Self {
            typ,
            method_name,
        })
    }
}
"
}
```

The **key fix** is replacing the static doc comment `/// This method is safe, because the macro guarantees that the enum is repr(#typ).` with a dynamically constructed `#[doc = ...]` attribute:

```rust
let safety_doc = format!(
    " This method is safe, because the macro guarantees that the enum is repr({}).",
    quote!(#typ)
);
// ...
#[doc = #safety_doc]
```

`quote!` does **not** interpolate variables inside string literals (including doc comments, which are syntactic sugar for `#[doc = "..."]`). By using `format!` to build the string with `quote!(#typ)` (which converts the type tokens to a string via `Display`), and then using `#[doc = #safety_doc]` where `#safety_doc` is a `String` that `quote!` *can* interpolate as a token, the type name appears correctly in the generated documentation.

