response:
Here's a solution that uses `Arc<AtomicBool>` as a shared stop flag, combined with non-blocking checks where possible, to allow threads to be stopped from the main function or from each other.

```json
{
  "Cargo.toml": "[package]
name = "event_loop_stop"
version = "0.1.0"
edition = "2021"

[dependencies]
termion = "2.0"
signal-hook = "0.3"
",
  "main.rs": "use std::io::{self, stdin, Read};
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::mpsc::{self, Sender};
use std::sync::Arc;
use std::thread;
use std::time::Duration;

use signal_hook::consts::{SIGINT, SIGTERM};
use signal_hook::iterator::Signals;
use termion::raw::IntoRawMode;

#[derive(Debug)]
enum Message {
    Key(char),
    Signal(i32),
    Quit,
}

fn yield_signals(sender: Sender<Message>, stop_flag: Arc<AtomicBool>) {
    let mut signals = Signals::new(&[SIGINT, SIGTERM]).unwrap();
    // Use the polling iterator so we can check the stop flag periodically
    loop {
        if stop_flag.load(Ordering::Relaxed) {
            break;
        }
        // Poll pending signals with a short timeout
        for sig in signals.pending() {
            match sig {
                SIGINT => {
                    let _ = sender.send(Message::Signal(SIGINT));
                    let _ = sender.send(Message::Quit);
                    stop_flag.store(true, Ordering::Relaxed);
                    return;
                }
                SIGTERM => {
                    let _ = sender.send(Message::Signal(SIGTERM));
                    let _ = sender.send(Message::Quit);
                    stop_flag.store(true, Ordering::Relaxed);
                    return;
                }
                _ => {}
            }
        }
        thread::sleep(Duration::from_millis(100));
    }
}

fn yield_keys(sender: Sender<Message>, stop_flag: Arc<AtomicBool>) {
    // Put stdout into raw mode so keystrokes are delivered immediately
    let _stdout = io::stdout().into_raw_mode().unwrap();

    // We'll read from stdin in a non-blocking fashion using try_clone + set_nonblocking
    // Since std stdin doesn't support non-blocking easily, we use a helper thread
    // that reads one byte at a time, and we check the stop flag between reads.
    //
    // Alternative approach: use a dedicated thread that does blocking reads and
    // we just let it die when the process exits. Here we use a small polling approach
    // with termion's async stdin.
    let mut stdin = termion::async_stdin();
    let mut buf = [0u8; 3];

    loop {
        if stop_flag.load(Ordering::Relaxed) {
            break;
        }

        match stdin.read(&mut buf) {
            Ok(0) => {
                // No data available
                thread::sleep(Duration::from_millis(50));
            }
            Ok(n) => {
                // Parse the bytes we got. For simplicity, handle single ASCII chars.
                for &b in &buf[..n] {
                    let ch = b as char;
                    if ch == 'q' {
                        let _ = sender.send(Message::Quit);
                        stop_flag.store(true, Ordering::Relaxed);
                        return;
                    } else {
                        let _ = sender.send(Message::Key(ch));
                    }
                }
            }
            Err(ref e) if e.kind() == io::ErrorKind::WouldBlock => {
                thread::sleep(Duration::from_millis(50));
            }
            Err(_) => {
                break;
            }
        }
    }
}

fn main() {
    let (sender, receiver) = mpsc::channel();
    let stop_flag = Arc::new(AtomicBool::new(false));

    println!("Event loop started. Press keys to see events. Press 'q' to quit. Send SIGINT/SIGTERM to stop.");
    println!("(Terminal is in raw mode — output may look odd)");

    let sig_sender = sender.clone();
    let sig_stop = stop_flag.clone();
    let signal_handle = thread::spawn(move || {
        yield_signals(sig_sender, sig_stop);
    });

    let key_sender = sender.clone();
    let key_stop = stop_flag.clone();
    let key_handle = thread::spawn(move || {
        yield_keys(key_sender, key_stop);
    });

    // Drop our copy of sender so the channel closes when all threads are done
    drop(sender);

    for msg in receiver.iter() {
        match msg {
            Message::Key(c) => {
                print!("Key pressed: {:?}\r\n", c);
            }
            Message::Signal(sig) => {
                print!("Received signal: {}\r\n", sig);
            }
            Message::Quit => {
                print!("Quit message received. Stopping...\r\n");
                stop_flag.store(true, Ordering::Relaxed);
                break;
            }
        }
    }

    // Wait for threads to notice the stop flag and finish
    let _ = signal_handle.join();
    let _ = key_handle.join();

    println!("Goodbye!");
}
"
}
```

### Key points of the solution:

1. **`Arc<AtomicBool>` as a shared stop flag**: All threads share a reference to the same atomic boolean. Any thread (or the main loop) can set it to `true` to signal all other threads to stop.

2. **Non-blocking / polling reads**: Instead of using blocking iterators like `signals.forever()` or `stdin.events()` (which would block indefinitely and ignore the stop flag), we use:
   - `signals.pending()` — polls for signals without blocking
   - `termion::async_stdin()` — non-blocking stdin reads

   Each thread sleeps briefly (50-100ms) between polls and checks the stop flag.

3. **Graceful shutdown**: When `'q'` is pressed or a signal is received, the thread sends a `Message::Quit`, sets the stop flag, and returns. The main loop sees `Quit`, sets the stop flag too (in case another thread sent it), breaks out, and joins all threads.

