/// the standard `reverse()`, which LLVM is very good at vectorising on both
/// x86-64 (SSSE3 `pshufb` / AVX2) and AArch64 (NEON `rev`/`tbl`).
///
/// Safety: we require that the slice length is a multiple of 4 (which it always
/// is for 4-byte pixels) and we go through `align_to_mut` so alignment is
/// handled automatically.  For the (common) aligned case there is zero overhead.
fn flip_line(line_bytes: &mut [u8]) {
    assert!(
        line_bytes.len() % BYTES_PER_PIXEL == 0,
        "line_bytes length must be a multiple of {BYTES_PER_PIXEL}"
    );

    // SAFETY: u32 has no invalid bit patterns, and we have verified the length
    // is a multiple of 4.  `align_to_mut` gives us a prefix, an aligned middle,
    // and a suffix.  For any 4-byte-aligned allocation (which Vec / array gives
    // us) prefix and suffix will be empty.
    //
    // In the (unlikely) unaligned case we fall back to a manual swap so
    // correctness is always preserved.
    unsafe {
        let (prefix, middle, suffix) = line_bytes.align_to_mut::<u32>();
        if prefix.is_empty() && suffix.is_empty() {
            // Fast path – the whole slice is nicely aligned.
            middle.reverse();
        } else {
            // Fallback – not 4-byte aligned (should be very rare).
            flip_line_fallback(line_bytes);
        }
    }
