    Router,
    extract::{self, ws::{WebSocket, WebSocketUpgrade}},
    http::{HeaderMap, Method, StatusCode, header::CONTENT_TYPE},
    middleware::{self, Next},
    response::{IntoResponse, Response},
    routing::get,
};
use http::HeaderValue;
use tower_http::cors::CorsLayer;

/// The allowed origin hostname for WebSocket connections.
const ALLOWED_ORIGIN: &str = "www.example.com";

/// Middleware that checks the `Origin` header on every request.
/// If the Origin header is present and does not match the allowed origin,
/// the request is rejected with 403 Forbidden.
///
/// This is especially useful for WebSocket upgrade requests, since CORS
/// does not apply to them.
async fn origin_check_middleware(
    headers: HeaderMap,
    request: axum::extract::Request,
    next: Next,
) -> Result<Response, StatusCode> {
    if let Some(origin_value) = headers.get("origin") {
        let origin_str = origin_value.to_str().unwrap_or("");

        let allowed = if let Ok(parsed) = url::Url::parse(origin_str) {
            parsed.host_str() == Some(ALLOWED_ORIGIN)
        } else {
            origin_str == ALLOWED_ORIGIN
        };

        if !allowed {
            println!("Rejected connection from origin: {origin_str}");
            return Err(StatusCode::FORBIDDEN);
        }

        println!("Accepted connection from origin: {origin_str}");
    } else {
        // No Origin header. Non-browser clients (curl, etc.) won't send one.
        // Uncomment the next line to reject requests without an Origin header:
        // return Err(StatusCode::FORBIDDEN);
        println!("No Origin header present – allowing request (non-browser client?)");
    }

    Ok(next.run(request).await)
}

async fn client_handler(
    ws: WebSocketUpgrade,
    extract::Path(session_id): extract::Path<String>,
) -> impl IntoResponse {
    println!("WebSocket upgrade for session: {session_id}");
    ws.on_upgrade(|socket| handle_socket(socket, session_id))
}

async fn handle_socket(mut socket: WebSocket, session_id: String) {
    println!("Client connected to session {session_id}");

    while let Some(msg) = socket.recv().await {
        match msg {
            Ok(msg) => {
                println!("Received from {session_id}: {msg:?}");
                if socket.send(msg).await.is_err() {
                    break;
                }
            }
            Err(e) => {
                println!("Error receiving from {session_id}: {e}");
                break;
            }
        }
    }

    println!("Client disconnected from session {session_id}");
}

async fn index() -> &'static str {
    "WebSocket server is running. Connect via ws://localhost:3000/client/<session_id>"
}

#[tokio::main]
async fn main() {
    let cors_layer = CorsLayer::new()
        .allow_origin(
