                let g = ((fy * pi + time * 1.3).sin() * 0.5 + 0.5) * 255.0;
                let b = (((fx + fy) * pi + time * 0.7).sin() * 0.5 + 0.5) * 255.0;

                shm_slice[offset] = r as u8;
                shm_slice[offset + 1] = g as u8;
                shm_slice[offset + 2] = b as u8;
                offset += 3;
            }
        }

        // Move cursor to top-left
        write!(handle, "\x1b[H").unwrap();

        if first_frame {
            // Transmit and display: t=s (shared memory), f=24 (RGB), action=T
            // The shared memory name is passed without the leading '/'
            write!(
                handle,
                "\x1b_Ga=T,t=s,f=24,s={},v={},i=1,q=2;{}\x1b\\",
                width,
                height,
                &shm_name[1..] // strip leading '/'
            )
            .unwrap();
            first_frame = false;
        } else {
            // For subsequent frames: transmit new data with same id, replacing the old image.
            // We use a=T again with the same id. Kitty will replace the image data.
            // First delete old placement, then re-transmit.
            // d=I deletes by image id
            write!(
                handle,
                "\x1b_Ga=d,d=I,i=1,q=2;\x1b\\"
            )
            .unwrap();
            write!(
                handle,
                "\x1b_Ga=T,t=s,f=24,s={},v={},i=1,q=2;{}\x1b\\",
                width,
                height,
                &shm_name[1..]
            )
            .unwrap();
        }

        handle.flush().unwrap();

        time += 0.1;

        // Frame rate limiting
        let elapsed = frame_start.elapsed();
        if elapsed < target_frame_duration {
            std::thread::sleep(target_frame_duration - elapsed);
        }
    }

    // Cleanup (unreachable in this loop, but for completeness)
    #[allow(unreachable_code)]
    {
        unsafe {
            munmap(shm_ptr, data_size).expect("Failed to munmap");
        }
        shm_unlink(shm_name).expect("Failed to unlink shared memory");
        // Show cursor
        write!(handle, "\x1b[?25h").unwrap();
    }
}
"
}
```

Looking at this problem, the issue is that SCEP clients (like many Microsoft/Apple SCEP implementations) encode the `SignedData` content using PKCS#7 (RFC 2315) conventions, where `EncapsulatedContentInfo.eContent` wraps the content in an `OCTET STRING`. However, the `cms` crate expects CMS (RFC 5652) encoding which is slightly different in how it handles the content.

The specific error about `INTEGER` at position 129 suggests the `SignedData` version or certificate serial number parsing is failing because the inner content structure doesn't match what the `cms` crate expects — specifically, PKCS#7 encodes `eContent` as a raw `ANY` value rather than an `OCTET STRING`.

The fix is to manually parse the `ContentInfo`, extract the `SignedData` bytes, and potentially re-encode or parse them with appropriate handling.

