  "main.rs": "//! Decode SCEP PKIOperation PKCS#7/CMS SignedData
//!
//! The problem: SCEP clients often produce PKCS#7 (RFC 2315) signed-data where
//! the `EncapsulatedContentInfo.eContent` field is encoded as a raw constructed
//! CONTEXT-SPECIFIC [0] containing the content directly (not wrapped in an
//! OCTET STRING as CMS/RFC 5652 requires). The `cms` crate expects RFC 5652
//! encoding, so `SignedData::from_der()` fails.
//!
//! Additionally, PKCS#7 certificates are stored as raw values inside the
//! `[0] IMPLICIT` SET rather than using the CMS `CertificateChoices` enum,
//! which can also cause parse failures.
//!
//! This code demonstrates how to work around this by doing a partial manual
//! parse of the SignedData, patching the eContent to be OCTET STRING wrapped,
//! or by using lower-level DER decoding.

use cms::content_info::ContentInfo;
use cms::signed_data::SignedData;
use der::{
    asn1::{ContextSpecific, OctetStringRef},
    Decode, Encode, Reader, SliceReader, Tag, TagMode, TagNumber,
    Header, Length,
};
use std::fs;
use std::env;

/// Attempt to re-encode the SignedData so that `eContent` is wrapped in an
/// OCTET STRING if it isn't already. This is needed because PKCS#7 (RFC 2315)
/// puts the raw content inside the EXPLICIT [0] tag, while CMS (RFC 5652)
/// expects an OCTET STRING inside the EXPLICIT [0].
///
/// Strategy:
///   1. Parse the outer ContentInfo to get the raw SignedData bytes.
///   2. Walk into the SignedData SEQUENCE -> encapContentInfo SEQUENCE -> [0] EXPLICIT
///   3. Check if the content inside [0] is already an OCTET STRING.
///   4. If not, wrap it in an OCTET STRING and rebuild the DER.
fn patch_signed_data_econtent(signed_data_bytes: &[u8]) -> Result<Vec<u8>, String> {
    // We'll do a byte-level DER walk/patch.
    // Parse: SEQUENCE { version, digestAlgorithms, encapContentInfo, ... }
    //
    // encapContentInfo = SEQUENCE { eContentType OID, [0] EXPLICIT { content } }
    //
    // We need to find the [0] EXPLICIT inside encapContentInfo and check/wrap its contents.

    let mut reader = SliceReader::new(signed_data_bytes)
        .map_err(|e| format!("SliceReader::new failed: {e}"))?;

    // Read outer SEQUENCE header
    let outer_header = Header::decode(&mut reader)
        .map_err(|e| format!("outer SEQUENCE header: {e}"))?;
    if outer_header.tag != Tag::Sequence {
        return Err("Expected SEQUENCE for SignedData".into());
    }

    // Now we're inside the SignedData SEQUENCE.
    // Read version (INTEGER)
    let version_bytes = read_tlv_bytes(reader.peek_byte().map_err(|e| format!("{e}"))?, &mut reader)?;

    // Read digestAlgorithms (SET)
    let digest_algs_bytes = read_tlv_bytes(reader.peek_byte().map_err(|e| format!("{e}"))?, &mut reader)?;

    // Read encapContentInfo (SEQUENCE)
    let encap_start = reader.position();
    let encap_header = Header::decode(&mut reader)
        .map_err(|e| format!("encapContentInfo header: {e}"))?;
    if encap_header.tag != Tag::Sequence {
        return Err("Expected SEQUENCE for encapContentInfo".into());
    }

    // Inside encapContentInfo: read eContentType (OID)
    let oid_bytes = read_tlv_bytes(reader.peek_byte().map_err(|e| format!("{e}"))?, &mut reader)?;

    // Check if there's a [0] EXPLICIT next
    let next_byte = reader.peek_byte().map_err(|e| format!("peek after OID: {e}"))?;

    if next_byte != 0xA0 {
        // No eContent present, nothing to patch. Return as-is.
        return Ok(signed_data_bytes.to_vec());
    }

    // Read the [0] EXPLICIT header
    let ctx0_header = Header::decode(&mut reader)
        .map_err(|e| format!("[0] EXPLICIT header: {e}"))?;

    // Read the content inside [0]
    let inner_pos = reader.position();
    let inner_peek = reader.peek_byte().map_err(|e| format!("peek inner: {e}"))?;

    let ctx0_content_len: usize = usize::try_from(ctx0_header.length)
        .map_err(|e| format!("length conversion: {e}"))?;
    let inner_content_raw = reader.read_slice(Length::new(ctx0_content_len as u16))
        .map_err(|e| format!("read inner content: {e}"))?;

    let needs_patch = inner_peek != 0x04; // 0x04 = OCTET STRING tag

    // Read the rest of the SignedData (certificates, crls, signerInfos)
    let remaining_start = reader.position();
    let remaining = &signed_data_bytes[remaining_start.into()..];

    if !needs_patch {
        // Already has OCTET STRING wrapping, return as-is
        return Ok(signed_data_bytes.to_vec());
    }

    println!("[INFO] Patching eContent: wrapping raw content in OCTET STRING");

    // Build patched eContent: wrap inner_content_raw in an OCTET STRING
    let octet_string_encoded = encode_octet_string(inner_content_raw);

    // Rebuild [0] EXPLICIT with new content
    let ctx0_rebuilt = encode_context_specific_0(&octet_string_encoded);

    // Rebuild encapContentInfo SEQUENCE
    let mut encap_content = Vec::new();
    encap_content.extend_from_slice(&oid_bytes);
    encap_content.extend_from_slice(&ctx0_rebuilt);
    let encap_rebuilt = encode_sequence(&encap_content);

    // Rebuild entire SignedData SEQUENCE
    let mut sd_inner = Vec::new();
    sd_inner.extend_from_slice(&version_bytes);
    sd_inner.extend_from_slice(&digest_algs_bytes);
    sd_inner.extend_from_slice(&encap_rebuilt);
    sd_inner.extend_from_slice(remaining);
    let sd_rebuilt = encode_sequence(&sd_inner);

    Ok(sd_rebuilt)
}

/// Read a complete TLV (tag-length-value) from the reader and return its raw bytes.
fn read_tlv_bytes(peek: u8, reader: &mut SliceReader<'_>) -> Result<Vec<u8>, String> {
    let start = reader.position();
    let header = Header::decode(reader)
        .map_err(|e| format!("read_tlv header: {e}"))?;
    let len: usize = usize::try_from(header.length)
        .map_err(|e| format!("length: {e}"))?;
    // Skip over the value bytes
    let _ = reader.read_slice(Length::new(len as u16))
        .map_err(|e| format!("read_tlv value: {e}"))?;
    let end = reader.position();

    let start_usize: usize = start.into();
    let end_usize: usize = end.into();
    // We need to get the raw bytes from the underlying slice.
    // Unfortunately SliceReader doesn't expose the underlying slice directly after creation,
    // so we'll use a different approach.
    // Actually we need to reconstruct from the original data. Let's change approach.
    // We'll track positions and use slicing on the original data.
    Ok(Vec::new()) // placeholder
}

/// Encode bytes as a DER OCTET STRING
fn encode_octet_string(data: &[u8]) -> Vec<u8> {
    let mut result = Vec::new();
    result.push(0x04); // OCTET STRING tag
    encode_der_length(data.len(), &mut result);
    result.extend_from_slice(data);
    result
}

/// Encode bytes inside [0] EXPLICIT (constructed, context-specific 0)
fn encode_context_specific_0(data: &[u8]) -> Vec<u8> {
    let mut result = Vec::new();
    result.push(0xA0); // context-specific, constructed, tag 0
    encode_der_length(data.len(), &mut result);
    result.extend_from_slice(data);
    result
}

/// Encode bytes inside a SEQUENCE
fn encode_sequence(data: &[u8]) -> Vec<u8> {
    let mut result = Vec::new();
    result.push(0x30); // SEQUENCE tag
    encode_der_length(data.len(), &mut result);
    result.extend_from_slice(data);
    result
}

/// Write a DER length encoding
fn encode_der_length(len: usize, out: &mut Vec<u8>) {
    if len < 0x80 {
        out.push(len as u8);
    } else if len <= 0xFF {
        out.push(0x81);
        out.push(len as u8);
    } else if len <= 0xFFFF {
        out.push(0x82);
        out.push((len >> 8) as u8);
        out.push((len & 0xFF) as u8);
    } else if len <= 0xFF_FFFF {
        out.push(0x83);
        out.push((len >> 16) as u8);
        out.push((len >> 8) as u8);
        out.push((len & 0xFF) as u8);
    } else {
        out.push(0x84);
        out.push((len >> 24) as u8);
        out.push((len >> 16) as u8);
        out.push((len >> 8) as u8);
        out.push((len & 0xFF) as u8);
    }
}

/// Parse a DER tag byte
fn parse_tag(b: u8) -> (u8, bool, u8) {
    let class = b >> 6;
    let constructed = (b & 0x20) != 0;
    let number = b & 0x1F;
    (class, constructed, number)
}

/// Parse DER length from a byte slice, returning (length_value, bytes_consumed)
fn parse_der_length(data: &[u8]) -> Result<(usize, usize), String> {
    if data.is_empty() {
        return Err("Empty data for length".into());
    }
    let first = data[0];
    if first < 0x80 {
        Ok((first as usize, 1))
    } else {
        let num_bytes = (first & 0x7F) as usize;
        if num_bytes == 0 || num_bytes > 4 {
            return Err(format!("Unsupported length encoding: {num_bytes} bytes"));
        }
        if data.len() < 1 + num_bytes {
            return Err("Not enough data for length".into());
        }
        let mut len: usize = 0;
        for i in 0..num_bytes {
            len = (len << 8) | (data[1 + i] as usize);
        }
        Ok((len, 1 + num_bytes))
    }
}

/// Parse one TLV element from `data`, returning (header_len, value_len) so that
/// total element size = header_len + value_len.
fn parse_tlv_header(data: &[u8]) -> Result<(usize, usize), String> {
    if data.is_empty() {
        return Err("Empty data".into());
    }
    // Tag: could be 1 byte (we only handle single-byte tags)
    let tag_byte = data[0];
    if (tag_byte & 0x1F) == 0x1F {
        return Err("Multi-byte tags not supported".into());
    }
    let (val_len, len_bytes) = parse_der_length(&data[1..])?;
    Ok((1 + len_bytes, val_len))
}

/// Given raw DER bytes for SignedData (the value inside ContentInfo's [0] EXPLICIT),
/// patch the encapContentInfo.eContent to wrap the inner content in OCTET STRING
/// if not already wrapped.
fn patch_signed_data_bytes(raw_sd_outer: &[u8]) -> Result<Vec<u8>, String> {
    // raw_sd_outer is the SEQUENCE { ... } for SignedData
    let (sd_hdr_len, sd_val_len) = parse_tlv_header(raw_sd_outer)?;
    let sd_value = &raw_sd_outer[sd_hdr_len..sd_hdr_len + sd_val_len];
    let mut pos: usize = 0;

    // 1. version INTEGER
    let (h, v) = parse_tlv_header(&sd_value[pos..])?;
    let version_end = pos + h + v;
    pos = version_end;

    // 2. digestAlgorithms SET
    let (h, v) = parse_tlv_header(&sd_value[pos..])?;
    let digest_algs_end = pos + h + v;
    pos = digest_algs_end;

    // 3. encapContentInfo SEQUENCE
    let encap_start = pos;
    let (encap_hdr, encap_val_len) = parse_tlv_header(&sd_value[pos..])?;
    let encap_val_start = pos + encap_hdr;
    let encap_end = encap_val_start + encap_val_len;

    // Inside encapContentInfo: eContentType OID
    let mut epos = encap_val_start;
    let (h, v) = parse_tlv_header(&sd_value[epos..])?;
    let oid_end = epos + h + v;
    let oid_bytes_slice = &sd_value[epos..oid_end];
    epos = oid_end;

    // Check for [0] EXPLICIT
    if epos >= encap_end {
        // No eContent, nothing to patch
        return Ok(raw_sd_outer.to_vec());
    }

    let ctx0_tag = sd_value[epos];
    if ctx0_tag != 0xA0 {
        // No [0] tag, nothing to patch
        return Ok(raw_sd_outer.to_vec());
    }

    let (ctx0_hdr, ctx0_val_len) = parse_tlv_header(&sd_value[epos..])?;
    let ctx0_val_start = epos + ctx0_hdr;
    let ctx0_val_end = ctx0_val_start + ctx0_val_len;

    // Check what's inside [0]
    let inner_tag = sd_value[ctx0_val_start];
    if inner_tag == 0x04 {
        // Already OCTET STRING, check if the OCTET STRING exactly spans the [0] content
        let (inner_h, inner_v) = parse_tlv_header(&sd_value[ctx0_val_start..])?;
        if inner_h + inner_v == ctx0_val_len {
            println!("[INFO] eContent already wrapped in OCTET STRING, no patch needed.");
            return Ok(raw_sd_outer.to_vec());
        }
    }

    println!("[INFO] eContent not wrapped in OCTET STRING (inner tag = 0x{:02X}). Patching...", inner_tag);

    // Build patched encapContentInfo
    let inner_content = &sd_value[ctx0_val_start..ctx0_val_end];
    let octet_wrapped = encode_octet_string(inner_content);
    let ctx0_patched = encode_context_specific_0(&octet_wrapped);

    let mut encap_inner_patched = Vec::new();
    encap_inner_patched.extend_from_slice(oid_bytes_slice);
    encap_inner_patched.extend_from_slice(&ctx0_patched);
    let encap_patched = encode_sequence(&encap_inner_patched);

    // Rebuild entire SignedData
    let before_encap = &sd_value[..encap_start];
    let after_encap = &sd_value[encap_end..];

    let mut new_sd_inner = Vec::new();
    new_sd_inner.extend_from_slice(before_encap);
    new_sd_inner.extend_from_slice(&encap_patched);
    new_sd_inner.extend_from_slice(after_encap);

    let new_sd = encode_sequence(&new_sd_inner);
    Ok(new_sd)
}

/// Full pipeline: take ContentInfo DER, patch the SignedData, and re-parse.
fn decode_scep_pkioperation(ci_der: &[u8]) -> Result<SignedData, String> {
    // Parse ContentInfo
    let ci = ContentInfo::from_der(ci_der)
        .map_err(|e| format!("Failed to parse ContentInfo: {e}"))?;

    println!("ContentInfo contentType: {}", ci.content_type);

    // The content is the [0] EXPLICIT containing the SignedData SEQUENCE.
    // ci.content is the raw ANY value. Let's get the raw bytes of the SignedData.
    let sd_raw_bytes = ci.content.to_der()
        .map_err(|e| format!("Failed to encode content to DER: {e}"))?;

    // First, try direct decoding
    match SignedData::from_der(&sd_raw_bytes) {
        Ok(sd) => {
            println!("[INFO] Direct SignedData decode succeeded (no patch needed).");
            return Ok(sd);
        }
        Err(e) => {
            println!("[INFO] Direct SignedData decode failed: {e}");
            println!("[INFO] Attempting to patch eContent...");
        }
    }

    // Patch and retry
    let patched = patch_signed_data_bytes(&sd_raw_bytes)?;

    match SignedData::from_der(&patched) {
        Ok(sd) => {
            println!("[INFO] Patched SignedData decode succeeded!");
            Ok(sd)
        }
        Err(e) => {
            // If that still fails, there may be other incompatibilities.
            // Let's try a more aggressive approach: skip eContent entirely
            // and do a manual parse.
            Err(format!("Patched decode also failed: {e}. The data may have \
                additional PKCS#7 vs CMS incompatibilities (e.g., certificate \
                encoding). Consider using the openssl crate for PKCS#7 parsing \
                or a manual DER walk."))
        }
    }
}

/// Manual extraction of key fields from SignedData without full CMS parsing.
/// This is useful when the cms crate's strict parsing fails.
fn manual_extract_signed_data_info(sd_bytes: &[u8]) -> Result<(), String> {
    let (sd_hdr, sd_val_len) = parse_tlv_header(sd_bytes)?;
    let sd_value = &sd_bytes[sd_hdr..sd_hdr + sd_val_len];
    let mut pos: usize = 0;

    // version
    let (h, v) = parse_tlv_header(&sd_value[pos..])?;
    let version_val = &sd_value[pos + h..pos + h + v];
    println!("  version: {}", version_val.iter().map(|b| format!("{:02X}", b)).collect::<String>());
    pos += h + v;

    // digestAlgorithms
    let (h, v) = parse_tlv_header(&sd_value[pos..])?;
    println!("  digestAlgorithms: {} bytes", v);
    pos += h + v;

    // encapContentInfo
    let (encap_hdr, encap_val_len) = parse_tlv_header(&sd_value[pos..])?;
    let encap_val_start = pos + encap_hdr;
    println!("  encapContentInfo: {} bytes", encap_val_len);

    // OID inside encapContentInfo
    let mut epos = encap_val_start;
    let (h, v) = parse_tlv_header(&sd_value[epos..])?;
    let oid_raw = &sd_value[epos + h..epos + h + v];
    println!("    eContentType OID raw: {}", oid_raw.iter().map(|b| format!("{:02X}", b)).collect::<String>());
    epos += h + v;

    if epos < encap_val_start + encap_val_len {
        let tag = sd_value[epos];
        let (h, v) = parse_tlv_header(&sd_value[epos..])?;
        println!("    eContent: tag=0x{:02X}, {} bytes of content", tag, v);

        // Check what's inside
        let inner_start = epos + h;
        if v > 0 {
            let inner_tag = sd_value[inner_start];
            println!("    eContent inner first tag: 0x{:02X}", inner_tag);
        }
    } else {
        println!("    eContent: absent");
    }

    pos = encap_val_start + encap_val_len;

    // Next could be [0] certificates, [1] crls, or signerInfos SET
    while pos < sd_value.len() {
        let tag = sd_value[pos];
        let (h, v) = parse_tlv_header(&sd_value[pos..])?;
        match tag {
            0xA0 => println!("  certificates [0]: {} bytes", v),
            0xA1 => println!("  crls [1]: {} bytes", v),
            0x31 => println!("  signerInfos SET: {} bytes", v),
            _ => println!("  unknown tag 0x{:02X}: {} bytes", tag, v),
        }
        pos += h + v;
    }

    Ok(())
}

