                    println!("  eContent present: {}", sd.encap_content_info.econtent.is_some());
                }
                Err(e) => println!("\nPatched parse: FAILED: {e}"),
            }
        }
        Err(e) => println!("Patch failed: {e}"),
    }

    // Now demonstrate CMS-style (correct) encoding
    println!("\n--- For comparison: CMS-style (correct) encoding ---");

    let octet_wrapped = encode_octet_string(&inner_as_seq);
    let ctx0_cms = encode_context_specific_0(&octet_wrapped);

    let mut encap_inner_cms = Vec::new();
    encap_inner_cms.extend_from_slice(&oid_der);
    encap_inner_cms.extend_from_slice(&ctx0_cms);
    let encap_ci_cms = encode_sequence(&encap_inner_cms);

    let mut sd_inner_cms = Vec::new();
    sd_inner_cms.extend_from_slice(&version_der);
    sd_inner_cms.extend_from_slice(&digest_algs);
    sd_inner_cms.extend_from_slice(&encap_ci_cms);
    sd_inner_cms.extend_from_slice(&signer_infos);
    let sd_seq_cms = encode_sequence(&sd_inner_cms);

    match SignedData::from_der(&sd_seq_cms) {
        Ok(sd) => {
            println!("CMS-style parse: SUCCESS");
            println!("  version: {:?}", sd.version);
            println!("  eContent present: {}", sd.encap_content_info.econtent.is_some());
        }
        Err(e) => println!("CMS-style parse: FAILED: {e}"),
    }
}
"
}
```

**Key points about the solution:**

1. **Root Cause**: SCEP clients (especially Microsoft NDES, Apple MDM, etc.) produce PKCS#7 (RFC 2315) encoding where `EncapsulatedContentInfo.eContent` contains raw content directly inside the `[0] EXPLICIT` tag. The `cms` crate expects CMS (RFC 5652) encoding where the content must be wrapped in an `OCTET STRING` inside `[0]`.

2. **The Fix**: The code performs a byte-level DER walk through the `SignedData` structure, finds the `eContent` field, checks if its contents are already an `OCTET STRING`, and if not, wraps them in one before re-serializing.

3. **Usage**: Run with `cargo run -- ci.der` where `ci.der` is your SCEP PKIOperation DER file. Without a file, it demonstrates the patching logic with synthetic data.

4. **Fallback**: If patching still fails (due to other PKCS#7 vs CMS differences like certificate encoding), the code provides a manual DER structure analyzer and suggests alternatives like the `openssl` crate.

