/// Recursively resolve all `{"$ref": "<file>#/<json_pointer>"}` nodes
/// found anywhere in a `serde_json::Value` tree.
///
/// Supported `$ref` format:  `./relative/path.json#/pointer/parts`
fn resolve_refs(value: &mut Value, base_dir: &std::path::Path) {
    match value {
        Value::Object(map) => {
            // Check whether this object is a $ref node
            if map.len() == 1 {
                if let Some(Value::String(ref_str)) = map.get("$ref") {
                    if let Some(resolved) = follow_ref(ref_str, base_dir) {
                        *value = resolved;
                        // The resolved value itself could contain further $ref nodes
                        resolve_refs(value, base_dir);
                        return;
                    }
                }
            }
            // Otherwise recurse into every value of the object
            for (_k, v) in map.iter_mut() {
                resolve_refs(v, base_dir);
            }
        }
        Value::Array(arr) => {
            for v in arr.iter_mut() {
                resolve_refs(v, base_dir);
            }
        }
        _ => {}
