/// Parse a `$ref` string of the form `<file_path>#/<json_pointer>`,
/// read the referenced file, and extract the value at the given
/// JSON Pointer location.
fn follow_ref(ref_str: &str, base_dir: &std::path::Path) -> Option<Value> {
    // Split on the first '#'
    let (file_part, pointer_part) = match ref_str.split_once('#') {
        Some((f, p)) => (f, p),
        None => (ref_str, ""),
    };

    let file_path = base_dir.join(file_part);
    let contents = fs::read_to_string(&file_path)
