        .unwrap_or_else(|e| panic!("failed to parse {:?}: {}", file_path, e));

    // Recursively resolve any $ref nodes inside the referenced file as well
    let ref_base = file_path.parent().unwrap_or(base_dir);
    resolve_refs(&mut root, ref_base);

    if pointer_part.is_empty() || pointer_part == "/" {
        Some(root)
    } else {
        root.pointer(pointer_part).cloned()
