{
  "Cargo.toml": "[package]
name = "block-gizmo-demo"
version = "0.1.0"
edition = "2021"

[dependencies]
bevy = "0.15"
",
  "main.rs": "use bevy::prelude::*;
use bevy::color::palettes::css;
use bevy::window::PrimaryWindow;
use bevy::math::Ray3d;

fn main() {
    App::new()
        .add_plugins(DefaultPlugins)
        .add_systems(Startup, setup)
        .add_systems(Update, (rotate_cube, cast_ray_and_draw_gizmo))
        .run();
}

#[derive(Component)]
struct Block;

#[derive(Component)]
struct MainCamera;

fn setup(
    mut commands: Commands,
    mut meshes: ResMut<Assets<Mesh>>,
    mut materials: ResMut<Assets<StandardMaterial>>,
) {
    // Cube
    commands.spawn((
        Mesh3d(meshes.add(Cuboid::new(1.0, 1.0, 1.0))),
        MeshMaterial3d(materials.add(StandardMaterial {
            base_color: Color::srgb(0.3, 0.5, 0.8),
            ..default()
        })),
        Transform::from_xyz(0.0, 0.5, 0.0),
        Block,
    ));

    // Floor
    commands.spawn((
        Mesh3d(meshes.add(Plane3d::default().mesh().size(10.0, 10.0))),
        MeshMaterial3d(materials.add(StandardMaterial {
            base_color: Color::srgb(0.4, 0.4, 0.4),
            ..default()
        })),
        Transform::from_xyz(0.0, 0.0, 0.0),
    ));

    // Light
    commands.spawn((
        PointLight {
            intensity: 2_000_000.0,
            shadows_enabled: true,
            ..default()
        },
        Transform::from_xyz(4.0, 8.0, 4.0),
    ));

    // Camera
    commands.spawn((
        Camera3d::default(),
        Transform::from_xyz(3.0, 3.0, 3.0).looking_at(Vec3::new(0.0, 0.5, 0.0), Vec3::Y),
        MainCamera,
    ));
}

fn rotate_cube(
    time: Res<Time>,
    keyboard: Res<ButtonInput<KeyCode>>,
    mut query: Query<&mut Transform, With<Block>>,
) {
    for mut xf in &mut query {
        if keyboard.pressed(KeyCode::KeyQ) {
            xf.rotate(Quat::from_rotation_y(time.delta_secs() * 1.0));
        }
        if keyboard.pressed(KeyCode::KeyE) {
            xf.rotate(Quat::from_rotation_y(-time.delta_secs() * 1.0));
        }
        if keyboard.pressed(KeyCode::KeyW) {
            xf.rotate(Quat::from_rotation_x(time.delta_secs() * 1.0));
        }
        if keyboard.pressed(KeyCode::KeyS) {
            xf.rotate(Quat::from_rotation_x(-time.delta_secs() * 1.0));
        }
        if keyboard.pressed(KeyCode::KeyA) {
            xf.rotate(Quat::from_rotation_z(time.delta_secs() * 1.0));
        }
        if keyboard.pressed(KeyCode::KeyD) {
            xf.rotate(Quat::from_rotation_z(-time.delta_secs() * 1.0));
        }
    }
}

/// Perform a manual ray-AABB (OBB) intersection against the cube,
/// determine which face was hit, and draw a gizmo rect flush with that face.
fn cast_ray_and_draw_gizmo(
    windows: Query<&Window, With<PrimaryWindow>>,
    camera_q: Query<(&Camera, &GlobalTransform), With<MainCamera>>,
    block_q: Query<&GlobalTransform, With<Block>>,
    mut gizmos: Gizmos,
) {
    let Ok(window) = windows.get_single() else { return };
    let Some(cursor_pos) = window.cursor_position() else { return };
    let Ok((camera, cam_gt)) = camera_q.get_single() else { return };
    let Ok(ray) = camera.viewport_to_world(cam_gt, cursor_pos) else { return };

    for block_gt in &block_q {
        let block_transform = block_gt.compute_transform();
        let block_pos = block_transform.translation;
        let block_rot = block_transform.rotation;
        let half_size = Vec3::splat(0.5); // unit cube half-extents

        // Transform ray into the cube's local space
        let inv_rot = block_rot.inverse();
        let local_origin = inv_rot * (ray.origin - block_pos);
        let local_dir = inv_rot * *ray.direction;

        // Ray-AABB intersection in local space
        if let Some((t, face_normal_local)) = ray_aabb_intersection(local_origin, local_dir, half_size) {
            if t < 0.0 { continue; }

            // Hit point in world space
            let hit_point_local = local_origin + local_dir * t;
            let _ = hit_point_local;

            // Face center in local space
            let face_center_local = face_normal_local * 0.5;
            // Face center in world space
            let face_center_world = block_pos + block_rot * face_center_local;

            // World-space face normal
            let face_normal_world = (block_rot * face_normal_local).normalize();

            // Now we need a full orientation for the gizmo rectangle.
            // The rectangle's Z axis should point along face_normal_world,
            // and the X/Y axes should align with the cube's edges on that face.
            //
            // We pick the local tangent and bitangent for each face:
            let (local_tangent, local_bitangent) = face_tangents(face_normal_local);

            let world_tangent = (block_rot * local_tangent).normalize();
            let world_bitangent = (block_rot * local_bitangent).normalize();

            // Build rotation matrix: columns are (X=tangent, Y=bitangent, Z=normal)
            let rot_mat = Mat3::from_cols(world_tangent, world_bitangent, face_normal_world);
            let gizmo_rot = Quat::from_mat3(&rot_mat).normalize();

            let gizmo_pos = face_center_world + face_normal_world * 0.01;

            gizmos.rect(
                Isometry3d::new(gizmo_pos, gizmo_rot),
                Vec2::new(1.0, 1.0),
                Color::from(css::WHITE),
            );

            // Also draw the normal as an arrow for debugging
            gizmos.arrow(
                face_center_world,
                face_center_world + face_normal_world * 0.5,
                Color::from(css::YELLOW),
            );
        }
    }
}

/// Returns (t, local_face_normal) for the closest intersection of a ray with an AABB centered at origin.
fn ray_aabb_intersection(origin: Vec3, dir: Vec3, half: Vec3) -> Option<(f32, Vec3)> {
    let mut t_min = f32::NEG_INFINITY;
    let mut t_max = f32::INFINITY;
    let mut entry_axis = 0usize;
    let mut entry_sign = 1.0f32;

    for i in 0..3 {
        let o = match i { 0 => origin.x, 1 => origin.y, _ => origin.z };
        let d = match i { 0 => dir.x, 1 => dir.y, _ => dir.z };
        let h = match i { 0 => half.x, 1 => half.y, _ => half.z };

        if d.abs() < 1e-8 {
            if o < -h || o > h {
                return None;
            }
        } else {
            let inv_d = 1.0 / d;
            let mut t1 = (-h - o) * inv_d;
            let mut t2 = (h - o) * inv_d;
            let mut sign = -1.0f32;
            if t1 > t2 {
                std::mem::swap(&mut t1, &mut t2);
                sign = 1.0;
            }
            if t1 > t_min {
                t_min = t1;
                entry_axis = i;
                entry_sign = sign;
            }
            t_max = t_max.min(t2);
            if t_min > t_max {
                return None;
            }
        }
    }

    let normal = match entry_axis {
        0 => Vec3::new(entry_sign, 0.0, 0.0),
        1 => Vec3::new(0.0, entry_sign, 0.0),
        _ => Vec3::new(0.0, 0.0, entry_sign),
    };

    Some((t_min, normal))
}

/// Given a local face normal (axis-aligned), return tangent and bitangent vectors
/// that span that face, consistent with the cube's local axes.
fn face_tangents(normal: Vec3) -> (Vec3, Vec3) {
    let abs = normal.abs();
    if abs.x > 0.5 {
        // +X or -X face: tangent=Z, bitangent=Y
        (Vec3::Z, Vec3::Y)
    } else if abs.y > 0.5 {
        // +Y or -Y face: tangent=X, bitangent=Z
        (Vec3::X, Vec3::Z)
    } else {
        // +Z or -Z face: tangent=X, bitangent=Y
        (Vec3::X, Vec3::Y)
    }
}
"
}
```

### How it works

The key solution to the original problem:

1. **Transform the ray into the cube's local space** to do a simple axis-aligned bounding box (AABB) intersection.
2. **Determine which local face was hit** — this gives you an axis-aligned normal in local space (e.g., `+X`, `-Y`, `+Z`).
3. **Compute local tangent/bitangent** vectors for that face (e.g., for the `+X` face, use `Z` and `Y` as the tangent axes).
4. **Rotate those local vectors by the cube's rotation** to get world-space tangent, bitangent, and normal.
5. **Build the gizmo's rotation** from those three orthogonal world-space vectors using `Quat::from_mat3`.

This way the gizmo rectangle is always flush with the actual cube face, regardless of how the cube is rotated. Use **Q/E** to rotate around Y, **W/S** around X, and **A/D** around Z.

