  "main.rs": "/// Splits a shell command string into tokens in a quote-aware fashion,
/// mimicking how bash handles single quotes and whitespace.
///
/// Rules:
/// - Unquoted whitespace separates tokens.
/// - Single-quoted regions preserve their content literally (including spaces).
/// - A quoted region glues to adjacent non-whitespace (e.g. `' two  'three` → ` two  three`).
fn tokenize(input: &str) -> Vec<String> {
    let mut tokens: Vec<String> = Vec::new();
    let mut current = String::new();
    let mut in_single_quote = false;
    let mut chars = input.chars();

    while let Some(ch) = chars.next() {
        if in_single_quote {
            if ch == '\'' {
                // End of single-quoted region.
                // Don't push token yet — more characters may be glued on.
                in_single_quote = false;
            } else {
                current.push(ch);
            }
        } else {
            match ch {
                '\'' => {
                    // Begin single-quoted region.
                    // Even an empty quoted string means we're building a token
                    // (ensures '' produces an empty token if standalone).
                    in_single_quote = true;
                }
                ' ' | '\t' => {
                    // Unquoted whitespace: finish current token if any.
                    if !current.is_empty() {
                        tokens.push(std::mem::take(&mut current));
                    }
                }
                _ => {
                    current.push(ch);
                }
            }
        }
    }

    // Push the last token if any.
    if !current.is_empty() {
        tokens.push(current);
    }

    tokens
}

fn main() {
    let input = " one  ' two  'three    four";
    let tokens = tokenize(input);
    println!("{} args:", tokens.len());
    for token in &tokens {
        println!("<{}>", token);
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_basic_example() {
        let tokens = tokenize(" one  ' two  'three    four");
        assert_eq!(tokens, vec!["one", " two  three", "four"]);
    }

    #[test]
    fn test_no_quotes() {
        let tokens = tokenize("hello world  foo");
        assert_eq!(tokens, vec!["hello", "world", "foo"]);
    }

    #[test]
    fn test_only_quoted() {
        let tokens = tokenize("'hello world'");
        assert_eq!(tokens, vec!["hello world"]);
    }

    #[test]
    fn test_adjacent_quoted_and_unquoted() {
        let tokens = tokenize("foo'bar baz'qux");
        assert_eq!(tokens, vec!["foobar bazqux"]);
    }

    #[test]
    fn test_empty_input() {
        let tokens = tokenize("");
        assert!(tokens.is_empty());
    }

    #[test]
    fn test_only_spaces() {
        let tokens = tokenize("    ");
        assert!(tokens.is_empty());
    }

    #[test]
    fn test_multiple_quoted_sections() {
        let tokens = tokenize("'a b' 'c d' e");
        assert_eq!(tokens, vec!["a b", "c d", "e"]);
    }
}
