                        line.pop();
                        match rl.readline(".. ") {
                            Ok(next) => {
                                line.push('\n');
                                line.push_str(&next);
                            }
                            Err(_) => break,
                        }
                    }
                    println!("Got input:");
                    dbg!(&line);
                }

                let _ = rl.add_history_entry(line.as_str());
            }
            Err(rustyline::error::ReadlineError::Interrupted) => {
                println!("Ctrl-C");
                break;
            }
            Err(rustyline::error::ReadlineError::Eof) => {
                println!("Ctrl-D");
                break;
            }
            Err(err) => {
                println!("Error: {:?}", err);
                break;
            }
        }
    }
