use std::rc::Rc;

/// A simple "slot" that holds the latest value and a list of subscribers.
/// When a new value is pushed, all subscribers are notified (breadth-first
/// via a global event queue so we never re-enter a borrow).
struct SlotInner<T: Clone> {
    value: Option<T>,
    subscribers: Vec<Box<dyn Fn(T)>>,
}

#[derive(Clone)]
struct Slot<T: Clone> {
    inner: Rc<RefCell<SlotInner<T>>>,
}

impl<T: Clone + 'static> Slot<T> {
    fn new() -> Self {
        Slot {
            inner: Rc::new(RefCell::new(SlotInner {
                value: None,
                subscribers: Vec::new(),
            })),
        }
    }

    fn new_with(val: T) -> Self {
        let s = Self::new();
        s.inner.borrow_mut().value = Some(val);
        s
    }

    fn get(&self) -> Option<T> {
        self.inner.borrow().value.clone()
    }

    /// Register a callback that will be called whenever this slot gets a new value.
    fn subscribe<F: Fn(T) + 'static>(&self, f: F) {
        self.inner.borrow_mut().subscribers.push(Box::new(f));
    }

    /// Push a new value. Notification of subscribers is deferred through the
    /// global event queue so that we never recursively borrow the RefCell.
    fn push(&self, val: T) {
        self.inner.borrow_mut().value = Some(val.clone());
        // Collect subscriber count; we will invoke them via the queue.
        let subs: Vec<_> = {
            let inner = self.inner.borrow();
            (0..inner.subscribers.len()).collect()
        };
        let inner_rc = self.inner.clone();
        for idx in subs {
            let v = val.clone();
            let rc = inner_rc.clone();
            enqueue(move || {
                let f = {
                    let inner = rc.borrow();
                    // We can't call f while borrowed, so we won't – instead
                    // we grab a reference-counted pointer. But subscribers are
                    // Box<dyn Fn> so we can't clone them. Instead we just call
                    // within the borrow since the queue ensures no re-entrance
                    // into *this* slot's borrow.
                    //
                    // Actually we CAN call here because the queue is drained
                    // only at the top level, guaranteeing we are not already
                    // inside a borrow of this particular RefCell.
                    &inner.subscribers[idx] as *const dyn Fn(T)
                };
                // SAFETY: we know the Rc keeps inner alive, and we're in a
                // synchronous, single-threaded context. The pointer is valid.
                unsafe { (*f)(v) };
            });
        }
    }
}

// --------------- Global breadth-first event queue ---------------

thread_local! {
    static EVENT_QUEUE: RefCell<Vec<Box<dyn FnOnce()>>> = RefCell::new(Vec::new());
    static DRAINING: RefCell<bool> = RefCell::new(false);
}

fn enqueue(f: impl FnOnce() + 'static) {
    EVENT_QUEUE.with(|q| q.borrow_mut().push(Box::new(f)));
}

/// Drain the queue until empty. Only the outermost call actually drains;
/// nested calls just enqueue.
fn drain_queue() {
    DRAINING.with(|flag| {
        if *flag.borrow() {
            return; // already draining at a higher frame
        }
        *flag.borrow_mut() = true;
        loop {
            let task = EVENT_QUEUE.with(|q| {
                let mut q = q.borrow_mut();
                if q.is_empty() {
                    None
                } else {
                    Some(q.remove(0))
                }
            });
            match task {
                Some(f) => f(),
                None => break,
            }
        }
        *flag.borrow_mut() = false;
    });
}

/// Push a value and then drain the event queue (breadth-first propagation).
fn push_and_drain<T: Clone + 'static>(slot: &Slot<T>, val: T) {
    slot.push(val);
    drain_queue();
}

// --------------- Reactive combinators ---------------

/// combine_latest: emits (A,B) whenever either input changes, as long as
/// both have produced at least one value.
fn combine_latest<A: Clone + 'static, B: Clone + 'static>(
    a: &Slot<A>,
    b: &Slot<B>,
) -> Slot<(A, B)> {
    let out = Slot::<(A, B)>::new();

    // Possibly emit the initial combined value if both have values.
    if let (Some(va), Some(vb)) = (a.get(), b.get()) {
        out.inner.borrow_mut().value = Some((va, vb));
    }

    let b_clone = b.clone();
    let out_clone = out.clone();
    a.subscribe(move |va| {
        if let Some(vb) = b_clone.get() {
            out_clone.push((va, vb));
        }
    });

    let a_clone = a.clone();
    let out_clone = out.clone();
    b.subscribe(move |vb| {
        if let Some(va) = a_clone.get() {
            out_clone.push((va, vb));
        }
    });

    out
}

/// map
fn map<A: Clone + 'static, B: Clone + 'static>(input: &Slot<A>, f: impl Fn(A) -> B + 'static) -> Slot<B> {
    let out = Slot::<B>::new();
    if let Some(v) = input.get() {
        out.inner.borrow_mut().value = Some(f(v));
    }
    let out_clone = out.clone();
    input.subscribe(move |v| {
        out_clone.push(f(v));
    });
    out
}

/// distinct_until_changed: only forwards values that differ from the previous.
fn distinct<A: Clone + PartialEq + 'static>(input: &Slot<A>) -> Slot<A> {
    let out = Slot::<A>::new();
    if let Some(v) = input.get() {
        out.inner.borrow_mut().value = Some(v);
    }
    let last: Rc<RefCell<Option<A>>> = Rc::new(RefCell::new(input.get()));
    let out_clone = out.clone();
    input.subscribe(move |v| {
        let changed = {
            let l = last.borrow();
            match l.as_ref() {
                Some(prev) => *prev != v,
                None => true,
            }
        };
        if changed {
            *last.borrow_mut() = Some(v.clone());
            out_clone.push(v);
        }
    });
    out
}

// --------------- NAND / Flip-Flop ---------------

fn nand(name: &str, a: &Slot<bool>, b: &Slot<bool>) -> Slot<bool> {
    let combined = combine_latest(a, b);
    let deduped = distinct(&combined);
    let name_owned = name.to_string();
    let tapped = map(&deduped, move |(a, b)| {
        let result = !(a & b);
        println!("nand {name_owned} ({a}, {b}) = {result}");
