    });
    tapped
}

/// RS flip-flop built from two cross-coupled NANDs.
///
/// S and R are active-low (active when false) as is standard for a
/// NAND-based SR latch.
///
/// The feedback is achieved by having BehaviorSubject-like slots (s2, r2)
/// whose values are written by subscribing to the NAND outputs. The
/// global breadth-first event queue prevents re-entrant borrows.
fn flipflop(s: &Slot<bool>, r: &Slot<bool>) -> (Slot<bool>, Slot<bool>) {
    // Feedback slots, initialised to sensible defaults for (S=true, R=true)
    // which is the "hold" state.
    let s2 = Slot::<bool>::new_with(true); // fed from q2
    let r2 = Slot::<bool>::new_with(true);  // fed from q1

