    let s2_clone = s2.clone();
    q2.subscribe(move |v| {
        s2_clone.push(v);
    });

    (q1, q2)
}

fn main() {
    let s = Slot::<bool>::new_with(true);
    let r = Slot::<bool>::new_with(true);

