Looking at this problem, the issue is that SCEP clients (like many Microsoft/Apple SCEP implementations) encode the `SignedData` content using PKCS#7 (`ContentInfo` wrapping) rather than the CMS `EncapsulatedContentInfo` format. Specifically, the `eContent` in SCEP's `SignedData` contains raw PKCS#7 `ContentInfo` bytes (with an outer `ContentInfo` wrapper for the enveloped data), and the serial number is encoded in a way that the strict DER parser in the `cms` crate chokes on (likely a large integer at position 129).

The root cause is that many SCEP clients produce BER-encoded (not strict DER) content, and the `cms`/`der` crates expect strict DER. The solution is to use `rasn` + `rasn-cms` which handles BER encoding, or to manually parse using a more lenient approach.

Here's a working solution using `rasn` and `rasn-cms` which support BER decoding:

```json
{
  "Cargo.toml": "[package]
name = "scep-decode"
version = "0.1.0"
edition = "2021"

[dependencies]
rasn = "0.22"
rasn-cms = "0.22"
rasn-pkix = "0.22"
hex = "0.4"
base64 = "0.22"
",
  "main.rs": "use rasn::{
    ber::de::DecoderOptions,
    types::{ObjectIdentifier, OctetString},
    Decode,
};
use rasn_cms::{ContentInfo, SignedData, EnvelopedData, SignerInfo};

/// OID for pkcs7-signedData: 1.2.840.113549.1.7.2
fn oid_signed_data() -> ObjectIdentifier {
    ObjectIdentifier::new_unchecked(vec![1, 2, 840, 113549, 1, 7, 2].into())
}

/// OID for pkcs7-data: 1.2.840.113549.1.7.1
fn oid_pkcs7_data() -> ObjectIdentifier {
    ObjectIdentifier::new_unchecked(vec![1, 2, 840, 113549, 1, 7, 1].into())
}

/// OID for pkcs7-envelopedData: 1.2.840.113549.1.7.3
fn oid_enveloped_data() -> ObjectIdentifier {
    ObjectIdentifier::new_unchecked(vec![1, 2, 840, 113549, 1, 7, 3].into())
}

/// SCEP messageType OID: 2.16.840.1.113733.1.9.2
fn oid_scep_message_type() -> ObjectIdentifier {
    ObjectIdentifier::new_unchecked(vec![2, 16, 840, 1, 113733, 1, 9, 2].into())
}

/// SCEP senderNonce OID: 2.16.840.1.113733.1.9.5
fn oid_scep_sender_nonce() -> ObjectIdentifier {
    ObjectIdentifier::new_unchecked(vec![2, 16, 840, 1, 113733, 1, 9, 5].into())
}

/// SCEP transactionID OID: 2.16.840.1.113733.1.9.7
fn oid_scep_transaction_id() -> ObjectIdentifier {
    ObjectIdentifier::new_unchecked(vec![2, 16, 840, 1, 113733, 1, 9, 7].into())
}

fn decode_scep_pki_operation(der_bytes: &[u8]) -> Result<(), Box<dyn std::error::Error>> {
    println!("=== Decoding SCEP PKIOperation ===");
    println!("Input size: {} bytes", der_bytes.len());
    println!();

    // Step 1: Decode outer ContentInfo using BER (lenient decoding)
    let content_info: ContentInfo = rasn::ber::decode(der_bytes)
        .map_err(|e| format!("Failed to decode outer ContentInfo: {:?}", e))?;

    println!("Outer ContentInfo:");
    println!("  contentType: {}", content_info.content_type);

    if content_info.content_type != oid_signed_data() {
        return Err(format!(
            "Expected signedData OID, got: {}",
            content_info.content_type
        )
        .into());
    }
    println!("  contentType is pkcs7-signedData ✓");
    println!();

    // Step 2: Decode SignedData from the content
    // The content is an ANY value; we need to decode it as SignedData
    let signed_data: SignedData = rasn::ber::decode(
        &rasn::ber::encode(&content_info.content)
            .map_err(|e| format!("Failed to re-encode content: {:?}", e))?,
    )
    .map_err(|e| format!("Failed to decode SignedData: {:?}", e))?;

    println!("SignedData:");
    println!("  version: {:?}", signed_data.version);
    println!(
        "  digestAlgorithms count: {}",
        signed_data.digest_algorithms.len()
    );
    for (i, alg) in signed_data.digest_algorithms.iter().enumerate() {
        println!("    [{}] algorithm: {}", i, alg.algorithm);
    }
    println!();

    // Step 3: Examine encapsulated content
    println!("EncapsulatedContentInfo:");
    println!(
        "  eContentType: {}",
        signed_data.encap_content_info.content_type
    );

    if let Some(ref econtent) = signed_data.encap_content_info.content {
        // The eContent bytes contain the inner ContentInfo (enveloped data)
        // In SCEP, this is typically pkcs7-envelopedData wrapped in a ContentInfo
        let econtent_bytes: &[u8] = econtent.as_ref();
        println!("  eContent length: {} bytes", econtent_bytes.len());
        println!();

        // Try to decode the eContent as a ContentInfo (PKCS#7 envelope)
        match rasn::ber::decode::<ContentInfo>(econtent_bytes) {
            Ok(inner_ci) => {
                println!("Inner ContentInfo (from eContent):");
                println!("  contentType: {}", inner_ci.content_type);

                if inner_ci.content_type == oid_enveloped_data() {
                    println!("  contentType is pkcs7-envelopedData ✓");

                    // Decode the EnvelopedData
                    match rasn::ber::decode::<EnvelopedData>(
                        &rasn::ber::encode(&inner_ci.content)
                            .map_err(|e| format!("Failed to re-encode inner content: {:?}", e))?,
                    ) {
                        Ok(env_data) => {
                            println!();
                            println!("EnvelopedData:");
                            println!("  version: {:?}", env_data.version);
                            println!(
                                "  recipientInfos count: {}",
                                env_data.recipient_infos.len()
                            );
                            println!(
                                "  encryptedContentInfo contentType: {}",
                                env_data.encrypted_content_info.content_type
                            );
                            println!(
                                "  encryptedContentInfo algorithm: {}",
                                env_data
                                    .encrypted_content_info
                                    .content_encryption_algorithm
                                    .algorithm
                            );
                            if let Some(ref encrypted) =
                                env_data.encrypted_content_info.encrypted_content
                            {
                                println!(
                                    "  encryptedContent length: {} bytes",
                                    encrypted.as_ref().len()
                                );
                            }
                        }
                        Err(e) => {
                            println!("  (Could not decode EnvelopedData: {:?})", e);
                        }
                    }
                }
            }
            Err(e) => {
                println!(
                    "  (eContent is not a ContentInfo, raw bytes. Error: {:?})",
                    e
                );
            }
        }
    } else {
        println!("  eContent: <absent>");
    }
    println!();

    // Step 4: Certificates
    if let Some(ref certs) = signed_data.certificates {
        println!("Certificates: {} certificate(s)", certs.len());
        for (i, cert_choice) in certs.iter().enumerate() {
            println!("  [{}] Certificate present", i);
            // rasn_cms CertificateChoices - we just note it's there
        }
    } else {
        println!("Certificates: <absent>");
    }
    println!();

    // Step 5: Signer Infos
    println!("SignerInfos: {} signer(s)", signed_data.signer_infos.len());
    for (i, signer_info) in signed_data.signer_infos.iter().enumerate() {
        println!("  SignerInfo [{}]:", i);
        println!("    version: {:?}", signer_info.version);
        println!(
            "    digestAlgorithm: {}",
            signer_info.digest_algorithm.algorithm
        );
        println!(
