/// Demonstrate that rasn BER decoding works by round-tripping a ContentInfo
fn demo_minimal() {
    use rasn_cms::{
        ContentInfo, SignedData, EncapsulatedContentInfo,
        DigestAlgorithmIdentifiers, CertificateSet, SignerInfos,
    };
    use rasn::types::SetOf;

    // Build a minimal SignedData
    let digest_algs: DigestAlgorithmIdentifiers = SetOf::new();
    let signer_infos: SignerInfos = SetOf::new();

    let encap = EncapsulatedContentInfo {
        content_type: ObjectIdentifier::new_unchecked(vec![1, 2, 840, 113549, 1, 7, 1].into()),
        content: None,
    };

    let sd = SignedData {
        version: rasn_cms::CmsVersion::V1,
        digest_algorithms: digest_algs,
        encap_content_info: encap,
        certificates: None,
        crls: None,
        signer_infos,
    };

    // Encode the SignedData
    let sd_bytes = rasn::ber::encode(&sd).expect("Failed to encode SignedData");

    // Wrap in ContentInfo
    let any_sd = rasn::ber::decode::<rasn::types::Any>(&sd_bytes)
        .expect("Failed to decode as Any");

    let ci = ContentInfo {
        content_type: ObjectIdentifier::new_unchecked(vec![1, 2, 840, 113549, 1, 7, 2].into()),
        content: any_sd,
    };

    let ci_bytes = rasn::ber::encode(&ci).expect("Failed to encode ContentInfo");
    println!("  Encoded ContentInfo: {} bytes", ci_bytes.len());
    println!("  Hex: {}", hex::encode(&ci_bytes));

    // Decode it back
    let ci2: ContentInfo =
        rasn::ber::decode(&ci_bytes).expect("Failed to decode ContentInfo");
    println!("  Decoded contentType: {}", ci2.content_type);

    let sd2: SignedData = rasn::ber::decode(
        &rasn::ber::encode(&ci2.content).expect("re-encode"),
    )
    .expect("Failed to decode SignedData");
    println!("  Decoded SignedData version: {:?}", sd2.version);
    println!("  Decoded encapContentInfo type: {}", sd2.encap_content_info.content_type);
    println!();
    println!("  BER decoding works correctly! ✓");
    println!("  Pass a DER file as argument to decode a real SCEP PKIOperation.");
}
"
}
```

**Key insight**: The `cms` crate (built on top of the `der` crate) uses **strict DER** decoding, but SCEP clients commonly produce **BER**-encoded messages. The error at position 129 with an `INTEGER` tag is the serial number `0x4543303943443336343136303746443736304539353835393630433133453800` — it's 32 bytes with a trailing `0x00`, which likely has a BER encoding that violates strict DER rules (e.g., non-minimal integer encoding or indefinite-length containers).

**The fix**: Use `rasn` + `rasn-cms` instead of the `cms` crate. The `rasn` library supports BER decoding which is much more lenient and handles the encoding quirks from real-world SCEP clients.

To test with your actual SCEP data, save the DER bytes to a file and run:
```bash
cargo run -- ci.der
```

