  "main.rs": "use serde::de::{self, Deserializer, MapAccess, SeqAccess, Visitor};
use serde::Deserialize;
use std::fmt;

// ---------------------------------------------------------------------------
// Data types
// ---------------------------------------------------------------------------

#[derive(Debug, Default)]
struct A {
    x: usize,
    b: Vec<B>,
}

#[derive(Debug)]
enum B {
    Num(f64),
    Text(String),
}

// ---------------------------------------------------------------------------
// Custom Deserialize for B (the inner / nested type)
// ---------------------------------------------------------------------------

struct BVisitor;

impl<'de> Visitor<'de> for BVisitor {
    type Value = B;

    fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "a number or a string representing variant B")
    }

    fn visit_f64<E: de::Error>(self, v: f64) -> Result<B, E> {
        Ok(B::Num(v))
    }

    fn visit_u64<E: de::Error>(self, v: u64) -> Result<B, E> {
        Ok(B::Num(v as f64))
    }

    fn visit_i64<E: de::Error>(self, v: i64) -> Result<B, E> {
        Ok(B::Num(v as f64))
    }

    fn visit_str<E: de::Error>(self, v: &str) -> Result<B, E> {
        Ok(B::Text(v.to_owned()))
    }

    fn visit_string<E: de::Error>(self, v: String) -> Result<B, E> {
        Ok(B::Text(v))
    }
}

impl<'de> Deserialize<'de> for B {
    fn deserialize<D: Deserializer<'de>>(deserializer: D) -> Result<B, D::Error> {
        deserializer.deserialize_any(BVisitor)
    }
}

// ---------------------------------------------------------------------------
// Custom Deserialize for A (the outer type that *contains* Vec<B>)
// ---------------------------------------------------------------------------

struct AVisitor;

impl<'de> Visitor<'de> for AVisitor {
    type Value = A;

    fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "a JSON object with keys 'x' and 'b'")
    }

    fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
    where
        V: MapAccess<'de>,
    {
        let mut val = A::default();

        // Use `String` (or a helper enum) for the key so we don't run into
        // lifetime issues that `&str` can cause with some formats.
        while let Some(key) = map.next_key::<String>()? {
            match key.as_str() {
                "x" => {
                    val.x = map.next_value()?;
                }
                "b" => {
                    // Because B already implements Deserialize, we can just
                    // ask for `Vec<B>` directly – serde will call B's
                    // Deserialize (our custom one) for every element.
                    val.b = map.next_value()?;
