// Demonstration – also shows an alternative approach where you manually
// deserialize the Vec by visiting the sequence yourself.
// ---------------------------------------------------------------------------

/// An alternative visitor that manually walks the sequence of B values
/// instead of relying on `Vec<B>`'s blanket `Deserialize` impl.
struct VecBVisitor;

impl<'de> Visitor<'de> for VecBVisitor {
    type Value = Vec<B>;

    fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "a sequence of B values")
    }

    fn visit_seq<S>(self, mut seq: S) -> Result<Vec<B>, S::Error>
    where
        S: SeqAccess<'de>,
    {
        let mut vec = Vec::with_capacity(seq.size_hint().unwrap_or(0));
        // Each `next_element` call will invoke B's custom Deserialize.
        while let Some(elem) = seq.next_element()? {
            vec.push(elem);
        }
        Ok(vec)
    }
}

/// Standalone function showing how you could deserialize a `Vec<B>` by hand.
#[allow(dead_code)]
fn deserialize_vec_b<'de, D>(deserializer: D) -> Result<Vec<B>, D::Error>
where
    D: Deserializer<'de>,
{
    deserializer.deserialize_seq(VecBVisitor)
}

// ---------------------------------------------------------------------------
fn main() {
    let json = r#"
    {
        "x": 42,
        "b": [1, "hello", 3.14, "world"]
    }
    "#;

    let a: A = serde_json::from_str(json).expect("failed to deserialize A");
    println!("Deserialized A: {:#?}", a);

    // Quick sanity checks
    assert_eq!(a.x, 42);
