        other => panic!("expected Num, got {:?}", other),
    }
    match &a.b[1] {
        B::Text(s) => assert_eq!(s, "hello"),
        other => panic!("expected Text, got {:?}", other),
    }

    println!("\nAll assertions passed!");
}
"
}
