  "main.rs": "use std::borrow::Cow;
use std::collections::HashMap;
use std::marker::PhantomData;

use kube::api::Resource;

/// The key insight: since `R::group()` and `R::kind()` return `Cow<'_, str>`,
/// the returned Cow may be either `Borrowed` (pointing into static data) or
/// `Owned`. When we want to store these values in a struct without tying the
/// struct's lifetime to a local variable, we simply convert them to owned
/// (`Cow::into_owned()` gives us a `String`, which we can wrap back into
/// `Cow<'static, str>`). This avoids the E0515 error while still using `Cow`
/// in the struct. For concrete (non-dynamic) Kubernetes types the group and
/// kind are compile-time constants so cloning is cheap, and we only pay for a
/// `String` allocation in the dynamic case.
///
/// Alternatively we can just store `Cow<'static, str>` by converting any
/// borrowed variant into an owned one. This is the "magic sauce".

#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct ResourceRef<R: Resource>
where
    R::DynamicType: Default,
{
    type_: PhantomData<R>,
    dynamic_type: R::DynamicType,
    group: Option<Cow<'static, str>>,
    kind: Cow<'static, str>,
    name: String,
}

/// Helper: convert a `Cow<'_, str>` into a `Cow<'static, str>` by taking
/// ownership of any borrowed data.
fn into_static(c: Cow<'_, str>) -> Cow<'static, str> {
    match c {
        Cow::Borrowed(s) => {
            // For concrete k8s types the group/kind are &'static str already,
            // so this branch is a no-op in practice.  We can't *prove* the
            // borrow is 'static at the type level here, so we allocate to be
            // safe. In practice you could use unsafe to transmute if you know
            // the source is 'static.
            Cow::Owned(s.to_owned())
        }
        Cow::Owned(s) => Cow::Owned(s),
    }
}

impl<R: Resource> ResourceRef<R>
where
    R::DynamicType: Default + std::fmt::Debug + Clone + PartialEq + Eq + std::hash::Hash,
{
    pub fn new(resource: &R) -> Self
    where
        R::DynamicType: Default,
    {
        let name = resource
            .meta()
            .name
            .as_deref()
            .expect("Resource must have a name");
        Self::new_named(name)
    }

    pub fn new_named(name: &str) -> Self {
        let dynamic_type = R::DynamicType::default();
        let group = R::group(&dynamic_type);
        let group = if group.is_empty() {
            None
        } else {
            Some(into_static(group))
        };
        let kind = into_static(R::kind(&dynamic_type));

        Self {
            type_: PhantomData,
            dynamic_type,
            group,
            kind,
            name: name.to_string(),
        }
    }

    pub fn group(&self) -> Option<&str> {
        self.group.as_deref()
    }

    pub fn kind(&self) -> &str {
        &self.kind
    }

    pub fn name(&self) -> &str {
        &self.name
    }
}

// ---------- demo with a concrete k8s type ----------

use k8s_openapi::api::core::v1::ConfigMap;
use k8s_openapi::api::apps::v1::Deployment;

fn main() {
    // Build some ResourceRef keys
    let cm_ref = ResourceRef::<ConfigMap>::new_named("my-config");
    let deploy_ref = ResourceRef::<Deployment>::new_named("my-deploy");

    println!("ConfigMap  ref: group={:?}, kind={}, name={}",
             cm_ref.group(), cm_ref.kind(), cm_ref.name());
    println!("Deployment ref: group={:?}, kind={}, name={}",
             deploy_ref.group(), deploy_ref.kind(), deploy_ref.name());

    // Use as HashMap key
    let mut map: HashMap<ResourceRef<ConfigMap>, String> = HashMap::new();
    map.insert(cm_ref.clone(), "some-value".to_string());

    println!("\nHashMap lookup for {:?}: {:?}", cm_ref.name(), map.get(&cm_ref));

    // Demonstrate creating from an actual resource object
    let mut cm = ConfigMap::default();
    cm.metadata.name = Some("live-config".to_string());
    let live_ref = ResourceRef::<ConfigMap>::new(&cm);
    println!("Live ConfigMap ref: group={:?}, kind={}, name={}",
             live_ref.group(), live_ref.kind(), live_ref.name());

    println!("\nDone! The Cow values are stored as Cow<'static, str> by converting borrowed data to owned.");
}
"
}
