",
  "main.rs": "use std::future::Future;
use std::pin::Pin;
use tokio::sync::mpsc;

pub struct Context(i32);

pub enum InnerAsyncEvent {
    DoWithContext {
        block: Box<
            dyn for<'a> FnOnce(
                    &'a mut Context,
                ) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
                + Send,
        >,
    },
}

/// Helper function that wraps an async closure into the boxed form needed by InnerAsyncEvent.
///
/// The key insight is that we cannot directly require `AsyncFnOnce` to produce a `Send` future
/// on stable Rust (the `CallOnceFuture` associated type isn't directly constrainable with `Send`).
///
/// Instead, we accept a plain closure that returns a pinned, boxed, Send future — but we provide
/// a nice macro below that makes the call-site look like you're just passing an async closure.
pub fn with_context_async<F>(work_sender: &mpsc::UnboundedSender<InnerAsyncEvent>, block: F)
where
    F: for<'a> FnOnce(&'a mut Context) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
        + Send
        + 'static,
{
    let _ = work_sender.send(InnerAsyncEvent::DoWithContext {
        block: Box::new(block),
    });
}

/// Macro that lets you write something that looks almost like an async closure
/// but expands to the right `|args| Box::pin(async move { ... })` form.
///
/// Usage:
///   async_closure!(|ctx: &mut Context| { ctx.0 += 1; })
///
/// You can also capture variables from the environment (they must be Send + 'static):
///   let value = 42;
///   async_closure!(move |ctx: &mut Context| { ctx.0 += value; })
macro_rules! async_closure {
    (|$arg:ident : &mut $t:ty| $body:expr) => {
        |$arg: &mut $t| -> Pin<Box<dyn Future<Output = ()> + Send + '_>> {
            Box::pin(async move { $body })
        }
    };
    (move |$arg:ident : &mut $t:ty| $body:expr) => {
        move |$arg: &mut $t| -> Pin<Box<dyn Future<Output = ()> + Send + '_>> {
            Box::pin(async move { $body })
        }
    };
}

#[tokio::main]
async fn main() {
    let (tx, mut rx) = mpsc::unbounded_channel::<InnerAsyncEvent>();

    // Example 1: simple usage with the macro
    with_context_async(&tx, async_closure!(|ctx: &mut Context| {
        ctx.0 += 1;
        println!("Example 1: ctx.0 = {}", ctx.0);
    }));

    // Example 2: capturing a variable with `move`
    let increment = 10;
    with_context_async(&tx, async_closure!(move |ctx: &mut Context| {
        ctx.0 += increment;
        println!("Example 2: ctx.0 = {}", ctx.0);
    }));

    // Example 3: using an actual async operation inside
    with_context_async(&tx, async_closure!(|ctx: &mut Context| {
        tokio::time::sleep(std::time::Duration::from_millis(10)).await;
        ctx.0 += 100;
        println!("Example 3: ctx.0 = {} (after async sleep)", ctx.0);
    }));

    // Example 4: direct construction without the macro (for comparison)
    with_context_async(&tx, |ctx: &mut Context| -> Pin<Box<dyn Future<Output = ()> + Send + '_>> {
        Box::pin(async move {
            ctx.0 += 1000;
            println!("Example 4: ctx.0 = {} (manual construction)", ctx.0);
        })
    });

    drop(tx);

    // Spawn a task on another thread to process the events
    let handle = tokio::spawn(async move {
        let mut ctx = Context(0);
        while let Some(event) = rx.recv().await {
            match event {
                InnerAsyncEvent::DoWithContext { block } => {
                    block(&mut ctx).await;
                }
            }
        }
        println!("Final ctx.0 = {}", ctx.0);
    });

    handle.await.unwrap();
}
"
}
```

