    let mut last_tick = Instant::now();

    loop {
        // Calculate how much time is left until the next tick.
        let timeout = tick_rate
            .checked_sub(last_tick.elapsed())
            .unwrap_or(Duration::ZERO);

        // `poll` will block for *at most* `timeout` duration.
        // It returns `true` if an event is available, `false` on timeout.
        if event::poll(timeout)? {
            // An event is ready — read it (this will NOT block because poll said it's ready).
            let ev = event::read()?;

            // We use `\r` at the end of lines because raw mode disables
            // the terminal's automatic carriage-return on newline.
            println!("- Event received: {:?}\r", ev);

            if let Event::Key(key) = ev {
                if key.code == KeyCode::Char('q') {
                    println!("'q' pressed, quitting.\r");
                    break;
                }
            }
        }

        // Check whether a full tick period has elapsed.
        if last_tick.elapsed() >= tick_rate {
            println!("Tick!\r");
            io::stdout().flush()?;
            last_tick = Instant::now();
        }
    }

    // Restore the terminal to its normal (cooked) mode before exiting.
    crossterm::terminal::disable_raw_mode()?;

    Ok(())
}
"
}
