/// which will register its own waker.
fn noop_waker() -> Waker {
    fn noop(_: *const ()) {}
    fn clone(data: *const ()) -> RawWaker {
        RawWaker::new(data, &VTABLE)
    }
    static VTABLE: RawWakerVTable = RawWakerVTable::new(clone, noop, noop, noop);
    unsafe { Waker::from_raw(RawWaker::new(std::ptr::null(), &VTABLE)) }
}

/// Try to poll a future exactly once.
/// - If it resolves immediately (`Ready`), return the value.
/// - Otherwise return `Pending` so the caller can decide what to do
///   (e.g. spawn the future on Tokio).
///
/// SAFETY / correctness notes:
///   We use a no-op waker.  This is fine because:
///     • If the future is `Ready`, no waker is needed.
///     • If the future is `Pending`, we will NOT poll it again with this
///       waker – instead we move it into `tokio::spawn`, which supplies
///       a proper waker.
fn try_poll<X>(future: Pin<&mut impl Future<Output = X>>) -> TryPollResult<X> {
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);
    match future.poll(&mut cx) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

