                println!("Future was immediately ready with value: {val}");
            }
            TryPollResult::Pending => {
                println!("Future is pending – spawning task...");
                tokio::spawn(async move {
                    let val = fut.await;
                    println!("  (spawned task) Future resolved with value: {val}");
                })
                .await
                .unwrap();
            }
        }
    }

