response:
Here's my solution. The key insight is that `log::warn!()` and similar macros hardcode `module_path!()` at the call site. To override the module name, you need to use the `log::Record` builder API directly, which lets you set the `module_path` to whatever you want. We can capture the caller's module path via a macro that wraps the trait method call.

```json
{
  "Cargo.toml": "[package]
name = "question-location-log"
version = "0.1.0"
edition = "2021"

[dependencies]
dotenvy = "0.15.7"
env_logger = "0.11.8"
log = "0.4.27"
thiserror = "2.0.14"
",
  "main.rs": "// Not my real error, I use [actix_web]
#[derive(Debug, thiserror::Error)]
pub enum FrameworkError {
    #[error("400: {0}")]
    Error400(Box<dyn std::error::Error>),
}

pub mod my_library {
    pub mod extensions {
        pub mod logging {
            use crate::FrameworkError;

            /// Helper function that does the actual work. It takes the caller's module path
            /// and location as parameters so the log record can attribute them correctly.
            pub fn log_and_explain_400_impl<T, E: std::error::Error + 'static>(
                result: Result<T, E>,
                caller_module: &str,
                caller_file: &str,
                caller_line: u32,
            ) -> Result<T, FrameworkError> {
                match result {
                    Ok(ok) => Ok(ok),
                    Err(err) => {
                        // Build a log::Record manually so we can override module_path
                        log::logger().log(
                            &log::Record::builder()
                                .args(format_args!(
                                    "location {file}:{line}: Error: {err:?}",
                                    file = caller_file,
                                    line = caller_line,
                                    err = err
                                ))
                                .level(log::Level::Warn)
                                .target(caller_module)
                                .module_path(Some(caller_module))
                                .file(Some(caller_file))
                                .line(Some(caller_line))
                                .build(),
                        );
                        Err(FrameworkError::Error400(Box::new(err)))
                    }
                }
            }

            /// This macro captures `module_path!()`, `file!()`, and `line!()` at the
            /// *call site* (the place where the macro is invoked), then forwards them
            /// to the implementation function. This way the log record shows the
            /// caller's module, file, and line.
            #[macro_export]
            macro_rules! log_and_explain_400 {
                ($expr:expr) => {
                    $crate::my_library::extensions::logging::log_and_explain_400_impl(
                        $expr,
                        module_path!(),
                        file!(),
                        line!(),
                    )
                };
            }
        }
    }
}

pub mod my_application_code {
    pub mod routes_example {
        fn failing_function() -> Result<u32, std::num::ParseIntError> {
            "abc".parse()
        }

        pub fn some_route() -> Result<u32, crate::FrameworkError> {
            log::warn!("This log call is from the correct module");
            // Use the macro instead of a trait method.
            // The macro captures module_path!(), file!(), line!() here at the call site.
            let long_chain = log_and_explain_400!(failing_function())? + 42;
            Ok(long_chain)
        }
    }
}

fn main() {
    let _ = dotenvy::dotenv();
    env_logger::builder()
        .filter_level(log::LevelFilter::Info)
        .init();

    let failure = my_application_code::routes_example::some_route();

    println!("{failure:?}");
}
"
}
```

**How it works:**

1. **The problem:** `log::warn!()` and friends expand `module_path!()` at the macro invocation site, which is inside your library module — so the log shows the library's module path.

2. **The solution:** Instead of a trait method, we use a **macro** (`log_and_explain_400!`) that the application code invokes. Because macros like `module_path!()`, `file!()`, and `line!()` expand at the point where they appear in source, and our macro is invoked from the application code, these values reflect the *caller's* location.

3. The macro passes these captured values to a regular function (`log_and_explain_400_impl`) which uses `log::logger().log()` with a manually-built `log::Record` where `module_path`, `file`, and `line` are all set to the caller's values.

**Output will now show:**
```
[WARN  question_location_log::my_application_code::routes_example] This log call is from the correct module
[WARN  question_location_log::my_application_code::routes_example] location src/main.rs:64: Error: ParseIntError { kind: InvalidDigit }
```

Both log lines now show the same correct module path.

```json
{
  "Cargo.toml": "[package]
name = "lazy-asset-loader"
version = "0.1.0"
edition = "2021"

[dependencies]
bevy = "0.15"
zip = "2.6"
",
  "main.rs": "//! Lazy Asset Loader for Bevy
//!
//! Demonstrates how to use a custom `AssetSource` + `AssetReader` so that
//! individual assets inside a zip (or any archive) are loaded on-demand
//! (lazily) through Bevy's normal asset system.
//!
//! With this approach you never load the whole archive up-front.  Instead,
//! when Bevy asks for  `zip://my_archive.zip#textures/brick.png`  only
//! *that one entry* is read from the zip file.
//!
//! ## How to test
//!
//! 1. Create a folder called `assets/` next to your `Cargo.toml`.
//! 2. Put a zip file in it, e.g. `assets/my_archive.zip`, that contains at
//!    least one image – say `textures/brick.png` inside the zip.
//! 3. `cargo run`
//!
//! The program will load `zip://my_archive.zip#textures/brick.png` lazily
//! and display it as a sprite.

use bevy::{
    asset::{
        io::{
            AssetReader, AssetReaderError, AssetSource, AssetSourceId,
            PathStream, Reader,
        },
        AssetApp,
    },
    prelude::*,
};
use std::{
    io::Read,
    path::{Path, PathBuf},
    sync::Arc,
};

// ---------------------------------------------------------------------------
// 1.  ZipAssetReader – the heart of the lazy loading
// ---------------------------------------------------------------------------

/// An [`AssetReader`] that interprets paths of the form
/// `<archive_path>#<entry_path>` and reads only the requested entry from the
/// zip file.  Everything is on-demand – no eager bulk-loading.
struct ZipAssetReader {
    /// Root directory that contains the zip files (typically the normal
    /// `assets/` folder).  We resolve archive paths relative to this.
    root: PathBuf,
}

impl ZipAssetReader {
    fn new(root: PathBuf) -> Self {
        Self { root }
    }

    /// Split a virtual path such as `my_archive.zip/textures/brick.png`
    /// into `("my_archive.zip", "textures/brick.png")`.
    ///
    /// Convention: the first component whose extension is `.zip` (case-
    /// insensitive) marks the boundary between the archive file and the
    /// inner entry path.
    fn split_archive_path(path: &Path) -> Option<(PathBuf, PathBuf)> {
        let mut archive = PathBuf::new();
        let mut remainder = PathBuf::new();
        let mut found = false;
        for component in path.components() {
            if !found {
                archive.push(component);
                if archive
                    .extension()
                    .map(|e| e.to_ascii_lowercase() == "zip")
                    .unwrap_or(false)
                {
                    found = true;
                }
            } else {
                remainder.push(component);
            }
        }
        if found && !remainder.as_os_str().is_empty() {
            Some((archive, remainder))
        } else {
            None
        }
    }
}

impl AssetReader for ZipAssetReader {
    fn read<'a>(
        &'a self,
        path: &'a Path,
    ) -> impl core::future::Future<
        Output = Result<Box<dyn Reader + 'a>, AssetReaderError>,
    > + Send {
        let owned_root = self.root.clone();
        let owned_path = path.to_path_buf();

        async move {
            let (archive_rel, entry_path) =
                Self::split_archive_path(&owned_path).ok_or_else(|| {
                    AssetReaderError::NotFound(owned_path.clone())
                })?;

            let archive_abs = owned_root.join(&archive_rel);

            // Open the zip and read *only* the requested entry.
            let file = std::fs::File::open(&archive_abs).map_err(|_| {
                AssetReaderError::NotFound(archive_abs.clone())
            })?;
            let mut zip = zip::ZipArchive::new(file).map_err(|_| {
                AssetReaderError::NotFound(archive_abs.clone())
            })?;

            let entry_str = entry_path.to_string_lossy().replace('\\', "/");

            let mut entry =
                zip.by_name(&entry_str).map_err(|_| {
                    AssetReaderError::NotFound(owned_path.clone())
                })?;

            let mut buf = Vec::with_capacity(entry.size() as usize);
            entry.read_to_end(&mut buf).map_err(|_| {
                AssetReaderError::NotFound(owned_path.clone())
            })?;

            let reader: Box<dyn Reader> =
                Box::new(bevy::asset::io::VecReader::new(buf));
            Ok(reader)
        }
    }

    fn read_meta<'a>(
        &'a self,
        path: &'a Path,
    ) -> impl core::future::Future<
        Output = Result<Box<dyn Reader + 'a>, AssetReaderError>,
    > + Send {
        async move {
            // We don't store .meta files inside the zip; just report not-found
            // so Bevy falls back to defaults.
            Err(AssetReaderError::NotFound(path.to_path_buf()))
        }
    }

    fn read_directory<'a>(
        &'a self,
        path: &'a Path,
    ) -> impl core::future::Future<
        Output = Result<Box<PathStream>, AssetReaderError>,
    > + Send {
        async move {
            // Directory listing inside a zip – left as an exercise.
            Err(AssetReaderError::NotFound(path.to_path_buf()))
        }
    }

    fn is_directory<'a>(
        &'a self,
        path: &'a Path,
    ) -> impl core::future::Future<Output = Result<bool, AssetReaderError>> + Send
    {
        async move { Ok(false) }
    }
}

// ---------------------------------------------------------------------------
// 2.  Plugin that registers the custom "zip://" asset source
// ---------------------------------------------------------------------------

pub struct ZipAssetSourcePlugin;

impl Plugin for ZipAssetSourcePlugin {
    fn build(&self, app: &mut App) {
        // Determine the default assets root that Bevy would use.  Bevy itself
        // resolves `CARGO_MANIFEST_DIR/assets` during development and a
        // relative `assets/` folder in release builds.  We replicate that
        // logic here so our zip reader looks in the same place.
        let assets_root = {
            if let Ok(manifest_dir) = std::env::var("CARGO_MANIFEST_DIR") {
                PathBuf::from(manifest_dir).join("assets")
            } else {
                PathBuf::from("assets")
            }
        };

        let root = Arc::new(assets_root);

        app.register_asset_source(
            AssetSourceId::Name("zip".into()),
            AssetSource::build().with_reader(move || {
                Box::new(ZipAssetReader::new((*root).clone()))
            }),
        );
    }
}

// ---------------------------------------------------------------------------
// 3.  Minimal Bevy app that uses the lazy zip loader
// ---------------------------------------------------------------------------

fn main() {
    // -- Create a tiny zip file in the assets folder so the demo is fully
    //    self-contained and "just works" with `cargo run`.  In real life
    //    you would of course ship pre-made archives.
    create_demo_zip_if_missing();

    App::new()
        .add_plugins(DefaultPlugins)
        .add_plugins(ZipAssetSourcePlugin)
        .add_systems(Startup, setup)
        .add_systems(Update, check_load)
        .run();
}

#[derive(Resource)]
struct LazyHandle(Handle<Image>);

fn setup(mut commands: Commands, asset_server: Res<AssetServer>) {
    commands.spawn(Camera2d::default());

    // Load a single entry from inside the zip – lazily!
    let handle: Handle<Image> =
        asset_server.load("zip://demo_archive.zip/textures/brick.png");

    info!("Requested lazy load of zip://demo_archive.zip/textures/brick.png");
    commands.insert_resource(LazyHandle(handle));
}

fn check_load(
    mut commands: Commands,
    handle: Option<Res<LazyHandle>>,
    assets: Res<Assets<Image>>,
) {
    let Some(h) = handle else { return };
    if assets.get(&h.0).is_some() {
        info!("Image loaded successfully from zip!");
        commands.spawn(Sprite::from_image(h.0.clone()));
        commands.remove_resource::<LazyHandle>();
    }
}

// ---------------------------------------------------------------------------
// Helper: generate a demo zip so the example is self-contained
// ---------------------------------------------------------------------------

fn create_demo_zip_if_missing() {
    let assets_dir = if let Ok(m) = std::env::var("CARGO_MANIFEST_DIR") {
        PathBuf::from(m).join("assets")
    } else {
        PathBuf::from("assets")
    };
    std::fs::create_dir_all(&assets_dir).ok();

    let zip_path = assets_dir.join("demo_archive.zip");
    if zip_path.exists() {
        return;
    }

    // Create a tiny 4×4 pink PNG in memory.
    let mut png_buf: Vec<u8> = Vec::new();
    {
        let mut encoder = png::Encoder::new(
            std::io::Cursor::new(&mut png_buf),
            4,
            4,
        );
        encoder.set_color(png::ColorType::Rgba);
        encoder.set_depth(png::BitDepth::Eight);
        let mut writer = encoder.write_header().expect("png header");
        // 4x4 pixels, RGBA, hot-pink
        let pixel: [u8; 4] = [255, 105, 180, 255];
        let row: Vec<u8> = pixel.repeat(4);
        let data: Vec<u8> = row.repeat(4);
        writer.write_image_data(&data).expect("png data");
    }

    // Write zip
    let file =
        std::fs::File::create(&zip_path).expect("create demo zip");
    let mut zip_writer = zip::ZipWriter::new(file);
    let options = zip::write::SimpleFileOptions::default()
        .compression_method(zip::CompressionMethod::Stored);
    zip_writer
        .start_file("textures/brick.png", options)
        .expect("zip entry");
    std::io::Write::write_all(&mut zip_writer, &png_buf)
        .expect("zip write");
    zip_writer.finish().expect("zip finish");

    info!("Created demo archive at {:?}", zip_path);
}
"
}
