        ArrayIteratorFromDynMut {
            store_ptr,
            dims,
            store_len,
            selection_iterators: selections,
            selection_dims,
            current_iterators,
            current_index_option,
            _marker: std::marker::PhantomData,
        }
    }

    /// Row-major flat index computation.
    fn flat_index(&self, index: &[usize]) -> usize {
        let mut flat = 0usize;
        let mut stride = 1usize;
        for i in (0..self.dims.len()).rev() {
            assert!(index[i] < self.dims[i]);
