                self.current_index_option[i] = self.current_iterators[i].next();
                if i < self.selection_iterators.len() - 1 {
                    self.current_index_option[i + 1] = self.current_iterators[i + 1].next();
                }
            } else {
                break;
            }
        }
        let current_index: Vec<usize> = self
            .current_index_option
            .iter()
            .map(|x| x.unwrap())
            .collect();
        let fi = self.flat_index(&current_index);
        assert!(fi < self.store_len);

        // SAFETY:
        // 1. `store_ptr` was obtained from a valid `&'a mut Array<T>`,
        //    so the memory is valid for the lifetime `'a`.
        // 2. The caller guarantees the selection iterators produce each
        //    multi-dimensional index at most once, so we never create
        //    two `&mut T` to the same element.
        let current_value: &'a mut T = unsafe { &mut *self.store_ptr.add(fi) };

        Some((current_index, current_value))
    }
}

