//! stage callbacks that may run on arbitrary Tokio threads.
//!
//! Key idea:
//!   1. Create a long-lived *request* span.
//!   2. Capture a `tracing::Span` handle and store it in your shared context.
//!   3. In every stage callback, enter that span (via `instrument` or
//!      `Span::enter` / `Span::entered`) so that new child spans are
//!      properly parented.
//!
//! The `tracing::Span` type is `Send + Sync + Clone`, so it is safe to stash
//! in an `Arc<Mutex<_>>`, a per-request context struct, etc.

use opentelemetry::trace::TracerProvider as _;
use opentelemetry_sdk::{
    trace::{SdkTracerProvider, Tracer},
    Resource,
};
use opentelemetry::KeyValue;
use std::sync::Arc;
use tokio::sync::Mutex;
use tracing::{info_span, instrument, Instrument, Span};
use tracing_opentelemetry::OpenTelemetryLayer;
use tracing_subscriber::{layer::SubscriberExt, registry::LookupSpan, util::SubscriberInitExt};

// ---------------------------------------------------------------------------
// 1.  Shared per-request context – this is what you'd put in Pingora's CTX.
// ---------------------------------------------------------------------------
#[derive(Clone)]
struct RequestContext {
    /// The long-lived parent span that covers the entire request.
    /// We will re-activate ("rehydrate") it in every stage callback.
    parent_span: Arc<Mutex<Span>>,
}

impl RequestContext {
    fn new(span: Span) -> Self {
        Self {
            parent_span: Arc::new(Mutex::new(span)),
        }
    }
}

// ---------------------------------------------------------------------------
// 2.  Stage callbacks – imagine these are called by Pingora on any thread.
// ---------------------------------------------------------------------------

/// Stage 1: e.g. `request_filter`
async fn stage1(ctx: &RequestContext) {
    // --- rehydrate: get a clone of the stored span and use it as parent ---
    let parent = ctx.parent_span.lock().await.clone();

    // Option A: create a child span explicitly parented
    let stage_span = info_span!(parent: &parent, "stage_1");

    // `.instrument(stage_span)` makes the span active for the duration of
    // the async block, even across `.await` points and thread migrations.
    async {
        tracing::info!("doing work in stage 1");
        do_stage_work("stage-1-work").await;
    }
    .instrument(stage_span)
    .await;
}

/// Stage 2: e.g. `upstream_peer`
async fn stage2(ctx: &RequestContext) {
    let parent = ctx.parent_span.lock().await.clone();
    let stage_span = info_span!(parent: &parent, "stage_2");

    async {
        tracing::info!("doing work in stage 2");
        do_stage_work("stage-2-work").await;
    }
    .instrument(stage_span)
    .await;
}

