async fn stage_upstream(ctx: &RequestContext) {
    let parent = ctx.parent_span.lock().await.clone();
    let stage_span = info_span!(parent: &parent, "upstream");

    async {
        tracing::info!("calling upstream");
        do_stage_work("upstream-work").await;
    }
    .instrument(stage_span)
    .await;
}

/// Simulate some async work inside a stage.
