    // Create the long-lived parent span.
    let request_span = info_span!("request", request_id = %uuid_v4());

    // Build context with the span handle.
    let ctx = RequestContext::new(request_span.clone());

    // Simulate Pingora calling stages on potentially different tasks/threads.
    // The parent span stays active across all of them because each stage
    // re-activates it via `info_span!(parent: &parent, ...)`.
    {
