    let ctx1 = ctx.clone();
    let h1 = tokio::spawn(async move { stage1(&ctx1).await });
    h1.await.unwrap();

    let ctx2 = ctx.clone();
    let h2 = tokio::spawn(async move { stage2(&ctx2).await });
    h2.await.unwrap();

    let ctx3 = ctx.clone();
    let h3 = tokio::spawn(async move { stage_upstream(&ctx3).await });
    h3.await.unwrap();

    // Mark the request span as complete.
    {
        let _guard = request_span.enter();
        tracing::info!("request finished");
    }
    drop(request_span);

    // Flush traces.
    let _ = provider.shutdown();

