  "main.rs": "use std::env;
use std::fs;
use std::io::Write;
use std::process::Command;

fn main() {
    // The Python script is embedded directly into the binary at compile time.
    // This means `cargo install` produces a single self-contained binary with
    // the Python script baked in. At runtime we write it to a temporary file
    // and invoke the Python interpreter on it.
    const SCRIPT_CONTENTS: &str = include_str!("python/script.py");

    // Write the embedded script to a temporary file
    let tmp_dir = env::temp_dir();
    let script_path = tmp_dir.join("rust_program_script.py");

    fs::write(&script_path, SCRIPT_CONTENTS).expect("Failed to write temporary Python script");

    // Try `python3` first, then fall back to `python`
    let python = if Command::new("python3").arg("--version").output().is_ok() {
        "python3"
    } else {
        "python"
    };

    let status = Command::new(python)
        .arg(&script_path)
        .status()
        .expect("Failed to execute Python interpreter. Is Python installed?");

    // Clean up the temporary file (best-effort)
    let _ = fs::remove_file(&script_path);

    // Propagate the exit code from the Python script
    std::process::exit(status.code().unwrap_or(1));
}
"
}
```

**How to use it:**

1. Create the project structure:
   ```
   rust-program/
   ├── Cargo.toml
   └── src/
       ├── main.rs
       └── python/
           └── script.py
   ```

2. Place your Python script at `src/python/script.py`. For example:
   ```python
   print("Hello from the embedded Python script!")
   ```

3. Run with `cargo run` or install with `cargo install --path .`

**How it works:**

- `include_str!("python/script.py")` embeds the entire contents of `script.py` into the compiled Rust binary at compile time. This means after `cargo install`, the binary is fully self-contained — no separate Python file needs to be distributed.
- At runtime, the embedded script is written to a temporary file in the OS temp directory, then the Python interpreter is invoked on it, and the temp file is cleaned up afterward.
- The user only needs Python installed; they never need to know about `script.py`.

