                let mut stdin = child_stdin.lock().unwrap();
                if writeln!(stdin, "{}", line).is_err() {
                    eprintln!("Child process stdin closed.");
                    break;
                }
                let _ = stdin.flush();

                // Give the child a moment to produce output
                // (In a real app you might use more sophisticated synchronization)
                thread::sleep(std::time::Duration::from_millis(100));
            }
            Err(ReadlineError::Interrupted) => {
                println!("CTRL-C");
                break;
            }
            Err(ReadlineError::Eof) => {
                println!("CTRL-D");
                break;
            }
            Err(err) => {
                println!("Error: {:?}", err);
                break;
            }
        }
    }

    // Clean up: kill the child process
    let _ = child.kill();
    let _ = child.wait();
    let _ = shutdown_tx.send(());

    // Wait for reader threads to finish
    let _ = stdout_handle.join();
    let _ = stderr_handle.join();

    println!("Goodbye!");
    Ok(())
