//! You'll see the shell output interleaved with your typing — true full-duplex.

use nix::fcntl::{fcntl, FcntlArg, OFlag};
use nix::poll::{poll, PollFd, PollFlags, PollTimeout};
use nix::pty::openpty;
use nix::sys::termios::{self, LocalFlags, SetArg};
use nix::unistd::{close, dup, execvp, fork, read, setsid, write, ForkResult};
use std::ffi::CString;
use std::io::{self, BufRead, Write};
use std::os::fd::{FromRawFd, OwnedFd};
use std::thread;

