    let pty = openpty(None, None).expect("openpty failed");
    let master_fd = pty.master;
    let slave_fd = pty.slave;

    // ── 2. Fork: child becomes the shell on the slave side ─────────────
    match unsafe { fork() }.expect("fork failed") {
        ForkResult::Child => {
            // New session so the slave becomes the controlling terminal
            setsid().ok();

            // Close master in child
            // Safety: we won't use master_fd after this in the child
            let _ = close(master_fd.as_raw_fd());

            // Dup slave onto stdin/stdout/stderr
            let slave_raw = slave_fd.as_raw_fd();
            unsafe {
                libc::dup2(slave_raw, 0);
                libc::dup2(slave_raw, 1);
                libc::dup2(slave_raw, 2);
            }
            if slave_raw > 2 {
                let _ = close(slave_raw);
            }

            // Exec a shell
            let sh = CString::new("/bin/sh").unwrap();
            let args: [CString; 1] = [sh.clone()];
            let args_ref: Vec<&std::ffi::CStr> = args.iter().map(|a| a.as_c_str()).collect();
            execvp(&sh, &args_ref).expect("execvp failed");
            unreachable!();
        }
