            // Close slave in parent
            let _ = close(slave_fd.as_raw_fd());
            // Forget the OwnedFd so it doesn't double-close
            std::mem::forget(slave_fd);

            let master_raw = master_fd.as_raw_fd();

            // ── 3. Dup the master fd — one copy for reading, one for writing ──
            let reader_raw = dup(master_raw).expect("dup failed for reader");
            let writer_raw = dup(master_raw).expect("dup failed for writer");

