use std::fmt;

// The borrowed struct we want to deserialize into
#[derive(Deserialize, Debug)]
struct MyData<'a> {
    data: &'a str,
    more_data: &'a str,
}

/// A self-referential container that owns the String and holds
/// the deserialized borrowed data pointing into it.
///
/// We use a raw pointer to erase the lifetime. This is safe because:
/// 1. The String is heap-allocated and pinned (we never move or mutate it after deserialization).
/// 2. The MyData borrows from that String, and we ensure the String outlives MyData.
/// 3. We encapsulate everything so the user cannot break the invariant.
struct OwnedMyData {
    // We keep the source string alive. Box<str> would also work, but String is fine.
    // IMPORTANT: _source must never be mutated or dropped before `parsed` is dropped.
    _source: String,
    // Raw pointer to a heap-allocated MyData<'static> (lifetime erased).
    // In reality the references inside point into `_source`.
    parsed: *const MyData<'static>,
}

// SAFETY: The String is immutable and lives on the heap. The parsed pointer
// points to a heap allocation whose references point into the String.
// We never hand out &mut to either, so sending across threads is safe.
unsafe impl Send for OwnedMyData {}
unsafe impl Sync for OwnedMyData {}

impl OwnedMyData {
    /// Deserialize once, storing both the source string and the parsed result.
    fn new(source: String) -> Result<Self, serde_json::Error> {
        // Deserialize borrowing from `source`.
        // We transmute the lifetime to 'static so we can store it.
        // This is safe because we guarantee `source` lives as long as `parsed`.
        let data: MyData<'_> = serde_json::from_str(&source)?;
        let data_static: MyData<'static> = unsafe { std::mem::transmute(data) };
        let boxed = Box::new(data_static);
        let ptr = Box::into_raw(boxed) as *const MyData<'static>;

        Ok(OwnedMyData {
            _source: source,
            parsed: ptr,
        })
    }

    /// Access the deserialized data.
    fn get(&self) -> &MyData<'_> {
        // SAFETY: `parsed` is valid as long as `self` is alive, and `_source` is alive.
        unsafe { &*self.parsed }
    }
}

impl Drop for OwnedMyData {
    fn drop(&mut self) {
        // SAFETY: We created this with Box::into_raw, so we must free it.
        unsafe {
            drop(Box::from_raw(self.parsed as *mut MyData<'static>));
        }
    }
}

impl fmt::Debug for OwnedMyData {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("OwnedMyData")
            .field("parsed", self.get())
            .finish()
    }
}

