  "main.rs": "use chumsky::prelude::*;

#[derive(Debug)]
pub enum BinOp {
    Mul,
    Div,
}

#[derive(Debug)]
pub enum Expr {
    Int(i32),
    Binary {
        left: Box<Expr>,
        op: BinOp,
        right: Box<Expr>,
    },
}

fn parse_mul_op<'a>() -> impl Parser<'a, &'a str, BinOp> {
    just('*').to(BinOp::Mul)
        .or(just('/').to(BinOp::Div))
}

fn parse_primary<'a>() -> impl Parser<'a, &'a str, Expr> {
    text::int(10).map(|s: &str| Expr::Int(s.parse().unwrap()))
}

fn parse_mul_div<'a>() -> impl Parser<'a, &'a str, Expr> {
    parse_primary()
        .foldl(parse_mul_op().then(parse_primary()).repeated(), |lhs, (op, rhs)| {
            Expr::Binary {
                left: Box::new(lhs),
                op,
                right: Box::new(rhs),
            }
        })
}

fn main() {
    let parser = parse_mul_div();
    let result = parser.parse("1*2*3");
    println!("{:?}", result);

    let result2 = parser.parse("10/2*5");
    println!("{:?}", result2);

    let result3 = parser.parse("42");
    println!("{:?}", result3);
}
