// ---------------------------------------------------------------------------
// Macro that replaces a proc-macro derive – works with stable Rust, no extra
// crate needed.  It reads "attribute-like" metadata from a declarative
// description of the struct and generates `IntoNotionProperties`.
//
// Usage:
//   notion_struct! {
//       #[derive(Debug, Clone, Serialize, Deserialize)]
//       struct MyUnit {
//           #[notion(type = "title", name = "Name")]
//           pub name: String,
//
//           #[notion(type = "url", name = "Icon url")]
//           pub icon_url: Option<String>,
//
//           #[notion(type = "multi_select", name = "Roles")]
//           pub categories: Option<Vec<serde_json::Value>>,
//       }
//   }
// ---------------------------------------------------------------------------

macro_rules! notion_struct {
    // Entry point – collect all fields
    (
        $(#[$struct_meta:meta])*
        struct $name:ident {
            $(
                #[notion(type = $prop_type:literal, name = $prop_name:literal)]
                $vis:vis $field:ident : $ftype:ty
            ),* $(,)?
        }
    ) => {
        $(#[$struct_meta])*
        pub struct $name {
            $(
                $vis $field : $ftype,
            )*
        }

        impl IntoNotionProperties for $name {
            fn into_notion_properties(&self) -> HashMap<String, PropertyValues> {
                let mut map = HashMap::new();
                $(
                    notion_struct!(@insert map, self, $field, $ftype, $prop_type, $prop_name);
                )*
                map
            }
        }
    };

    // ---- per-type insertion rules ----

    // Option<String> fields  – only insert when Some
    (@insert $map:ident, $self:ident, $field:ident, Option<String>, $prop_type:literal, $prop_name:literal) => {
        if let Some(ref val) = $self.$field {
            let pv = notion_struct!(@make $prop_type, string val);
            $map.insert($prop_name.to_string(), pv);
        }
    };

    // Option<Vec<serde_json::Value>> – multi-select
    (@insert $map:ident, $self:ident, $field:ident, Option<Vec<serde_json::Value>>, $prop_type:literal, $prop_name:literal) => {
        if let Some(ref vals) = $self.$field {
            let pv = notion_struct!(@make $prop_type, vec vals);
            $map.insert($prop_name.to_string(), pv);
        }
    };

    // Vec<serde_json::Value>  – multi-select (non-optional)
    (@insert $map:ident, $self:ident, $field:ident, Vec<serde_json::Value>, $prop_type:literal, $prop_name:literal) => {
        {
            let pv = notion_struct!(@make $prop_type, vec &$self.$field);
            $map.insert($prop_name.to_string(), pv);
        }
    };

    // Option<f64>
    (@insert $map:ident, $self:ident, $field:ident, Option<f64>, $prop_type:literal, $prop_name:literal) => {
        if let Some(val) = $self.$field {
            let pv = notion_struct!(@make $prop_type, number val);
            $map.insert($prop_name.to_string(), pv);
        }
    };

    // Option<bool>
    (@insert $map:ident, $self:ident, $field:ident, Option<bool>, $prop_type:literal, $prop_name:literal) => {
        if let Some(val) = $self.$field {
            let pv = notion_struct!(@make $prop_type, bool val);
            $map.insert($prop_name.to_string(), pv);
        }
    };

    // String (non-optional)
    (@insert $map:ident, $self:ident, $field:ident, String, $prop_type:literal, $prop_name:literal) => {
        {
            let pv = notion_struct!(@make $prop_type, string &$self.$field);
            $map.insert($prop_name.to_string(), pv);
        }
    };

    // f64 (non-optional)
    (@insert $map:ident, $self:ident, $field:ident, f64, $prop_type:literal, $prop_name:literal) => {
        {
            let pv = notion_struct!(@make $prop_type, number $self.$field);
            $map.insert($prop_name.to_string(), pv);
        }
    };

    // bool (non-optional)
    (@insert $map:ident, $self:ident, $field:ident, bool, $prop_type:literal, $prop_name:literal) => {
        {
            let pv = notion_struct!(@make $prop_type, bool $self.$field);
            $map.insert($prop_name.to_string(), pv);
        }
    };

    // ---- @make helpers that map the type string to the constructor ----

    (@make "title", string $val:expr) => { make_title($val) };
    (@make "rich_text", string $val:expr) => { make_rich_text($val) };
    (@make "url", string $val:expr) => { make_url($val) };
    (@make "email", string $val:expr) => { make_email($val) };
    (@make "phone_number", string $val:expr) => { make_phone_number($val) };
    (@make "select", string $val:expr) => { make_select($val) };
    (@make "number", number $val:expr) => { make_number($val) };
    (@make "checkbox", bool $val:expr) => { make_checkbox($val) };
    (@make "multi_select", vec $val:expr) => { make_multi_select($val) };
}

// ---------------------------------------------------------------------------
// Define a concrete struct with the macro
// ---------------------------------------------------------------------------

notion_struct! {
    #[derive(Debug, Clone, Serialize, Deserialize)]
    struct MyUnit {
