use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::mpsc::{self, Sender};
use std::sync::Arc;
use std::thread;
use std::time::Duration;

use signal_hook::consts::{SIGINT, SIGTERM};
use signal_hook::iterator::Signals;
use termion::raw::IntoRawMode;

#[derive(Debug)]
enum Message {
    Key(char),
    Signal(i32),
    Quit,
}

/// Listens for Unix signals (SIGINT, SIGTERM) and sends a Message.
/// Checks the `shutdown` flag periodically via `Signals::wait` with a timeout-like approach.
fn yield_signals(sender: Sender<Message>, shutdown: Arc<AtomicBool>) {
    let mut signals = Signals::new(&[SIGINT, SIGTERM]).expect("Failed to register signals");

    // signals.forever() blocks indefinitely, but we can use the pending() iterator
    // in a loop with a small sleep so we can check the shutdown flag.
    loop {
        if shutdown.load(Ordering::Relaxed) {
            break;
        }
        // pending() returns signals that have arrived since the last call, non-blocking.
        for sig in signals.pending() {
            match sig {
                SIGINT => {
                    let _ = sender.send(Message::Signal(SIGINT));
                    let _ = sender.send(Message::Quit);
                    shutdown.store(true, Ordering::Relaxed);
                    return;
                }
                SIGTERM => {
                    let _ = sender.send(Message::Signal(SIGTERM));
                    let _ = sender.send(Message::Quit);
                    shutdown.store(true, Ordering::Relaxed);
                    return;
                }
                _ => {}
            }
        }
        thread::sleep(Duration::from_millis(100));
    }
}

/// Listens for key events from stdin and sends a Message.
/// Uses non-blocking reads so we can check the shutdown flag.
fn yield_keys(sender: Sender<Message>, shutdown: Arc<AtomicBool>) {
    // We need raw mode so keys are sent immediately without waiting for Enter.
    let _stdout = io::stdout().into_raw_mode().expect("Failed to enter raw mode");

    // Set stdin to non-blocking so we can poll it.
    // We'll read byte-by-byte with a small timeout.
    let stdin = stdin();
    // On Unix we can set the file descriptor to non-blocking.
    #[cfg(unix)]
    {
        use std::os::unix::io::AsRawFd;
        let fd = stdin.as_raw_fd();
        unsafe {
            let flags = libc::fcntl(fd, libc::F_GETFL);
            libc::fcntl(fd, libc::F_SETFL, flags | libc::O_NONBLOCK);
        }
    }

    let mut buf = [0u8; 1];
    loop {
        if shutdown.load(Ordering::Relaxed) {
            break;
        }
        match stdin.lock().read(&mut buf) {
            Ok(1) => {
                let ch = buf[0] as char;
                if ch == 'q' {
                    let _ = sender.send(Message::Quit);
                    shutdown.store(true, Ordering::Relaxed);
                    return;
                } else {
                    let _ = sender.send(Message::Key(ch));
                }
            }
            Ok(_) => {
                // EOF or 0 bytes
                thread::sleep(Duration::from_millis(50));
            }
            Err(ref e) if e.kind() == io::ErrorKind::WouldBlock => {
                // No data available right now
                thread::sleep(Duration::from_millis(50));
            }
            Err(_) => {
                // Some other error; just sleep and retry
                thread::sleep(Duration::from_millis(50));
            }
        }
    }
}

fn main() {
    println!("Event loop demo. Press keys to see events. Press 'q' to quit.");
    println!("You can also send SIGINT (Ctrl+C) or SIGTERM to quit.\n");

    let (sender, receiver) = mpsc::channel();
    let shutdown = Arc::new(AtomicBool::new(false));

    // Spawn signal listener thread
    let sig_sender = sender.clone();
    let sig_shutdown = shutdown.clone();
    let sig_handle = thread::spawn(move || {
        yield_signals(sig_sender, sig_shutdown);
    });

    // Spawn key listener thread
    let key_sender = sender.clone();
    let key_shutdown = shutdown.clone();
    let key_handle = thread::spawn(move || {
        yield_keys(key_sender, key_shutdown);
    });

    // Drop our copy of sender so the receiver closes when all threads finish
    drop(sender);

    // Main event loop
    for msg in receiver.iter() {
        match msg {
            Message::Key(ch) => {
                println!("Key pressed: {:?}", ch);
            }
            Message::Signal(sig) => {
                println!("Received signal: {}", sig);
            }
            Message::Quit => {
                println!("Quit message received. Shutting down...");
                shutdown.store(true, Ordering::Relaxed);
                break;
            }
        }
    }

    // Wait for threads to finish
    let _ = sig_handle.join();
    let _ = key_handle.join();

    println!("Goodbye!");
}
"
}
```

### How it works:

1. **`Arc<AtomicBool>` shutdown flag**: Shared between all threads and the main function. Any thread or the main loop can set it to `true` to signal all threads to stop.

2. **Non-blocking reads**: Instead of using blocking iterators like `signals.forever()` or `stdin.events()`, we use:
   - `signals.pending()` — returns only already-arrived signals (non-blocking), combined with a small sleep
   - Non-blocking stdin reads via `O_NONBLOCK` on the file descriptor, combined with a small sleep

3. **Prompt shutdown**: Because each thread checks the shutdown flag every ~50-100ms (during its sleep), threads exit promptly when shutdown is requested — they don't need to wait for the next event.

4. **Quit triggers**: Either pressing `q` or receiving `SIGINT`/`SIGTERM` sends `Message::Quit` and sets the shutdown flag, causing all threads and the main loop to exit cleanly.

Here's a solution that demonstrates how to work around the `enum_dispatch` same-crate limitation by using a procedural-macro-free approach with a custom macro that generates the enum dispatch boilerplate. This keeps the three-layer architecture (`al`, `il`, `bl`) separate within modules while avoiding circular dependencies.

```json
{
  "Cargo.toml": "[package]
name = "enum_dispatch_design"
version = "0.1.0"
edition = "2021"

[dependencies]
async-trait = "0.1"",
  "main.rs": "// =============================================================================
// This example demonstrates how to solve the enum_dispatch cross-crate problem
// by using a declarative macro to generate the dispatching enum + impl.
//
// Architecture:
//   - `al` (abstract layer): defines the `Rest` trait
//   - `il` (implementation layer): defines `Foo` and `Boo` implementing `Rest`
//   - `bl` (business layer): ties everything together, creates the dispatch enum
//
// The key insight: instead of relying on the `enum_dispatch` crate (which
// requires trait + enum in the same crate), we write a declarative macro
// `impl_rest_dispatch!` in the `al` layer that can be invoked from *any* crate
// to generate both the enum and the trait impl with full static dispatch.
// =============================================================================

// ---------------------------------------------------------------------------
// Abstract Layer (al)
// ---------------------------------------------------------------------------
mod al {
    /// The trait with many methods (simplified here to a representative set).
    /// In your real code this would have ~20 methods.
    pub trait Rest {
        fn get(&self, url: &str) -> String;
        fn post(&self, url: &str, body: &str) -> String;
        fn put(&self, url: &str, body: &str) -> String;
        fn delete(&self, url: &str) -> String;
        fn patch(&self, url: &str, body: &str) -> String;
        fn head(&self, url: &str) -> String;
        fn options(&self, url: &str) -> String;
        fn name(&self) -> &'static str;
    }

    /// A declarative macro that generates an enum and a `Rest` impl that
    /// delegates every method to the inner variant — exactly what
    /// `enum_dispatch` would do, but without the same-crate restriction.
    ///
    /// Usage (from any downstream crate / module):
    ///
    /// ```ignore
    /// impl_rest_dispatch! {
    ///     pub enum Item {
    ///         Foo(path::to::Foo),
    ///         Boo(path::to::Boo),
    ///     }
    /// }
    /// ```
    ///
    /// If you add or remove methods from `Rest`, you only need to update this
    /// macro in one place.
    #[macro_export]
    macro_rules! impl_rest_dispatch {
        (
            $vis:vis enum $Enum:ident {
                $( $Variant:ident( $Ty:ty ) ),+ $(,)?
            }
        ) => {
            $vis enum $Enum {
                $( $Variant($Ty), )+
            }

            // Generate From impls so we can do `.into()`
            $(
                impl From<$Ty> for $Enum {
                    fn from(v: $Ty) -> Self {
                        $Enum::$Variant(v)
                    }
                }
            )+

            impl $crate::al::Rest for $Enum {
                fn get(&self, url: &str) -> String {
                    match self {
                        $( $Enum::$Variant(inner) => inner.get(url), )+
                    }
                }

                fn post(&self, url: &str, body: &str) -> String {
                    match self {
                        $( $Enum::$Variant(inner) => inner.post(url, body), )+
                    }
                }

                fn put(&self, url: &str, body: &str) -> String {
                    match self {
                        $( $Enum::$Variant(inner) => inner.put(url, body), )+
                    }
                }

                fn delete(&self, url: &str) -> String {
                    match self {
                        $( $Enum::$Variant(inner) => inner.delete(url), )+
                    }
                }

                fn patch(&self, url: &str, body: &str) -> String {
                    match self {
                        $( $Enum::$Variant(inner) => inner.patch(url, body), )+
                    }
                }

                fn head(&self, url: &str) -> String {
                    match self {
                        $( $Enum::$Variant(inner) => inner.head(url), )+
                    }
                }

                fn options(&self, url: &str) -> String {
                    match self {
                        $( $Enum::$Variant(inner) => inner.options(url), )+
                    }
                }

                fn name(&self) -> &'static str {
                    match self {
                        $( $Enum::$Variant(inner) => inner.name(), )+
                    }
                }
            }
        };
    }
}

// ---------------------------------------------------------------------------
// Implementation Layer (il) — depends only on `al`
// ---------------------------------------------------------------------------
mod il {
    use crate::al::Rest;

    // --- Foo ---------------------------------------------------------------
    pub struct Foo {
        pub base_url: String,
    }

    impl Foo {
        pub fn new(base_url: &str) -> Self {
            Self {
                base_url: base_url.to_owned(),
            }
        }
    }

    impl Rest for Foo {
        fn get(&self, url: &str) -> String {
            format!("[Foo GET] {} -> {}{}", self.base_url, self.base_url, url)
        }
        fn post(&self, url: &str, body: &str) -> String {
            format!("[Foo POST] {}{} body={}", self.base_url, url, body)
        }
        fn put(&self, url: &str, body: &str) -> String {
            format!("[Foo PUT] {}{} body={}", self.base_url, url, body)
        }
        fn delete(&self, url: &str) -> String {
            format!("[Foo DELETE] {}{}", self.base_url, url)
        }
        fn patch(&self, url: &str, body: &str) -> String {
            format!("[Foo PATCH] {}{} body={}", self.base_url, url, body)
        }
        fn head(&self, url: &str) -> String {
            format!("[Foo HEAD] {}{}", self.base_url, url)
        }
        fn options(&self, url: &str) -> String {
            format!("[Foo OPTIONS] {}{}", self.base_url, url)
        }
        fn name(&self) -> &'static str {
            "Foo"
        }
    }

    // --- Boo ---------------------------------------------------------------
    pub struct Boo {
        pub token: String,
    }

    impl Boo {
        pub fn new(token: &str) -> Self {
            Self {
                token: token.to_owned(),
            }
        }
    }

    impl Rest for Boo {
        fn get(&self, url: &str) -> String {
            format!("[Boo GET] {} (token={})", url, self.token)
        }
        fn post(&self, url: &str, body: &str) -> String {
            format!("[Boo POST] {} body={} (token={})", url, body, self.token)
        }
        fn put(&self, url: &str, body: &str) -> String {
            format!("[Boo PUT] {} body={} (token={})", url, body, self.token)
        }
        fn delete(&self, url: &str) -> String {
            format!("[Boo DELETE] {} (token={})", url, self.token)
        }
        fn patch(&self, url: &str, body: &str) -> String {
            format!("[Boo PATCH] {} body={} (token={})", url, body, self.token)
        }
        fn head(&self, url: &str) -> String {
            format!("[Boo HEAD] {} (token={})", url, self.token)
        }
        fn options(&self, url: &str) -> String {
            format!("[Boo OPTIONS] {} (token={})", url, self.token)
        }
        fn name(&self) -> &'static str {
            "Boo"
        }
    }
}

// ---------------------------------------------------------------------------
// Business Layer (bl) — depends on both `al` and `il`
// ---------------------------------------------------------------------------
mod bl {
    use crate::al::Rest;
    use crate::il::{Boo, Foo};

    // Invoke the macro from `al` to generate the dispatch enum in *this* layer.
    // This is the key trick: the macro lives in `al` (no dependency on `il`),
    // but it is expanded here in `bl` where both `Foo` and `Boo` are visible.
    //
    // The generated code is equivalent to what `enum_dispatch` would produce:
    //   - An enum `Item` with variants wrapping `Foo` and `Boo`
    //   - `impl Rest for Item` that delegates via match
    //   - `impl From<Foo> for Item` and `impl From<Boo> for Item`
    crate::impl_rest_dispatch! {
        pub enum Item {
            Foo(Foo),
            Boo(Boo),
        }
    }

    /// Example business function that accepts any `Item` and exercises the
    /// trait methods through static dispatch (no vtable, no boxing).
    pub fn run_service(item: &Item) {
        println!("--- Using service: {} ---", item.name());
        println!("{}", item.get("/users"));
        println!("{}", item.post("/users", r#"{"name":"Alice"}"#));
        println!("{}", item.put("/users/1", r#"{"name":"Bob"}"#));
        println!("{}", item.delete("/users/2"));
        println!("{}", item.patch("/users/3", r#"{"email":"c@d.com"}"#));
        println!("{}", item.head("/health"));
        println!("{}", item.options("/users"));
        println!();
    }

    /// Demonstrate that generic code over `Rest` works seamlessly.
    pub fn generic_consumer<R: Rest>(r: &R) {
        println!("[generic_consumer] name={}, get={}", r.name(), r.get("/ping"));
    }
}

// ---------------------------------------------------------------------------
// main
// ---------------------------------------------------------------------------
fn main() {
    use bl::{generic_consumer, run_service, Item};
    use il::{Boo, Foo};

    // Create concrete implementations
    let foo = Foo::new("https://api.foo.com");
    let boo = Boo::new("s3cr3t");

    // Wrap them in the dispatch enum (From impls generated by the macro)
    let item_foo: Item = foo.into();
    let item_boo: Item = boo.into();

    // Static dispatch through the enum — no dyn, no Box, no vtable
    run_service(&item_foo);
    run_service(&item_boo);

    // Also works with generic code bounded on `Rest`
    generic_consumer(&item_foo);
    generic_consumer(&item_boo);

    // Show that we can collect heterogeneous variants in a Vec<Item>
    let items: Vec<Item> = vec![
        Foo::new("https://one.com").into(),
        Boo::new("tok1").into(),
        Foo::new("https://two.com").into(),
        Boo::new("tok2").into(),
    ];

    println!("--- Iterating over {} items ---", items.len());
    for item in &items {
        println!("  {} -> {}", item.name(), item.get("/status"));
    }
}
"
}
```

**How this solves the problem:**

1. **No circular dependencies**: `al` defines the trait + the macro, `il` depends only on `al`, and `bl` depends on both `al` and `il`. The dependency graph is a clean DAG.

2. **No `enum_dispatch` crate needed**: The `impl_rest_dispatch!` declarative macro lives in `al` alongside the `Rest` trait. When you add/remove methods from `Rest`, you update the macro in the same place — single source of truth.

3. **Static dispatch**: The generated `match` on enum variants compiles to the same efficient code as `enum_dispatch` — no vtable, no dynamic dispatch, no heap allocation.

4. **Ergonomic**: `From` impls are generated so you can use `.into()`. The enum works in `Vec<Item>` for heterogeneous collections with static dispatch.

5. **Scalable to real workspaces**: In a multi-crate workspace, the macro would be `#[macro_export]`ed from the `al` crate and invoked in the `bl` crate with `al::impl_rest_dispatch! { ... }`.

