fn main() {
    let a: Vec<Vec<usize>> = vec![
        vec![1, 2, 3],
        vec![10, 20],
        vec![100, 200, 300, 400],
        vec![5],
    ];

    // Approach 1: Parallel over outer, sequential over inner
    let result1: Vec<Vec<String>> = a
        .par_iter()
        .map(|inner| inner.iter().map(|&x| format!("val={}", x * 2)).collect())
        .collect();

    println!("Approach 1 (parallel outer, sequential inner):");
    for (i, inner) in result1.iter().enumerate() {
        println!("  [{i}]: {inner:?}");
    }

    // Approach 2: Parallel over both outer AND inner
    let result2: Vec<Vec<String>> = a
        .par_iter()
        .map(|inner| {
            inner
                .par_iter()
                .map(|&x| format!("val={}", x * 2))
                .collect()
        })
        .collect();

    println!("\nApproach 2 (parallel outer and inner):");
    for (i, inner) in result2.iter().enumerate() {
        println!("  [{i}]: {inner:?}");
    }

    // Approach 3: Flatten, process in parallel, then reshape
    let lengths: Vec<usize> = a.iter().map(|inner| inner.len()).collect();
    let flat: Vec<usize> = a.iter().flatten().copied().collect();

    let processed: Vec<String> = flat
        .par_iter()
        .map(|&x| format!("val={}", x * 2))
        .collect();

    // Reshape back to the original nested structure
    let mut iter = processed.into_iter();
    let result3: Vec<Vec<String>> = lengths
        .iter()
        .map(|&len| iter.by_ref().take(len).collect())
        .collect();

    println!("\nApproach 3 (flatten, parallel process, reshape):");
    for (i, inner) in result3.iter().enumerate() {
        println!("  [{i}]: {inner:?}");
    }
}
"
