  "main.rs": "use std::ops::Deref;
use std::sync::Arc;
use tokio::sync::OnceCell;
use tokio_postgres::{Client, NoTls};

/// The key insight: when you cache the `Client`, you must also keep the
/// `JoinHandle` (or some other owned handle) for the spawned connection task
/// alive.  If you only store the `Client` and the spawned task happens to
/// complete (e.g. because the runtime polls it before the next use), the
/// connection is considered closed.
///
/// In practice the connection future only resolves when:
///   1. A fatal error occurs, **or**
///   2. The associated `Client` is dropped **and** all outstanding work has
///      completed.
///
/// But there is a subtle race: between the moment the `Client` finishes its
/// last piece of work and the moment you issue the *next* request, the
/// connection task can observe "no outstanding work + client not yet used
/// again" and resolve, which closes the connection.  This does NOT happen
/// when the `Client` is dropped – it happens when there is temporarily no
/// in-flight work.  The spawned task is essentially a `select!` loop that
/// can exit early if it sees an idle + closed-sender state.
///
/// The real fix is to **store the `JoinHandle`** so that the connection
/// task's result is never silently consumed, AND – more importantly – to
/// make sure you are not accidentally dropping the `Client`.  With
/// `OnceCell` + borrowing this should already work, so the 40%-failure the
/// author sees is most likely caused by the connection task finishing due to
/// a transient error (container not fully ready, etc.) rather than a
/// lifetime issue.
///
/// Below is a complete, self-contained example that demonstrates the
/// correct caching pattern.  It uses `Arc` so the cached connection can be
/// shared across calls, and stores the `JoinHandle` alongside the `Client`
/// so nothing is dropped prematurely.
///
/// To actually run this you need a Postgres instance on localhost:5432 with
/// password "postgres".  You can start one with:
///
/// ```sh
/// docker run --rm -e POSTGRES_PASSWORD=postgres -p 5432:5432 postgres:16
/// ```

// ---------------------------------------------------------------------------
// Cached connection handle
// ---------------------------------------------------------------------------

/// We store both the `Client` **and** the `JoinHandle` for the connection
/// driver task.  Dropping the `JoinHandle` does NOT abort the task (it just
/// detaches it), but keeping it around makes the intent clear and lets us
/// check for errors later if we want to.
struct CachedConnection {
    client: Client,
    _conn_handle: tokio::task::JoinHandle<()>,
}

impl Deref for CachedConnection {
    type Target = Client;
    fn deref(&self) -> &Self::Target {
        &self.client
    }
}

// ---------------------------------------------------------------------------
// ClientWrapper – owned vs borrowed
// ---------------------------------------------------------------------------

enum ClientWrapper<'a> {
    Owned(CachedConnection),
    Borrowed(&'a Client),
}

impl Deref for ClientWrapper<'_> {
    type Target = Client;
    fn deref(&self) -> &Self::Target {
        match self {
            Self::Owned(c) => &c.client,
            Self::Borrowed(c) => c,
        }
    }
}

// ---------------------------------------------------------------------------
// DbConfig / DbContainer
// ---------------------------------------------------------------------------

#[derive(Debug)]
pub struct DbConfig {
    pub port: u16,
    pub name: String,
    pub user: String,
    pub postgres_password: String,
    pub db_password: String,
}

pub struct DbContainer {
    #[allow(dead_code)]
    container_name: String,
    db_config: DbConfig,
    /// Cached connection to the default `postgres` database.
    default_conn: OnceCell<CachedConnection>,
}

impl DbContainer {
    pub fn new<N>(container_name: N, db_config: DbConfig) -> Self
    where
        N: Into<String>,
    {
        Self {
            container_name: container_name.into(),
            db_config,
            default_conn: OnceCell::const_new(),
        }
    }

    /// Return a client for the given database.  When `db_name` is `None` the
    /// cached connection to the default `postgres` database is returned.
    async fn connect<'a>(
        &'a self,
        db_name: Option<&str>,
    ) -> Result<ClientWrapper<'a>, tokio_postgres::Error> {
        let base = format!(
            "host=localhost port={} user=postgres password={}",
            self.db_config.port, self.db_config.postgres_password
        );

        if let Some(dbname) = db_name {
            // Named DB → always a fresh, owned connection.
            let conn_str = format!("{base} dbname={dbname}");
            let (client, conn) = tokio_postgres::connect(&conn_str, NoTls).await?;
            let handle = tokio::spawn(async move {
                if let Err(e) = conn.await {
                    eprintln!("Connection error: {e}");
                }
            });
            Ok(ClientWrapper::Owned(CachedConnection {
                client,
                _conn_handle: handle,
            }))
        } else {
            // Default DB → cached connection.
            //
            // `get_or_try_init` lets us propagate errors instead of
            // panicking inside the initializer.
            let cached = self
                .default_conn
                .get_or_try_init(|| async {
                    let (client, conn) =
                        tokio_postgres::connect(&base, NoTls).await?;
                    let handle = tokio::spawn(async move {
                        if let Err(e) = conn.await {
                            eprintln!("Connection error: {e}");
                        }
                    });
                    Ok::<_, tokio_postgres::Error>(CachedConnection {
                        client,
                        _conn_handle: handle,
                    })
                })
                .await?;

            // Before handing the cached client back, do a quick liveness
            // check.  If the connection died (e.g. server restart) we
            // cannot re-initialize a OnceCell, so we just report the error.
            // For a production-grade solution consider `bb8` or `deadpool`.
            if cached.client.is_closed() {
                return Err(tokio_postgres::Error::__private_api_timeout());
            }

            Ok(ClientWrapper::Borrowed(&cached.client))
        }
    }

    pub async fn create_database(&self, name: &str) -> Result<(), tokio_postgres::Error> {
        let client = self.connect(None).await?;
        client
            .execute(&format!("CREATE DATABASE {name}"), &[])
            .await?;
        // Connect to the newly-created database to run schema migrations, etc.
        let _client = self.connect(Some(name)).await?;
        // client.batch_execute(load_schema()).await  // your schema here
        println!("  ✓ created database `{name}`");
        Ok(())
    }

    pub async fn drop_database(&self, name: &str) -> Result<u64, tokio_postgres::Error> {
        let client = self.connect(None).await?;
        let terminate_sql = format!(
            "
            SELECT pg_terminate_backend(pid)
            FROM pg_stat_activity
            WHERE datname = '{name}' AND pid <> pg_backend_pid();
            "
        );
        client.execute(&terminate_sql, &[]).await?;
        let rows = client
            .execute(&format!("DROP DATABASE IF EXISTS {name}"), &[])
            .await?;
        println!("  ✓ dropped database `{name}`");
        Ok(rows)
    }
}

// ---------------------------------------------------------------------------
// main – demonstrates create → drop cycle reusing the cached connection
// ---------------------------------------------------------------------------

#[tokio::main]
async fn main() {
    // Adjust these values to match your local Postgres / Docker setup.
    let config = DbConfig {
        port: 5432,
        name: "postgres".into(),
        user: "postgres".into(),
        postgres_password: "postgres".into(),
        db_password: "postgres".into(),
    };

    let container = DbContainer::new("my_test_container", config);

    // Run several create/drop cycles to prove the cached connection stays
    // alive across calls.
    for i in 0..5 {
        let db_name = format!("test_db_{i}");

        // Make sure the database doesn't already exist from a previous run.
        let _ = container.drop_database(&db_name).await;

        match container.create_database(&db_name).await {
            Ok(()) => println!("  → Created `{db_name}` (iteration {i})"),
            Err(e) => {
                eprintln!("  ✗ Failed to create `{db_name}`: {e}");
                continue;
            }
        }

        match container.drop_database(&db_name).await {
            Ok(_) => println!("  → Dropped `{db_name}` (iteration {i})"),
            Err(e) => eprintln!("  ✗ Failed to drop `{db_name}`: {e}"),
        }
    }

    println!("\nDone – the cached connection was reused for every iteration.");
}
"
}
```

