  "main.rs": "use rustyline::completion::{Completer, FilenameCompleter, Pair};
use rustyline::error::ReadlineError;
use rustyline::highlight::Highlighter;
use rustyline::hint::Hinter;
use rustyline::validate::Validator;
use rustyline::{Context, Editor, Helper, Result};

/// A helper struct that implements all the traits required by rustyline's `Helper`.
/// `Editor` is generic over `H: Helper`, and `DefaultEditor` is just `Editor<()>`.
/// Since `()` doesn't implement `Completer` in a useful way, we need our own type.
struct MyHelper {
    completer: FilenameCompleter,
}

impl MyHelper {
    fn new() -> Self {
        MyHelper {
            completer: FilenameCompleter::new(),
        }
    }
}

/// The `Helper` trait is a marker trait that combines `Completer + Hinter + Highlighter + Validator`.
impl Helper for MyHelper {}

/// Delegate completion to the inner `FilenameCompleter`.
impl Completer for MyHelper {
    type Candidate = Pair;

    fn complete(
        &self,
        line: &str,
        pos: usize,
        ctx: &Context<'_>,
    ) -> Result<(usize, Vec<Pair>)> {
        self.completer.complete(line, pos, ctx)
    }
}

/// We don't need hints, so provide a trivial implementation.
impl Hinter for MyHelper {
    type Hint = String;

    fn hint(&self, _line: &str, _pos: usize, _ctx: &Context<'_>) -> Option<String> {
        None
    }
}

/// We don't need highlighting, so provide a trivial implementation.
impl Highlighter for MyHelper {}

/// We don't need validation, so provide a trivial implementation.
impl Validator for MyHelper {}

fn main() -> Result<()> {
    // Create an Editor parameterized with our helper type.
    // Note: we use `Editor::<MyHelper, _>::new()` instead of `DefaultEditor::new()`
    // because `DefaultEditor` is `Editor<()>` and `()` doesn't do useful completion.
    let config = rustyline::Config::builder()
        .completion_type(rustyline::CompletionType::List)
        .build();
    let mut rl = Editor::with_config(config)?;

    // Register our helper so that tab-completion is handled by `MyHelper`.
    rl.set_helper(Some(MyHelper::new()));

    println!("Type a partial filename and press Tab to see completion in action.");
    println!("Press Ctrl-D to exit.\n");

    loop {
        let readline = rl.readline(">> ");
        match readline {
            Ok(line) => {
                let _ = rl.add_history_entry(line.as_str());
                println!("Line: {}", line);
            }
            Err(ReadlineError::Interrupted) => {
                println!("CTRL-C");
                break;
            }
            Err(ReadlineError::Eof) => {
                println!("CTRL-D");
                break;
            }
            Err(err) => {
                println!("Error: {:?}", err);
                break;
            }
        }
    }

    Ok(())
}
"
}
