/// Flip a single line of pixels horizontally (reverse the order of 4-byte pixels).
///
/// This version reinterprets the byte slice as a slice of `u32` values so that
/// each pixel swap is a single 32-bit swap instead of four individual byte swaps.
/// On both x86-64 and AArch64 this compiles down to plain 32-bit load/store pairs
/// which the CPU handles in a single cycle – no special intrinsics needed for an
/// 8-pixel line.
fn flip_line(line_bytes: &mut [u8]) {
    assert_eq!(
        line_bytes.len() % BYTES_PER_PIXEL,
        0,
        "line length must be a multiple of BYTES_PER_PIXEL"
    );

    // Safety-free path: work with u32 chunks so each pixel is one element.
    // `chunks_exact_mut` + manual index swap keeps everything in safe Rust while
    // giving the compiler the chance to emit the tightest possible code.

    let pixel_count = line_bytes.len() / BYTES_PER_PIXEL;

    // We need to swap pixels i and (pixel_count - 1 - i).  Because the slice
    // borrow-checker doesn't let us hold two mutable references into the same
    // slice at once, we use `split_at_mut` to obtain non-overlapping halves.
    for i in 0..pixel_count / 2 {
        let j = pixel_count - 1 - i;
        // byte ranges
        let lo = i * BYTES_PER_PIXEL;
        let hi = j * BYTES_PER_PIXEL;

        // Split so that left contains bytes [0 .. hi) and right contains [hi ..].
        let (left, right) = line_bytes.split_at_mut(hi);

        // left[lo..lo+4]  is pixel i
        // right[0..4]     is pixel j  (because right starts at index hi)
        let left_pixel: &mut [u8] = &mut left[lo..lo + BYTES_PER_PIXEL];
        let right_pixel: &mut [u8] = &mut right[..BYTES_PER_PIXEL];

        // Swap as u32 – single 32-bit register swap on any modern arch.
        let l = u32::from_ne_bytes(left_pixel.try_into().unwrap());
        let r = u32::from_ne_bytes(right_pixel.try_into().unwrap());
        left_pixel.copy_from_slice(&r.to_ne_bytes());
        right_pixel.copy_from_slice(&l.to_ne_bytes());
    }
