{
  "Cargo.toml": "[package]
name = "shell-tokenizer"
version = "0.1.0"
edition = "2021"

[dependencies]
",
  "main.rs": "/// Splits a shell command string into tokens in a quote-aware fashion,
/// mimicking how bash handles single quotes and whitespace.
///
/// - Unquoted regions are split on whitespace.
/// - Single-quoted regions preserve their content literally (including spaces).
/// - A quoted region glued to adjacent unquoted text (no separating whitespace)
///   merges into a single token.
fn tokenize(input: &str) -> Vec<String> {
    let mut tokens: Vec<String> = Vec::new();
    let mut current = String::new();
    let mut in_single_quote = false;
    let mut in_double_quote = false;
    let mut chars = input.chars().peekable();

    while let Some(c) = chars.next() {
        if in_single_quote {
            if c == '\'' {
                in_single_quote = false;
            } else {
                current.push(c);
            }
        } else if in_double_quote {
            if c == '"' {
                in_double_quote = false;
            } else {
                current.push(c);
            }
        } else {
            match c {
                '\'' => {
                    // Opening a single quote. Even if nothing follows,
                    // this starts/continues a token (could produce empty string token).
                    in_single_quote = true;
                }
                '"' => {
                    in_double_quote = true;
                }
                ' ' | '\t' => {
                    // Whitespace outside quotes: finish current token if any
                    if !current.is_empty() {
                        tokens.push(std::mem::take(&mut current));
                    }
                }
                _ => {
                    current.push(c);
                }
            }
        }
    }

    // Don't forget the last token
    if !current.is_empty() {
        tokens.push(current);
    }

    tokens
}

fn main() {
    let input = " one  ' two  'three    four";
    let tokens = tokenize(input);
    println!("{} args:", tokens.len());
    for t in &tokens {
        println!("<{}>", t);
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_basic() {
        let tokens = tokenize(" one  ' two  'three    four");
        assert_eq!(tokens, vec!["one", " two  three", "four"]);
    }

    #[test]
    fn test_empty() {
        let tokens = tokenize("");
        assert!(tokens.is_empty());
    }

    #[test]
    fn test_only_spaces() {
        let tokens = tokenize("    ");
        assert!(tokens.is_empty());
    }

    #[test]
    fn test_simple() {
        let tokens = tokenize("hello world");
        assert_eq!(tokens, vec!["hello", "world"]);
    }

    #[test]
    fn test_quoted_spaces() {
        let tokens = tokenize("'hello world'");
        assert_eq!(tokens, vec!["hello world"]);
    }

    #[test]
    fn test_adjacent_quotes() {
        let tokens = tokenize("'hello'world");
        assert_eq!(tokens, vec!["helloworld"]);
    }

    #[test]
    fn test_multiple_tokens() {
        let tokens = tokenize("a b c");
        assert_eq!(tokens, vec!["a", "b", "c"]);
    }
}
"
}
