/// Loads the todo list from the JSON file.
/// If the file does not exist or is empty, returns an empty Vec.
fn load_file(path: &str) -> Vec<TodoItem> {
    if !Path::new(path).exists() {
        return Vec::new();
    }

    let data = match fs::read_to_string(path) {
        Ok(contents) => contents,
        Err(_) => return Vec::new(),
    };

    if data.trim().is_empty() {
        return Vec::new();
    }

    match serde_json::from_str(&data) {
        Ok(items) => items,
        Err(e) => {
            eprintln!("Warning: could not parse existing JSON file: {}", e);
            Vec::new()
        }
    }
}

/// Saves the todo list to the JSON file, overwriting its contents.
fn save_file(path: &str, items: &Vec<TodoItem>) {
    let json = serde_json::to_string_pretty(items).expect("Failed to serialize todo list.");
