name = "kitty-shm-animation"
version = "0.1.0"
edition = "2021"

[dependencies]
nix = { version = "0.29", features = ["fs", "mman"] }
termion = "4"
",
  "main.rs": "use nix::fcntl::OFlag;
use nix::sys::mman::{shm_open, shm_unlink, mmap, munmap, MapFlags, ProtFlags};
use nix::sys::stat::Mode;
use nix::unistd::ftruncate;
use std::io::{self, Write};
use std::num::NonZeroUsize;
use std::os::unix::io::AsRawFd;
use std::time::{Duration, Instant};
use termion::terminal_size_pixels;

fn main() {
    let stdout = io::stdout();
    let mut handle = stdout.lock();

    let (width, height) = terminal_size_pixels().unwrap_or((640, 480));
    let (width, height) = (width as usize, height as usize);

    let data_size = width * height * 3; // RGB, 3 bytes per pixel

    let shm_name = "/kitty_shm_anim";

    // Clean up any previous leftover
    let _ = shm_unlink(shm_name);

    // Create shared memory object
    let shm_fd = shm_open(
        shm_name,
        OFlag::O_CREAT | OFlag::O_RDWR,
        Mode::S_IRUSR | Mode::S_IWUSR,
    )
    .expect("Failed to create shared memory");

    // Set size
    ftruncate(&shm_fd, data_size as i64).expect("Failed to set shared memory size");

    // Memory map it
    let shm_ptr = unsafe {
        mmap(
            None,
            NonZeroUsize::new(data_size).unwrap(),
            ProtFlags::PROT_READ | ProtFlags::PROT_WRITE,
            MapFlags::MAP_SHARED,
            &shm_fd,
            0,
        )
        .expect("Failed to mmap shared memory")
    };

    let shm_slice = unsafe {
        std::slice::from_raw_parts_mut(shm_ptr.as_ptr() as *mut u8, data_size)
    };

    let shm_path = format!("/dev/shm{}", shm_name);

    let mut time: f32 = 0.0;
    let target_frame_duration = Duration::from_secs_f64(1.0 / 60.0);

    // Assign a persistent image id so we can replace in-place
    let image_id: u32 = 1;

    // Hide cursor
    write!(handle, "\x1b[?25l").unwrap();

    // Use a flag to detect if this is the first frame (use 'a=T' to transmit and display)
    // For subsequent frames we transmit with a=T and the same image id to replace.
    // We also use placement with C=1 to not move cursor, and p=1 for placement id.
    let mut first_frame = true;

    // Install a ctrl-c handler to clean up
    let running = std::sync::Arc::new(std::sync::atomic::AtomicBool::new(true));
    {
        let running = running.clone();
        ctrlc_handler(move || {
            running.store(false, std::sync::atomic::Ordering::SeqCst);
        });
    }

    while running.load(std::sync::atomic::Ordering::SeqCst) {
        let frame_start = Instant::now();

        // Generate animated RGB gradient pixel data directly into shared memory
        let inv_w = 1.0 / width as f32;
        let inv_h = 1.0 / height as f32;
        let pi = std::f32::consts::PI;

        let mut offset = 0;
        for y in 0..height {
            let fy = y as f32 * inv_h;
            let g_phase = fy * pi + time * 1.3;
            for x in 0..width {
                let fx = x as f32 * inv_w;

                let r = ((fx * pi + time).sin() * 0.5 + 0.5) * 255.0;
                let g = (g_phase.sin() * 0.5 + 0.5) * 255.0;
                let b = (((fx + fy) * pi + time * 0.7).sin() * 0.5 + 0.5) * 255.0;

                shm_slice[offset] = r as u8;
                shm_slice[offset + 1] = g as u8;
                shm_slice[offset + 2] = b as u8;
                offset += 3;
            }
        }

        // Move cursor to top-left
        write!(handle, "\x1b[H").unwrap();

        if first_frame {
            // Transmit and display: t=s (shared memory), f=24 (RGB), action=T
            write!(
                handle,
                "\x1b_Ga=T,t=s,f=24,s={},v={},i={},p=1,q=2;{}\x1b\\",
                width, height, image_id, shm_path
            )
            .unwrap();
            first_frame = false;
        } else {
            // For subsequent frames, transmit and display, replacing the image with same id
            // Using a=T will replace the existing image data
            write!(
                handle,
                "\x1b_Ga=T,t=s,f=24,s={},v={},i={},p=1,q=2;{}\x1b\\",
                width, height, image_id, shm_path
            )
            .unwrap();
        }

        handle.flush().unwrap();

        time += 0.1;

        // Frame rate limiting
        let elapsed = frame_start.elapsed();
        if elapsed < target_frame_duration {
            std::thread::sleep(target_frame_duration - elapsed);
        }
    }

    // Cleanup
    write!(handle, "\x1b[?25h").unwrap(); // show cursor
    // Delete the image from kitty
    write!(handle, "\x1b_Ga=d,d=I,i={};\x1b\\", image_id).unwrap();
    handle.flush().unwrap();

    unsafe {
        let _ = munmap(shm_ptr, data_size);
    }
    let _ = shm_unlink(shm_name);
}

/// Simple ctrl-c handler without pulling in another dependency
fn ctrlc_handler<F: Fn() + Send + 'static>(f: F) {
    unsafe {
        // Set up a signal handler for SIGINT
        libc_sigaction(f);
    }
}

static mut CTRLC_HANDLER: Option<Box<dyn Fn() + Send>> = None;

unsafe fn libc_sigaction<F: Fn() + Send + 'static>(f: F) {
    CTRLC_HANDLER = Some(Box::new(f));

    let mut sa: libc::sigaction = std::mem::zeroed();
    sa.sa_sigaction = ctrlc_signal_handler as usize;
    sa.sa_flags = libc::SA_SIGINFO;
    libc::sigemptyset(&mut sa.sa_mask);
    libc::sigaction(libc::SIGINT, &sa, std::ptr::null_mut());
}

extern "C" fn ctrlc_signal_handler(_sig: libc::c_int, _info: *mut libc::siginfo_t, _ctx: *mut libc::c_void) {
    unsafe {
        if let Some(ref handler) = CTRLC_HANDLER {
            handler();
        }
    }
}
"
}
```

**Important notes about this solution:**

1. **Shared memory approach**: Instead of base64-encoding the entire frame and chunking it over stdout, we create a POSIX shared memory object (`/dev/shm/kitty_shm_anim`) and write pixel data directly into it. The Kitty graphics escape sequence references this file path with `t=s` (shared memory transmission medium), so Kitty reads the pixels directly from shared memory — no base64 encoding or chunking overhead.

2. **Key protocol parameters**:
   - `t=s` — shared memory transmission
   - `f=24` — 24-bit RGB format
   - `a=T` — transmit and display
   - `i=1` — persistent image ID so frames replace each other
   - `q=2` — suppress responses from kitty (reduces I/O)

3. **Performance**: The pixel generation writes directly to the mmap'd buffer, avoiding an allocation + copy step. The only thing sent over stdout per frame is a small escape sequence (~100 bytes) pointing kitty to the shared memory file.

4. **Cleanup**: On Ctrl-C, the signal handler sets a flag, the loop exits, the cursor is restored, the kitty image is deleted, and the shared memory is unmapped and unlinked.

