    // The store defines which operations are available at vertex (internal)
    // nodes and leaf nodes.
    let store = vec![
        (
            NodeType::Vertex,
            vec![
                Op::add(),
                Op::sub(),
                Op::mul(),
                sqrt_plus_one.clone(),
                hypot.clone(),
                sigmoid.clone(),
            ],
        ),
        (
            NodeType::Leaf,
            vec![Op::var(0)],  // var(0) refers to the first input variable
        ),
    ];

    // Create sample data: we want to discover f(x) = sqrt(x) + 1
    let inputs: Vec<Vec<f32>> = (0..20).map(|i| vec![i as f32 * 0.5]).collect();
    let answers: Vec<f32> = inputs
        .iter()
        .map(|x| x[0].abs().sqrt() + 1.0)
        .collect();

    // Build the genetic programming codec (tree-based)
    let codex = TreeCodex::new(store)
        .set_depth(3)
        .set_gates(true);

    // Define the fitness function.
    // Lower error = better fitness. We use the negative MSE so that
    // the engine (which maximizes by default) drives error down.
    let regression = GeneticEngine::from_codex(&codex)
        .minimizing()  // we want to minimize the error
        .offspring_selector(BoltzmannSelector::new(4.0))
        .survivor_selector(TournamentSelector::new(3))
        .alterer(vec![
