            }
            // Mean squared error
            total_error / inputs.len() as f32
        })
        .build();

    // Run the engine for a number of generations
    let result = regression.run(|output| {
        let dominated = output.best.front().first();
        if let Some(score) = dominated {
            println!("[ {:>4} ] MSE: {:.6}", output.index, score.score().as_float());
            output.index >= 500 || score.score().as_float() < 0.001
        } else {
            output.index >= 500
        }
    });

