                }
            } else {
                break;
            }
        }
        let current_index: Vec<usize> = self
            .current_index_option
            .iter()
            .map(|x| x.unwrap())
            .collect();
        let fi = self.flat_index(&current_index);
        assert!(fi < self.store_len, "flat index out of bounds");
        // SAFETY: We rely on the selection iterators producing each flat index
        // at most once, so no two yielded `&mut T` will alias.
        let current_value: &'a mut T = unsafe { &mut *self.store_ptr.add(fi) };
        Some((current_index, current_value))
    }
