    unsafe { Waker::from_raw(RawWaker::new(std::ptr::null(), &VTABLE)) }
}

/// Poll the future **once**.  
/// - If it completes immediately → `TryPollResult::Ready(value)`  
/// - Otherwise                   → `TryPollResult::Pending`  
///
/// The future is taken by `Pin<&mut F>` so the caller retains ownership
/// and can still use it afterwards (e.g. spawn it on Tokio).
fn try_poll<X>(future: Pin<&mut impl Future<Output = X>>) -> TryPollResult<X> {
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);
    match future.poll(&mut cx) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

// ---------------------------------------------------------------------------
// Demo helpers
// ---------------------------------------------------------------------------

/// A future that is immediately ready (completes without yielding).
async fn immediate_future() -> &'static str {
    "I was ready immediately!"
}

/// A future that yields at least once before completing.
async fn delayed_future() -> &'static str {
    // Yield control once so the first poll returns Pending.
    tokio::task::yield_now().await;
    "I completed after yielding!"
}

// ---------------------------------------------------------------------------
// Main – runs inside the Tokio runtime
// ---------------------------------------------------------------------------

#[tokio::main]
async fn main() {
    // ---- Example 1: future that is immediately ready ----
    println!("=== Example 1: immediate future ===");
    {
        let fut = immediate_future();
        // Pin on the stack so we can poll it manually.
        tokio::pin!(fut);

        match try_poll(fut.as_mut()) {
            TryPollResult::Ready(val) => {
                println!("  Ready on first poll: {val}");
            }
            TryPollResult::Pending => {
                println!("  Pending – spawning task…");
                let handle = tokio::spawn(async move {
                    // `fut` has been moved into this task
                    fut.await
                });
                let val = handle.await.unwrap();
                println!("  Task finished: {val}");
            }
        }
    }

    // ---- Example 2: future that yields (Pending on first poll) ----
    println!("\n=== Example 2: delayed future ===");
    {
        let fut = delayed_future();
        tokio::pin!(fut);

        match try_poll(fut.as_mut()) {
            TryPollResult::Ready(val) => {
                println!("  Ready on first poll: {val}");
            }
            TryPollResult::Pending => {
                println!("  Pending – spawning task…");
                // We can still use `fut` because we only borrowed it above.
                let handle = tokio::spawn(async move {
                    fut.await
                });
                let val = handle.await.unwrap();
                println!("  Task finished: {val}");
            }
        }
    }
}
"
}
