    // Each outer vector is processed in parallel; elements within each inner vector are mapped sequentially.
    let result_a: Vec<Vec<String>> = a
        .par_iter()
        .map(|inner| inner.iter().map(|&x| format!("item_{}", x * 2)).collect())
        .collect();

    println!("Approach 1 (par outer, seq inner): {:?}", result_a);

    // Approach 2: Parallel over both outer AND inner
    // Both levels use par_iter for maximum parallelism.
    let result_b: Vec<Vec<String>> = a
        .par_iter()
        .map(|inner| {
            inner
                .par_iter()
                .map(|&x| format!("item_{}", x * 2))
                .collect()
        })
        .collect();

    println!("Approach 2 (par outer, par inner): {:?}", result_b);

    // Approach 3: Flatten, process in parallel, then reshape back
    // This is the flatten/reshape strategy mentioned in the question.
    let lengths: Vec<usize> = a.iter().map(|inner| inner.len()).collect();

    let flattened: Vec<usize> = a.iter().flatten().copied().collect();

    let processed: Vec<String> = flattened
        .par_iter()
        .map(|&x| format!("item_{}", x * 2))
        .collect();

    // Reshape back using the recorded lengths
    let mut iter = processed.into_iter();
    let result_c: Vec<Vec<String>> = lengths
        .iter()
        .map(|&len| iter.by_ref().take(len).collect())
        .collect();

    println!("Approach 3 (flatten/reshape):      {:?}", result_c);

    // Verify all approaches produce the same result
    assert_eq!(result_a, result_b);
    assert_eq!(result_b, result_c);
    println!("\nAll three approaches produce identical results!");
}
