/// Middleware that checks the `Origin` header on WebSocket upgrade requests.
/// If the Origin is missing or doesn't match the allowed origin, the request
/// is rejected with 403 Forbidden.
///
/// Non-upgrade requests are passed through unchanged (CORS layer handles those).
async fn check_websocket_origin(
    req: Request<axum::body::Body>,
    next: Next,
) -> Result<Response, StatusCode> {
    // Only enforce on WebSocket upgrade requests
    let is_upgrade = req
        .headers()
        .get(http::header::UPGRADE)
        .and_then(|v| v.to_str().ok())
        .map(|v| v.eq_ignore_ascii_case("websocket"))
        .unwrap_or(false);

    if is_upgrade {
        let origin = req
            .headers()
            .get(http::header::ORIGIN)
            .and_then(|v| v.to_str().ok())
            .map(|s| s.to_string());

        match origin {
