                Err(StatusCode::FORBIDDEN)
            }
            None => {
                eprintln!("Rejected WebSocket with no Origin header");
                Err(StatusCode::FORBIDDEN)
            }
        }
    } else {
        // Not a WebSocket upgrade – let it pass (CORS layer will handle it)
        Ok(next.run(req).await)
    }
}

