pub mod my_library {
    pub mod extensions {
        pub mod logging {
            use crate::FrameworkError;

            pub trait LogChangeErrForRespExt {
                type R;

                fn log_and_explain_400(self) -> Self::R;
            }

            /// This macro does the actual work. Because macros expand at the call site,
            /// `module_path!()` and `file!()` / `line!()` resolve to the *caller's*
            /// location, not to this crate's internal module.
            #[macro_export]
            macro_rules! log_and_explain_400 {
                ($expr:expr) => {{
                    match $expr {
                        Ok(ok) => Ok(ok),
                        Err(err) => {
                            // module_path!() expands to the calling module
                            log::warn!(
                                target: module_path!(),
                                "{}:{}  Error: {:?}",
                                file!(),
                                line!(),
                                err
                            );
                            Err($crate::FrameworkError::Error400(Box::new(err)))
                        }
                    }
                }};
            }

            // We still keep the trait-based approach available, but the trait
            // method now delegates to `log::warn!` using `target:` with a
            // caller-supplied module path.  The convenience macro above is the
            // simplest zero-boilerplate way, but below we also show how to
            // make the *trait method* log with the right module by accepting
            // the module path at compile time through a thin macro wrapper.

            impl<T, E: std::error::Error + 'static> LogChangeErrForRespExt for Result<T, E> {
                type R = Result<T, FrameworkError>;

                /// Fallback that still works, but will show this module in the
                /// log target.  Prefer the [`log_and_explain_400!`] macro or
                /// the [`log_and_explain_400_here!`] wrapper for correct module
                /// attribution.
                #[track_caller]
                fn log_and_explain_400(self) -> Self::R {
                    match self {
                        Ok(ok) => Ok(ok),
                        Err(err) => {
                            let loc = std::panic::Location::caller();
                            log::warn!(
                                "{}:{}: Error: {:?}",
                                loc.file(),
                                loc.line(),
                                err
                            );
                            Err(FrameworkError::Error400(Box::new(err)))
                        }
                    }
                }
            }

            /// Helper that lets you call it like a method-style macro while
            /// still getting the caller's `module_path!()` as the log target.
            ///
            /// Usage:
            ///   `log_and_explain_400_here!(some_result)`
            ///
            /// This is equivalent to `some_result.log_and_explain_400()` but
            /// the log line will attribute the message to the calling module.
            #[macro_export]
            macro_rules! log_and_explain_400_here {
                ($expr:expr) => {
                    $crate::log_and_explain_400!($expr)
                };
            }
        }
    }
