        pub fn some_route() -> Result<u32, crate::FrameworkError> {
            log::warn!("This log call is from the correct module");

            // --- Option A (recommended): use the macro for correct module attribution ---
            let long_chain = log_and_explain_400!(failing_function())? + 42;

            Ok(long_chain)
        }

        pub fn some_route_trait() -> Result<u32, crate::FrameworkError> {
            log::warn!("(trait version) This log call is from the correct module");

            // --- Option B: trait method – location (file:line) is correct but
            //     the *module* in the default log target will show the library module.
            let long_chain = failing_function().log_and_explain_400()? + 42;

            Ok(long_chain)
        }
    }
}

