//!
//! This demonstrates the correct pattern for interactive CLI forwarding
//! (like xterm.js <-> PTY) where reads and writes must happen concurrently.
//!
//! The key insight: instead of wrapping the entire session in a Mutex,
//! we duplicate the PTY file descriptor so the reader and writer each
//! own an independent `File` handle. No mutex needed at all.
//!
//! Run with: cargo run
//! Then type commands (e.g. `ls`, `echo hello`, `exit`) interactively.

use std::fs::File;
use std::io::{self, BufRead, Read, Write};
use std::os::fd::{AsRawFd, FromRawFd, IntoRawFd, RawFd};
use std::sync::mpsc;
use std::thread;

use nix::fcntl::{fcntl, FcntlArg, OFlag};
use nix::pty::{openpty, OpenptyResult};
use nix::sys::termios::{self, LocalFlags, SetArg};
use nix::unistd::{close, dup, execvp, fork, read as nix_read, setsid, ForkResult};

fn main() {
    // ── 1. Open a PTY pair ──────────────────────────────────────────────
    let OpenptyResult { master, slave } = openpty(None, None).expect("openpty failed");

    // ── 2. Fork a child process (the "agent") ──────────────────────────
    match unsafe { fork() }.expect("fork failed") {
        ForkResult::Child => {
            // New session so the child gets the controlling terminal
            setsid().ok();

            // Redirect stdin/stdout/stderr to the slave side
            nix::unistd::dup2(slave.as_raw_fd(), 0).unwrap();
            nix::unistd::dup2(slave.as_raw_fd(), 1).unwrap();
            nix::unistd::dup2(slave.as_raw_fd(), 2).unwrap();

            // Close originals
            let _ = close(slave.into_raw_fd());
            let _ = close(master.into_raw_fd());

            // Set TERM for colour support
            std::env::set_var("TERM", "xterm-256color");

            // Exec a shell
            let shell = std::ffi::CString::new("/bin/bash").unwrap();
            let args = [shell.clone()];
            execvp(&shell, &args).expect("execvp failed");
            unreachable!();
        }
        ForkResult::Parent { child } => {
            // Close slave in parent – we only talk through master
            let _ = close(slave.into_raw_fd());

            let master_fd: RawFd = master.as_raw_fd();

            // ── KEY TECHNIQUE: dup() the master FD ─────────────────────
            // This gives us two independent file descriptors to the same
            // PTY master. One for reading, one for writing.
            // No Mutex required!
            let write_fd = dup(master_fd).expect("dup failed");

            // Wrap in File for ergonomic I/O
            let mut reader_file = unsafe { File::from_raw_fd(master_fd) };
            let mut writer_file = unsafe { File::from_raw_fd(write_fd) };

            // Put host terminal in raw mode so we get individual keypresses
            let stdin_fd = io::stdin().as_raw_fd();
            let original_termios = termios::tcgetattr(unsafe {
                std::os::fd::BorrowedFd::borrow_raw(stdin_fd)
            })
            .ok();

            if let Some(ref orig) = original_termios {
                let mut raw = orig.clone();
                termios::cfmakeraw(&mut raw);
                termios::tcsetattr(
                    unsafe { std::os::fd::BorrowedFd::borrow_raw(stdin_fd) },
                    SetArg::TCSANOW,
                    &raw,
                )
                .ok();
            }

            // ── 3. Reader thread: PTY master -> stdout ─────────────────
            let reader_handle = thread::spawn(move || {
                let mut buf = [0u8; 4096];
                loop {
                    match reader_file.read(&mut buf) {
                        Ok(0) => break,
                        Ok(n) => {
                            // In a Tauri app you would emit an event here:
                            //   app.emit("agent-output", &buf[..n]);
                            let _ = io::stdout().write_all(&buf[..n]);
                            let _ = io::stdout().flush();
                        }
                        Err(e) => {
                            eprintln!("\r\n[reader error: {}]\r\n", e);
                            break;
                        }
                    }
                }
            });

            // ── 4. Writer thread: stdin -> PTY master ──────────────────
            //
            // In a Tauri app this would be replaced by your IPC command:
            //
            //   #[tauri::command]
            //   fn send_to_agent(msg: String, state: State<WriterHandle>) {
            //       state.writer.lock().unwrap().write_all(msg.as_bytes()).ok();
            //   }
            //
            // Because the writer File is *independent* of the reader File,
            // writing never blocks on the read loop.
            let writer_handle = thread::spawn(move || {
                let mut buf = [0u8; 1024];
                let mut stdin = io::stdin().lock();
                loop {
                    match stdin.read(&mut buf) {
                        Ok(0) => break,
                        Ok(n) => {
                            if writer_file.write_all(&buf[..n]).is_err() {
                                break;
                            }
                            let _ = writer_file.flush();
                        }
                        Err(_) => break,
                    }
                }
            });

            // Wait for reader to finish (child exited)
            let _ = reader_handle.join();

            // Restore terminal
            if let Some(ref orig) = original_termios {
                termios::tcsetattr(
                    unsafe { std::os::fd::BorrowedFd::borrow_raw(stdin_fd) },
                    SetArg::TCSANOW,
                    orig,
                )
                .ok();
            }

            // Reap child
            let _ = nix::sys::wait::waitpid(child, None);
            println!("\r\n[child process exited]");
        }
    }
}

