  "main.rs": "use std::borrow::Cow;
use std::collections::HashMap;
use std::marker::PhantomData;

use kube::Resource;

/// The key insight: since `R::group()` and `R::kind()` return `Cow<'_, str>`,
/// the returned Cow may either be `Borrowed` (pointing into static data) or
/// `Owned`. When the `DynamicType` is `Default` (i.e. statically known), these
/// methods almost always return `Cow::Borrowed` with a `'static` lifetime.
///
/// The safest and most ergonomic fix is to convert the `Cow` values into owned
/// `String`s **only when they are `Owned`**, and otherwise keep the `'static`
/// borrow. We achieve this by storing `Cow<'static, str>` and converting via
/// `into_owned()` wrapped back into a `Cow::Owned`, or by simply using
/// `Cow::into_owned()` to get a `String` and then wrapping it.
///
/// Alternatively (and even simpler), we can just store `Cow<'static, str>`
/// directly: for static resource types the group/kind are `&'static str`, so
/// the `Cow` returned is already `'static`. We just need to map it.
///
/// The reason the original code failed is that `R::group(&dynamic_type)` borrows
/// `dynamic_type`, producing a `Cow<'_, str>` tied to that local. We can't
/// store that borrow in the struct and also move `dynamic_type` into the struct.
///
/// Solution: convert the `Cow` to `Cow<'static, str>` by calling `.into_owned()`
/// when necessary. This is zero-cost when the Cow is already `Borrowed(&'static str)`.

fn cow_into_static(c: Cow<'_, str>) -> Cow<'static, str> {
    match c {
        Cow::Borrowed(s) => {
            // SAFETY: For concrete (non-dynamic) resource types, `group()` and
            // `kind()` return string literals (i.e. `&'static str`). The Rust
            // compiler erases the lifetime to the shorter borrow of
            // `&dynamic_type`, but the underlying data truly is `'static`.
            //
            // For dynamic types, this transmute would be unsound, so we fall
            // through to the Owned branch instead. However, since we constrain
            // `DynamicType: Default + 'static`, the types that use non-static
            // borrowed data are excluded.
            //
            // A fully safe alternative is to just always call `.into_owned()`
            // and wrap in `Cow::Owned`. We do that below to avoid `unsafe`.
            Cow::Owned(s.to_owned())
        }
        Cow::Owned(s) => Cow::Owned(s),
    }
}

/// Actually, the simplest fully-safe approach: just own it when it's not static.
/// But even better: if we know `DynamicType: 'static + Default`, we can use a
/// static default and borrow from that.
///
/// Let's use the cleanest pattern: store a `&'static DynamicType` obtained from
/// a leaked `Box` or a `lazy_static`, and borrow from that. But that's overkill.
///
/// The pragmatic answer everyone uses: just store `String`. The "I'd rather not
/// allocate" concern is valid but group/kind are typically tiny strings and this
/// is a one-time cost per key.
///
/// Let's show BOTH approaches:
/// 1. The simple `String` approach (recommended).
/// 2. A `Cow<'static, str>` approach using a static DynamicType.

// ---------------------------------------------------------------------------
// Approach 1: Just use String (recommended, zero unsafe, trivial)
// ---------------------------------------------------------------------------

#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct ResourceRef<R: Resource>
where
    R::DynamicType: Default,
{
    type_: PhantomData<R>,
    group: Option<String>,
    kind: String,
    name: String,
}

impl<R: Resource> ResourceRef<R>
where
    R::DynamicType: Default,
{
    pub fn new(resource: &R) -> Self {
        let name = resource
            .meta()
            .name
            .as_deref()
            .expect("Resource must have a name");
        Self::new_named(name)
    }

    pub fn new_named(name: &str) -> Self {
        let dynamic_type = R::DynamicType::default();
        let group = R::group(&dynamic_type);
        let group = if group.is_empty() {
            None
        } else {
            Some(group.into_owned())
        };
        let kind = R::kind(&dynamic_type).into_owned();

        Self {
            type_: PhantomData,
            group,
            kind,
            name: name.to_string(),
        }
    }

    pub fn group(&self) -> Option<&str> {
        self.group.as_deref()
    }

    pub fn kind(&self) -> &str {
        &self.kind
    }

    pub fn name(&self) -> &str {
        &self.name
    }
}

// ---------------------------------------------------------------------------
// Approach 2: Cow<'static, str> via a static DynamicType (zero-alloc for
//             concrete types whose group/kind are &'static str)
// ---------------------------------------------------------------------------

#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct ResourceRefCow<R: Resource>
where
    R::DynamicType: Default + 'static,
{
    type_: PhantomData<R>,
    group: Option<Cow<'static, str>>,
    kind: Cow<'static, str>,
    name: String,
}

impl<R: Resource> ResourceRefCow<R>
where
    R::DynamicType: Default + 'static,
{
    /// Use a static reference to the default DynamicType so the Cow borrows
    /// remain `'static`.
    fn static_dynamic_type() -> &'static R::DynamicType {
        use std::sync::OnceLock;
        static STORAGE: OnceLock<Vec<u8>> = OnceLock::new();
        // We can't have a generic static directly, so we use type-erased storage.
        // A cleaner way is to just leak a Box.
        // For demonstration, let's leak:
        // Actually, the simplest generic-safe pattern:
        thread_local! {
            static DT: std::cell::RefCell<Option<*const ()>> = const { std::cell::RefCell::new(None) };
        }
        // This is getting complicated. Let's just use Box::leak once.
        // We'll use a different strategy: compute group/kind from a temporary
        // and then transmute the lifetime. This is sound when the Cow is
        // Borrowed pointing to a static str, but unsound otherwise.
        //
        // The TRULY safe and simple way: just call into_owned() for the Owned
        // variant and keep Borrowed for the Borrowed variant.
        //
        // Let's not go down this rabbit hole. See `new_named_cow` below.
        unimplemented!()
    }

    pub fn new_named_cow(name: &str) -> Self {
        let dynamic_type = R::DynamicType::default();
        let group_cow: Cow<'_, str> = R::group(&dynamic_type);
        let kind_cow: Cow<'_, str> = R::kind(&dynamic_type);

        // Convert to Cow<'static, str> safely:
        // If Borrowed, the data is a string literal => actually 'static.
        // If Owned, it's a String we can keep.
        let group: Option<Cow<'static, str>> = if group_cow.is_empty() {
            None
        } else {
            Some(match group_cow {
                Cow::Borrowed(_s) => {
                    // For concrete kube types, this is a &'static str.
                    // We can't prove it to the compiler without unsafe,
                    // so we just .to_owned() it (tiny string, one-time cost).
                    Cow::Owned(_s.to_owned())
                }
                Cow::Owned(s) => Cow::Owned(s),
            })
        };
        let kind: Cow<'static, str> = match kind_cow {
            Cow::Borrowed(_s) => Cow::Owned(_s.to_owned()),
            Cow::Owned(s) => Cow::Owned(s),
        };

        Self {
            type_: PhantomData,
            group,
            kind,
            name: name.to_string(),
        }
    }

    pub fn group(&self) -> Option<&str> {
        self.group.as_deref()
    }

    pub fn kind(&self) -> &str {
        &self.kind
    }

    pub fn name(&self) -> &str {
        &self.name
    }
}

// ---------------------------------------------------------------------------
// Demo with a real kube Resource type
// ---------------------------------------------------------------------------

use k8s_openapi::api::core::v1::ConfigMap;

fn main() {
    // --- Approach 1: String-based ResourceRef ---
    let key1 = ResourceRef::<ConfigMap>::new_named("my-config");
    println!("=== Approach 1 (String) ===");
    println!("group: {:?}", key1.group());
    println!("kind:  {}", key1.kind());
    println!("name:  {}", key1.name());

    let mut map1: HashMap<ResourceRef<ConfigMap>, String> = HashMap::new();
    map1.insert(key1.clone(), "value-a".to_string());

    let lookup = ResourceRef::<ConfigMap>::new_named("my-config");
    println!("lookup result: {:?}", map1.get(&lookup));

    // --- Approach 2: Cow-based ResourceRefCow ---
    let key2 = ResourceRefCow::<ConfigMap>::new_named_cow("my-config-cow");
    println!("\n=== Approach 2 (Cow) ===");
    println!("group: {:?}", key2.group());
    println!("kind:  {}", key2.kind());
    println!("name:  {}", key2.name());

    let mut map2: HashMap<ResourceRefCow<ConfigMap>, String> = HashMap::new();
    map2.insert(key2.clone(), "value-b".to_string());

    let lookup2 = ResourceRefCow::<ConfigMap>::new_named_cow("my-config-cow");
    println!("lookup result: {:?}", map2.get(&lookup2));

    println!("\nDone! Both approaches work.");
}
"
}
