  "main.rs": "//! Demonstration of how to "rehydrate" (re-attach) a parent span across
//! async trait callbacks that may run on arbitrary Tokio threads.
//!
//! The key idea:
//!   1. Create a long-lived *request span* and grab its `tracing::Span` handle.
//!   2. Store that `Span` in your shared context object that is threaded through
//!      every callback.
//!   3. At the top of each callback, call `ctx.request_span.in_scope(|| { .. })`
//!      **or** use `#[tracing::instrument(parent = &ctx.request_span)]` so that
//!      any new child spans are parented under the original request span.
//!
//! The output is sent to stdout via `opentelemetry-stdout` so you can verify
//! the parent/child relationships without needing Jaeger.

use opentelemetry::trace::TracerProvider as _;
use opentelemetry_sdk::{
    trace::{SdkTracerProvider, Tracer},
    Resource,
};
use opentelemetry::KeyValue;
use tracing::{info_span, Instrument, Span};
use tracing_opentelemetry::OpenTelemetryLayer;
use tracing_subscriber::{layer::SubscriberExt, Registry};

// ---------------------------------------------------------------------------
// 1. The shared context that travels across callbacks
// ---------------------------------------------------------------------------

/// This is analogous to your Pingora `CTX` object.
struct MyContext {
    /// The top-level request span.  We store a `tracing::Span` so we can
    /// re-parent later child spans even if we are on a different thread.
    request_span: Span,
}

// ---------------------------------------------------------------------------
// 2. The trait that models Pingora-style stage callbacks
// ---------------------------------------------------------------------------

#[allow(async_fn_in_trait)]
trait ProxyLifecycle {
    async fn stage_request_filter(&self, ctx: &MyContext);
    async fn stage_upstream_peer(&self, ctx: &MyContext);
    async fn stage_upstream_request(&self, ctx: &MyContext);
}

struct MyProxy;

impl ProxyLifecycle for MyProxy {
    async fn stage_request_filter(&self, ctx: &MyContext) {
        // ---- TECHNIQUE 1: `instrument()` with explicit parent ---------------
        //
        // Create a child span whose parent is the stored request span.
        // `.instrument(span)` keeps the span active for the whole future.
        async {
            tracing::info!("doing request filter work");
            tokio::time::sleep(std::time::Duration::from_millis(30)).await;
            tracing::info!("request filter done");
        }
        .instrument(info_span!(parent: &ctx.request_span, "stage_request_filter"))
        .await;
    }

    async fn stage_upstream_peer(&self, ctx: &MyContext) {
        // ---- TECHNIQUE 2: `in_scope` for synchronous + instrument for async -
        let span = info_span!(parent: &ctx.request_span, "stage_upstream_peer");
        async {
            // `in_scope` is useful for quick synchronous blocks:
            span.in_scope(|| {
                tracing::info!("choosing upstream peer (sync part)");
            });
            // For async work, keep using `.instrument()`:
            async {
                tokio::time::sleep(std::time::Duration::from_millis(20)).await;
                tracing::info!("upstream peer selected");
            }
            .instrument(span.clone())
            .await;
        }
        .await;
    }

    async fn stage_upstream_request(&self, ctx: &MyContext) {
        // ---- TECHNIQUE 3: `#[tracing::instrument]`-style via entered guard --
        let span = info_span!(parent: &ctx.request_span, "stage_upstream_request");
        // `span.enter()` returns a guard.  While the guard is alive **on this
        // thread** the span is the current span.  Because we `.await` below
        // this is safe only if the future is `!Send` or we are inside a
        // `tokio::task::spawn_local`. For `Send` futures prefer `.instrument()`.
        //
        // Here we demonstrate the safe pattern: wrap the whole body in
        // `.instrument()`.
        async {
            tracing::info!("sending upstream request");
            tokio::time::sleep(std::time::Duration::from_millis(40)).await;
            tracing::info!("upstream responded");
        }
        .instrument(span)
        .await;
    }
}

// ---------------------------------------------------------------------------
// 3. Wire up OpenTelemetry + tracing and simulate a request
// ---------------------------------------------------------------------------

fn init_tracer() -> (SdkTracerProvider, Tracer) {
    let exporter = opentelemetry_stdout::SpanExporter::default();

    let provider = SdkTracerProvider::builder()
        .with_simple_exporter(exporter)
        .with_resource(Resource::new(vec![KeyValue::new(
            "service.name",
            "span-rehydration-demo",
        )]))
        .build();

    let tracer = provider.tracer("demo");
    (provider, tracer)
}

#[tokio::main]
async fn main() {
    // --- Set up the tracing subscriber with an OTel layer --------------------
    let (provider, tracer) = init_tracer();

    let telemetry_layer = OpenTelemetryLayer::new(tracer);
    let subscriber = Registry::default().with(telemetry_layer);
    tracing::subscriber::set_global_default(subscriber)
        .expect("setting default subscriber failed");

    // --- Simulate a Pingora-style request lifecycle --------------------------
    //
    // Step A: create the long-lived request/parent span and grab a handle.
    let request_span = info_span!("request", http.method = "GET", http.url = "/foo");

    // Step B: store it in our context so every callback can access it.
    let ctx = MyContext {
        request_span: request_span.clone(),
    };

    let proxy = MyProxy;

    // Step C: the stages may be called from different tasks / threads.
    //         We simulate that with `tokio::spawn`.

    // -- Stage 1 (possibly on a different thread) --
    let ctx_ref = &ctx;
    let proxy_ref = &proxy;

    // Using a scoped approach; in real Pingora you'd pass Arc<MyContext>.
    let h1 = tokio::spawn({
        let span = ctx.request_span.clone();
        let _ctx = unsafe_send_sync_ctx(&ctx);
        let _proxy = unsafe_send_sync_proxy(&proxy);
        async move {
            // Even though we are on a potentially different thread,
            // the child span will be parented correctly because we
            // explicitly set `parent: &ctx.request_span` inside the method.
            _proxy.stage_request_filter(&_ctx).await;
        }
    });
    h1.await.unwrap();

    // -- Stage 2 --
    let h2 = tokio::spawn({
        let _ctx = unsafe_send_sync_ctx(&ctx);
        let _proxy = unsafe_send_sync_proxy(&proxy);
        async move {
            _proxy.stage_upstream_peer(&_ctx).await;
        }
    });
    h2.await.unwrap();

    // -- Stage 3 --
    let h3 = tokio::spawn({
        let _ctx = unsafe_send_sync_ctx(&ctx);
        let _proxy = unsafe_send_sync_proxy(&proxy);
        async move {
            _proxy.stage_upstream_request(&_ctx).await;
        }
    });
    h3.await.unwrap();

    // Close the request span so it gets exported.
    drop(ctx);
    drop(request_span);

    // Flush
    provider.force_flush();
    provider.shutdown().expect("shutdown failed");

    eprintln!("\n=== Done. Look at the JSON above for parent/child span IDs ===");
}

// ---------------------------------------------------------------------------
// Helpers to move references into `tokio::spawn` for this demo only.
// In production you would use `Arc<MyContext>` and `Arc<MyProxy>` instead.
// ---------------------------------------------------------------------------

fn unsafe_send_sync_ctx(ctx: &MyContext) -> SendWrapper<&MyContext> {
    SendWrapper(ctx)
}

fn unsafe_send_sync_proxy(proxy: &MyProxy) -> SendWrapper<&MyProxy> {
    SendWrapper(proxy)
}

struct SendWrapper<T>(T);
unsafe impl<T> Send for SendWrapper<T> {}
unsafe impl<T> Sync for SendWrapper<T> {}

impl std::ops::Deref for SendWrapper<&MyContext> {
    type Target = MyContext;
    fn deref(&self) -> &Self::Target {
        self.0
    }
}

impl std::ops::Deref for SendWrapper<&MyProxy> {
    type Target = MyProxy;
    fn deref(&self) -> &Self::Target {
        self.0
    }
}
"
}
