{
  "Cargo.toml": "[package]
name = "lazy-asset-loader"
version = "0.1.0"
edition = "2021"

[dependencies]
bevy = "0.15"
zip = "2.6"
",
  "main.rs": "//! Lazy Asset Loader for Bevy
//!
//! Demonstrates how to create a custom `AssetReader` that wraps Bevy's default
//! file-system reader but can also lazily pull individual entries out of a
//! zip-like archive (or any other container format such as GoldSrc WAD3).
//!
//! Key ideas
//! ---------
//! * Instead of a custom `AssetLoader` that must parse an entire archive up
//!   front, we implement a custom **`AssetReader`**.  `AssetReader` is the
//!   lowest level of Bevy's asset pipeline – it simply maps an `AssetPath` to
//!   a byte stream.  This means every built-in `AssetLoader` (images, audio,
//!   scenes …) keeps working; the only thing that changes is *where* the bytes
//!   come from.
//!
//! * We support a virtual path convention:
//!     `archive://<archive_file>#<entry>`
//!   In practice we encode it as a regular asset path that starts with
//!   `zip/` followed by the archive name, then the inner entry path:
//!     `zip/my_archive.zip/textures/brick01.png`
//!   The custom reader intercepts paths that start with `zip/`, opens only
//!   that single entry from the zip (lazy!), and returns its bytes.
//!
//! * For every other path the reader falls through to Bevy's default
//!   file-system reader, so normal assets keep loading as usual.
//!
//! How to test
//! -----------
//! 1. Create an `assets/` folder next to `Cargo.toml`.
//! 2. Put a zip file in it, e.g. `assets/zip/sample.zip` containing at least
//!    one PNG named `texture.png`.
//!    Quick way (on Linux / macOS):
//!      mkdir -p assets/zip
//!      cd /tmp && convert -size 64x64 xc:red texture.png   # or use any png
//!      zip sample.zip texture.png
//!      cp sample.zip <project>/assets/zip/
//! 3. `cargo run`  – a window opens showing the texture loaded lazily from
//!    inside the zip.
//!
//! Adapting to WAD3 or other formats
//! ----------------------------------
//! Replace the `read_zip_entry` function with your own parser that seeks to
//! the correct lump/entry inside the WAD and returns its raw bytes.  The rest
//! of the plumbing stays the same.

use bevy::{
    asset::{
        io::{
            AssetReader, AssetReaderError, AssetSource, AssetSourceId,
            PathStream, Reader,
        },
        AssetApp,
    },
    prelude::*,
};
use std::{
    io::Read,
    path::{Path, PathBuf},
};

// ---------------------------------------------------------------------------
// 1. The custom AssetReader
// ---------------------------------------------------------------------------

/// An `AssetReader` that intercepts reads and lazily extracts individual
/// entries from zip archives located under the `assets/zip/` directory.
///
/// Path convention (relative to the source root which is `assets/zip/`):
///   `<archive_name>/<entry_inside_archive>`
///
/// Example asset path:  `texture.png`  when the source root already points
/// at a specific zip, or `sample.zip/texture.png` when we keep it generic.
struct ZipAssetReader {
    /// Root directory on disk where zip archives are stored.
    root: PathBuf,
}

impl ZipAssetReader {
    fn new(root: PathBuf) -> Self {
        Self { root }
    }

    /// Given a virtual path like `sample.zip/textures/brick.png`, split it
    /// into the on-disk archive path and the entry name inside that archive.
    fn split_archive_path<'a>(&self, path: &'a Path) -> Option<(PathBuf, String)> {
        let components: Vec<_> = path.components().collect();
        // Walk components until we find one that looks like it ends with
        // `.zip` (case-insensitive).  Everything before & including it is
        // the archive; everything after is the entry.
        for (i, comp) in components.iter().enumerate() {
            let s = comp.as_os_str().to_string_lossy();
            if s.to_ascii_lowercase().ends_with(".zip") {
                let archive: PathBuf = components[..=i].iter().collect();
                let entry: PathBuf = components[i + 1..].iter().collect();
                let entry_str = entry.to_string_lossy().replace('\\', "/");
                return Some((self.root.join(archive), entry_str));
            }
        }
        None
    }
}

impl AssetReader for ZipAssetReader {
    fn read<'a>(
        &'a self,
        path: &'a Path,
    ) -> impl core::future::Future<Output = Result<Box<dyn Reader + 'a>, AssetReaderError>> + Send
    {
        async move {
            let (archive_path, entry_name) = self
                .split_archive_path(path)
                .ok_or_else(|| AssetReaderError::NotFound(path.to_path_buf()))?;

            let bytes = read_zip_entry(&archive_path, &entry_name).map_err(|e| {
                bevy::log::error!("Failed to read zip entry `{}` from `{:?}`: {}", entry_name, archive_path, e);
                AssetReaderError::NotFound(path.to_path_buf())
            })?;

            let cursor = std::io::Cursor::new(bytes);
            let reader: Box<dyn Reader + 'a> = Box::new(cursor);
            Ok(reader)
        }
    }

    fn read_meta<'a>(
        &'a self,
        path: &'a Path,
    ) -> impl core::future::Future<Output = Result<Box<dyn Reader + 'a>, AssetReaderError>> + Send
    {
        async move {
            // We don't store .meta inside zips – just report not found so Bevy
            // falls back to defaults.
            Err(AssetReaderError::NotFound(path.to_path_buf()))
        }
    }

    fn read_directory<'a>(
        &'a self,
        path: &'a Path,
    ) -> impl core::future::Future<Output = Result<Box<PathStream>, AssetReaderError>> + Send
    {
        async move {
            // Listing directories inside a zip is possible but not required
            // for lazy loading.  Return NotFound for now.
            Err(AssetReaderError::NotFound(path.to_path_buf()))
        }
    }

    fn is_directory<'a>(
        &'a self,
        path: &'a Path,
    ) -> impl core::future::Future<Output = Result<bool, AssetReaderError>> + Send {
        async move {
            Ok(false)
        }
    }
}

// ---------------------------------------------------------------------------
// 2. Zip helper – reads ONE entry from a zip. Replace with WAD3 logic etc.
// ---------------------------------------------------------------------------

fn read_zip_entry(
    archive_path: &Path,
    entry_name: &str,
) -> Result<Vec<u8>, Box<dyn std::error::Error + Send + Sync>> {
    let file = std::fs::File::open(archive_path)?;
    let mut archive = zip::ZipArchive::new(file)?;
    let mut entry = archive.by_name(entry_name)?;
    let mut buf = Vec::with_capacity(entry.size() as usize);
    entry.read_to_end(&mut buf)?;
    Ok(buf)
}

// ---------------------------------------------------------------------------
// 3. Plugin that registers the custom source
// ---------------------------------------------------------------------------

pub struct ZipAssetReaderPlugin;

impl Plugin for ZipAssetReaderPlugin {
    fn build(&self, app: &mut App) {
        // Register a new *asset source* called "zip".
        // Asset paths will look like:  zip://sample.zip/texture.png
        app.register_asset_source(
            AssetSourceId::Name("zip".into()),
            AssetSource::build().with_reader(|| {
                // Resolve the root to `<workspace>/assets/zip/`
                let root = std::env::current_dir()
                    .unwrap_or_default()
                    .join("assets")
                    .join("zip");
                Box::new(ZipAssetReader::new(root))
            }),
        );
    }
}

// ---------------------------------------------------------------------------
// 4. Minimal Bevy app to prove it works
// ---------------------------------------------------------------------------

fn main() {
    // ---- Create a tiny sample zip so the demo is fully self-contained ----
    create_sample_zip_if_missing();

    App::new()
        .add_plugins(DefaultPlugins)
        .add_plugins(ZipAssetReaderPlugin)
        .add_systems(Startup, setup)
        .run();
}

fn setup(
    mut commands: Commands,
    asset_server: Res<AssetServer>,
) {
    // Load a texture lazily from inside the zip.
    // The path format is   source://archive/entry
    let texture: Handle<Image> =
        asset_server.load("zip://sample.zip/texture.png");

    commands.spawn(Camera2d);

    commands.spawn(Sprite {
        image: texture,
        custom_size: Some(Vec2::new(256.0, 256.0)),
        ..default()
    });

    info!("Requested lazy load of `zip://sample.zip/texture.png`");
}

// ---------------------------------------------------------------------------
// Helper: generate a minimal valid PNG and pack it into a zip so the demo
// runs out of the box without manual preparation.
// ---------------------------------------------------------------------------

fn create_sample_zip_if_missing() {
    let dir = std::env::current_dir()
        .unwrap_or_default()
        .join("assets")
        .join("zip");
    let zip_path = dir.join("sample.zip");
    if zip_path.exists() {
        return;
    }
    std::fs::create_dir_all(&dir).expect("failed to create assets/zip dir");

    // Create a 2×2 red PNG in memory.
    let png_bytes = create_tiny_png();

    // Write zip
    let file = std::fs::File::create(&zip_path).expect("failed to create sample.zip");
    let mut zip_writer = zip::ZipWriter::new(file);
    let options = zip::write::SimpleFileOptions::default()
        .compression_method(zip::CompressionMethod::Stored);
    zip_writer
        .start_file("texture.png", options)
        .expect("zip start_file");
    std::io::Write::write_all(&mut zip_writer, &png_bytes).expect("zip write");
    zip_writer.finish().expect("zip finish");

    info!("Created sample zip at {:?}", zip_path);
}

/// Produces a minimal valid 2×2 RGBA PNG (red pixels) entirely in memory.
fn create_tiny_png() -> Vec<u8> {
    let mut buf = Vec::new();
    {
        let mut encoder = png_encode(&mut buf, 2, 2);
        // 2x2 RGBA red pixels
        let data: Vec<u8> = vec![255, 0, 0, 255].repeat(4);
        encoder(&data);
    }
    buf
}

/// Tiny PNG encoder without extra dependencies (just enough for a demo).
/// We manually construct a valid PNG file.
fn png_encode(out: &mut Vec<u8>, width: u32, height: u32) -> impl FnMut(&[u8]) + '_ {
    use std::io::Write;

    // PNG signature
    out.write_all(&[137, 80, 78, 71, 13, 10, 26, 10]).unwrap();

    // IHDR
    let mut ihdr_data = Vec::new();
    ihdr_data.extend_from_slice(&width.to_be_bytes());
    ihdr_data.extend_from_slice(&height.to_be_bytes());
    ihdr_data.push(8); // bit depth
    ihdr_data.push(6); // color type RGBA
    ihdr_data.push(0); // compression
    ihdr_data.push(0); // filter
    ihdr_data.push(0); // interlace
    write_png_chunk(out, b"IHDR", &ihdr_data);

    move |pixel_data: &[u8]| {
        // Build raw image data with filter byte (0) per row
        let row_len = (width as usize) * 4;
        let mut raw = Vec::new();
        for y in 0..height as usize {
            raw.push(0u8); // filter none
            raw.extend_from_slice(&pixel_data[y * row_len..(y + 1) * row_len]);
        }

        // Compress with deflate (zlib)
        let compressed = mini_deflate(&raw);
        write_png_chunk(out, b"IDAT", &compressed);
        write_png_chunk(out, b"IEND", &[]);
    }
}

fn write_png_chunk(out: &mut Vec<u8>, chunk_type: &[u8; 4], data: &[u8]) {
    use std::io::Write;
    out.write_all(&(data.len() as u32).to_be_bytes()).unwrap();
    out.write_all(chunk_type).unwrap();
    out.write_all(data).unwrap();
    let mut crc_input = Vec::new();
    crc_input.extend_from_slice(chunk_type);
    crc_input.extend_from_slice(data);
    let crc = png_crc32(&crc_input);
    out.write_all(&crc.to_be_bytes()).unwrap();
}

fn png_crc32(data: &[u8]) -> u32 {
    let mut crc: u32 = 0xFFFF_FFFF;
    for &byte in data {
        crc ^= byte as u32;
        for _ in 0..8 {
            if crc & 1 != 0 {
                crc = (crc >> 1) ^ 0xEDB8_8320;
            } else {
                crc >>= 1;
            }
        }
    }
    crc ^ 0xFFFF_FFFF
}

/// Minimal zlib wrapper around stored (uncompressed) deflate blocks.
/// Not actually compressed – just valid zlib so PNG decoders accept it.
fn mini_deflate(data: &[u8]) -> Vec<u8> {
    let mut out = Vec::new();
    // zlib header: CM=8 (deflate), CINFO=7, FCHECK so header%31==0
    out.push(0x78);
    out.push(0x01);

    // Stored blocks (max 65535 bytes each)
    let chunks: Vec<&[u8]> = if data.is_empty() {
        vec![&[]]
    } else {
        data.chunks(65535).collect()
    };
    for (i, chunk) in chunks.iter().enumerate() {
        let is_last = i == chunks.len() - 1;
        out.push(if is_last { 0x01 } else { 0x00 });
        let len = chunk.len() as u16;
        out.extend_from_slice(&len.to_le_bytes());
        let nlen = !len;
        out.extend_from_slice(&nlen.to_le_bytes());
        out.extend_from_slice(chunk);
    }

    // Adler-32 checksum
    let adler = adler32(data);
    out.extend_from_slice(&adler.to_be_bytes());
    out
}

fn adler32(data: &[u8]) -> u32 {
    let mut a: u32 = 1;
    let mut b: u32 = 0;
    for &byte in data {
        a = (a + byte as u32) % 65521;
        b = (b + a) % 65521;
    }
    (b << 16) | a
}
"
}
