{
  "Cargo.toml": "[package]
name = "zql"
version = "0.1.0"
edition = "2021"

[dependencies]
rustyline = "14.0.0"
",
  "main.rs": "use rustyline::{
    Cmd, ConditionalEventHandler, Editor, Event, EventContext, EventHandler, KeyEvent,
    Modifiers, Movement, RepeatCount, Result,
};
use rustyline::history::DefaultHistory;
use rustyline::hint::HistoryHinter;
use rustyline::completion::{Completer, Pair};
use rustyline::highlight::Highlighter;
use rustyline::hint::Hinter;
use rustyline::validate::Validator;
use rustyline::Helper;
use rustyline::Context;

/// A minimal helper that provides simple tab completion for demo purposes.
#[derive(Helper, Highlighter, Validator)]
struct CommandHelper {
    words: Vec<String>,
}

impl Hinter for CommandHelper {
    type Hint = String;
    fn hint(&self, _line: &str, _pos: usize, _ctx: &Context<'_>) -> Option<String> {
        None
    }
}

impl Completer for CommandHelper {
    type Candidate = Pair;

    fn complete(
        &self,
        line: &str,
        pos: usize,
        _ctx: &Context<'_>,
    ) -> Result<(usize, Vec<Pair>)> {
        let line_up_to_pos = &line[..pos];
        // Find the start of the current word
        let start = line_up_to_pos
            .rfind(|c: char| c.is_whitespace() || c == '.' || c == ',')
            .map(|i| i + 1)
            .unwrap_or(0);
        let prefix = &line_up_to_pos[start..];

        let mut matches: Vec<Pair> = self
            .words
            .iter()
            .filter(|w| w.to_lowercase().starts_with(&prefix.to_lowercase()))
            .map(|w| Pair {
                display: w.clone(),
                // Add a trailing space after completion
                replacement: format!("{} ", w),
            })
            .collect();

        // If there's exactly one match, keep the space; otherwise no space
        if matches.len() != 1 {
            for m in &mut matches {
                m.replacement = m.replacement.trim_end().to_string();
            }
        }

        Ok((start, matches))
    }
}

/// Event handler that deletes trailing whitespace before cursor and inserts
/// the punctuation character, leaving the cursor AFTER the inserted character.
struct SmartPunctuationHandler {
    ch: char,
}

impl SmartPunctuationHandler {
    fn new(ch: char) -> Self {
        SmartPunctuationHandler { ch }
    }
}

impl ConditionalEventHandler for SmartPunctuationHandler {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();
        let before_cursor = &line[0..pos];

        // Count trailing whitespace characters before cursor
        let trimmed_len = before_cursor.trim_end().len();
        let ws_count = pos - trimmed_len;

        if ws_count > 0 {
            // We need to:
            // 1) Delete the ws_count whitespace characters before the cursor
            // 2) Insert our punctuation character
            //
            // Cmd::Replace(Movement::BackwardChar(n), Some(s)) replaces n chars
            // backward with string s, but leaves cursor BEFORE s.
            //
            // Workaround: We use Cmd::Replace to replace the whitespace with
            // the punctuation char, then we need to move forward.
            //
