/// Decode using rasn-cms which handles BER encoding properly
fn decode_with_rasn(body: &[u8]) -> Result<(), Box<dyn std::error::Error>> {
    use rasn::ber::de::decode as ber_decode;
    use rasn_cms::ContentInfo;
    use rasn_cms::SignedData;
    use rasn_cms::ContentType;

    // Step 1: Decode outer ContentInfo
    let ci: ContentInfo = ber_decode(body)
        .map_err(|e| format!("Failed to decode ContentInfo: {:?}", e))?;

    let signed_data_oid: ContentType = rasn::types::ObjectIdentifier::new_unchecked(
        vec![1, 2, 840, 113549, 1, 7, 2].into(),
    );

    println!("  ContentInfo.contentType: {:?}", ci.content_type);

    if ci.content_type != signed_data_oid {
        return Err(format!(
            "Expected pkcs7-signedData OID, got {:?}",
            ci.content_type
        ).into());
    }

    // Step 2: Decode SignedData from the content
    let sd: SignedData = ber_decode(&ci.content.contents)
        .map_err(|e| format!("Failed to decode SignedData: {:?}", e))?;

    println!("  SignedData.version: {:?}", sd.version);

    // Digest Algorithms
    println!("  DigestAlgorithms:");
    for alg in sd.digest_algorithms.iter() {
        println!("    - {:?}", alg.algorithm);
    }

    // Encapsulated Content Info
    println!("  EncapContentInfo.eContentType: {:?}", sd.encap_content_info.content_type);
    if let Some(ref econtent) = sd.encap_content_info.content {
        println!("  EncapContentInfo.eContent: {} bytes", econtent.len());

        // For SCEP, the eContent is typically EnvelopedData wrapped in ContentInfo
        let pkcs7_data_oid: ContentType = rasn::types::ObjectIdentifier::new_unchecked(
            vec![1, 2, 840, 113549, 1, 7, 1].into(),
        );
        let pkcs7_enveloped_oid: ContentType = rasn::types::ObjectIdentifier::new_unchecked(
