    use cms::signed_data::SignedData;
    use der::Decode;

    // Step 1: Decode outer ContentInfo
    let ci = ContentInfo::from_der(body)
        .map_err(|e| format!("Failed to decode ContentInfo: {}", e))?;

    println!("  ContentInfo.contentType: {}", ci.content_type);

    // Step 2: Try to decode SignedData
    // This is where it typically fails for real SCEP messages due to strict DER
    let sd: SignedData = ci.content.decode_as()
        .map_err(|e| format!("Failed to decode SignedData: {} -- \
            This is the known issue with strict DER parsing. \
            Use rasn-cms instead.", e))?;

    println!("  SignedData.version: {:?}", sd.version);
    println!("  DigestAlgorithms: {} algorithm(s)", sd.digest_algorithms.len());
    println!("  SignerInfos: {} signer(s)", sd.signer_infos.len());

    if let Some(ref certs) = sd.certificates {
        println!("  Certificates: {} item(s)", certs.0.len());
    }

    Ok(())
}

/// Build and decode a minimal synthetic SignedData for demonstration
fn demonstrate_with_synthetic() {
    use rasn::ber::de::decode as ber_decode;
    use rasn::der::encode as der_encode;
    use rasn_cms::*;
    use rasn::types::*;

    println!("=== Demonstrating with synthetic minimal SignedData ===");
    println!();

    // Build a minimal SignedData structure
    let digest_alg = rasn_pkix::AlgorithmIdentifier {
        algorithm: ObjectIdentifier::new_unchecked(vec![2, 16, 840, 1, 101, 3, 4, 2, 1].into()), // sha256
        parameters: None,
    };

    let encap = EncapsulatedContentInfo {
        content_type: ObjectIdentifier::new_unchecked(vec![1, 2, 840, 113549, 1, 7, 1].into()),
        content: Some(OctetString::from(vec![0x01, 0x02, 0x03])),
    };

    let sd = SignedData {
        version: CmsVersion::V1,
        digest_algorithms: rasn::types::SetOf::from_vec(vec![digest_alg]),
        encap_content_info: encap,
        certificates: None,
        crls: None,
        signer_infos: rasn::types::SetOf::from_vec(vec![]),
    };

    let sd_bytes = der_encode(&sd).expect("Failed to DER-encode SignedData");

    let ci = ContentInfo {
        content_type: ObjectIdentifier::new_unchecked(vec![1, 2, 840, 113549, 1, 7, 2].into()),
        content: rasn::types::Any::new(sd_bytes),
    };

    let ci_bytes = der_encode(&ci).expect("Failed to DER-encode ContentInfo");

    println!("Synthetic ContentInfo: {} bytes", ci_bytes.len());
    println!("Hex: {}", hex::encode(&ci_bytes));
    println!();

    // Now decode it back
    let ci2: ContentInfo = ber_decode(&ci_bytes).expect("Failed to decode ContentInfo");
    let sd2: SignedData = ber_decode(&ci2.content.contents).expect("Failed to decode SignedData");

    println!("Decoded ContentInfo.contentType: {:?}", ci2.content_type);
    println!("Decoded SignedData.version: {:?}", sd2.version);
    println!("Decoded SignedData.digestAlgorithms count: {}", sd2.digest_algorithms.len());
    println!("Decoded SignedData.encapContentInfo.eContentType: {:?}", sd2.encap_content_info.content_type);
    println!();
    println!("Synthetic decode succeeded! Use a real SCEP .der file for full testing.");
}
"
}
```

**Key insight**: The RustCrypto `cms` crate uses strict DER parsing, but SCEP clients (Windows NDES, Apple MDM, etc.) commonly produce BER-encoded messages. The serial number `0x4543303943443336343136303746443736304539353835393630433133453800` (which is actually the ASCII hex of the transaction ID) has a trailing `0x00` byte that causes the strict DER integer parser to choke at position 129.

**The solution** uses `rasn-cms` which supports BER decoding and handles these real-world encoding quirks. The program:

1. Decodes with `rasn-cms` (BER-tolerant) — **recommended for SCEP**
2. Attempts `cms` (strict DER) to show the failure
3. Falls back to a synthetic demo if no `.der` file is provided

Run with: `cargo run -- ci.der` (where `ci.der` is your SCEP PKIOperation POST body).

