 <p>Is it possible to use Serde to deserialize following JSON into single simple struct instead of having nested structs?</p>
<p>JSON:</p>
<pre class="lang-json prettyprint-override"><code>{ 
    name: &quot;Name&quot;, 
    server: { 
        name: &quot;Server&quot; 
    } 
}
</code></pre>
<p>Struct:</p>
<pre><code>struct Character {
    name: String,
    server: String,
}
</code></pre>


Instruction: Your deliverables is a Cargo.toml file and a main.rs file that's self-contained so I can move them into a rust project and test it with `cargo run`. Only return a json object with the following keys: - Cargo.toml: the contents of the Cargo.toml file - main.rs: the contents of the main.rs file

response:
```json
{
  "Cargo.toml": "[package]
name = "json_deserialize"
version = "0.1.0"
edition = "2021"

[dependencies]
serde = { version = "1", features = ["derive"] }
serde_json = "1"
",
  "main.rs": "use serde::de::{self, Deserializer, MapAccess, Visitor};
use serde::Deserialize;
use std::fmt;

#[derive(Debug)]
struct Character {
    name: String,
    server: String,
}

impl<'de> Deserialize<'de> for Character {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        #[derive(Deserialize)]
        #[serde(field_identifier, rename_all = "lowercase")]
        enum Field {
            Name,
            Server,
        }

        struct CharacterVisitor;

        impl<'de> Visitor<'de> for CharacterVisitor {
            type Value = Character;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("struct Character")
            }

            fn visit_map<V>(self, mut map: V) -> Result<Character, V::Error>
            where
                V: MapAccess<'de>,
            {
                let mut name: Option<String> = None;
                let mut server: Option<String> = None;

                while let Some(key) = map.next_key()? {
                    match key {
                        Field::Name => {
                            if name.is_some() {
                                return Err(de::Error::duplicate_field("name"));
                            }
                            name = Some(map.next_value()?);
                        }
                        Field::Server => {
                            if server.is_some() {
                                return Err(de::Error::duplicate_field("server"));
                            }
                            // Deserialize the nested object and extract the "name" field
                            #[derive(Deserialize)]
                            struct ServerObj {
                                name: String,
                            }
                            let server_obj: ServerObj = map.next_value()?;
                            server = Some(server_obj.name);
                        }
                    }
                }

                let name = name.ok_or_else(|| de::Error::missing_field("name"))?;
                let server = server.ok_or_else(|| de::Error::missing_field("server"))?;

                Ok(Character { name, server })
            }
        }

        const FIELDS: &[&str] = &["name", "server"];
        deserializer.deserialize_struct("Character", FIELDS, CharacterVisitor)
    }
}

fn main() {
    let json_data = r#"{
        "name": "Name",
        "server": {
            "name": "Server"
        }
    }"#;

    let character: Character = serde_json::from_str(json_data).expect("Failed to deserialize");

    println!("Character name: {}", character.name);
    println!("Server name: {}", character.server);
    println!("\nFull debug output: {:?}", character);
}
"
}
```

