    // The Python script is embedded directly into the binary at compile time.
    // This means `cargo install` will produce a single binary with the script inside.
    let script_contents = include_str!("python/script.py");

    // Write the embedded script to a temporary file so we can invoke the Python interpreter on it.
    let temp_dir = env::temp_dir();
    let script_path = temp_dir.join("rust_program_script.py");

    let mut file = fs::File::create(&script_path).expect("Failed to create temporary Python script file");
    file.write_all(script_contents.as_bytes()).expect("Failed to write Python script to temp file");
    drop(file);

    // Try "python3" first, then fall back to "python"
    let python = if Command::new("python3").arg("--version").output().is_ok() {
        "python3"
    } else {
        "python"
    };

    let status = Command::new(python)
        .arg(&script_path)
        .status()
        .expect("Failed to execute Python interpreter. Is Python installed and on your PATH?");

    // Clean up the temporary file (best-effort)
    let _ = fs::remove_file(&script_path);

    if !status.success() {
        std::process::exit(status.code().unwrap_or(1));
    }
}
"
}
```

**How to use this:**

1. Place `Cargo.toml` and `src/main.rs` in your project as usual.
2. Create `src/python/script.py` with whatever Python code you want. For example:

```python
print("Hello from the embedded Python script!")
```

3. Run `cargo run` (or `cargo install --path .` and then `rust-program`).

**How it works:**

- `include_str!("python/script.py")` embeds the contents of `src/python/script.py` directly into the compiled Rust binary at compile time. This means `cargo install` produces a **single self-contained binary** — no separate file to distribute.
- At runtime, the binary writes the embedded script to a temporary file and invokes the system's Python interpreter on it.
- The temporary file is cleaned up after execution.
- The user only needs Python installed; they never need to know about `script.py`.

