{
  "Cargo.toml": "[package]
name = "tui-event-loop"
version = "0.1.0"
edition = "2021"

[dependencies]
crossterm = "0.27"
",
  "main.rs": "use crossterm::event::{self, Event, KeyCode, KeyEventKind};
use crossterm::terminal::{disable_raw_mode, enable_raw_mode};
use std::io::{self, Write};
use std::time::{Duration, Instant};

fn main() -> io::Result<()> {
    // Enable raw mode so we get key events immediately (no line buffering).
    enable_raw_mode()?;

    println!("Starting event loop. Press 'q' to quit.\r");
    println!("The 'Tick!' message will appear every second, independent of key presses.\r");
    io::stdout().flush()?;

    let tick_rate = Duration::from_secs(1);
    let mut last_tick = Instant::now();

    loop {
        // Calculate how much time is left until the next tick.
        let timeout = tick_rate
            .checked_sub(last_tick.elapsed())
            .unwrap_or(Duration::ZERO);

        // `poll` will block for *at most* `timeout` duration.
        // It returns `true` if an event is available to read, `false` on timeout.
        if event::poll(timeout)? {
            // An event is available — read it (this will NOT block because poll said it's ready).
            let ev = event::read()?;

            // In raw mode, crossterm on some platforms sends both Press and Release events.
            // We only act on Press to avoid double-handling.
            if let Event::Key(key) = &ev {
                if key.kind == KeyEventKind::Press {
                    println!("- Key pressed: {:?}\r", key.code);

                    if key.code == KeyCode::Char('q') {
                        println!("'q' pressed, quitting.\r");
                        break;
                    }
                }
            } else {
                println!("- Event received: {:?}\r", ev);
            }
        }

        // After poll returns (either because an event arrived or because it timed out),
        // check whether it's time for a tick.
        if last_tick.elapsed() >= tick_rate {
