    fn complete(
        &self,
        line: &str,
        pos: usize,
        ctx: &Context<'_>,
    ) -> Result<(usize, Vec<Pair>)> {
        // Simple heuristic: if the line so far has no spaces, the user is
        // typing a command name → complete from our known commands list.
        // Otherwise fall back to filename completion.
        let word_start = line[..pos].rfind(' ').map(|i| i + 1).unwrap_or(0);
