/// Listens for Unix signals (SIGINT, SIGTERM) and sends messages.
/// Checks the `running` flag periodically because `signals.forever()` blocks.
/// We use `signals.wait()` with a timeout-like approach instead.
fn yield_signals(sender: Sender<Message>, running: Arc<AtomicBool>) {
    let mut signals = Signals::new(&[SIGINT, SIGTERM]).unwrap();

    // `signals.forever()` blocks indefinitely, so we use the polling approach:
    // `signals.wait()` also blocks, but we can use `signals.pending()` in a loop
    // with a small sleep to allow checking the `running` flag.
    while running.load(Ordering::Relaxed) {
        // pending() is non-blocking — returns signals that have arrived so far
        for sig in signals.pending() {
            match sig {
                SIGINT | SIGTERM => {
                    let _ = sender.send(Message::Signal(sig));
                    let _ = sender.send(Message::Quit);
                    running.store(false, Ordering::Relaxed);
                    return;
                }
                _ => {}
            }
        }
        thread::sleep(Duration::from_millis(100));
    }
}

/// Listens for key events from stdin. Uses `set_nonblocking` on stdin
/// (via termion's async reader) so we can check the `running` flag.
fn yield_keys(sender: Sender<Message>, running: Arc<AtomicBool>) {
    // We use termion's AsyncReader to get non-blocking reads from stdin,
    // so we can periodically check the `running` flag.
    let _stdout = io::stdout().into_raw_mode().unwrap();
    let mut async_stdin = termion::async_stdin();

    let mut buf = [0u8; 64];
    while running.load(Ordering::Relaxed) {
        // Try to read bytes from async stdin
        match async_stdin.read(&mut buf) {
            Ok(0) => {
                // No data available yet
                thread::sleep(Duration::from_millis(50));
            }
            Ok(n) => {
                // Parse the bytes we got as termion events.
                // We can use termion's event iterator over a slice.
                let slice = &buf[..n];
                for event in slice.events() {
                    if let Ok(evt) = event {
                        match evt {
                            Event::Key(Key::Char('q')) => {
                                let _ = sender.send(Message::Quit);
                                running.store(false, Ordering::Relaxed);
                                return;
                            }
                            Event::Key(Key::Char(c)) => {
                                let _ = sender.send(Message::KeyPressed(c));
                            }
                            Event::Key(Key::Ctrl('c')) => {
                                let _ = sender.send(Message::Quit);
                                running.store(false, Ordering::Relaxed);
                                return;
                            }
                            _ => {}
                        }
                    }
                }
            }
            Err(ref e) if e.kind() == io::ErrorKind::WouldBlock => {
                thread::sleep(Duration::from_millis(50));
            }
            Err(_) => {
                break;
            }
        }
    }
}

fn main() {
    let (sender, receiver): (Sender<Message>, Receiver<Message>) = mpsc::channel();

    // Shared flag that all threads check to know when to stop
    let running = Arc::new(AtomicBool::new(true));

    let running_signals = Arc::clone(&running);
    let sender_signals = sender.clone();
    let signal_thread = thread::spawn(move || {
        yield_signals(sender_signals, running_signals);
    });

    let running_keys = Arc::clone(&running);
    let sender_keys = sender.clone();
    let keys_thread = thread::spawn(move || {
        yield_keys(sender_keys, running_keys);
    });

    // Drop the original sender so the receiver will eventually hang up
    // when all sender clones are dropped.
    drop(sender);

    println!("Event loop started. Press keys to see events. Press 'q' or Ctrl+C to quit.");

    for msg in receiver.iter() {
        match msg {
            Message::KeyPressed(c) => {
                println!("Key pressed: {:?}", c);
            }
            Message::Signal(sig) => {
                println!("Received signal: {}", sig);
            }
            Message::Quit => {
                println!("Quit message received. Shutting down...");
                // Ensure the running flag is set to false so threads exit
                running.store(false, Ordering::Relaxed);
                break;
            }
        }
    }

    // Wait for threads to finish (they should exit soon since running is false)
    let _ = signal_thread.join();
    let _ = keys_thread.join();

    println!("Goodbye!");
}
