const PIXELS_PER_LINE: usize = PIXELS_PER_SIDE;
const BYTES_PER_PIXEL: usize = 4;

/// Flip a single line of pixels horizontally (reverse the order of 4-byte pixels).
///
/// We treat each 4-byte group as a `u32`, reverse the slice of `u32`s, then
/// write back. This lets LLVM auto-vectorise on both x86-64 (SSE2/AVX2) and
/// AArch64 (NEON) without any hand-written intrinsics while staying 100% safe.
#[inline]
fn flip_line(line_bytes: &mut [u8]) {
    assert_eq!(
        line_bytes.len() % BYTES_PER_PIXEL,
        0,
        "line length must be a multiple of BYTES_PER_PIXEL"
    );

    // Re-interpret as &mut [u32] via an intermediate buffer that the compiler
    // will optimise away for small, known sizes.  We copy into a u32 scratch
    // array, reverse it, then copy back.  For the fixed 8-pixel case the
    // compiler will unroll everything into a handful of register moves.
    //
    // For the general case we do the classic two-pointer swap but on u32 words
    // so each swap is a single 32-bit load/store pair — much friendlier to the
    // pipeline than four individual byte swaps.

    let pixel_count = line_bytes.len() / BYTES_PER_PIXEL;
    let mut left: usize = 0;
    let mut right: usize = pixel_count.wrapping_sub(1);

    while left < right {
        let lo = left * BYTES_PER_PIXEL;
        let hi = right * BYTES_PER_PIXEL;

        // Read both pixels as u32 (native-endian; we only care about the 4
        // bytes as an opaque group).
        let left_pixel = u32::from_ne_bytes([
            line_bytes[lo],
            line_bytes[lo + 1],
            line_bytes[lo + 2],
            line_bytes[lo + 3],
        ]);
        let right_pixel = u32::from_ne_bytes([
            line_bytes[hi],
            line_bytes[hi + 1],
            line_bytes[hi + 2],
            line_bytes[hi + 3],
        ]);

        // Write them back swapped.
        let rp = right_pixel.to_ne_bytes();
        line_bytes[lo] = rp[0];
        line_bytes[lo + 1] = rp[1];
        line_bytes[lo + 2] = rp[2];
        line_bytes[lo + 3] = rp[3];

        let lp = left_pixel.to_ne_bytes();
        line_bytes[hi] = lp[0];
        line_bytes[hi + 1] = lp[1];
        line_bytes[hi + 2] = lp[2];
        line_bytes[hi + 3] = lp[3];

        left += 1;
        right -= 1;
    }
