use std::fmt;

/// The borrowed struct we want to deserialize into.
#[derive(Deserialize, Debug)]
struct MyData<'a> {
    data: &'a str,
    more_data: &'a str,
}

/// A self-referential container that owns the JSON `String` and holds
/// the deserialized `MyData` that borrows from it.
///
/// Safety contract:
/// 1. `source` is heap-allocated (`String`) and is **never mutated or moved
///    in memory** after `parsed` is created (we only move the outer `Box`).
/// 2. `parsed` stores references that point into `source`.
/// 3. We transmute the lifetime to `'static` so the struct is `Send + 'static`,
///    but we never expose the inner references beyond the lifetime of `&self`.
/// 4. `source` is declared **before** `parsed` so that `parsed` is dropped
///    first (Rust drops fields in declaration order).
struct OwnedMyData {
    // Must be dropped second (fields drop in declaration order, so this is fine).
    #[allow(dead_code)]
    source: String,
    // Dropped first. References point into `source`.
    parsed: MyData<'static>,
}

// SAFETY: The String is fully owned and MyData only borrows from it.
// We never hand out 'static references externally; we re-bind to &'self.
unsafe impl Send for OwnedMyData {}
unsafe impl Sync for OwnedMyData {}

impl OwnedMyData {
    /// Deserialize `json` **once** into `MyData` that borrows from the owned
    /// `String`. The string is moved into the struct so it lives as long as
    /// the container.
    fn new(json: String) -> Result<Box<Self>, serde_json::Error> {
        // Deserialize borrowing from `json`.
        let parsed: MyData<'_> = serde_json::from_str(&json)?;

        // SAFETY: We are about to store `json` right next to `parsed` inside
        // the same struct, and we will never mutate `json` afterwards.
        // The references inside `parsed` point into the heap buffer of `json`,
        // which will not move because `String`'s data is on the heap and we
        // never reallocate it.  We erase the lifetime to 'static so the
        // struct can be Send + 'static; the accessor below re-binds the
        // lifetime to the borrow of `&self`.
        let parsed: MyData<'static> = unsafe { std::mem::transmute(parsed) };

        Ok(Box::new(OwnedMyData { source: json, parsed }))
    }

    /// Borrow the parsed data with a lifetime tied to `&self`, which is sound
    /// because `self.source` (and therefore the backing memory) lives at least
    /// as long as `&self`.
    fn get(&self) -> &MyData<'_> {
        &self.parsed
    }
}

impl fmt::Debug for OwnedMyData {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("OwnedMyData")
            .field("parsed", self.get())
            .finish()
    }
}

#[tokio::main]
async fn main() {
    // Simulate receiving JSON strings from a channel / TCP stream.
    let payloads: Vec<String> = vec![
        r#"{"data": "hello", "more_data": "world"}"#.to_string(),
        r#"{"data": "foo",   "more_data": "bar"}"#.to_string(),
        r#"{"data": "rust",  "more_data": "tokio"}"#.to_string(),
    ];

    let mut handles = Vec::new();

    for json in payloads {
        // Deserialize exactly once here (or inside the task – either works).
        let owned = OwnedMyData::new(json).expect("valid JSON");

        // `owned` is Send + 'static, so it can cross the spawn boundary.
        let handle = tokio::spawn(async move {
            // Access the borrowed fields without any extra allocation.
            let data: &MyData<'_> = owned.get();
            println!(
                "[task] data = {:?}, more_data = {:?}",
                data.data, data.more_data
            );
        });

        handles.push(handle);
    }

    for h in handles {
        h.await.unwrap();
    }

    println!("\nAll tasks completed.");
}
"
