                    let dy = pi[1] - pj[1];
                    let dz = pi[2] - pj[2];
                    let dist2 = dx * dx + dy * dy + dz * dz;
                    if dist2 < cutoff {
                        nb.push(j);
                    }
                }
                nb
            })
            .collect();

        // Assign results
        for (i, nb) in neighbor_lists.into_iter().enumerate() {
            self.elems[i].nb = nb;
        }
    }

    /// Parallel version exploiting symmetry (i,j) => both get each other as neighbors.
    /// Uses Mutex to protect the neighbor lists from concurrent writes.
    pub fn build_lists_parallel_symmetric(&mut self) {
        let cutoff = self.cutoff;
        let nelems = self.elems.len();

        let positions: Vec<[f64; 3]> = self.elems.iter().map(|b| [b.r[0], b.r[1], b.r[2]]).collect();

        // Use Mutex-protected neighbor lists for concurrent appending
        let neighbor_lists: Vec<Mutex<Vec<usize>>> = (0..nelems).map(|_| Mutex::new(Vec::new())).collect();

        // Generate all unique pairs (i, j) where i < j, and process in parallel
        // We parallelize over i, and for each i we iterate over j > i.
        (0..nelems).into_par_iter().for_each(|i| {
            let pi = &positions[i];
            for j in (i + 1)..nelems {
