                    neighbor_lists[j].lock().unwrap().push(i);
                }
            }
        });

        // Assign results
        for (i, nb_mutex) in neighbor_lists.into_iter().enumerate() {
            self.elems[i].nb = nb_mutex.into_inner().unwrap();
        }
    }
