",
  "main.rs": "use pavao::{SmbClient, SmbCredentials, SmbDirentType, SmbOptions};
use std::error::Error;

fn list_dir_recursive(
    client: &SmbClient,
    base_url: &str,
    path: &str,
    depth: usize,
) -> Result<(), Box<dyn Error>> {
    let full_path = if path.is_empty() {
        base_url.to_string()
    } else {
        format!("{}/{}", base_url, path)
    };

    let entries = client.list_dir(&full_path)?;

    for entry in entries {
        let name = entry.name();

        // Skip . and .. to avoid infinite recursion
        if name == "." || name == ".." {
            continue;
        }

        let relative_path = if path.is_empty() {
            name.to_string()
        } else {
            format!("{}/{}", path, name)
        };

        let indent = "  ".repeat(depth);
        let type_label = match entry.get_type() {
            SmbDirentType::Dir => "[DIR] ",
            SmbDirentType::File => "[FILE]",
            SmbDirentType::FileShare => "[SHR] ",
            SmbDirentType::Server => "[SRV] ",
            SmbDirentType::Printer => "[PRN] ",
            SmbDirentType::Workgroup => "[WKG] ",
            SmbDirentType::CommsShare => "[COM] ",
            SmbDirentType::IpcShare => "[IPC] ",
            _ => "[UNK] ",
        };

        println!("{}{} {}", indent, type_label, relative_path);

        // Recurse into directories
        if matches!(entry.get_type(), SmbDirentType::Dir) {
            if let Err(e) = list_dir_recursive(client, base_url, &relative_path, depth + 1) {
                eprintln!("{}  Error reading {}: {}", indent, relative_path, e);
            }
        }
    }

    Ok(())
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    // --- Configuration: update these values for your environment ---
    let smb_server = std::env::var("SMB_SERVER").unwrap_or_else(|_| "10.0.0.1".to_string());
    let smb_share = std::env::var("SMB_SHARE").unwrap_or_else(|_| "shared".to_string());
    let smb_user = std::env::var("SMB_USER").unwrap_or_else(|_| "guest".to_string());
    let smb_password = std::env::var("SMB_PASSWORD").unwrap_or_else(|_| "".to_string());
