/// So to keep the connection alive we simply must keep the `Client` alive.
/// The intermittent `Closed` errors in the original code were almost certainly
/// caused by the `Connection` future completing due to the runtime being
/// shut down or the spawned task being dropped between tests (e.g. when using
/// `#[tokio::test]` which creates a *new* runtime per test). Each
/// `#[tokio::test]` has its own single-threaded runtime, so tasks spawned in
/// one test are cancelled when that runtime is dropped — even if the `Client`
/// stored in a `OnceCell` survives (because it lives in a `lazy_static` or
/// similar). The solution is to **spawn the connection task on the same
/// runtime that will use the client**, or use a long-lived runtime.
///
/// In a real application you would typically use a connection pool (e.g.
/// `deadpool-postgres` or `bb8`). This example shows the minimal approach
/// of caching a single client.
struct CachedClient {
    client: Client,
    _conn_handle: JoinHandle<()>,
}

impl CachedClient {
    fn client(&self) -> &Client {
        &self.client
    }
}

enum ClientWrapper<'a> {
    Owned {
        client: Client,
        _conn_handle: JoinHandle<()>,
    },
    Borrowed(&'a Client),
}

impl Deref for ClientWrapper<'_> {
    type Target = Client;

    fn deref(&self) -> &Self::Target {
        match self {
            Self::Owned { client, .. } => client,
            Self::Borrowed(c) => c,
        }
    }
}

impl DbContainer {
    pub fn new<N>(container_name: N, db_config: DbConfig) -> Self
    where
        N: Into<String>,
    {
        Self {
            args: vec![
                "--env".to_string(),
                format!("POSTGRES_PASSWORD={}", &db_config.postgres_password),
                "--publish".to_string(),
                format!("{}:5432", db_config.port),
            ],
            container_name: container_name.into(),
            db_config,
            default_client: OnceCell::const_new(),
        }
    }

    pub async fn create_database(&self, name: &str) -> Result<(), tokio_postgres::Error> {
        let client = self.connect(None).await?;
        client
            .execute(&format!("CREATE DATABASE {name}"), &[])
            .await?;
        // Connect to the newly created database to run schema migrations, etc.
        let client = self.connect(Some(name)).await?;
        // client.batch_execute(load_schema()).await  // uncomment with your schema
        client.batch_execute("SELECT 1").await?;
        Ok(())
    }

    pub async fn drop_database(&self, name: &str) -> Result<u64, tokio_postgres::Error> {
        let client = self.connect(None).await?;
        let terminate_sql = format!(
            "
            SELECT pg_terminate_backend(pid)
            FROM pg_stat_activity
            WHERE datname = '{name}' AND pid <> pg_backend_pid();
            ",
        );
        client.execute(&terminate_sql, &[]).await?;
        client.execute(&format!("DROP DATABASE {name}"), &[]).await
    }

    /// Returns a client wrapper. When `db_name` is `None` the cached default
    /// connection is returned; otherwise a fresh connection to the specified
    /// database is created.
    async fn connect(
        &self,
        db_name: Option<&str>,
    ) -> Result<ClientWrapper<'_>, tokio_postgres::Error> {
        let mut conn_str = format!(
            "host=localhost port={} user=postgres password={}",
            self.db_config.port, self.db_config.postgres_password
        );

        if let Some(dbname) = db_name {
            conn_str.push_str(&format!(" dbname={dbname}"));

            let (client, conn) = tokio_postgres::connect(&conn_str, NoTls).await?;

            let handle = tokio::spawn(async move {
                if let Err(e) = conn.await {
                    eprintln!("Connection error: {e}");
                }
            });

            Ok(ClientWrapper::Owned {
                client,
                _conn_handle: handle,
            })
        } else {
            // Use the cached client for the default postgres database.
            // `get_or_try_init` lets us propagate errors (unlike `get_or_init`).
            let cached = self
                .default_client
                .get_or_try_init(|| async {
                    let (client, conn) =
                        tokio_postgres::connect(&conn_str, NoTls).await?;

                    let handle = tokio::spawn(async move {
                        if let Err(e) = conn.await {
                            eprintln!("Connection error: {e}");
                        }
                    });

                    Ok::<CachedClient, tokio_postgres::Error>(CachedClient {
                        client,
                        _conn_handle: handle,
                    })
                })
                .await?;

            // Before returning the cached client, verify it's still usable.
            // If the connection was lost (e.g. server restart), we could
            // clear the cell and retry — but for simplicity we just return it.
            // In production, use a connection pool instead.
            if cached.client().is_closed() {
                // The OnceCell doesn't support resetting easily, so in a
                // production scenario you'd use an RwLock<Option<...>> or a pool.
                return Err(tokio_postgres::Error::__private_api_timeout());
            }

            Ok(ClientWrapper::Borrowed(cached.client()))
        }
    }
}

#[tokio::main]
async fn main() {
