    let mon = 3u32;
    let day = 15u32;
    let hour = 10u32;
    let mins = 30u32;
    let secs = 45u32;
    let millisecs = 123u32;

    // ----- Approach 1: Use with_ymd_and_hms() and then add milliseconds via checked_add_signed -----
    let time1 = Utc
        .with_ymd_and_hms(year, mon, day, hour, mins, secs)
        .unwrap()
