    println!("Approach 1 (with_ymd_and_hms + Duration): {}", time1);

    // ----- Approach 2: Build a NaiveDate + NaiveTime with milliseconds, then convert to DateTime<Utc> -----
    let naive_date = NaiveDate::from_ymd_opt(year, mon, day).unwrap();
    let naive_time = chrono::NaiveTime::from_hms_milli_opt(hour, mins, secs, millisecs).unwrap();
    let naive_datetime = naive_date.and_time(naive_time);
    let time2 = naive_datetime.and_utc(); // converts NaiveDateTime to DateTime<Utc>
