Here's a self-contained Bevy project that demonstrates the solution. The key insight is that you need to transform the hit normal into the cube's local space, figure out which face it corresponds to, then compose the cube's rotation with the local face rotation.

```json
{
  "Cargo.toml": "[package]
name = "block-gizmo-demo"
version = "0.1.0"
edition = "2021"

[dependencies]
bevy = "0.15"
",
  "main.rs": "use bevy::prelude::*;
use bevy::window::PrimaryWindow;
use bevy::color::palettes::css;

fn main() {
    App::new()
        .add_plugins(DefaultPlugins)
        .add_systems(Startup, setup)
        .add_systems(Update, (rotate_cube, raycast_and_draw_gizmo))
        .run();
}

#[derive(Component)]
struct Block;

fn setup(
    mut commands: Commands,
    mut meshes: ResMut<Assets<Mesh>>,
    mut materials: ResMut<Assets<StandardMaterial>>,
) {
    // Spawn a cube
    commands.spawn((
        Mesh3d(meshes.add(Cuboid::new(1.0, 1.0, 1.0))),
        MeshMaterial3d(materials.add(StandardMaterial {
            base_color: Color::srgb(0.4, 0.6, 0.8),
            ..default()
        })),
        Transform::from_translation(Vec3::ZERO),
        Block,
    ));

    // Light
    commands.spawn((
        DirectionalLight {
            illuminance: 10000.0,
            shadows_enabled: true,
            ..default()
        },
        Transform::from_rotation(Quat::from_euler(EulerRot::XYZ, -0.8, 0.4, 0.0)),
    ));

    // Camera
    commands.spawn((
        Camera3d::default(),
        Transform::from_xyz(3.0, 3.0, 3.0).looking_at(Vec3::ZERO, Vec3::Y),
    ));
}

fn rotate_cube(
    time: Res<Time>,
    mut query: Query<&mut Transform, With<Block>>,
) {
    for mut transform in query.iter_mut() {
        transform.rotation = Quat::from_euler(
            EulerRot::XYZ,
            time.elapsed_secs() * 0.3,
            time.elapsed_secs() * 0.5,
            time.elapsed_secs() * 0.2,
        );
    }
}

/// Given a normal in world space and the cube's transform, compute the rotation
/// for a gizmo rect that is flush with the corresponding cube face.
///
/// The idea:
/// 1. Transform the world-space normal into the cube's local space.
/// 2. Snap to the nearest axis-aligned face normal (+X, -X, +Y, -Y, +Z, -Z).
/// 3. Determine the local rotation that would orient the rect (whose default normal is +Z)
///    to align with that local face normal.
/// 4. Compose: final_rotation = cube_rotation * local_face_rotation
///
/// This ensures the gizmo both points outward along the face normal AND
/// rotates with the cube's orientation.
fn face_flush_rotation(cube_rotation: Quat, world_normal: Vec3) -> Quat {
    // Step 1: bring the hit normal into the cube's local space
    let inv_rot = cube_rotation.inverse();
    let local_normal = (inv_rot * world_normal).normalize();

    // Step 2: snap to nearest axis
    let axes = [
        Vec3::X,
        Vec3::NEG_X,
        Vec3::Y,
        Vec3::NEG_Y,
        Vec3::Z,
        Vec3::NEG_Z,
    ];
    let mut best_axis = Vec3::Z;
    let mut best_dot = f32::NEG_INFINITY;
    for axis in &axes {
        let d = local_normal.dot(*axis);
        if d > best_dot {
            best_dot = d;
            best_axis = *axis;
        }
    }

    // Step 3: local rotation from +Z to the snapped face axis
    // gizmos.rect draws the rect in the XY plane with normal along +Z
    let local_face_rot = if best_axis.dot(Vec3::Z) > 0.999 {
        Quat::IDENTITY
    } else if best_axis.dot(Vec3::Z) < -0.999 {
        Quat::from_rotation_y(std::f32::consts::PI)
    } else {
        Quat::from_rotation_arc(Vec3::Z, best_axis)
    };

    // Step 4: compose
    cube_rotation * local_face_rot
}

fn raycast_and_draw_gizmo(
    mut gizmos: Gizmos,
    camera_q: Query<(&Camera, &GlobalTransform)>,
    block_q: Query<(&GlobalTransform, &Mesh3d), With<Block>>,
    meshes: Res<Assets<Mesh>>,
    windows: Query<&Window, With<PrimaryWindow>>,
) {
    let Ok(window) = windows.get_single() else { return };
    let Some(cursor_pos) = window.cursor_position() else { return };
    let Ok((camera, cam_gt)) = camera_q.get_single() else { return };
    let Ok(ray) = camera.viewport_to_world(cam_gt, cursor_pos) else { return };

    // Manual ray-OBB intersection against each cube
    for (gt, mesh_handle) in block_q.iter() {
        let Some(mesh) = meshes.get(&mesh_handle.0) else { continue };

        // Get the cube's half-extents from the AABB
        let aabb = mesh.compute_aabb().unwrap();
        let half = Vec3::from(aabb.half_extents);

        let cube_translation = gt.translation();
        let cube_rotation = gt.to_scale_rotation_translation().1;
        let inv_rot = cube_rotation.inverse();

        // Transform ray into local space of the cube
        let local_origin = inv_rot * (ray.origin - cube_translation);
        let local_dir = inv_rot * *ray.direction;

        // Ray-AABB intersection in local space
        if let Some((t, local_normal)) = ray_aabb(local_origin, local_dir, half) {
            let world_hit = ray.origin + *ray.direction * t;
            let world_normal = (cube_rotation * local_normal).normalize();

            let face_center = cube_translation + world_normal * half.x; // half-extent along that face
            // More precisely, compute face center based on which axis
            let snapped_local = snap_to_axis(local_normal);
            let face_center_local = snapped_local * half;
            let face_center_world = cube_rotation * face_center_local + cube_translation;

            let rotation = face_flush_rotation(cube_rotation, world_normal);

            gizmos.rect(
                Isometry3d::new(
                    face_center_world + world_normal * 0.01,
                    rotation,
                ),
                Vec2::new(1.0, 1.0),
                Color::WHITE,
            );

            // Also draw the adjacent "placement" cube as wireframe for visual reference
            let placement_center = face_center_world + world_normal * 0.5;
            gizmos.cuboid(
                Transform::from_translation(placement_center)
                    .with_rotation(cube_rotation),
                css::LIME,
            );

            // Draw the normal for debugging
            gizmos.arrow(world_hit, world_hit + world_normal * 0.5, css::RED);
        }
    }
}

fn snap_to_axis(n: Vec3) -> Vec3 {
    let axes = [
        Vec3::X,
        Vec3::NEG_X,
        Vec3::Y,
        Vec3::NEG_Y,
        Vec3::Z,
        Vec3::NEG_Z,
    ];
    let mut best = Vec3::Z;
    let mut best_dot = f32::NEG_INFINITY;
    for axis in &axes {
        let d = n.dot(*axis);
        if d > best_dot {
            best_dot = d;
            best = *axis;
        }
    }
    best
}

/// Returns (t, local_face_normal) for the closest intersection of a ray with an AABB centered at origin.
fn ray_aabb(origin: Vec3, dir: Vec3, half: Vec3) -> Option<(f32, Vec3)> {
    let mut tmin = f32::NEG_INFINITY;
    let mut tmax = f32::INFINITY;
    let mut entry_normal = Vec3::ZERO;

    for i in 0..3 {
        let o = [origin.x, origin.y, origin.z][i];
        let d = [dir.x, dir.y, dir.z][i];
        let h = [half.x, half.y, half.z][i];

        if d.abs() < 1e-8 {
            if o < -h || o > h {
                return None;
            }
        } else {
            let t1 = (-h - o) / d;
            let t2 = (h - o) / d;
            let (t_near, t_far, near_sign) = if t1 < t2 {
                (t1, t2, -1.0_f32)
            } else {
                (t2, t1, 1.0_f32)
            };

            if t_near > tmin {
                tmin = t_near;
                let mut n = Vec3::ZERO;
                match i {
                    0 => n.x = near_sign,
                    1 => n.y = near_sign,
                    _ => n.z = near_sign,
                }
                entry_normal = n;
            }
            tmax = tmax.min(t_far);

            if tmin > tmax {
                return None;
            }
        }
    }

    if tmin < 0.0 {
        return None; // intersection behind camera
    }

    Some((tmin, entry_normal))
}
"
}
```

**How it works:**

The key function is `face_flush_rotation()`. The algorithm:

1. **Transform the world-space hit normal into the cube's local space** using the inverse of the cube's rotation.
2. **Snap to the nearest axis** — this tells us which face of the cube was hit (+X, -X, +Y, -Y, +Z, -Z).
3. **Compute a local rotation** that rotates the gizmo's default normal (+Z) to align with that local face direction.
4. **Compose**: `final_rotation = cube_rotation * local_face_rotation` — this ensures the gizmo both faces outward along the correct normal AND rotates with the cube.

The demo shows a slowly rotating cube. Point your mouse at different faces and you'll see the white rectangle gizmo flush against each face, a green wireframe showing where a new block would be placed, and a red arrow showing the face normal.

