  "main.rs": "use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::fmt;

// ---------------------------------------------------------------------------
// Notion-like domain types (simplified but representative)
// ---------------------------------------------------------------------------

#[derive(Debug, Clone, Serialize, Deserialize)]
