    RichText(Vec<RichTextObject>),
    Url(String),
    Number(f64),
    Checkbox(bool),
    Select(SelectObject),
    MultiSelect(Vec<SelectObject>),
}

impl fmt::Display for PropertyValues {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            PropertyValues::Title(v) => {
                let texts: Vec<&str> = v.iter().map(|r| r.text.content.as_str()).collect();
