            PropertyValues::Number(n) => write!(f, "Number({})", n),
            PropertyValues::Checkbox(b) => write!(f, "Checkbox({})", b),
            PropertyValues::Select(s) => write!(f, "Select({})", s.name),
            PropertyValues::MultiSelect(v) => {
