}

// ---------------------------------------------------------------------------
// Declarative macro: notion_properties!
//
// This macro replaces a proc-macro derive + custom attributes.  It generates
// the struct definition **and** the `IntoNotionProperties` implementation in
// one shot.  Each field carries its Notion property name and type via a small
// DSL understood by the macro.
//
// Supported property types (case-insensitive in intent but matched literally):
//   title, rich_text, url, number, checkbox, select, multi_select
//
// Field kinds:
//   required  – always inserted
//   optional  – wrapped in Option<T>, only inserted when Some
// ---------------------------------------------------------------------------

macro_rules! notion_properties {
    (
        $( #[$struct_meta:meta] )*
        $vis:vis struct $name:ident {
            $(
                // Each field: #[notion("Notion Name", type)]
                // followed by the normal field definition.
                [notion: $notion_name:literal, $notion_type:ident $(, optional)?]
                $( #[$field_meta:meta] )*
                $field_vis:vis $field:ident : $field_ty:ty
            ),* $(,)?
        }
    ) => {
        $( #[$struct_meta] )*
        $vis struct $name {
            $(
                $( #[$field_meta] )*
                $field_vis $field : $field_ty,
            )*
        }

        impl IntoNotionProperties for $name {
            fn into_notion_properties(&self) -> HashMap<String, PropertyValues> {
                let mut map = HashMap::new();
                $(
                    notion_properties!(@insert map, self, $field, $field_ty, $notion_name, $notion_type);
                )*
                map
            }
        }
    };

    // --- internal insertion rules ------------------------------------------

    // Option<String> fields  (url, title, rich_text, select)
    (@insert $map:ident, $self:ident, $field:ident, Option<String>, $notion_name:literal, title) => {
        if let Some(ref v) = $self.$field {
            $map.insert($notion_name.to_string(), make_title(v));
        }
    };
    (@insert $map:ident, $self:ident, $field:ident, Option<String>, $notion_name:literal, rich_text) => {
        if let Some(ref v) = $self.$field {
            $map.insert($notion_name.to_string(), make_rich_text(v));
        }
    };
    (@insert $map:ident, $self:ident, $field:ident, Option<String>, $notion_name:literal, url) => {
        if let Some(ref v) = $self.$field {
            $map.insert($notion_name.to_string(), make_url(v));
