{
  "Cargo.toml": "[package]
name = "custom-op-radiate"
version = "0.1.0"
edition = "2021"

[dependencies]
radiate = "1.2"
",
  "main.rs": "use radiate::*;

fn main() {
    // Define a custom operation: sqrt(x) + 1
    // In radiate, Op has a method `op` that lets you create a custom operation
    // by providing a name, arity, and a closure.
    let sqrt_plus_one = Op::op(
        "sqrt_plus_one",  // name of the operation
        1,                // arity: number of inputs (1 = unary operator)
        |args| {
            // args is a slice of f32 values
            let x = args[0];
            x.abs().sqrt() + 1.0
        },
    );

    // Another custom operator example: x^2 + 2x
    let quad = Op::op(
        "quad",
        1,
        |args| {
            let x = args[0];
            x * x + 2.0 * x
        },
    );

    // A custom binary operator example: weighted sum a*0.7 + b*0.3
    let weighted_sum = Op::op(
        "wsum",
        2, // arity 2 = binary operator
        |args| {
            let a = args[0];
            let b = args[1];
            a * 0.7 + b * 0.3
        },
    );

    // Build the store (the set of operations the GP tree can use)
    // NodeType::Vertex = internal nodes (operators with children)
    // NodeType::Leaf   = terminal nodes (inputs / constants)
    let store = vec![
        (
            NodeType::Vertex,
            vec![
                Op::add(),
                Op::sub(),
                Op::mul(),
                sqrt_plus_one.clone(),
                quad.clone(),
                weighted_sum.clone(),
            ],
        ),
        (
            NodeType::Leaf,
            vec![
                Op::var(0), // input variable x
                Op::value(1.0),
                Op::value(2.0),
            ],
        ),
    ];

    // Target function: we want the GP to discover f(x) = sqrt(|x|) + 1
    // We'll generate training data for x in [-10, 10]
    let inputs: Vec<Vec<f32>> = (-10..=10).map(|i| vec![i as f32]).collect();
    let answers: Vec<f32> = inputs
        .iter()
        .map(|v| {
            let x = v[0];
            x.abs().sqrt() + 1.0 // target
        })
        .collect();

    // Build the genetic programming codex (tree-based)
    let codex = TreeCodex::regression(1, store)
        .with_depth(4)       // max tree depth
        .with_growth(Grow);  // tree growth method

    // Define the fitness function
    // Lower error = better fitness. We use Score::from to return the
    // negative mean squared error so that the engine maximizes towards 0.
    let inputs_clone = inputs.clone();
    let answers_clone = answers.clone();

    let engine = GeneticEngine::from_codex(&codex)
        .minimizing()  // we want to minimize the error
        .num_threads(1)
        .population_size(200)
        .max_age(10)
        .offspring_fraction(0.5)
        .alterer(vec![
            Alterer::TreeCrossover(0.5),
            Alterer::TreeMutator(0.05),
        ])
        .fitness_fn(move |genotype: TreeGenotype<f32>| {
            let program = genotype.program();
            let mut total_error = 0.0f32;
            for (input, &expected) in inputs_clone.iter().zip(answers_clone.iter()) {
                let result = program.eval(input);
                let diff = result - expected;
                total_error += diff * diff;
            }
            let mse = total_error / inputs_clone.len() as f32;
            Score::from(mse)
        })
        .build();

    // Run the engine for up to 500 generations
    let result = engine.run(|output| {
        output.index >= 500 || output.score().as_float() < 0.001
    });

    // Display results
    let best = result.best;
    let program = best.program();

    println!("Best expression found:");
    println!("{}", program);
    println!("\nScore (MSE): {}", result.score.as_float());

    println!("\nVerification:");
    for x_val in &[-5.0f32, -2.0, 0.0, 1.0, 3.0, 7.0] {
        let predicted = program.eval(&[*x_val]);
        let expected = x_val.abs().sqrt() + 1.0;
        println!(
            "  x={:6.2} => predicted={:8.4}, expected={:8.4}, diff={:8.4}",
            x_val,
            predicted,
            expected,
            (predicted - expected).abs()
        );
    }
}
"
}
