// caller cares about (everything else is `None` / `false` / default).
// `matches` returns `true` when every *set* field in `self` (the filter)
// equals the corresponding field in `data`.
// ---------------------------------------------------------------------------

trait FilterMatch {
    fn matches(&self, data: &Self) -> bool;
}

// ---------------------------------------------------------------------------
// Macro that auto-implements `FilterMatch` for a struct whose fields are
// either `Option<T>` (where T: PartialEq or T: FilterMatch) or plain
// values (compared with ==).
//
// Usage:
//   impl_filter_match!(MyStruct {
//       option_field_simple,          // Option<T> where T: PartialEq
//       option_field_recursive(*),    // Option<T> where T: FilterMatch  (recurse)
//       !plain_field,                 // T: PartialEq + Default  (skip when default)
//   });
// ---------------------------------------------------------------------------

macro_rules! impl_filter_match {
    ($ty:ty { $( $spec:tt )* }) => {
        impl FilterMatch for $ty {
            fn matches(&self, data: &Self) -> bool {
                impl_filter_match!(@fields self, data, $($spec)*)
            }
        }
    };

    // --- terminal -----------------------------------------------------------
    (@fields $filter:expr, $data:expr, ) => { true };

    // --- Option<T> with recursive FilterMatch -------------------------------
    (@fields $filter:expr, $data:expr, $field:ident (*) , $($rest:tt)*) => {
        {
            let ok = match (&$filter.$field, &$data.$field) {
                (Some(f), Some(d)) => f.matches(d),
                (Some(_), None)    => false,
                (None, _)          => true,   // filter doesn't care
            };
            ok && impl_filter_match!(@fields $filter, $data, $($rest)*)
        }
    };

    // --- Option<T> with simple PartialEq ------------------------------------
    (@fields $filter:expr, $data:expr, $field:ident , $($rest:tt)*) => {
        {
            let ok = match (&$filter.$field, &$data.$field) {
                (Some(f), Some(d)) => f == d,
                (Some(_), None)    => false,
                (None, _)          => true,
            };
            ok && impl_filter_match!(@fields $filter, $data, $($rest)*)
        }
    };

    // --- plain field (not Option) – skip when it equals Default -------------
    (@fields $filter:expr, $data:expr, ! $field:ident , $($rest:tt)*) => {
        {
            let dominated = $filter.$field == Default::default();
            let ok = dominated || ($filter.$field == $data.$field);
            ok && impl_filter_match!(@fields $filter, $data, $($rest)*)
        }
    };
}

