where
    R::DynamicType: Default,
{
    _type: PhantomData<R>,
    #[allow(dead_code)]
    dynamic_type: R::DynamicType,
    group: Option<Cow<'static, str>>,
    kind: Cow<'static, str>,
    name: String,
}

impl<R: Resource> ResourceRef<R>
where
    R::DynamicType: Default,
{
    pub fn new(resource: &R) -> Self
    where
        R::DynamicType: Default,
    {
        let name = resource
            .meta()
            .name
            .as_deref()
            .expect("Resource must have a name");
        Self::new_named(name)
    }

    pub fn new_named(name: &str) -> Self {
        let dynamic_type = R::DynamicType::default();
        let group = R::group(&dynamic_type);
        let group = if group.is_empty() {
            None
        } else {
            Some(into_static_cow(group))
        };
        let kind = into_static_cow(R::kind(&dynamic_type));

        Self {
            _type: PhantomData,
            dynamic_type,
            group,
            kind,
            name: name.to_string(),
        }
    }

    pub fn group(&self) -> Option<&str> {
        self.group.as_deref()
    }

    pub fn kind(&self) -> &str {
        &self.kind
    }

    pub fn name(&self) -> &str {
        &self.name
    }
}

fn main() {
    use k8s_openapi::api::core::v1::ConfigMap;
    use k8s_openapi::api::apps::v1::Deployment;

    // --- Construct from a name alone ---
    let cm_ref = ResourceRef::<ConfigMap>::new_named("my-config");
    println!("ConfigMap ref:");
    println!("  group: {:?}", cm_ref.group());   // None (core group)
    println!("  kind:  {}", cm_ref.kind());      // ConfigMap
    println!("  name:  {}", cm_ref.name());      // my-config
    println!();

    let deploy_ref = ResourceRef::<Deployment>::new_named("my-deploy");
    println!("Deployment ref:");
    println!("  group: {:?}", deploy_ref.group()); // Some("apps")
    println!("  kind:  {}", deploy_ref.kind());    // Deployment
    println!("  name:  {}", deploy_ref.name());    // my-deploy
    println!();

    // --- Use as a HashMap key (via Debug for demonstration) ---
    use std::collections::HashMap;
    let mut map: HashMap<String, String> = HashMap::new();
    let key = format!("{:?}/{}/{}",
        deploy_ref.group(),
        deploy_ref.kind(),
        deploy_ref.name(),
    );
    map.insert(key.clone(), "hello".to_string());
    println!("HashMap entry: {} -> {:?}", key, map.get(&key));
}
"
}
