  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll, RawWaker, RawWakerVTable, Waker};

/// Result of trying to poll a future once without blocking.
enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// Create a no-op waker. When the future returns `Pending`, the waker will
/// never be called (we don't need it to be because we plan to hand the future
/// off to `tokio::spawn` which installs its own waker).
fn noop_waker() -> Waker {
    fn noop(_: *const ()) {}
    fn clone(data: *const ()) -> RawWaker {
        RawWaker::new(data, &VTABLE)
    }
    static VTABLE: RawWakerVTable = RawWakerVTable::new(clone, noop, noop, noop);
    unsafe { Waker::from_raw(RawWaker::new(std::ptr::null(), &VTABLE)) }
}

/// Try to poll a pinned future exactly once.
///
/// - If it completes immediately (`Poll::Ready`), return the value.
/// - Otherwise return `Pending` so the caller can decide what to do with the
///   future (e.g. spawn it on Tokio).
fn try_poll<X>(future: Pin<&mut dyn Future<Output = X>>) -> TryPollResult<X> {
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);
    match future.poll(&mut cx) {
        Poll::Ready(value) => TryPollResult::Ready(value),
        Poll::Pending => TryPollResult::Pending,
    }
}

// ---------------------------------------------------------------------------
// Demo helpers
// ---------------------------------------------------------------------------

/// A future that is immediately ready (no `.await` / yield points).
async fn instant_future() -> u32 {
    42
}

/// A future that yields at least once before completing.
async fn pending_future() -> u32 {
    // tokio::task::yield_now() returns Pending on the first poll, then Ready.
    tokio::task::yield_now().await;
    99
}

// ---------------------------------------------------------------------------
// The non-async function that manually polls and decides what to do.
// It receives a *boxed* future so it can pin it, try-poll it, and—if
// still pending—move it into a spawned task.
// ---------------------------------------------------------------------------
fn handle_future(
    future: Pin<Box<dyn Future<Output = u32> + Send + 'static>>,
    label: &str,
) {
    // We need to be able to mutate (poll) the pinned future and potentially
    // move the whole Box later, so we unpin the Box, try-poll, then decide.
    let mut future = future;

    match try_poll(future.as_mut()) {
        TryPollResult::Ready(value) => {
            println!("[{label}] Future was immediately ready with value: {value}");
        }
        TryPollResult::Pending => {
            println!("[{label}] Future is pending – spawning a Tokio task to await it.");
            let owned_label = label.to_string();
            tokio::spawn(async move {
                let value = future.await;
                println!("[{owned_label}] Spawned task completed with value: {value}");
            });
        }
    }
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------
#[tokio::main]
async fn main() {
    // Case 1: a future that completes on the first poll.
    handle_future(Box::pin(instant_future()), "instant");

    // Case 2: a future that is NOT ready on the first poll.
    handle_future(Box::pin(pending_future()), "pending");

    // Give the spawned task a moment to finish.
    tokio::task::yield_now().await;
    tokio::task::yield_now().await;

    println!("Done.");
}
"
}
