  "main.rs": "use azure_storage::StorageCredentials;
use azure_storage_blobs::prelude::*;
use futures::stream::StreamExt;
use reqwest::Client;
use serde::{Deserialize, Serialize};
use std::env;
use std::sync::Arc;
use std::time::Instant;

// ---------------------------------------------------------------------------
// Trade data model – adjust fields to match your actual JSON schema
// ---------------------------------------------------------------------------
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TradeData {
    // Using serde_json::Value so any JSON shape is accepted.
    // Replace with concrete fields for better performance if you know the schema.
    #[serde(flatten)]
    pub fields: serde_json::Value,
}

// ---------------------------------------------------------------------------
// OAuth helpers
// ---------------------------------------------------------------------------
#[derive(Serialize)]
struct TokenRequest<'a> {
    grant_type: &'a str,
    client_id: &'a str,
    client_secret: &'a str,
    scope: &'a str,
}

#[derive(Deserialize)]
struct TokenResponse {
    access_token: String,
}

async fn get_oauth_token(
    http: &Client,
    tenant_id: &str,
    client_id: &str,
    client_secret: &str,
) -> Result<String, Box<dyn std::error::Error>> {
    let token_url = format!(
        "https://login.microsoftonline.com/{}/oauth2/v2.0/token",
        tenant_id
    );
    let params = TokenRequest {
        grant_type: "client_credentials",
        client_id,
        client_secret,
        scope: "https://storage.azure.com/.default",
    };
    let response = http.post(&token_url).form(&params).send().await?;
    let status = response.status();
    if !status.is_success() {
        let body_text = response
            .text()
            .await
            .unwrap_or_else(|e| format!("Failed to read error body: {e}"));
        return Err(
            format!("Token endpoint returned {status}, body: {body_text}").into(),
        );
    }
    let body_text = response.text().await?;
    let token_response: TokenResponse = serde_json::from_str(&body_text)?;
    Ok(token_response.access_token)
}

// ---------------------------------------------------------------------------
// Core logic – list all blob names first, then download in parallel
// ---------------------------------------------------------------------------

/// Collect every blob name under `prefix` into a Vec.
async fn list_all_blob_names(
    container_client: &ContainerClient,
    prefix: &str,
) -> Result<Vec<String>, String> {
    let mut names: Vec<String> = Vec::new();
    let mut stream = container_client
        .list_blobs()
        .prefix(prefix.to_owned())
        .into_stream();

    while let Some(page) = stream.next().await {
        let page = page.map_err(|e| format!("list_blobs error: {e}"))?;
        for blob in page.blobs.blobs() {
            if blob.name.ends_with(".json") {
                names.push(blob.name.clone());
            }
        }
    }
    Ok(names)
}

/// Download + deserialize a single blob.
async fn download_blob(
    container_client: &ContainerClient,
    blob_name: &str,
) -> Option<TradeData> {
    let blob_client = container_client.blob_client(blob_name);
    match blob_client.get_content().await {
        Ok(data) => serde_json::from_slice::<TradeData>(&data).ok(),
        Err(e) => {
            eprintln!("Failed to download {blob_name}: {e}");
            None
        }
    }
}

// ---------------------------------------------------------------------------
// Public entry-point
// ---------------------------------------------------------------------------
pub async fn fetch_trades_from_azure() -> Result<Vec<TradeData>, String> {
    let total = Instant::now();

    // ---- env vars ---------------------------------------------------------
    let tenant_id = env::var("AZURE_TENANT_ID").map_err(|e| e.to_string())?;
    let client_id = env::var("AZURE_CLIENT_ID").map_err(|e| e.to_string())?;
    let client_secret = env::var("AZURE_CLIENT_SECRET").map_err(|e| e.to_string())?;
    let storage_account = env::var("AZURE_ACCOUNT_NAME").map_err(|e| e.to_string())?;
    let container_name = env::var("AZURE_CONTAINER_NAME").map_err(|e| e.to_string())?;

    // Prefixes – fall back to empty string (= whole container) when unset.
    let prefixes: Vec<String> = {
        let mut p = Vec::new();
        if let Ok(v) = env::var("AZURE_PREFIX_OPT") {
            if !v.is_empty() {
                p.push(v);
            }
        }
        if let Ok(v) = env::var("AZURE_PREFIX_FUT") {
            if !v.is_empty() {
                p.push(v);
            }
        }
        if p.is_empty() {
            p.push(String::new()); // list everything
        }
        p
    };

    // ---- Reusable HTTP client (connection pool) ---------------------------
    // The default reqwest Client already keeps a connection pool.
    // Building one explicitly lets us tune pool sizes.
    let http = Client::builder()
        .pool_max_idle_per_host(100)
        .build()
        .map_err(|e| e.to_string())?;

    // ---- Authenticate -----------------------------------------------------
    let t = Instant::now();
    println!("[LOG] Authenticating…");
    let token =
        get_oauth_token(&http, &tenant_id, &client_id, &client_secret)
            .await
            .map_err(|e| e.to_string())?;
    println!("[LOG] Auth took {:.2}s", t.elapsed().as_secs_f64());

    // ---- Build container client -------------------------------------------
    let credentials = StorageCredentials::bearer_token(token);
    let blob_service = BlobServiceClient::new(&storage_account, credentials);
    let container_client = Arc::new(blob_service.container_client(&container_name));

    // ---- 1. List ALL blob names across every prefix in parallel -----------
    let t = Instant::now();
    println!("[LOG] Listing blobs…");
    let list_futures: Vec<_> = prefixes
        .iter()
        .map(|pfx| {
            let cc = Arc::clone(&container_client);
            let pfx = pfx.clone();
            tokio::spawn(async move { list_all_blob_names(&cc, &pfx).await })
        })
        .collect();

    let mut all_names: Vec<String> = Vec::new();
    for handle in list_futures {
        let names = handle.await.map_err(|e| e.to_string())??;
        all_names.extend(names);
    }
    println!(
        "[LOG] Listed {} blobs in {:.2}s",
        all_names.len(),
        t.elapsed().as_secs_f64()
    );

    // ---- 2. Download all blobs with bounded concurrency -------------------
    //
    // KEY INSIGHT: The C# code uses `Parallel.ForEachAsync` which fires off
    // up to `Environment.ProcessorCount` concurrent downloads.  Using
    // `buffer_unordered` with a similar (or higher) limit gives us the same
    // behaviour without spawning OS threads.
    //
    // Increase CONCURRENCY if your machine / network can handle more.
    // On most Azure VMs 64-128 concurrent HTTP requests is fine.
    let concurrency: usize = env::var("DOWNLOAD_CONCURRENCY")
        .ok()
        .and_then(|v| v.parse().ok())
        .unwrap_or(64);

    let t = Instant::now();
    println!(
        "[LOG] Downloading {} blobs (concurrency={})…",
        all_names.len(),
        concurrency
    );

    let cc = Arc::clone(&container_client);
    let trades: Vec<TradeData> = futures::stream::iter(all_names.into_iter().map(move |name| {
        let cc = Arc::clone(&cc);
        async move { download_blob(&cc, &name).await }
    }))
    .buffer_unordered(concurrency)
    .filter_map(|opt| async { opt })
    .collect()
    .await;

    println!(
        "[LOG] Downloaded {} trades in {:.2}s",
        trades.len(),
        t.elapsed().as_secs_f64()
    );
    println!(
        "[LOG] Total time: {:.2}s",
        total.elapsed().as_secs_f64()
    );

    Ok(trades)
}

// ---------------------------------------------------------------------------
// main
// ---------------------------------------------------------------------------
#[tokio::main]
async fn main() {
    // Load .env file if present (same as C# Env.Load())
    let _ = dotenv::dotenv();

    match fetch_trades_from_azure().await {
        Ok(trades) => {
            println!("Successfully fetched {} trades.", trades.len());
        }
        Err(e) => {
            eprintln!("Error: {e}");
            std::process::exit(1);
        }
    }
}
"
}
```

**Why the original Rust code was slower and what changed:**

1. **Per-page sequential gating**: The original `process_blobs` downloaded blobs *within* each listing page, meaning the next page couldn't even be listed until every download in the current page completed. The C# code lists *all* blobs first, then fires downloads in parallel.

2. **Low effective concurrency**: `FuturesUnordered` only held futures from one page at a time (typically 5,000 items max, but often much fewer). The new version lists everything first, then uses `buffer_unordered(64)` (configurable via `DOWNLOAD_CONCURRENCY` env var) across *all* blobs simultaneously.

3. **No shared HTTP client**: Each `reqwest::Client::new()` in the token call created a fresh connection pool. Now a single `reqwest` client is reused (and the Azure SDK's internal client also benefits from connection reuse via `Arc<ContainerClient>`).

4. **`futures::join!` on only 2 prefixes**: The original parallelism ceiling was 2 concurrent prefix streams. Now listing is truly parallel via `tokio::spawn`, and all blob names are merged before a single high-concurrency download pass.

Set the `DOWNLOAD_CONCURRENCY` environment variable (default 64) to tune throughput. On Azure VMs you can often push this to 128+ for small JSON files.

