  "main.rs": "//! Demonstration: concurrent read/write to a PTY without mutex contention.
//!
//! The core problem in the original code is that a single `Arc<Mutex<Session>>`
//! is shared between the read thread and the write path.  Because the read
//! thread calls blocking `read()` while holding the mutex guard, the write
//! path can never acquire the lock until data arrives — classic deadlock.
//!
//! ## Solution: split the file descriptor
//!
//! A PTY master fd is full‑duplex.  We `dup()` the fd so we get two
//! independent owned `OwnedFd` / `File` handles:
//!   • one used exclusively for **reading**  (in a dedicated thread)
//!   • one used exclusively for **writing** (from any thread)
//!
//! No mutex is needed at all — the kernel handles concurrent read/write on
//! the same underlying fd just fine.
//!
//! This file is 100 % self‑contained (no Tauri, no expectrl) so you can
//! test it with `cargo run`.  It spawns `/bin/bash` inside a PTY, forwards
//! your stdin to the PTY (write side), and forwards PTY output (read side)
//! to your stdout — fully concurrently.
//!
//! To quit, type `exit` + Enter (or Ctrl‑D) inside the spawned shell.
//!
//! ### How to adapt this for Tauri + expectrl
//!
//! The same `dup()` trick works with expectrl's `Session`.  After spawning:
//!
//! ```ignore
//! use std::os::fd::AsRawFd;
//! let session = expectrl::spawn("bash").unwrap();
//! let master_fd = session.as_raw_fd();           // or however expectrl exposes it
//! let reader_fd = nix::unistd::dup(master_fd).unwrap();
//! let reader_file = unsafe { std::fs::File::from_raw_fd(reader_fd) };
//! // reader thread uses `reader_file.read()`  — no mutex
//! // writer uses `session.send()` (or `session.write_all()`) — no mutex
//! ```
//!
//! If expectrl doesn't expose the raw fd, you can use the `portable-pty`
//! or `pty-process` crate instead, which hand you separate reader/writer
//! halves natively.

use nix::fcntl::OFlag;
use nix::pty::{openpty, OpenptyResult};
use nix::sys::termios::{self, LocalFlags, SetArg};
use nix::unistd::{self, ForkResult};
use std::io::{self, Read, Write};
use std::os::fd::{AsRawFd, FromRawFd, OwnedFd};
use std::thread;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    // ── 1. Open a PTY pair ──────────────────────────────────────────────
    let OpenptyResult { master, slave } = openpty(None, None)?;

    // ── 2. Fork ─────────────────────────────────────────────────────────
    match unsafe { unistd::fork() }? {
        ForkResult::Child => {
            // ── child: become session leader, set controlling terminal ──
            unistd::setsid()?;

            // Slave becomes stdin / stdout / stderr
            unistd::dup2(slave.as_raw_fd(), 0)?;
            unistd::dup2(slave.as_raw_fd(), 1)?;
            unistd::dup2(slave.as_raw_fd(), 2)?;

            // Close originals
            drop(master);
            drop(slave);

            // Exec a shell
            let shell = std::ffi::CString::new("/bin/bash").unwrap();
            let args: &[&std::ffi::CStr] = &[&shell];
            let env_term = std::ffi::CString::new("TERM=xterm-256color").unwrap();
            let env_vars: &[&std::ffi::CStr] = &[&env_term];
            nix::unistd::execve(&shell, args, env_vars)?;
            unreachable!();
        }
        ForkResult::Parent { child } => {
            // Close slave in parent
            drop(slave);

            // ── 3. Dup the master fd ────────────────────────────────────
            //
            // This is the KEY insight: by dup()'ing the master fd we get
            // two independent file handles to the same PTY.  One for
            // reading, one for writing.  No mutex needed.
            let writer_fd: OwnedFd = unistd::dup(master.as_raw_fd())
                .map(|raw| unsafe { OwnedFd::from_raw_fd(raw) })?;

            let mut reader_file = unsafe { std::fs::File::from_raw_fd(master.as_raw_fd()) };
            let mut writer_file = unsafe { std::fs::File::from_raw_fd(writer_fd.as_raw_fd()) };

            // Prevent the OwnedFds from double‑closing
            std::mem::forget(master);
            std::mem::forget(writer_fd);

            // ── 4. Put host terminal in raw mode so keystrokes pass through
            let orig_termios = termios::tcgetattr(io::stdin())?;
            let mut raw = orig_termios.clone();
            termios::cfmakeraw(&mut raw);
            termios::tcsetattr(io::stdin(), SetArg::TCSANOW, &raw)?;

            // ── 5. Spawn READ thread (PTY → stdout) ─────────────────────
            let read_handle = thread::Builder::new()
                .name("pty-reader".into())
                .spawn(move || {
                    let mut buf = [0u8; 4096];
                    loop {
                        match reader_file.read(&mut buf) {
                            Ok(0) => break,   // EOF — child exited
                            Ok(n) => {
                                // In Tauri you would emit an event here:
                                //   app.emit("agent-output", &buf[..n]);
                                let _ = io::stdout().write_all(&buf[..n]);
                                let _ = io::stdout().flush();
                            }
                            Err(e) => {
                                eprintln!("\r\n[read error: {e}]\r\n");
                                break;
                            }
                        }
                    }
                })?;

            // ── 6. WRITE loop (stdin → PTY) ─ runs on main thread ───────
            //
            // In Tauri you would call `writer_file.write_all(data)` from
            // your `send_to_agent` command — no mutex required.
            let write_result: io::Result<()> = (|| {
                let mut buf = [0u8; 1024];
                loop {
                    let n = io::stdin().read(&mut buf)?;
                    if n == 0 {
                        break;
                    }
                    writer_file.write_all(&buf[..n])?;
                    writer_file.flush()?;
                }
                Ok(())
            })();

            // ── 7. Cleanup ──────────────────────────────────────────────
            // Restore terminal
            let _ = termios::tcsetattr(io::stdin(), SetArg::TCSANOW, &orig_termios);

            if let Err(e) = write_result {
                eprintln!("\r\n[write error: {e}]\r\n");
            }

            let _ = read_handle.join();

            // Reap child
            let _ = nix::sys::wait::waitpid(child, None);

            println!("\r\n[session ended]");
        }
    }

    Ok(())
}
"
}
