```json
{
  "Cargo.toml": "[package]
name = "rewrite-imports"
version = "0.1.0"
edition = "2021"

[dependencies]
ra_ap_syntax = "0.0.232"
",
  "main.rs": "use ra_ap_syntax::{
    AstNode, SyntaxNode, SourceFile,
    ast::{self, HasName},
    ted,
};

/// Test inputs demonstrating various import shapes.
const TEST_INPUT: &str = r#"
use vexide::{devices::smart::*, prelude::*};
use vexide::devices::*;
use vexide::devices::smart::Motor;
use vexide::{devices, fs};
use vexide::devices;
use vexide::devices::{smart, adi};
use {vexide::{devices, fs}, core::borrow};
use vexide::devices::smart::{Motor, Gps};
use something_else::devices::Foo;
use vexide::prelude;
"#;

fn main() {
    let parse = SourceFile::parse(TEST_INPUT, ra_ap_syntax::Edition::Edition2021);
    let file = parse.tree();
    let syntax = file.syntax().clone_for_update();

    rewrite_imports(&syntax);

    println!("=== Original ===");
    println!("{}", TEST_INPUT);
    println!("=== Rewritten ===");
    println!("{}", syntax);
}

/// Find all `use` items in the file and rewrite them.
pub fn rewrite_imports(root: &SyntaxNode) {
    // Collect all use items first to avoid mutating while iterating.
    let use_items: Vec<ast::Use> = root.descendants().filter_map(ast::Use::cast).collect();

    for use_item in use_items {
        if let Some(tree) = use_item.use_tree() {
            rewrite_use_tree_root(root, &use_item, &tree);
        }
    }
}

/// Collect the segments of a `Path` node into a Vec of strings.
fn path_segments(path: &ast::Path) -> Vec<String> {
    let mut segs = Vec::new();
    let mut cur = path.clone();
    loop {
        if let Some(seg) = cur.segment() {
            if let Some(name) = seg.name_ref() {
                segs.push(name.text().to_string());
            }
        }
        match cur.qualifier() {
            Some(q) => cur = q,
            None => break,
        }
    }
    segs.reverse();
    segs
}

/// Build a path string from segments.
fn segments_to_path_string(segs: &[String]) -> String {
    segs.join("::")
}

/// Build a new `UseTree` node from source text.
fn make_use_tree(text: &str) -> ast::UseTree {
    // Parse a synthetic use item and extract its tree.
    let wrapped = format!("use {};\n", text);
    let file = SourceFile::parse(&wrapped, ra_ap_syntax::Edition::Edition2021);
    file.tree()
        .syntax()
        .descendants()
        .find_map(ast::UseTree::cast)
        .expect("failed to parse synthetic use tree")
}

/// Given a `UseTree`, collect all leaf import paths (fully-qualified from the
/// tree root) along with their glob/rename status.
fn collect_leaves(tree: &ast::UseTree, prefix: &[String]) -> Vec<LeafImport> {
    let mut results = Vec::new();

    let mut current_prefix = prefix.to_vec();
    if let Some(path) = tree.path() {
        current_prefix.extend(path_segments(&path));
    }

    if let Some(list) = tree.use_tree_list() {
        for sub in list.use_trees() {
            results.extend(collect_leaves(&sub, &current_prefix));
        }
    } else {
        // This is a leaf.
        let star = tree.star_token().is_some();
        let rename = tree.rename().map(|r| r.name().map(|n| n.text().to_string())).flatten();
        results.push(LeafImport {
            segments: current_prefix,
            star,
            rename,
        });
    }

    results
}

#[derive(Debug, Clone)]
struct LeafImport {
    segments: Vec<String>,
    star: bool,
    rename: Option<String>,
}

impl LeafImport {
    fn to_use_path_string(&self) -> String {
        let base = segments_to_path_string(&self.segments);
        if self.star {
            format!("{}::*", base)
        } else if let Some(ref alias) = self.rename {
            format!("{} as {}", base, alias)
        } else {
            base
        }
    }
}

/// Apply the rewrite rule: remove `devices` from `vexide::devices::...`
fn rewrite_leaf(leaf: &mut LeafImport) -> bool {
    // Pattern: ["vexide", "devices", ...rest]
    // If rest is empty, this is `use vexide::devices` which imports the module itself.
    // We still flatten it to `use vexide::devices` ... actually that's tricky.
    // The rule is: flatten `vexide::devices::X` -> `vexide::X`.
    // `use vexide::devices` alone (importing the module) we should remove the
    // `devices` segment only if there's something after it. If it's just
    // `vexide::devices` (importing the devices module), we leave it as-is or
    // the user can decide. For this implementation, let's only rewrite when
    // there are segments after `devices`, OR when there's a glob.

    if leaf.segments.len() >= 2
        && leaf.segments[0] == "vexide"
        && leaf.segments[1] == "devices"
    {
        if leaf.segments.len() > 2 || leaf.star {
            // Remove the "devices" segment.
            leaf.segments.remove(1);
            return true;
        }
        // `use vexide::devices` with no glob and no further segments:
        // This imports the `devices` module itself. We'll leave it alone
        // since flattening means items moved, not that the module disappeared.
    }
    false
}

/// Group leaf imports back into a (potentially nested) use tree string.
/// This uses a simple trie approach to reconstruct `use` trees with braces.
fn rebuild_use_tree_string(leaves: &[LeafImport]) -> String {
    if leaves.is_empty() {
        return String::new();
    }
    if leaves.len() == 1 {
        return leaves[0].to_use_path_string();
    }

    // Find longest common prefix.
    let first = &leaves[0].segments;
    let mut common_len = 0;
    'outer: for i in 0..first.len() {
        for leaf in &leaves[1..] {
            if i >= leaf.segments.len() || leaf.segments[i] != first[i] {
                break 'outer;
            }
        }
        common_len = i + 1;
    }

    if common_len == 0 {
        // No common prefix: emit as `{a, b, c}`
        let parts: Vec<String> = leaves.iter().map(|l| l.to_use_path_string()).collect();
        return format!("{{{}}}", parts.join(", "));
    }

    let prefix = segments_to_path_string(&first[..common_len]);

    // Build sub-leaves with the prefix stripped.
    let sub_leaves: Vec<LeafImport> = leaves
        .iter()
        .map(|l| LeafImport {
            segments: l.segments[common_len..].to_vec(),
            star: l.star,
            rename: l.rename.clone(),
        })
        .collect();

    // Check if any sub-leaf is empty (meaning the prefix itself is imported).
    let mut parts: Vec<String> = Vec::new();
    for sl in &sub_leaves {
        if sl.segments.is_empty() && !sl.star {
            // This was `use prefix` - but since we factored it into a group
            // we need `self`.
            if let Some(ref alias) = sl.rename {
                parts.push(format!("self as {}", alias));
            } else {
                // We'll just push it; but this can only happen if the prefix
                // itself is used alongside sub-items.
                // Actually, we handle this correctly below.
                parts.push("self".to_string());
            }
        } else {
            parts.push(sl.to_use_path_string());
        }
    }

    if parts.len() == 1 {
        let only = &parts[0];
        if only == "*" {
            format!("{}::*", prefix)
        } else if only == "self" {
            prefix
        } else {
            format!("{}::{}", prefix, only)
        }
    } else {
        format!("{}::{{{}}}", prefix, parts.join(", "))
    }
}

/// Top-level handler for a single `use` item's tree.
fn rewrite_use_tree_root(root: &SyntaxNode, use_item: &ast::Use, tree: &ast::UseTree) {
    // Step 1: Collect all leaf imports from the tree.
    let mut leaves = collect_leaves(tree, &[]);

    // Step 2: Apply the rewrite rule to each leaf.
    let mut any_changed = false;
    for leaf in &mut leaves {
        if rewrite_leaf(leaf) {
            any_changed = true;
        }
    }

    if !any_changed {
        return;
    }

    // Step 3: Deduplicate leaves.
    dedup_leaves(&mut leaves);

    // Step 4: Rebuild the use tree string.
    let new_tree_str = rebuild_use_tree_string(&leaves);

    // Step 5: Parse it back into a UseTree node and replace in the syntax tree.
    let new_tree = make_use_tree(&new_tree_str);

    // Use `ted` for mutable tree editing (since we called clone_for_update).
    ted::replace(tree.syntax(), new_tree.syntax().clone_for_update());
}

/// Remove duplicate leaf imports.
fn dedup_leaves(leaves: &mut Vec<LeafImport>) {
    let mut seen = std::collections::HashSet::new();
    leaves.retain(|l| {
        let key = l.to_use_path_string();
        seen.insert(key)
    });
}
"
}
```

**How it works:**

1. **`collect_leaves`** — Does a depth-first traversal of the `UseTree` AST, accumulating the full path at each leaf (including globs and renames).

2. **`rewrite_leaf`** — Applies the rewrite rule: if a leaf's path starts with `["vexide", "devices", ...]` and has further segments (or a glob), it removes the `"devices"` segment, flattening `vexide::devices::smart` → `vexide::smart`.

3. **`rebuild_use_tree_string`** — Reconstructs a grouped `use` tree string from the rewritten leaves by finding their longest common prefix and grouping with braces.

4. **`ted::replace`** — Performs an in-place edit of the syntax tree (preserving the rest of the file's formatting) by swapping the old `UseTree` node for the newly constructed one.

**Key insight:** Rather than trying to handle every structural case (nested braces, moving children up, etc.) as separate edge cases, the approach **decomposes** the tree into flat leaf paths, applies a simple string-level rewrite to each, then **recomposes** them back into a tree. This avoids the combinatorial explosion of structural cases entirely.

