  "main.rs": "use serde::Deserialize;
use std::sync::Arc;

/// Our borrowed data structure — borrows from the source string.
#[derive(Deserialize, Debug)]
struct MyData<'a> {
    data: &'a str,
    more_data: &'a str,
}

/// A self-referential wrapper that owns the source `String` (via `Arc`)
/// and stores the deserialized borrowed fields as raw parts so the struct
/// is `Send + Sync`.
///
/// Safety contract:
/// • The `Arc<String>` is never mutated (Arcs to String are immutable).
/// • The pointers stored inside are derived from that `Arc<String>` and
///   remain valid as long as we hold the `Arc`.
/// • We only hand out references with the lifetime of `&self`, which
///   cannot outlive the `Arc`.
struct OwnedMyData {
    /// Keeps the backing string alive.
    _source: Arc<String>,
    /// Pointer + length for `data`
    data_ptr: *const u8,
    data_len: usize,
    /// Pointer + length for `more_data`
    more_data_ptr: *const u8,
    more_data_len: usize,
}

// The raw pointers inside are derived from an `Arc<String>` that we hold,
// so they are safe to send/share across threads.
unsafe impl Send for OwnedMyData {}
unsafe impl Sync for OwnedMyData {}

impl OwnedMyData {
    /// Deserialize once, storing the result together with the owned source.
    fn new(source: String) -> Result<Self, serde_json::Error> {
        let source = Arc::new(source);

        // Deserialize borrowing from `source`.
        // SAFETY: `source` lives inside the Arc we keep; the references
        // we obtain here point into that allocation.
        let data: MyData<'_> = {
            // We need a reference whose lifetime we can reason about.
            // The Arc is never dropped while `self` is alive, so the
            // pointers we extract remain valid.
            let s: &str = source.as_str();
            serde_json::from_str(s)?
        };

        Ok(Self {
            _source: source,
            data_ptr: data.data.as_ptr(),
            data_len: data.data.len(),
            more_data_ptr: data.more_data.as_ptr(),
            more_data_len: data.more_data.len(),
        })
    }

    /// Reconstruct the borrowed view.  Lifetime is tied to `&self`,
    /// guaranteeing the backing `Arc<String>` is alive.
    fn get(&self) -> MyData<'_> {
        unsafe {
            let data = std::str::from_utf8_unchecked(
                std::slice::from_raw_parts(self.data_ptr, self.data_len),
            );
            let more_data = std::str::from_utf8_unchecked(
                std::slice::from_raw_parts(self.more_data_ptr, self.more_data_len),
            );
            MyData { data, more_data }
        }
    }
}

impl std::fmt::Debug for OwnedMyData {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        self.get().fmt(f)
    }
}

#[tokio::main]
async fn main() {
    // Simulate incoming JSON from a channel / TCP stream.
    let incoming_json = String::from(r#"{"data": "hello", "more_data": "world"}"#);

    // Deserialize ONCE.  No clone, no DeserializeOwned.
    let owned = Arc::new(
        OwnedMyData::new(incoming_json).expect("failed to deserialize"),
    );

    // Spawn several tasks that share the same deserialized data.
    let mut handles = Vec::new();
    for i in 0..4 {
        let owned = Arc::clone(&owned);
        handles.push(tokio::spawn(async move {
            // Access the borrowed fields without any extra allocation.
            let view = owned.get();
            println!("Task {i}: data = {:?}, more_data = {:?}", view.data, view.more_data);
        }));
    }

    for h in handles {
        h.await.unwrap();
    }

    // Also usable on the main task.
    println!("Main: {:?}", owned.get());
}
"
}
