}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum PropertyValues {
    Title(Vec<RichTextObject>),
    RichText(Vec<RichTextObject>),
    Url(String),
    Number(f64),
    Checkbox(bool),
    MultiSelect(Vec<SelectObject>),
    Select(SelectObject),
}

impl fmt::Display for PropertyValues {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            PropertyValues::Title(v) => {
                let texts: Vec<&str> = v.iter().map(|r| r.text.content.as_str()).collect();
                write!(f, "Title({:?})", texts)
            }
            PropertyValues::RichText(v) => {
                let texts: Vec<&str> = v.iter().map(|r| r.text.content.as_str()).collect();
                write!(f, "RichText({:?})", texts)
            }
            PropertyValues::Url(u) => write!(f, "Url({})", u),
            PropertyValues::Number(n) => write!(f, "Number({})", n),
            PropertyValues::Checkbox(b) => write!(f, "Checkbox({})", b),
            PropertyValues::MultiSelect(v) => {
                let names: Vec<&str> = v.iter().map(|s| s.name.as_str()).collect();
                write!(f, "MultiSelect({:?})", names)
            }
            PropertyValues::Select(s) => write!(f, "Select({})", s.name),
