// ---------------------------------------------------------------------------
// Declarative macro that acts like a derive + attribute macro
//
// Usage:
//   notion_struct! {
//       #[derive(Debug, Clone, Serialize, Deserialize)]
//       struct MyUnit {
//           #[notion(type = "title", name = "Name")]
//           pub name: String,
//
//           #[notion(type = "url", name = "Icon url")]
//           pub icon_url: Option<String>,
//
//           #[notion(type = "multi_select", name = "Roles")]
//           pub categories: Option<Vec<serde_json::Value>>,
//       }
//   }
//
// Supported types:
//   title, rich_text, url, number, checkbox, multi_select, select
//
// Field Rust types expected per notion‐type:
//   title        => String
//   rich_text    => String
//   url          => String  (or Option<String>)
//   number       => f64     (or Option<f64>)
//   checkbox     => bool    (or Option<bool>)
//   multi_select => Vec<serde_json::Value>  (or Option<…>)
//   select       => String  (or Option<String>)
//
// Wrapping the Rust type in Option<…> makes the field optional: if None the
// property is simply omitted from the HashMap.
// ---------------------------------------------------------------------------

macro_rules! notion_struct {
    // -- entry: strip outer derives, parse fields --------------------------
    (
        $( #[$meta:meta] )*
        $vis:vis struct $name:ident {
            $(
                #[notion(type = $ntype:literal, name = $nname:literal)]
                $fvis:vis $fname:ident : $fty:ty
            ),* $(,)?
        }
    ) => {
        // Emit the struct itself with serde attributes so it stays usable.
        $( #[$meta] )*
        $vis struct $name {
            $(
                $fvis $fname : $fty,
            )*
        }

        // Implement the conversion trait.
        impl IntoNotionProperties for $name {
            fn into_notion_properties(&self) -> HashMap<String, PropertyValues> {
                let mut map = HashMap::new();
                $(
                    notion_struct!(@insert map, self, $fname, $fty, $ntype, $nname);
                )*
                map
            }
        }
    };

    // ---- helpers: one @insert arm per (notion‐type × optional?) ----------

    // String fields --------------------------------------------------------
    (@insert $map:ident, $self:ident, $fname:ident, String, "title", $nname:literal) => {
        $map.insert($nname.to_string(), make_title(&$self.$fname));
    };
    (@insert $map:ident, $self:ident, $fname:ident, Option<String>, "title", $nname:literal) => {
        if let Some(ref v) = $self.$fname {
            $map.insert($nname.to_string(), make_title(v));
        }
    };
    (@insert $map:ident, $self:ident, $fname:ident, String, "rich_text", $nname:literal) => {
        $map.insert($nname.to_string(), make_rich_text(&$self.$fname));
    };
    (@insert $map:ident, $self:ident, $fname:ident, Option<String>, "rich_text", $nname:literal) => {
        if let Some(ref v) = $self.$fname {
            $map.insert($nname.to_string(), make_rich_text(v));
        }
    };
    (@insert $map:ident, $self:ident, $fname:ident, String, "url", $nname:literal) => {
        $map.insert($nname.to_string(), make_url(&$self.$fname));
    };
    (@insert $map:ident, $self:ident, $fname:ident, Option<String>, "url", $nname:literal) => {
        if let Some(ref v) = $self.$fname {
            $map.insert($nname.to_string(), make_url(v));
        }
    };
    (@insert $map:ident, $self:ident, $fname:ident, String, "select", $nname:literal) => {
        $map.insert($nname.to_string(), make_select(&$self.$fname));
    };
    (@insert $map:ident, $self:ident, $fname:ident, Option<String>, "select", $nname:literal) => {
        if let Some(ref v) = $self.$fname {
            $map.insert($nname.to_string(), make_select(v));
        }
    };

    // Numeric fields -------------------------------------------------------
    (@insert $map:ident, $self:ident, $fname:ident, f64, "number", $nname:literal) => {
        $map.insert($nname.to_string(), make_number($self.$fname));
    };
    (@insert $map:ident, $self:ident, $fname:ident, Option<f64>, "number", $nname:literal) => {
        if let Some(v) = $self.$fname {
            $map.insert($nname.to_string(), make_number(v));
        }
    };

    // Bool fields ----------------------------------------------------------
    (@insert $map:ident, $self:ident, $fname:ident, bool, "checkbox", $nname:literal) => {
        $map.insert($nname.to_string(), make_checkbox($self.$fname));
    };
    (@insert $map:ident, $self:ident, $fname:ident, Option<bool>, "checkbox", $nname:literal) => {
        if let Some(v) = $self.$fname {
            $map.insert($nname.to_string(), make_checkbox(v));
        }
    };

    // MultiSelect fields ---------------------------------------------------
    (@insert $map:ident, $self:ident, $fname:ident, Vec<serde_json::Value>, "multi_select", $nname:literal) => {
        $map.insert($nname.to_string(), make_multi_select(&$self.$fname));
    };
    (@insert $map:ident, $self:ident, $fname:ident, Option<Vec<serde_json::Value>>, "multi_select", $nname:literal) => {
        if let Some(ref v) = $self.$fname {
            $map.insert($nname.to_string(), make_multi_select(v));
        }
    };
}

// ---------------------------------------------------------------------------
// Now define the struct using the macro — looks almost identical to the
// original snippet from the question.
// ---------------------------------------------------------------------------

notion_struct! {
    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct MyUnit {
        #[notion(type = "title", name = "Name")]
        pub name: String,

        #[notion(type = "url", name = "Icon url")]
        pub icon_url: Option<String>,

        #[notion(type = "multi_select", name = "Roles")]
        pub categories: Option<Vec<serde_json::Value>>,
    }
}

// A second example with more field types to show extensibility.
notion_struct! {
    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct Task {
        #[notion(type = "title", name = "Task")
        ]
        pub title: String,

        #[notion(type = "rich_text", name = "Description")]
        pub description: Option<String>,

        #[notion(type = "number", name = "Priority")]
        pub priority: Option<f64>,

        #[notion(type = "checkbox", name = "Done")]
        pub done: bool,

        #[notion(type = "select", name = "Status")]
        pub status: Option<String>,
    }
}

// ---------------------------------------------------------------------------
// main — demo
// ---------------------------------------------------------------------------

fn main() {
    println!("=== MyUnit ===");
    let unit = MyUnit {
        name: "Archer".to_string(),
        icon_url: Some("https://example.com/archer.png".to_string()),
        categories: Some(vec![
            serde_json::Value::String("DPS".to_string()),
            serde_json::Value::String("Ranged".to_string()),
        ]),
    };

    let props = unit.into_notion_properties();
    for (key, value) in &props {
        println!("  {key}: {value}");
    }

    // Serialise to JSON to show Notion-ready output.
    println!(
        "\n  JSON:\n{}",
        serde_json::to_string_pretty(&props).unwrap()
    );

    println!("\n=== MyUnit with None fields ===");
    let unit2 = MyUnit {
        name: "Knight".to_string(),
        icon_url: None,
        categories: None,
    };
    let props2 = unit2.into_notion_properties();
    for (key, value) in &props2 {
        println!("  {key}: {value}");
    }

    println!("\n=== Task ===");
    let task = Task {
        title: "Write Notion integration".to_string(),
        description: Some("Use Rust macros to auto-generate property maps.".to_string()),
        priority: Some(1.0),
        done: false,
        status: Some("In Progress".to_string()),
    };
    let props3 = task.into_notion_properties();
    for (key, value) in &props3 {
        println!("  {key}: {value}");
    }
    println!(
        "\n  JSON:\n{}",
        serde_json::to_string_pretty(&props3).unwrap()
    );
}
"
}
