use bevy::window::PrimaryWindow;
use bevy::color::palettes::css;

fn main() {
    App::new()
        .add_plugins(DefaultPlugins)
        .add_systems(Startup, setup)
        .add_systems(Update, (rotate_cube, cast_ray_and_draw_gizmo))
        .run();
}

#[derive(Component)]
struct Block;

fn setup(
    mut commands: Commands,
    mut meshes: ResMut<Assets<Mesh>>,
    mut materials: ResMut<Assets<StandardMaterial>>,
) {
    // Cube
    commands.spawn((
        Mesh3d(meshes.add(Cuboid::new(1.0, 1.0, 1.0))),
        MeshMaterial3d(materials.add(StandardMaterial {
            base_color: Color::srgb(0.3, 0.5, 0.8),
            ..default()
        })),
        Transform::from_translation(Vec3::ZERO)
            .with_rotation(Quat::from_euler(EulerRot::XYZ, 0.3, 0.5, 0.2)),
        Block,
    ));

    // Light
    commands.spawn((
        DirectionalLight {
            illuminance: 10000.0,
            shadows_enabled: true,
            ..default()
        },
        Transform::from_rotation(Quat::from_euler(EulerRot::XYZ, -0.8, 0.4, 0.0)),
    ));

    // Camera
    commands.spawn((
        Camera3d::default(),
        Transform::from_xyz(3.0, 3.0, 3.0).looking_at(Vec3::ZERO, Vec3::Y),
    ));
}

fn rotate_cube(
    time: Res<Time>,
    keyboard: Res<ButtonInput<KeyCode>>,
    mut query: Query<&mut Transform, With<Block>>,
) {
    for mut xf in query.iter_mut() {
        if keyboard.pressed(KeyCode::KeyR) {
            xf.rotate(Quat::from_euler(
                EulerRot::XYZ,
                0.3 * time.delta_secs(),
                0.5 * time.delta_secs(),
                0.2 * time.delta_secs(),
            ));
        }
    }
}

fn cast_ray_and_draw_gizmo(
    mut gizmos: Gizmos,
    window_q: Query<&Window, With<PrimaryWindow>>,
    camera_q: Query<(&Camera, &GlobalTransform)>,
    block_q: Query<(&GlobalTransform, &Mesh3d), With<Block>>,
    meshes: Res<Assets<Mesh>>,
) {
    let Ok(window) = window_q.get_single() else { return };
    let Some(cursor_pos) = window.cursor_position() else { return };
    let Ok((camera, cam_gt)) = camera_q.get_single() else { return };
    let Ok(ray) = camera.viewport_to_world(cam_gt, cursor_pos) else { return };

    for (block_gt, mesh_handle) in block_q.iter() {
        let Some(mesh) = meshes.get(&mesh_handle.0) else { continue };

        // We do a manual ray-vs-OBB test by transforming the ray into the cube's local space
        // and doing an AABB intersection, then transforming results back.
        let block_transform = block_gt.compute_transform();
        let inv_rot = block_transform.rotation.inverse();
        let inv_scale = Vec3::ONE / block_transform.scale;

        // Ray in local space of the cube
        let local_origin = inv_rot * (ray.origin - block_transform.translation) * inv_scale;
        let local_dir = (inv_rot * *ray.direction).normalize();

        // AABB half-extents (unit cube)
        let half = Vec3::splat(0.5);

        // Slab method for AABB intersection
        let mut tmin = f32::NEG_INFINITY;
        let mut tmax = f32::INFINITY;
        let mut hit_normal_local = Vec3::ZERO;

        for axis in 0..3 {
            let o = local_origin[axis];
            let d = local_dir[axis];
            let h = half[axis];

            if d.abs() < 1e-8 {
                if o < -h || o > h {
                    // No intersection on this slab
                    tmin = f32::INFINITY;
                    break;
                }
            } else {
                let inv_d = 1.0 / d;
                let mut t1 = (-h - o) * inv_d;
                let mut t2 = (h - o) * inv_d;
                let mut normal = Vec3::ZERO;
                normal[axis] = -1.0;

                if t1 > t2 {
                    std::mem::swap(&mut t1, &mut t2);
                    normal[axis] = 1.0;
                }

                if t1 > tmin {
                    tmin = t1;
                    hit_normal_local = normal;
                }
                if t2 < tmax {
                    tmax = t2;
                }

                if tmin > tmax {
                    break;
                }
            }
        }

        if tmin > tmax || tmin < 0.0 {
            continue;
        }

        // We have a hit!
        let hit_normal_world = (block_transform.rotation * hit_normal_local).normalize();

        // Face center in world space
        let face_center_local = hit_normal_local * 0.5;
        let face_center_world = block_transform.rotation * (face_center_local * block_transform.scale)
            + block_transform.translation;

        // === THE KEY SOLUTION ===
        // We need a rotation that:
        //   1) Has its Z-axis pointing along hit_normal_world (so the rect faces outward)
        //   2) Has its X and Y axes aligned with the cube's edges on that face
        //
        // The trick: determine the local-face rotation (which local axis maps to Z),
        // then compose with the cube's world rotation.
        //
        // For gizmos.rect, the rectangle is drawn in the XY plane of the given transform,
        // with Z being the normal direction.
        //
        // In local space, we need a rotation that maps Z -> hit_normal_local.
        // For a unit cube, hit_normal_local is one of ±X, ±Y, ±Z.

        let local_face_rotation = if hit_normal_local.x.abs() > 0.5 {
            // Normal is along ±X. We want local Z -> ±X
            // Rotate 90° around Y: Z -> X
            if hit_normal_local.x > 0.0 {
                Quat::from_rotation_y(std::f32::consts::FRAC_PI_2)
            } else {
                Quat::from_rotation_y(-std::f32::consts::FRAC_PI_2)
            }
        } else if hit_normal_local.y.abs() > 0.5 {
            // Normal is along ±Y. We want local Z -> ±Y
            // Rotate -90° around X: Z -> Y
            if hit_normal_local.y > 0.0 {
                Quat::from_rotation_x(-std::f32::consts::FRAC_PI_2)
            } else {
                Quat::from_rotation_x(std::f32::consts::FRAC_PI_2)
            }
        } else {
            // Normal is along ±Z
            if hit_normal_local.z > 0.0 {
                Quat::IDENTITY
            } else {
                Quat::from_rotation_y(std::f32::consts::PI)
            }
        };

        // Compose: first apply the local face rotation, then the cube's world rotation
        let final_rotation = block_transform.rotation * local_face_rotation;

        // Draw the gizmo rect slightly offset along the normal to avoid z-fighting
        let gizmo_pos = face_center_world + hit_normal_world * 0.005;

        gizmos.rect(
            Isometry3d::new(gizmo_pos, final_rotation),
            Vec2::new(1.0, 1.0),
            Color::from(css::LIME),
        );

        // Also draw the hit point for debugging
        let hit_point_world = ray.origin + *ray.direction * tmin;
        gizmos.sphere(
            Isometry3d::from_translation(hit_point_world),
            0.03,
            Color::from(css::RED),
        );

        // Draw cube axes for reference
        let center = block_transform.translation;
        gizmos.line(center, center + block_transform.rotation * Vec3::X * 0.8, Color::from(css::RED));
        gizmos.line(center, center + block_transform.rotation * Vec3::Y * 0.8, Color::from(css::GREEN));
        gizmos.line(center, center + block_transform.rotation * Vec3::Z * 0.8, Color::from(css::BLUE));
    }
}
"
}
```

## How the solution works

The critical insight is:

1. **Transform the ray into the cube's local space** to do the intersection test and find which face (local axis) was hit.

2. **Build a local-face rotation** — a quaternion that rotates the gizmo's default Z-normal to align with the hit face's local normal (e.g., `Quat::from_rotation_y(90°)` to map Z→X for the +X face).

3. **Compose with the cube's world rotation**: `final_rotation = cube_rotation * local_face_rotation`. This ensures the gizmo's normal points outward from the correct face AND the gizmo's edges stay aligned with the cube's edges, even as the cube rotates arbitrarily.

**Controls:** Press `R` to rotate the cube. Move the mouse cursor over the cube to see the green rectangle gizmo flush against whichever face you're pointing at.

